// ═══════════════════════════════════════════════════════════════
// CALIGO - 클라이언트 (game.js)
// ═══════════════════════════════════════════════════════════════

const socket = io();
window.socket = socket;  // auth.js 등 다른 스크립트에서 참조

// #9: 연결 직후 세션 재접속 시도 (새로고침 시 게임 복구)
socket.on('connect', () => {
  try {
    const raw = sessionStorage.getItem('caligo_session');
    if (!raw) return;
    const sess = JSON.parse(raw);
    if (!sess || !sess.token || !sess.roomId) return;
    // 2시간 이상 지난 세션은 무시 (일반 게임 최대 한 판 기준)
    if (Date.now() - (sess.ts || 0) > 2 * 60 * 60 * 1000) {
      sessionStorage.removeItem('caligo_session');
      return;
    }
    // ★ FIX (팀전 새로고침 시 isTeamMode 유실): 커스텀 2v2 vs AI 는 1v1 셋업 페이즈(hp/placement/reveal)를
    //   재사용하므로 서버가 1v1 재접속 이벤트를 보내 S.isTeamMode 가 false 로 남았다 → 보드가 5×5/단일
    //   프로필로 깨짐. 세션에 저장된 isTeam 으로 재접속 즉시 복원(team_game_start 가 오면 거기서도 true).
    if (sess.isTeam) { try { S.isTeamMode = true; } catch (e) {} }
    socket.emit('reconnect_game', { roomId: sess.roomId, sessionToken: sess.token });
  } catch (e) {}
});

socket.on('reconnect_failed', ({ reason }) => {
  try { sessionStorage.removeItem('caligo_session'); } catch (e) {}
  console.warn('[reconnect failed]', reason);
});

socket.on('reconnect_ok', ({ idx, phase }) => {
  // 상태는 다른 이벤트(joined/team_game_start)로 복구
  // ★ 새로고침으로 잃어버린 playerIdx 복원 — 1v1 세팅 단계 이벤트(reveal/placement 등)는
  //   idx 를 싣지 않으므로 여기서 보정해 둬야 이후 렌더·전송 로직이 올바르게 동작.
  if (typeof idx === 'number') S.playerIdx = idx;
  // ★ 재접속 시 애니메이션 guard/lock 잔류 제거 (끊김 도중 콜백 미수신으로 인한 프리징 방지).
  resetAnimGuards();
  if (typeof showSkillToast === 'function') {
    showSkillToast('재접속', false, undefined, 'event');
  }
});

socket.on('reconnect_phase_resume', ({ phase }) => {
  // 세팅 단계 재접속 — 서버가 현재 phase에 맞는 이벤트를 뒤이어 보냄
  console.log('[reconnect] phase resume:', phase);
});

// 1v1 입장 버튼으로 팀 방 코드를 입력한 경우 — 자동으로 팀전 입장으로 전환
socket.on('team_room_redirect', ({ roomId, playerName }) => {
  S.isTeamMode = true;
  S.myName = playerName;
  S.roomId = roomId;
  showSkillToast('이 방은 2v2 팀전 방입니다. 팀전으로 입장합니다.', false, undefined, 'event');
  socket.emit('join_team_room', { roomId, playerName });
});

socket.on('opp_disconnected_pending', ({ msg, graceMs }) => {
  try { showSkillToast(`🔌 ${msg}`, true, undefined, 'event'); } catch (e) {}
});

// 팀전: 끊긴 플레이어가 재접속 실패로 탈락 → 남은 팀원이 1v2 속행 (재접속 대기 알림 종료용).
socket.on('team_dc_continue', ({ msg, playerIdx }) => {
  try { showSkillToast(`🔌 ${msg}`, false, playerIdx, 'event'); } catch (e) {}
  try { addLog(msg, 'system'); } catch (e) {}
});

// ── 좌표 변환 헬퍼 (세로=A~E, 가로=1~5) ──
const ROW_LABELS = ['A','B','C','D','E','F','G'];
function coord(col, row) { return `${ROW_LABELS[row] || row}${col + 1}`; }
function coordLabel(col, row) { return `${ROW_LABELS[row] || row}${col + 1}`; }
function myN() { return S.myName || '나'; }
function oppN() { return S.opponentName || '상대'; }

// 한국어 조사 자동 변환 — 마지막 글자의 받침 유무로 with받침/without받침 선택.
function 조사(word, with받침, without받침) {
  if (!word || typeof word !== 'string') return without받침;
  const last = word.charCodeAt(word.length - 1);
  if (last < 0xAC00 || last > 0xD7A3) return without받침;
  const hasJongseong = (last - 0xAC00) % 28 !== 0;
  return hasJongseong ? with받침 : without받침;
}

// 슬라이더 좌측 컬럼 오버플로 감지 → --slide-scale을 점진적으로 줄여 최적점 찾기
function autoFitLeftCol(leftCol) {
  if (!leftCol) return;
  leftCol.style.setProperty('--slide-scale', '1');
  requestAnimationFrame(() => {
    const name = leftCol.querySelector('.slide-name');
    const atkRow = leftCol.querySelector('.slide-atk-row');
    const miniRow = leftCol.querySelector('.slide-mini-headers');
    const overflowing = () => {
      const o = (el) => el && (el.scrollWidth > el.clientWidth + 1);
      return o(name) || o(atkRow) || o(miniRow);
    };
    let scale = 1;
    const MIN = 0.72;
    const STEP = 0.04;
    for (let i = 0; i < 10 && overflowing() && scale > MIN; i++) {
      scale = Math.max(MIN, scale - STEP);
      leftCol.style.setProperty('--slide-scale', String(scale.toFixed(2)));
    }
  });
}

// 팩션 도장 뱃지 — PNG 도장 + 팩션 대표색 글로우(1.5px). 5팩션 지원: royal/villain/spirit/pagan/none.
//   현재 royal/villain 만 캐릭터에 배정됨. spirit/pagan/none 은 예약(데이터/렌더만 준비 — 배정 시 자동 표시).
const _FACTION_LABELS = { royal: '왕실', villain: '악인', spirit: '정령', pagan: '이교도', none: '무소속' };
function tagBadgeHtml(tag) {
  // ★ 소속(tag) 이 없으면(null/미지정/미상) 무소속(none) — 모든 캐릭터는 항상 팩션 도장을 단다.
  const t = _FACTION_LABELS[tag] ? tag : 'none';
  const stamps = window.FACTION_STAMPS || {};
  const src = stamps[t] || '';
  const label = _FACTION_LABELS[t];
  return `<span class="tag-badge ${t}" title="${label}"><img class="tag-stamp" src="${src}" alt="${label}"></span>`;
}

// ── 캐릭터 아이콘 <img> 생성 헬퍼 ──────────────────────────────────────
// 모든 UI 에서 이모지 대신 PNG 아이콘을 렌더링할 때 사용.
// src 가 이미지 경로이면 <img> 태그, 아니면(폴백) 텍스트 그대로 반환.
// cls: 추가 CSS 클래스, size: 인라인 크기(em 단위, 기본 1.2em)
function pieceIconHtml(src, opts) {
  if (!src) return '';
  const o = opts || {};
  const cls = o.cls || '';
  const size = o.size || '1.2em';
  // 이미지 경로가 아니면 (이모지 등 레거시) 텍스트 그대로 반환
  if (!src.startsWith('/') && !src.startsWith('http')) return src;
  return `<img src="${src}" alt="" class="piece-icon-img ${cls}" style="width:${size};height:${size};vertical-align:middle;object-fit:contain;" draggable="false">`;
}

// 텍스트 전용 컨텍스트에서 아이콘 이름만 반환 (드래그 데이터 등)
// 이미지 경로면 빈 문자열 반환 (텍스트로 표시 불가)
function pieceIconText(src) {
  if (!src) return '';
  if (src.startsWith('/') || src.startsWith('http')) return '';
  return src;
}

// 특수 공격 범위 캐릭터만 desc 표시 — 나머지는 미니 그리드로 충분
const SPECIAL_DESC_TYPES = new Set([
  'archer',         // 좌측 대각선 전체 (토글)
  'spearman',       // 세로줄 전체
  'cavalry',        // 가로줄 전체
  'twins',          // 형/동생 패턴
  'shadowAssassin', // 1칸 선택
  'witch',          // 원하는 칸 1곳
  'ratMerchant',    // 쥐 위치
  'weaponSmith',    // 가로/세로 토글
]);
function shouldShowDesc(typeOrObj) {
  if (!typeOrObj) return false;
  const t = typeof typeOrObj === 'string' ? typeOrObj : typeOrObj.type;
  return SPECIAL_DESC_TYPES.has(t);
}

function ratDestroyMsg(rats, mine) {
  const suffix = mine ? '격파됨' : '격파함';
  const coords = rats.map(r => coord(r.col, r.row));
  return `${coords.join(', ')}의 쥐 ${suffix}`;
}

function animateRatDestruction(cells, isMyRat) {
  const board = document.getElementById('game-board');
  if (!board) return;
  if (cells && cells.length > 0) playSfxRatDeath();

  const rc = window.RAT_ANIM_CONFIG?.death;
  const rGifs = window.RAT_GIFS;
  const rColor = isMyRat ? 'black' : 'white';
  const deathUrl = rGifs?.[rColor]?.death;

  for (const { col, row } of cells) {
    const cell = board.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
    if (!cell) continue;

    if (rc && deathUrl) {
      // ★ 사망 GIF — RAT_ANIM_CONFIG.death 위치에 1회 재생 후 제거
      const rx = isMyRat ? rc.x : -rc.x;
      const ry = rc.y; // Y 반전 없음 — 같은 수평선에서 마주봄
      const flip = isMyRat ? '' : ' scaleX(-1)';

      // 기존 idle GIF 제거 (중복 idle 대비 전체 제거)
      cell.querySelectorAll('img[src*="rat_' + rColor + '_idle"]').forEach(el => el.remove());

      // 사망 GIF Blob URL (1회 재생: NETSCAPE 블록 제거)
      fetch(deathUrl).then(r => r.arrayBuffer()).then(ab => {
        const src = new Uint8Array(ab);
        let patched = src;
        for (let i = 0; i < src.length - 18; i++) {
          if (src[i] === 0x21 && src[i+1] === 0xFF && src[i+2] === 0x0B) {
            const sig = String.fromCharCode(src[i+3],src[i+4],src[i+5],src[i+6],src[i+7],src[i+8],src[i+9],src[i+10],src[i+11],src[i+12],src[i+13]);
            if (sig === 'NETSCAPE2.0') {
              patched = new Uint8Array(src.length - 19);
              patched.set(src.subarray(0, i), 0);
              patched.set(src.subarray(i + 19), i);
              break;
            }
          }
        }
        const blobUrl = URL.createObjectURL(new Blob([patched], { type: 'image/gif' }));
        const img = document.createElement('img');
        img.className = 'rat-board-gif';
        img.style.cssText = `width:${rc.w}%;height:${rc.h}%;left:${50+rx}%;top:${50+ry}%;transform:translate(-50%,-50%)${flip};z-index:20`;
        img.src = blobUrl;
        cell.appendChild(img);

        const dur = (window._gifDurationCache && window._gifDurationCache[deathUrl]) || 650;
        setTimeout(() => { URL.revokeObjectURL(blobUrl); img.remove(); }, dur + 100);
      });
    } else {
      // 폴백: 이모지
      const emoji = isMyRat ? '🐀' : '🐁';
      const color = isMyRat ? '#52b788' : '#e05252';
      const posStyle = isMyRat ? 'top:1px;left:7px;z-index:4' : 'top:1px;left:2px;z-index:3';
      const ratEl = document.createElement('span');
      ratEl.style.cssText = `position:absolute;${posStyle};font-size:0.5rem;color:${color};pointer-events:none`;
      ratEl.textContent = emoji;
      ratEl.classList.add('rat-fading');
      cell.appendChild(ratEl);
      setTimeout(() => { ratEl.classList.add('rat-fadeout'); setTimeout(() => ratEl.remove(), 600); }, 400);
    }
  }
}

// ── 쥐 공격 GIF — 쥐장수 공격 시 보드 위 쥐 셀마다 동시 재생 ───────────────
//   쥐장수(ratMerchant) 공격 시 본인 소유 쥐가 있는 셀에 rat attack GIF 오버레이.
//   각 쥐 셀에 RAT_ANIM_CONFIG.attack 위치·크기로 Blob URL GIF 1루프 재생.
//   반환: Promise (모든 쥐 GIF 완료 시 resolve)
function animateRatAttackGifs(ownerIdx, viewerIdx, filterCells) {
  const rc = window.RAT_ANIM_CONFIG?.attack;
  const rGifs = window.RAT_GIFS;
  if (!rc || !rGifs) return Promise.resolve();

  const board = document.getElementById('game-board');
  if (!board) return Promise.resolve();

  // 현재 보드 위 해당 소유자의 쥐 좌표 수집
  // ★ filterCells 가 주어지면 해당 좌표의 쥐만 애니 (피격 시 전체 모션 방지)
  const _filterSet = filterCells ? new Set(filterCells.map(c => `${c.col},${c.row}`)) : null;
  const ratCells = [];
  if (S.boardObjects) {
    for (const obj of S.boardObjects) {
      if (obj.type === 'rat' && obj.owner === ownerIdx) {
        if (_filterSet && !_filterSet.has(`${obj.col},${obj.row}`)) continue;
        ratCells.push({ col: obj.col, row: obj.row });
      }
    }
  }
  if (ratCells.length === 0) return Promise.resolve();

  const isMyRat = (ownerIdx === viewerIdx);
  const rColor = isMyRat ? 'black' : 'white';
  const atkUrl = rGifs[rColor]?.attack;
  if (!atkUrl) return Promise.resolve();

  const rx = isMyRat ? rc.x : -rc.x;
  const ry = rc.y; // Y 반전 없음 — 같은 수평선에서 마주봄
  const flip = isMyRat ? '' : ' scaleX(-1)';

  // ★ NETSCAPE 블록 제거된 Blob 준비 — 모든 쥐 셀에서 공유
  const blobCache = window._gifBlobCache && window._gifBlobCache[atkUrl];
  const blobPromise = blobCache
    ? Promise.resolve(blobCache)
    : fetch(atkUrl).then(r => r.blob());

  // ★ 공격 애니 진행 중인 셀 추적 — renderGameBoard 가 셀 재구축 시 새 idle 을 hidden 으로 생성하도록.
  if (!S._ratAttackAnimCells) S._ratAttackAnimCells = new Set();

  const promises = ratCells.map(({ col, row }) => {
    const cell = board.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
    if (!cell) return Promise.resolve();

    const _cellKey = `${col},${row}`;
    S._ratAttackAnimCells.add(_cellKey);

    return new Promise(resolve => {
      // 기존 idle GIF 숨김 (querySelectorAll 로 중복 idle 모두 처리)
      cell.querySelectorAll('img[src*="rat_' + rColor + '_idle"]').forEach(el => el.style.visibility = 'hidden');

      blobPromise.then(blob => blob.arrayBuffer()).then(ab => {
        // ★ NETSCAPE2.0 블록 제거 → 정확히 1회 재생
        const src = new Uint8Array(ab);
        let patched = src;
        for (let i2 = 0; i2 < src.length - 18; i2++) {
          if (src[i2] === 0x21 && src[i2+1] === 0xFF && src[i2+2] === 0x0B) {
            const sig = String.fromCharCode(src[i2+3],src[i2+4],src[i2+5],src[i2+6],src[i2+7],
              src[i2+8],src[i2+9],src[i2+10],src[i2+11],src[i2+12],src[i2+13]);
            if (sig === 'NETSCAPE2.0') {
              patched = new Uint8Array(src.length - 19);
              patched.set(src.subarray(0, i2), 0);
              patched.set(src.subarray(i2 + 19), i2);
              break;
            }
          }
        }
        // ★ 고유 GIF Comment Extension 삽입 — Chrome 동일 바이너리 GIF 타이머 공유 차단.
        if (!window._ratGifUid) window._ratGifUid = 0;
        const _uid2 = ++window._ratGifUid;
        const _cb = new Uint8Array([0x21, 0xFE, 4,
          (_uid2 >>> 24) & 0xFF, (_uid2 >>> 16) & 0xFF, (_uid2 >>> 8) & 0xFF, _uid2 & 0xFF, 0x00]);
        const _pk = patched[10];
        const _hg = (_pk >> 7) & 1;
        const _gb = _hg ? 3 * (1 << ((_pk & 7) + 1)) : 0;
        const _ia = 13 + _gb;
        const _fn = new Uint8Array(patched.length + _cb.length);
        _fn.set(patched.subarray(0, _ia), 0);
        _fn.set(_cb, _ia);
        _fn.set(patched.subarray(_ia), _ia + _cb.length);
        const blobUrl = URL.createObjectURL(new Blob([_fn], { type: 'image/gif' }));
        const img = document.createElement('img');
        img.src = blobUrl;
        img.alt = '';

        // ★ body 에 fixed 배치 — renderGameBoard() 가 셀 innerHTML 을 재구축해도 GIF 파괴 안 됨.
        //   기존에는 cell.appendChild → _impactDelay 후 renderGameBoard() 가 GIF 를 중간에 제거했음.
        const cellRect = cell.getBoundingClientRect();
        const imgW = cellRect.width * rc.w / 100;
        const imgH = cellRect.height * rc.h / 100;
        const imgLeft = cellRect.left + cellRect.width * (50 + rx) / 100 - imgW / 2;
        const imgTop = cellRect.top + cellRect.height * (50 + ry) / 100 - imgH / 2;
        img.style.cssText = `position:fixed;left:${imgLeft}px;top:${imgTop}px;width:${imgW}px;height:${imgH}px;`
          + `transform:${flip || 'none'};z-index:9999;pointer-events:none;image-rendering:pixelated;`
          + `filter:drop-shadow(0 0 1px rgba(0,0,0,1)) drop-shadow(0 0 1px rgba(0,0,0,1));`;

        const cleanup = () => {
          if (img.parentNode) img.remove();
          URL.revokeObjectURL(blobUrl);
          // ★ Set 에서 제거 + 현재 셀의 idle GIF 를 fresh 참조로 복원.
          //   renderGameBoard 가 셀을 재구축했을 수 있으므로 기존 참조(idleImg)는 stale 가능.
          S._ratAttackAnimCells && S._ratAttackAnimCells.delete(_cellKey);
          const _freshCell = board.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
          if (_freshCell) _freshCell.querySelectorAll('img[src*="rat_' + rColor + '_idle"]').forEach(el => el.style.visibility = '');
          resolve();
        };

        // ★ Blob URL 즉시 DOM 추가 — decode() 지연 없이 프레임 0부터 렌더링
        const t0 = performance.now();
        document.body.appendChild(img);
        const cachedDur = window._gifDurationCache && window._gifDurationCache[atkUrl];
        const durP = cachedDur ? Promise.resolve(cachedDur)
          : (typeof _fetchGifDuration === 'function' ? _fetchGifDuration(atkUrl) : Promise.resolve(650));
        durP.then(dur => {
          const elapsed = performance.now() - t0;
          setTimeout(cleanup, Math.max(50, dur - elapsed + 100));
        }).catch(() => setTimeout(cleanup, 750));
      }).catch(() => {
        S._ratAttackAnimCells && S._ratAttackAnimCells.delete(_cellKey);
        const _freshCell2 = board.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
        if (_freshCell2) _freshCell2.querySelectorAll('img[src*="rat_' + rColor + '_idle"]').forEach(el => el.style.visibility = '');
        resolve();
      });
    });
  });

  return Promise.all(promises);
}

// ── 쥐 공격 GIF (자동 감지) — atkCells 내 쥐 위치를 검출하여 재생 ──────────
//   being_attacked / spectator_attack_anim 등 공격자 타입을 모르는 상황에서 사용.
//   atkCells 에 쥐가 있으면 쥐장수 공격 → 해당 쥐에 공격 GIF 재생.
//   viewerIdx: 시점 주체 (0/1). specMode: 관전자 — owner→color 직접 매핑.
function animateRatAttackFromCells(atkCells, viewerIdx, excludeOwner) {
  if (!Array.isArray(atkCells) || atkCells.length === 0) return;
  const objs = S.boardObjects;
  if (!objs) return;
  const atkSet = new Set(atkCells.map(c => `${c.col},${c.row}`));
  // atkCells 에 위치하는 쥐 수집 (소유자별 그룹)
  // ★ excludeOwner: 이 owner 의 쥐는 제외 (being_attacked 에서 내 쥐가 피격당하는 건 공격 모션 X)
  const ratsByOwner = {};
  for (const obj of objs) {
    if (obj.type !== 'rat') continue;
    if (!atkSet.has(`${obj.col},${obj.row}`)) continue;
    if (excludeOwner != null && obj.owner === excludeOwner) continue;
    if (!ratsByOwner[obj.owner]) ratsByOwner[obj.owner] = [];
    ratsByOwner[obj.owner].push(obj);
  }
  // 관전자: viewerIdx=0 → owner 0=black(아군식), owner 1=white(적군식) — 관전 보드와 동일
  // ★ filterCells 전달 — atkCells 에 해당하는 쥐만 공격 애니 재생 (전체 모션 방지)
  for (const ownerStr of Object.keys(ratsByOwner)) {
    animateRatAttackGifs(parseInt(ownerStr), viewerIdx, ratsByOwner[ownerStr]);
  }
}

// ── 쥐 공격 모션 (서버 신호) — 쥐장수가 실제로 공격했을 때만 서버가 보냄 ──────────
//   클라 자동 추정(atkCells 에 쥐가 있으면 공격) 은 일반 유닛 공격이 쥐 셀을 덮을 때 오작동 →
//   서버가 공격자=ratMerchant 일 때만 이 이벤트를 보내므로, 그 owner 의 쥐만 정확히 공격 모션 재생.
socket.on('rat_attack_anim', ({ owner }) => {
  if (typeof owner !== 'number' || typeof animateRatAttackGifs !== 'function') return;
  const viewerIdx = S.isSpectator ? 0 : S.playerIdx;
  animateRatAttackGifs(owner, viewerIdx);   // 해당 owner 의 모든 쥐 (쥐장수 공격 = 전원 가담)
});

// ── 스킬(유황범람 등)로 파괴된 쥐 사망 모션 ───────────────────────────────
//   서버가 result.data.destroyedRats=[{col,row,owner}] 로 전달. boardObjects 에서 제거 + 소유자별 사망 애니.
function _animateSkillDestroyedRats(destroyedRats) {
  if (!Array.isArray(destroyedRats) || destroyedRats.length === 0 || typeof animateRatDestruction !== 'function') return;
  const viewerIdx = S.isSpectator ? 0 : S.playerIdx;
  if (Array.isArray(S.boardObjects)) {
    S.boardObjects = S.boardObjects.filter(o => !(o.type === 'rat' &&
      destroyedRats.some(r => r.col === o.col && r.row === o.row && r.owner === o.owner)));
    S._cellFP = null;
  }
  const byOwner = {};
  for (const r of destroyedRats) (byOwner[r.owner] = byOwner[r.owner] || []).push({ col: r.col, row: r.row });
  for (const owner in byOwner) animateRatDestruction(byOwner[owner], parseInt(owner) === viewerIdx);
}

