// 4명 확정 상태를 구슬로 표시 — 블루 2개 + 레드 2개
function renderConfirmBeads(doneArr) {
  const teams = S.teamTeams || [[],[]];
  const blueTeam = teams[0] || [];
  const redTeam = teams[1] || [];
  const beadHtml = (idx, color) => {
    const done = !!(doneArr || [])[idx];
    return `<span class="confirm-bead bead-${color}${done ? ' bead-done' : ''}" title="${done ? '확정 완료' : '대기 중'}">${done ? '✓' : ''}</span>`;
  };
  const blue = (blueTeam.length > 0 ? blueTeam : [-1, -1]).slice(0, 2).map(idx => beadHtml(idx, 'blue')).join('');
  const red = (redTeam.length > 0 ? redTeam : [-1, -1]).slice(0, 2).map(idx => beadHtml(idx, 'red')).join('');
  // 슬롯이 부족할 때 빈 구슬로 보충
  const blueFill = '<span class="confirm-bead bead-blue"></span>'.repeat(Math.max(0, 2 - blueTeam.length));
  const redFill = '<span class="confirm-bead bead-red"></span>'.repeat(Math.max(0, 2 - redTeam.length));
  return `<div class="confirm-beads"><div class="confirm-beads-side">${blue}${blueFill}</div><div class="confirm-beads-divider">·</div><div class="confirm-beads-side">${red}${redFill}</div></div>`;
}

function renderTeamPlacement() {
  const titleEl = document.getElementById('team-placement-title');
  if (titleEl) {
    const teamLabel = S.teamId === 0 ? '블루팀' : '레드팀';
    titleEl.textContent = `배치 — ${teamLabel}`;
  }
  // 보드 렌더 (7x7)
  const board = document.getElementById('team-placement-board');
  if (!board) return;
  const b = S.teamPlacement.boardBounds || { min: 0, max: 6 };
  // 팀 점유 맵
  const occupied = {};  // key = `${c},${r}`, val = { owner: idx, piece }
  for (const pc of S.teamPlacement.myPieces || []) {
    if (pc.col >= 0) occupied[`${pc.col},${pc.row}`] = { owner: 'me', piece: pc };
  }
  for (const tm of S.teamPlacement.teammates || []) {
    for (const pc of tm.pieces || []) {
      if (pc.col >= 0) occupied[`${pc.col},${pc.row}`] = { owner: 'teammate', piece: pc, teammateName: tm.name };
    }
  }
  let html = '';
  for (let r = b.min; r <= b.max; r++) {
    for (let c = b.min; c <= b.max; c++) {
      const classes = ['cell'];
      // 팀원 점유: 다른 말이 차지함을 표시
      const occ = occupied[`${c},${r}`];
      let inner = `<span class="coord-label">${coord(c, r)}</span>`;
      if (occ) {
        inner += `<span class="piece-icon">${pieceIconHtml(occ.piece.icon, {size:'1.2em'})}</span>`;
        if (occ.owner === 'teammate') classes.push('occupied-other');
      }
      html += `<div class="${classes.join(' ')}" data-col="${c}" data-row="${r}">${inner}</div>`;
    }
  }
  board.innerHTML = html;
  // 보드 7x7 그리드 강제
  const totalSize = b.max - b.min + 1;
  board.style.gridTemplateColumns = `repeat(${totalSize}, 44px)`;
  board.style.gridTemplateRows = `repeat(${totalSize}, 44px)`;
  // 클릭: 선택된 piece를 해당 위치에 배치 — 구역 제한 없음
  board.querySelectorAll('.cell').forEach(cellEl => {
    cellEl.addEventListener('click', () => {
      if (S.teamPlacement.confirmed) return;
      const c = parseInt(cellEl.dataset.col, 10);
      const r = parseInt(cellEl.dataset.row, 10);
      const pIdx = S.teamPlacement.selectedPieceIdx;
      if (pIdx === null || pIdx === undefined) { showSkillToast('먼저 말을 선택하세요.', false, undefined, 'event'); return; }
      socket.emit('team_place_piece', { pieceIdx: pIdx, col: c, row: r });
    });
  });
  // 내 pieces 리스트
  const myList = document.getElementById('team-placement-my-pieces');
  if (myList) {
    myList.innerHTML = (S.teamPlacement.myPieces || []).map((pc, i) => {
      const placed = pc.col >= 0;
      const selected = S.teamPlacement.selectedPieceIdx === i;
      return `<div class="team-placement-piece ${placed ? 'placed' : ''} ${selected ? 'selected' : ''}" data-idx="${i}">
        <span class="piece-icon">${pieceIconHtml(pc.icon, {size:'1.2em'})}</span>
        <span class="piece-name">${escapeHtmlGlobal(pc.name || pc.type)}</span>
        <span class="piece-hp">HP ${pc.hp}</span>
      </div>`;
    }).join('');
    myList.querySelectorAll('.team-placement-piece').forEach(el => {
      el.addEventListener('click', () => {
        if (S.teamPlacement.confirmed) return;
        const i = parseInt(el.dataset.idx, 10);
        S.teamPlacement.selectedPieceIdx = S.teamPlacement.selectedPieceIdx === i ? null : i;
        renderTeamPlacement();
      });
    });
  }
  // 팀원 pieces
  const tmList = document.getElementById('team-placement-teammate-pieces');
  if (tmList) {
    const teammates = S.teamPlacement.teammates || [];
    if (!teammates.length) {
      tmList.innerHTML = '<p class="muted" style="font-size:0.78rem">팀원 정보 없음</p>';
    } else {
      tmList.innerHTML = teammates.map(tm => {
        const placedCnt = (tm.pieces || []).filter(p => p.col >= 0).length;
        const totalCnt = (tm.pieces || []).length;
        return `<div class="team-placement-piece">
          <span class="piece-name"><strong>${escapeHtmlGlobal(tm.name)}</strong></span>
          <span class="piece-hp">${placedCnt}/${totalCnt} 배치</span>
        </div>`;
      }).join('');
    }
  }
  // 확정 버튼
  const btn = document.getElementById('btn-team-placement-confirm');
  if (btn) {
    const allPlaced = (S.teamPlacement.myPieces || []).every(p => p.col >= 0);
    btn.disabled = S.teamPlacement.confirmed || !allPlaced;
    btn.textContent = S.teamPlacement.confirmed ? '✅ 확정됨' : allPlaced ? '배치 확정' : '모든 말을 배치하세요';
  }
}

const _btnTeamPlacementConfirm = document.getElementById('btn-team-placement-confirm');
if (_btnTeamPlacementConfirm) {
  _btnTeamPlacementConfirm.addEventListener('click', () => {
    if (_btnTeamPlacementConfirm.disabled) return;
    socket.emit('team_confirm_placement');
  });
}

// ═══════════════════════════════════════════════════════════════
// ── 팀전 게임 루프 ────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════
function applyTeamGameState(state) {
  if (!state) return;
  S.playerIdx = state.myIdx;
  S.teamId = state.myTeamId;
  S.teamTeams = state.teams || S.teamTeams;
  S.turnNumber = state.turnNumber;
  S.boardBounds = state.boardBounds;
  S._cellFP = null; // ★ 팀전 상태 적용 — 핑거프린트 캐시 무효화
  S.sp = state.sp;
  S.instantSp = state.instantSp;
  S.currentPlayerIdx = state.currentPlayerIdx;
  // ★ 사용자 보고 (턴오더 양쪽 슬롯 빛남): 팀원 사망 시 같은 플레이어가 두 슬롯 차지 →
  //   currentPlayerIdx 만으로는 활성 슬롯 식별 불가. 서버의 turnSlotIdx 를 함께 저장해 단일 슬롯만 강조.
  if (typeof state.turnSlotIdx === 'number') S.turnSlotIdx = state.turnSlotIdx;
  S.isMyTurn = !!state.isMyTurn;
  if (typeof applyTurnUiState === 'function') applyTurnUiState();
  S.teamGamePlayers = state.players || [];
  S.boardObjects = state.boardObjects || [];
  // ★ FIX (#1 유해 타이밍 / #5 사망·피격 모션과 유해 겹침): 1v1 의 _applyServerRemainsExcludingDeaths
  //   와 동일하게, 지금 사망 GIF 가 재생 중인 셀(_pendingDeathCells)의 유해는 제외하고 적용한다.
  //   그 셀의 유해는 사망 GIF 완료 후 _addClientSideRemains 가 추가·렌더한다. (이전엔 무조건 교체라
  //   사망/피격 모션 위에 유해가 겹쳐 보이거나, 게이트로 렌더가 밀려 그 턴에 유해가 안 보였음.)
  {
    const _rem = state.remains || [];
    const _pend = S._pendingDeathCells;
    let _next = (_pend && _pend.size > 0) ? _rem.filter(r => !_pend.has(`${r.col},${r.row}`)) : _rem;
    // ★ #5: 유해 피격 애니 진행 중인 셀은 현재 단계(hits)를 유지 — 서버의 새 단계로 조기 교체하면
    //   피격 GIF 위에 다음 단계 PNG 가 겹쳐 보임. 정착(finalize) 후 remains_update 가 최종 단계 반영.
    const _hitPend = S._pendingRemainsHitCells;
    if (_hitPend && _hitPend.size > 0) {
      const _cur = S.remains || [];
      _next = _next.map(r => {
        if (!_hitPend.has(`${r.col},${r.row}`)) return r;
        const _old = _cur.find(o => o.col === r.col && o.row === r.row);
        return _old || r;
      });
    }
    S.remains = _next;
  }
  // 내 pieces / 팀원 pieces / 적팀 pieces 재구성
  const me = S.teamGamePlayers.find(p => p.idx === S.playerIdx);
  const teammate = S.teamGamePlayers.find(p => p.teamId === S.teamId && p.idx !== S.playerIdx);
  const enemies = S.teamGamePlayers.filter(p => p.teamId !== S.teamId);
  S.myPieces = me ? me.pieces : [];
  S.teammatePieces = teammate ? teammate.pieces : [];
  // 적 2명의 pieces를 합쳐서 oppPieces처럼 다룸 (oppSummary 포맷)
  S.oppPieces = enemies.flatMap(e => (e.pieces || []).map(pc => ({ ...pc, ownerIdx: e.idx, ownerName: e.name, ownerTeamId: e.teamId })));
}

socket.on('team_game_start', (state) => {
  S.isTeamMode = true;          // buildBoard가 7x7로 그리도록 보장
  S._gameEnded = false;         // C-9: 이전 판의 _gameEnded 플래그 리셋
  S._gameOverShown = false;     // 결과화면 토스트 차단 플래그 리셋
  resetAnimGuards();            // C-4: 애니메이션 lock·guard 일괄 리셋 (재접속/새 판 대비)
  closeAllModals(); // C-8: 모달 잔류 방지
  // ★ 표식 노출 정보 — 새 팀전 시작 시 stale 엔트리 모두 정리
  if (S._revealedMarkedOpps instanceof Map) S._revealedMarkedOpps.clear();
  applyTeamGameState(state);
  // ★ 재접속 시 내 이번 턴 행동 소진 상태 복원 (이미 행동했는데 새로고침하면 다시 가능해 보이던 버그).
  //   팀 상태의 per-player actionDone 사용. 신규 게임이면 actionDone=false 이므로 영향 없음.
  if (state.reconnected) {
    const _me = (S.teamGamePlayers || []).find(p => p.idx === S.playerIdx);
    S.actionDone = !!(_me && _me.actionDone);
    // ★ FIX (#8 팀전 재접속 기억): 새로고침으로 잃은 클라 사적 지식(추리토큰·공격마크·표식위치·유해방향)
    //   복원. 1v1 game_start 는 _restoreKnowledge 를 호출하지만 team_game_start 는 빠져 있었다.
    try { _restoreKnowledge(); S.oppPieces = S.oppPieces; } catch (e) {}
    if (typeof refreshDeductionTokens === 'function') { try { refreshDeductionTokens(); } catch (e) {} }
  }
  if (typeof buildGameUI === 'function') {
    try { buildGameUI(); } catch (e) {}
  }
  showScreen('screen-game');
  // 팀전 시작 — 데미지 도장 초기 스냅샷
  if (typeof snapshotTurnStartHps === 'function') snapshotTurnStartHps();
  renderTeamGameSnapshot();
  showActionBar(S.isMyTurn);
  if (S.isMyTurn) try { playTurnBell(); } catch (e) {}
  // 재접속 vs 신규 게임 시작 구분 — 1v1과 동일하게 turnNumber > 1 또는 reconnect 플래그
  //   ★ 서버 페이로드 필드명은 reconnected (이전엔 state.reconnect 오타로 항상 false → 턴1 재접속 시 신규 인트로 재생).
  const isReconnect = !!state.reconnected || (state.turnNumber && state.turnNumber > 1);
  if (isReconnect) {
    const cur = (S.teamGamePlayers || []).find(p => p.idx === S.currentPlayerIdx);
    const turnOwnerName = cur ? (cur.idx === S.playerIdx ? (myN() || cur.name) : cur.name) : '?';
    addLog(`${turnOwnerName}의 턴`, 'system');
    playGameStartAnimation(S.isMyTurn, true, turnOwnerName);
  } else {
    // 팀전 시작 애니메이션
    playGameStartAnimation(S.isMyTurn);
  }
});

let _teamUpdateSeq = 0; // C-10: team_game_update render sequence counter
socket.on('team_game_update', (state) => {
  ++_teamUpdateSeq;
  const wasMyTurn = S.isMyTurn;
  const prevTurnIdx = S.currentPlayerIdx;
  const prevSnap = (typeof snapshotTeamHps === 'function') ? snapshotTeamHps() : null;
  applyTeamGameState(state);
  // 내가 쌍둥이 이동 중이었는데 턴이 넘어가는 케이스 (타이머 만료/강제 종료 등) — UI 정리
  if (wasMyTurn && !S.isMyTurn && S.twinPhaseActive && typeof exitTwinMovePhase === 'function') {
    exitTwinMovePhase(/*emitToast=*/false);
  }
  // 스킬·패시브로 HP가 변한 piece에 hit/heal 애니메이션 — 1v1 skill_result/status_update와 동일
  const currSnap = (typeof snapshotTeamHps === 'function') ? snapshotTeamHps() : null;
  const changes = (typeof detectTeamHpChanges === 'function') ? detectTeamHpChanges(prevSnap, currSnap) : [];
  // 내 턴 새로 들어왔을 때 — 1v1의 your_turn처럼 액션 플래그 전체 리셋
  if (S.isMyTurn && !wasMyTurn) {
    S.action = null;
    S.selectedPiece = null;
    S.targetSelectMode = false;
    S.actionDone = false;
    S.moveDone = false;
    S.actionUsedSkillReplace = false;
    S.twinMovePending = false;
    S.twinMovedSub = null;
    S.twinElderSkipped = false;
    S.twinYoungerSkipped = false;
    S.skillsUsedThisTurn = [];
    S.lastActionType = null;
    S.lastActionPieceType = null;
    // ★ 사용자 보고 (유닛 딤 안 풀림): 이전 턴 행동 모드 잔재 방어적 클리어 (팀 모드).
    document.body.classList.remove('action-locked', 'dim-morale-zone');
    if (typeof setActionButtonMode === 'function') setActionButtonMode(null);
    try { playTurnBell(); } catch (e) {}
  }
  // 턴이 바뀌었으면 — 1v1처럼 로그·토스트로 누구 차례인지 명확히 알림
  if (prevTurnIdx !== S.currentPlayerIdx && S.currentPlayerIdx !== undefined) {
    // ★ 방어적: 이전 턴에 스킬 시전 dim 이 걸린 채로 턴이 넘어가는 케이스 — 강제 해제.
    //   endSkillCastDim 은 idempotent (hidden 클래스 추가 + 포인터 정리) 이라 중복 호출 무해.
    if (typeof endSkillCastDim === 'function') endSkillCastDim();
    // 이전 턴 동안 켜져 있던 turn-bright 카드 모두 해제 — 다음 턴부터 다시 dim 으로
    clearAllTurnBright();
    // ★ 방어적 — 이전 턴에 flush 안 된 패시브 alert 버퍼 폐기 (turn 경계 stale 누설 방지).
    if (Array.isArray(S._pendingDefensiveAlerts)) S._pendingDefensiveAlerts.length = 0;
    const cur = (S.teamGamePlayers || []).find(p => p.idx === S.currentPlayerIdx);
    if (cur) {
      const isMine = cur.idx === S.playerIdx;
      const isAlly = cur.teamId === S.teamId && !isMine;
      const label = isMine ? `${myN() || cur.name}` : cur.name;
      const turnMsg = `${S.turnNumber}턴 : ${label} 차례`;
      addLog(turnMsg, 'system');
      // 내 차례만 토스트 (사용자 요청: 다른 플레이어 차례 알림 불필요)
      if (isMine) {
        showSkillToast(`내 차례`, false, S.playerIdx, 'event');
      }
    }
    // 새 턴 시작 — 데미지 도장/HP 빨간 마킹 초기화 (팀모드 turn change 시점)
    // preCurseHps (서버 제공) 로 startHp 캡처해 저주 보라 도장 표시 가능
    if (typeof snapshotTurnStartHps === 'function') snapshotTurnStartHps(state.preCurseHps);
    S.attackLog = S.attackLog.filter(a => a.turn >= S.turnNumber - 1); // C-5: prune old entries
  }
  // ★ FIX (팀전 스킬 타이밍 — 1v1 통일): 마법구(SP 오브) 비행 중에는 보드/HP 시각 갱신을
  //   orb 도착(T+SP_END) 시점까지 지연. 데이터(state)는 위 applyTeamGameState 로 이미 반영됨.
  //   - 증상1(난리): 이전엔 team_game_update 가 T+0 에 즉시 렌더 → HP/보드가 마법구보다 먼저 변함.
  //   - 증상2(지연): skill_result 의 도장 렌더는 _skipTeamRender 로 건너뛰어졌고(team_game_update 가
  //     이미 렌더했다고 판단), team_game_update 의 T+0 렌더는 도장이 생기기 전이라 도장이 다음
  //     렌더(턴 종료)까지 안 보였음. → orb 착지 직후(+40ms) 렌더하면 도장+HP가 함께 표시됨.
  //   gated 핸들러(skill_result/team_skill_notice/attack_result/being_attacked/team_ally_*)가 연출
  //   시작 시 S._teamRenderGateUntil(= 마법구 착지 or 공격 임팩트 예정 시각)을 기록한다. 서버가 그
  //   알림들을 broadcastTeamGameState 보다 먼저 보내므로 이 시점엔 이미 설정돼 있음.
  // 턴이 바뀐 업데이트는 게이트 무시하고 즉시 렌더 — 턴 전환 응답성 보장.
  if (prevTurnIdx !== S.currentPlayerIdx) S._teamRenderGateUntil = 0;
  // ★ FIX (팀전 보드 애니 충돌 — 1v1 단일 렌더 경로 통일): 게이트(스킬 마법구/공격 임팩트) 진행
  //   중이면 여기서 보드를 렌더하지 않는다. 연출 핸들러(skill_result/team_skill_notice/attack_result/
  //   being_attacked/team_ally_attacked)가 임팩트 시점에 보드 렌더 + 피격/사망 GIF 재생을 전담한다.
  //   team_game_update 가 그 사이 추가 렌더하면 핸들러가 적용한 피격 셀 플래시/사망 GIF 를 덮어써
  //   모션이 잘리거나 프레임이 밀려 보였음(1v1 은 team_game_update 가 없어 단일 렌더라 이 문제 없음).
  //   데이터(state)는 위 applyTeamGameState 로 이미 반영 → 핸들러가 최신 상태로 렌더한다.
  const _gatePending = S.isTeamMode && (S._teamRenderGateUntil || 0) > Date.now();
  if (!_gatePending) renderTeamGameSnapshot();
  showActionBar(S.isMyTurn);
  // 보드 외곽 팀 컬러 갱신 (현재 차례 플레이어의 팀)
  if (typeof setTurnBackground === 'function') setTurnBackground(S.isMyTurn);
  if (state.extra_msg) showSkillToast(state.extra_msg, false, undefined, 'event');
  // 스냅샷 비교 — HP 줄어든 piece에 profile-hit, HP 회복된 piece에 heal flash
  if (changes && changes.length > 0) {
    const damaged = changes.filter(c => !c.healed);
    const healed = changes.filter(c => c.healed);
    // 회복량 추적(데이터) — 녹색 도장 + HP 바 녹색 오버레이용. 항상 누적(지연 렌더가 표시).
    for (const ch of healed) {
      const delta = (ch.newHp || 0) - (ch.oldHp || 0);
      if (delta > 0) addHeal(`${ch.playerIdx}:${ch.pieceIdx}`, delta);
    }
    // ★ FIX (회복 도장 지연): 회복 스킬(herb/divine)은 skill_result 의 프로필 재렌더가 데미지 스킬
    //   (hitsData) 경로에만 있어 호출되지 않는다 → 게이트 중엔 team_game_update 렌더도 스킵돼 도장이
    //   턴 종료까지 안 보였다. 게이트 진행 중 회복이 있으면 게이트 종료(마법구 착지) 시점에 프로필만
    //   렌더 예약 → HP 변화와 함께 도장이 제때 표시. (이중 도장 없음 — addHeal 단일 소스 유지.)
    if (_gatePending && healed.length > 0) {
      const _hd = Math.max(0, (S._teamRenderGateUntil || 0) - Date.now()) + 40;
      setTimeout(() => { if (typeof renderTeamProfiles === 'function') { try { renderTeamProfiles(); } catch (e) {} } }, _hd);
    }
    // ★ 피격 플래시(시각)는 게이트 진행 중이면 gated 핸들러(skill_result/team_skill_notice/
    //   attack_result/being_attacked)가 임팩트 시점에 전담 → 중복/조기노출 방지로 스킵.
    if (!_gatePending) requestAnimationFrame(() => {
      for (const ch of damaged) {
        // 직전 curse_tick 으로 처리된 piece는 빨간 일반 피격 애니 스킵 (보라 애니가 이미 발동)
        const player = (S.teamGamePlayers || []).find(p => p.idx === ch.playerIdx);
        const piece = player?.pieces?.[ch.pieceIdx];
        if (piece && S._recentCurseDamageKeys?.has(`${ch.playerIdx}:${piece.name}`)) {
          continue;
        }
        // ★ 사용자 보고 (2v2 보드파괴 사망 시 내 프로필이 잘못 흔들림): 컨테이너 prefix 가
        //   뷰어 상대 기준(`isOwnTeam`) 으로 결정됐지만, 실제 DOM 은 절대 팀 색상으로 매핑
        //   (#my-pieces-info=BLUE, #opp-pieces-info=RED). 뷰어가 RED 팀일 때 prefix 가 뒤집혀
        //   잘못된 카드를 잡거나 못 잡음 → 플레이어 명시(data-player-idx) 만으로 전역 검색.
        const card = (typeof _findPieceCard === 'function')
          ? _findPieceCard(ch.playerIdx, ch.pieceIdx)
          : document.querySelector(`.team-profile-block[data-player-idx="${ch.playerIdx}"] [data-piece-idx="${ch.pieceIdx}"]`);
        applyHitFlashWithBrighten(card);
      }
      // 힐 효과 제거 — skill_result / team_skill_notice 가 T+1500ms 에 flashHealPieces 호출
      // (team_game_update 가 즉시 발동하면 중복 + SP 마법구 도중에 노출되므로 차단)
      const _legacyHealLoop = false;
      for (const ch of (_legacyHealLoop ? healed : [])) {
        // ★ 위와 동일 — 컨테이너 prefix 의존 제거, data-player-idx 로 전역 매핑.
        const card = (typeof _findPieceCard === 'function')
          ? _findPieceCard(ch.playerIdx, ch.pieceIdx)
          : document.querySelector(`.team-profile-block[data-player-idx="${ch.playerIdx}"] [data-piece-idx="${ch.pieceIdx}"]`);
        if (card) {
          card.classList.remove('heal-flash');
          void card.offsetWidth;
          card.classList.add('heal-flash');
          setTimeout(() => card.classList.remove('heal-flash'), 1800);
        }
      }
    });
  }
});

// 팀전 플레이어 전멸 알림 — 토스트 + 로그
// 같은 팀의 살아남은 멤버가 탈락자의 슬롯을 대신 채우게 됨 (renderTurnOrderDots 자동 갱신)
socket.on('team_player_eliminated', ({ playerIdx, playerName, teamId }) => {
  if (playerIdx == null || !playerName) return;
  const isMyTeam = (teamId === S.teamId);
  const txt = `${playerName} 탈락`;
  // 효과음: 우리 팀이면 무거운 톤, 상대 팀이면 일반 톤
  try { playSfx(isMyTeam ? 'opp_skill' : 'skill'); } catch (e) {}
  // 'event' 토스트 — 중립(어두운 회색) 시스템 이벤트 톤
  showSkillToast(txt, false, playerIdx, 'event');
  addLog(txt, 'system');
});

socket.on('team_skill_notice', ({ casterIdx, casterName, casterTeamId, skillUsed, msg, casterPieceIdx, sp, instantSp, hits, cursedPieceIdx, cursedOwnerIdx, borderCells, healedPieces, twinJoin, ringTeleport, herbCenter, divineTarget, nightmareCells, destroyedRats }) => {
  const myTeam = casterTeamId === S.teamId;
  const label = skillUsed?.skillName ? `${skillUsed.skillName}` : '스킬';
  const icon = skillUsed?.icon || '✨';
  const hasMsg = !!msg;
  // ★ 스킬로 사망 발생 시 game_over 조기 노출 방지 가드 (동기)
  _markSkillDeathIncoming(hits);

  // ★ 분신 비행 애니메이션 — 같은 팀(myTeam)에만 공유, 적팀에는 비공유.
  //   서버는 모두에게 twinJoin 좌표를 보내지만, 클라에서 viewer 팀 기준으로 필터링.
  //   ★ FIX (관전자 패리티): 관전자는 전 정보 가시 → 양 팀 분신 비행 모두 표시.
  if (twinJoin && (myTeam || S.isSpectator) && typeof playTwinJoinFlight === 'function') {
    const moverSub = twinJoin.moverSub || 'elder';
    playTwinJoinFlight(moverSub, twinJoin.fromCol, twinJoin.fromRow, twinJoin.toCol, twinJoin.toRow);
  }

  // 마법구 비행 + dim 시퀀스 (skill_result/status_update 와 동일)
  const oldSpSnap = Array.isArray(S.sp) ? [...S.sp] : [0, 0];
  const oldInstantSnap = Array.isArray(S.instantSp) ? [...S.instantSp] : [0, 0];
  const newSp = sp || S.sp;
  const newInstant = instantSp || S.instantSp;

  // 시전자 카드 찾기 — 팀 모드 프로필 마크업 [data-player-idx][data-piece-idx]
  const casterCard = (typeof casterPieceIdx === 'number')
    ? document.querySelector(`.team-profile-block[data-player-idx="${casterIdx}"] [data-piece-idx="${casterPieceIdx}"]`)
    : null;
  const _spotlightTarget = (typeof casterPieceIdx === 'number' && casterIdx != null)
    ? { playerIdx: casterIdx, pieceIdx: casterPieceIdx }
    : null;
  startSkillCastDim(casterCard, _spotlightTarget);
  try { spendSPAttention(oldSpSnap, newSp, oldInstantSnap, newInstant); } catch (e) {}

  // ★ 시전자 말풍선 — 팀모드 시점에서도 시전자 카드에서 보드 쪽으로 표시
  if (casterCard && typeof casterPieceIdx === 'number' && casterIdx != null) {
    const casterPlayer = (S.teamGamePlayers || []).find(p => p.idx === casterIdx);
    const casterPc = casterPlayer?.pieces?.[casterPieceIdx];
    const skName = skillUsed?.skillName || label || (msg ? (msg.match(/[가-힣A-Za-z]+(?=:)/) || [])[0] : null);
    if (skName) {
      const stype = getSkillTypeFromPiece(casterPc, skName);
      showSkillCastBubble(casterCard, skName, stype);
    }
  }

  // ★ 통일된 시퀀스 — SP 비행 종료 시점에 SFX + 토스트/로그 동시 발사
  const _spCost = spCostFromDelta(oldSpSnap, newSp, oldInstantSnap, newInstant);
  const TOAST_DELAY_MS = getSpFlightEndMs(_spCost);
  // ★ FIX (팀전 스킬 타이밍): 마법구 착지 예정 시각 기록 → 곧 도착할 team_game_update 가 이 시각까지
  //   보드/HP 시각 갱신을 지연(1v1 호흡 통일). 서버가 team_skill_notice 를 broadcast 보다 먼저 보냄.
  S._teamRenderGateUntil = Date.now() + TOAST_DELAY_MS;

  // T+SP_END: SFX + dim 해제 + sp 동기화 + 토스트·로그 (HP/보드는 team_game_update 가 동시 처리)
  //   ★ 기폭 msg 는 SFX 스킵 — detonation_intro blast 가 폭발 SFX 담당
  const _isDetonateMsgTeam = msg && msg.indexOf('기폭') === 0;
  setTimeout(() => {
    if (!_isDetonateMsgTeam) {
      const sfxRoute = (typeof pickSkillSfxByMsg === 'function') ? pickSkillSfxByMsg(msg || label) : null;
      if (sfxRoute) sfxRoute();
      else playSfx(myTeam ? 'skill' : 'opp_skill');
    }

    endSkillCastDim(casterCard);
    if (sp) { S.sp = sp; }
    if (instantSp) { S.instantSp = instantSp; }
    if (sp || instantSp) { try { updateSPBar(); } catch (e) {} }

    // ★ FIX (관전 시점 사망 GIF — 유황범람 등 비-악몽 데미지 스킬): 사망 셀을 먼저 _pendingDeathCells
    //   로 가려 유해 조기 노출 방지(증상2). 실제 사망 GIF 는 아래 통합 블록에서 재생(증상3). _detectDeaths
    //   는 렌더 전 DOM(생존 마커)에서 방향을 읽으므로 첫 renderGameBoard 전에 호출해야 함.
    let _skillDeathInfosT = [];
    if (!_isDetonateMsgTeam && Array.isArray(hits) && hits.some(h => h.destroyed)) {
      _skillDeathInfosT = _detectDeaths(hits.filter(h => h.destroyed), !myTeam);
      if (_skillDeathInfosT.length > 0) {
        if (!S._pendingDeathCells) S._pendingDeathCells = new Set();
        for (const di of _skillDeathInfosT) S._pendingDeathCells.add(`${di.col},${di.row}`);
      }
    }
    // ★ 데미지 스킬 hits — 셀 hit 애니 + 본체 빨간 도장 / 충성 파란 도장.
    //   팀모드 키 형식: `${defOwnerIdx}:${defPieceIdx}` — owner 별 인덱스로 통일.
    //   ★ 기폭은 스킵 — bomb_detonated 가 폭발 순간 처리.
    if (!_isDetonateMsgTeam && Array.isArray(hits) && hits.length > 0) {
      const hitCells = hits.filter(h => h.col != null && h.row != null).map(h => ({ col: h.col, row: h.row }));
      // ★ 유황범람 라바 애니가 있을 때 hit 셀 표시를 지연 — 라바 ::before 가 빨간 배경을 덮으므로 라바 피크 후 표시
      if (hitCells.length > 0) {
        const _hasLava = Array.isArray(borderCells) && borderCells.length > 0;
        if (_hasLava) {
          setTimeout(() => { animateAttack([], hitCells); }, 1100);
        } else {
          animateAttack([], hitCells);
        }
      }
      // ★ attackLog 기록 — 보드 위 💥/· 셀 마크 (팀모드 팀원/적 시점)
      //   borderCells 가 있으면 전체 범위 (빗나감 · + 명중 💥), 없으면 hit 만 💥.
      const _hitSetT = new Set(hitCells.map(c => `${c.col},${c.row}`));
      if (Array.isArray(borderCells) && borderCells.length > 0) {
        for (const bc of borderCells) {
          S.attackLog.push({ col: bc.col, row: bc.row, hit: _hitSetT.has(`${bc.col},${bc.row}`), turn: S.turnNumber });
        }
      } else {
        for (const c of hitCells) {
          S.attackLog.push({ col: c.col, row: c.row, hit: true, turn: S.turnNumber });
        }
      }
      renderGameBoard(); // attackLog 마커 즉시 반영
      for (const h of hits) {
        const dmg = (typeof h.damage === 'number') ? h.damage : 0;
        if (dmg <= 0 || h.defPieceIdx == null || h.defOwnerIdx == null) continue;
        const key = `${h.defOwnerIdx}:${h.defPieceIdx}`;
        if (h.bodyguardRedirect) {
          addLoyaltyDamage(key, dmg);
        } else if (!h.redirectedToBodyguard) {
          addBodyDamage(key, dmg);
        }
      }
      // ★ 사용자 보고 (유황범람 누락): 데미지 스킬로 피격된 카드의 profile-hit 애니 + 밝아짐 누락.
      //   skill_result 와 동일하게 team-profile-block 매핑으로 즉시 적용.
      requestAnimationFrame(() => {
        for (const h of hits) {
          if (h.defPieceIdx == null || h.defOwnerIdx == null) continue;
          if (h.redirectedToBodyguard) continue;
          const isProtected = (h.damage === 0 && !h.destroyed);
          const card = document.querySelector(`.team-profile-block[data-player-idx="${h.defOwnerIdx}"] [data-piece-idx="${h.defPieceIdx}"]`);
          if (!card) continue;
          if (isProtected) {
            applyProtectedAnim(card);
            // ★ 사용자 요청: 데미지 0 도장.
            addProtectedHit(`${h.defOwnerIdx}:${h.defPieceIdx}`);
          } else {
            applyHitFlashWithBrighten(card);
          }
        }
      });
      // 도장 노출을 위해 즉시 재렌더 (renderTeamProfiles 가 buildDamageOverlay 로 도장 표시)
      if (typeof renderTeamProfiles === 'function') renderTeamProfiles();
      // ★ 버퍼된 wizard 등 패시브 alert flush (유황범람 등 데미지 스킬 타이밍 동기화)
      if (typeof flushDefensiveAlerts === 'function') {
        const _killed = hits.some(h => h.destroyed);
        flushDefensiveAlerts({ skipReduction: _killed });
      }
      // ★ 자동 추리토큰 — 팀원이 스킬로 1명 hit + 사망 아닌 경우 (시전자 본인의 skill_result 와 동일 조건).
      //   같은 팀끼리 정찰 정보 공유 — 시전자가 받는 토큰을 ally 도 동일하게 받음.
      if (myTeam) {
        const _meaningful = hits.filter(h => !h.redirectedToBodyguard && !(h.damage === 0 && !h.destroyed));
        const _eligible = _meaningful.filter(h => !h.destroyed && h.defPieceIdx != null && h.defOwnerIdx != null);
        if (_meaningful.length === 1 && _eligible.length === 1) {
          const c = _eligible[0];
          const ownerPlayer = (S.teamGamePlayers || []).find(p => p.idx === c.defOwnerIdx);
          const piece = ownerPlayer?.pieces?.[c.defPieceIdx];
          if (piece) {
            const pieceKey = `${piece.type}:${piece.subUnit || ''}@${c.defOwnerIdx}`;
            try {
              S.deductionTokens = (S.deductionTokens || []).filter(t => t.pieceKey !== pieceKey && !(t.col === c.col && t.row === c.row));
              S.deductionTokens.push({ pieceKey, icon: piece.icon, name: piece.name, col: c.col, row: c.row });
              if (typeof renderGameBoard === 'function') renderGameBoard();
            } catch (e) {}
          }
        }
      }
    }

    // ★ 저주 부여 turn-bright (사용자 요청)
    if (typeof cursedPieceIdx === 'number' && typeof cursedOwnerIdx === 'number') {
      requestAnimationFrame(() => {
        _persistTurnBright(cursedOwnerIdx, cursedPieceIdx);
        const card = _findPieceCard(cursedOwnerIdx, cursedPieceIdx);
        if (card) card.classList.add('turn-bright');
      });
    }
    // ★ 유황범람 라바 애니 — borderCells 모든 셀에 .lava-bubbling 클래스
    if (Array.isArray(borderCells) && borderCells.length > 0 && typeof animateLavaCells === 'function') {
      animateLavaCells(borderCells);
    }
    // ★ 유황범람으로 죽은 쥐 사망 모션 (팀 시점)
    _animateSkillDestroyedRats(destroyedRats);
    // ★ 악몽 시전 (팀모드 시점) — 표식 적 셀 보라 펄스 + scale. (사망 GIF 는 아래 통합 블록에서 처리.)
    if (Array.isArray(nightmareCells) && nightmareCells.length > 0 &&
        typeof animateNightmareCast === 'function') {
      animateNightmareCast(nightmareCells, { spiralStyle: 'a', opacityLevel: 2 });
    }
    // ★ FIX (관전 시점 사망 GIF 통합): 악몽뿐 아니라 유황범람 등 모든 데미지 스킬의 사망 GIF 를 재생.
    //   위에서 _pendingDeathCells 로 사망 셀을 가려 둠(유해 조기노출 차단) → 피격 표시 후 사망 GIF 재생
    //   → 완료 콜백에서 유해 생성.
    //   ★ FIX (유황범람 피격 모션 누락): 라바 스킬은 피격 표시가 +1100ms 지연되므로, 사망을 500ms 에
    //     재생하면 사망 GIF 의 재렌더가 피격 셀 플래시를 덮어씀 → 라바면 사망을 피격 이후(1600ms)로 지연.
    if (_skillDeathInfosT.length > 0) {
      const _lavaDeathDelayT = (Array.isArray(borderCells) && borderCells.length > 0) ? 1600 : 500;
      setTimeout(() => {
        playDeathAnimations(_skillDeathInfosT, () => {
          S._pendingDeathCells = null;
          _addClientSideRemains(_skillDeathInfosT);
          renderGameBoard();
        });
      }, _lavaDeathDelayT);
    }
    // ★ 회복 애니메이션 — 약초학/신성 등이 시전자 외 시점(팀원/적팀)에서도 보이도록.
    //   team_game_update 가 곧이어 도착해 renderTeamProfiles 가 DOM 을 재생성하므로
    //   살짝 지연 후 적용 — 재렌더 후 카드를 다시 찾아 heal-flash 부여.
    if (Array.isArray(healedPieces) && healedPieces.length > 0) {
      setTimeout(() => flashHealPiecesByOwner(healedPieces), 50);
    }
    // ★ 약초학 / 신성 보드 시전 애니 — 같은 팀(myTeam)만 표시. 적팀에는 비공개.
    //   ★ FIX (관전자 패리티): 관전자(S.isSpectator)는 전 정보 가시 → 양 팀 시전 모두 표시.
    if ((myTeam || S.isSpectator) && herbCenter && typeof animateHerbCast === 'function') {
      animateHerbCast(herbCenter.col, herbCenter.row);
    }
    if ((myTeam || S.isSpectator) && divineTarget && typeof animateDivineCast === 'function') {
      animateDivineCast(divineTarget.col, divineTarget.row);
    }
    // ★ 절대복종 반지 — 모든 viewer 가 보는 애니. 같은 팀이면 'observer', 적팀(피해자 팀)은 'victim'.
    if (ringTeleport && typeof animateRingTeleport === 'function') {
      // 피해자 팀 = ringTeleport.victimOwnerIdx 의 팀이 내 팀과 같음.
      const victimPlayer = (S.teamGamePlayers || []).find(p => p.idx === ringTeleport.victimOwnerIdx);
      const isVictimTeam = victimPlayer && victimPlayer.teamId === S.teamId;
      // 시전자 측 (myTeam) 일 때 자동 추리 토큰 — 같은 pieceKey 기존 토큰 제거 후 새 위치로 갱신.
      // ★ 사용자 보고: push 후 refresh 누락으로 DOM 에 토큰이 즉시 안 나타남. animateRingTeleport
      //   호출 전에 push + refresh 하여 aurora 인트로 시점에는 이미 보드에 토큰이 있도록 함.
      if (myTeam && !isVictimTeam) {
        try {
          const rt = ringTeleport;
          const pieceKey = `${rt.victimType}:@${rt.victimOwnerIdx}`;
          S.deductionTokens = (S.deductionTokens || []).filter(t =>
            t.pieceKey !== pieceKey && !(t.col === rt.toCol && t.row === rt.toRow));
          S.deductionTokens.push({ pieceKey, icon: rt.victimIcon, name: rt.victimName, col: rt.toCol, row: rt.toRow });
          if (typeof refreshDeductionTokens === 'function') refreshDeductionTokens();
          if (typeof updateDeductionBadgesInPlace === 'function') updateDeductionBadgesInPlace();
        } catch (e) {}
      }
      animateRingTeleport(ringTeleport, isVictimTeam ? 'victim' : 'observer');
      if (window._crForceRingVictim) window._crForceRingVictim(ringTeleport);
    }
    if (hasMsg) {
      showSkillToast(msg, !myTeam, casterIdx, 'skill');
      addLog(msg, 'skill');
    }
  }, TOAST_DELAY_MS);
});

// 팀 모드: HP 감소 감지를 위한 이전 상태 스냅샷
S._prevTeamHpSnap = null;
function snapshotTeamHps() {
  if (!S.teamGamePlayers) return null;
  return S.teamGamePlayers.map(p => ({
    idx: p.idx,
    hps: (p.pieces || []).map(pc => pc.hp),
  }));
}
function detectTeamHpChanges(prev, curr) {
  if (!prev || !curr) return [];
  const changes = [];  // [{ playerIdx, pieceIdx, oldHp, newHp, healed }]
  for (const pl of curr) {
    const old = prev.find(p => p.idx === pl.idx);
    if (!old) continue;
    const ply = (S.teamGamePlayers || []).find(p => p.idx === pl.idx);
    if (!ply) continue;
    for (let i = 0; i < (pl.hps || []).length; i++) {
      const newHp = pl.hps[i];
      const oldHp = old.hps[i];
      if (newHp !== oldHp && oldHp != null) {
        changes.push({ playerIdx: pl.idx, pieceIdx: i, oldHp, newHp, healed: newHp > oldHp });
      }
    }
  }
  return changes;
}

socket.on('team_game_over', ({ win, winnerTeamId, winTeamLabel, loseTeamLabel, winners, losers, reason, spectator }) => {
  stopClientTimer();
  // 1v1과 동일: 마지막 연출(사망 GIF·유해 / 보드 파괴)이 끝난 뒤 1초 텀을 두고 결과 화면.
  const inGame = _isInGameScreen();
  scheduleGameOverReveal(inGame, () => {
    _showGameOverScreen(!inGame);
    if (!spectator) bgmPlay(win ? 'victory' : 'defeat');
    const r = reason || {};
    const W = winTeamLabel || (winnerTeamId === 0 ? '블루팀' : '레드팀');
    const L = loseTeamLabel || (winnerTeamId === 0 ? '레드팀' : '블루팀');
    const killer = r.killer || '';

    const iconEl = document.getElementById('gameover-icon');
    const titleEl = document.getElementById('gameover-title');
    const subEl = document.getElementById('gameover-sub');

    // 무승부 (양 팀 동시 전멸 / unreachable / 사망 기폭으로 동시 전멸)
    if (r.type === 'draw' || r.type === 'unreachable_draw' || r.type === 'simultaneous_draw') {
      if (iconEl) iconEl.textContent = '🤝';
      if (titleEl) { titleEl.textContent = '무승부'; titleEl.style.color = 'var(--muted)'; }
      const subMsg = r.type === 'unreachable_draw'
        ? '게임을 끝낼 수 없어 무승부입니다.'
        : r.type === 'simultaneous_draw'
        ? '폭탄 폭발로 양 팀 모든 유닛이 동시에 전멸했습니다.'
        : '보드 축소로 양 팀 모든 말이 전멸해 무승부입니다.';
      if (subEl) subEl.innerHTML = subMsg;
      return;
    }

    const isSpec = spectator || S.isSpectator;
    let sub = '';

    if (isSpec) {
      // 관전자 메시지 — 1v1 카피
      if (iconEl) iconEl.textContent = '👁';
      if (titleEl) { titleEl.textContent = '게임 종료'; titleEl.style.color = 'var(--accent)'; }
      switch (r.type) {
        case 'surrender': sub = `${L}의 기권으로, ${W}의 승리입니다.`; break;
        case 'shrink': sub = `보드 축소로 ${L}의 말이 전멸해 ${W}의 승리`; break;
        case 'trap': sub = `덫으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
        case 'bomb': sub = `폭탄으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
        case 'sulfur': sub = `유황범람으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
        case 'nightmare': sub = `악몽으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
        case 'attack': sub = `${W}의 승리`; break;
        default: sub = `${W}의 승리`;
      }
    } else if (win) {
      // 승리 메시지 — 기권은 1v1과 동일한 디자인(🏆 + 승리!), 그 외는 팀전 컨텍스트 유지
      if (iconEl) iconEl.textContent = '🏆';
      if (titleEl) {
        titleEl.textContent = r.type === 'surrender' ? '승리' : '팀 승리';
        titleEl.style.color = 'var(--accent)';
      }
      switch (r.type) {
        case 'surrender': sub = `${L}의 기권입니다.`; break;
        case 'shrink': sub = `${L}${조사(L, '이', '가')} 보드 축소를 피하지 못해 승리했습니다.`; break;
        case 'trap': sub = `덫으로 ${L}의 모든 유닛을 제거해 승리했습니다.`; break;
        case 'bomb': sub = `폭탄으로 ${L}의 모든 유닛을 제거해 승리했습니다.`; break;
        case 'sulfur': sub = `유황범람으로 ${L}의 모든 유닛을 제거해 승리했습니다.`; break;
        case 'nightmare': sub = `악몽으로 ${L}의 모든 유닛을 제거해 승리했습니다.`; break;
        case 'attack': sub = `${L}의 모든 유닛을 제거해 승리했습니다.`; break;
        default: sub = `${L}의 모든 유닛을 제거해 승리했습니다.`;
      }
    } else {
      // 패배 메시지 — 기권은 1v1과 동일한 디자인(🏳 + 기권), 그 외는 팀전 컨텍스트 유지
      if (iconEl) iconEl.textContent = r.type === 'surrender' ? '🏳' : '💀';
      if (titleEl) {
        titleEl.textContent = r.type === 'surrender' ? '기권' : '팀 패배';
        titleEl.style.color = 'var(--danger)';
      }
      switch (r.type) {
        case 'surrender': sub = `기권하여 패배했습니다.`; break;
        case 'shrink': sub = `보드 축소를 피하지 못해 패배하였습니다.`; break;
        case 'trap': sub = `덫으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
        case 'bomb': sub = `폭탄으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
        case 'sulfur': sub = `유황범람으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
        case 'nightmare': sub = `악몽으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
        case 'attack': sub = `${L}에게 패배했습니다.`; break;
        default: sub = `${L}에게 패배했습니다.`;
      }
    }
    if (subEl) {
      // 팀 구분(🟦 블루팀: ... 🟥 레드팀: ...) 중복 표시 제거 — 위 sub 문구만 노출
      subEl.innerHTML = sub;
    }
  });
});

// 팀전 게임 화면 렌더 — 4인 프로필 + 턴 표시 (턴 배너는 updateTurnBanner가 통일)
function renderTeamGameSnapshot() {
  try {
    // ★ #2 차례별 밝기 반전: 평소엔 내 말 밝게/팀원 말 딤(.teammate-piece). 팀원 차례에는 반대로
    //   팀원 말을 밝게, 내 말을 딤한다(body.team-teammate-turn 토글 → CSS 가 반전 적용).
    if (S.isTeamMode && !S.isSpectator) {
      const curIsTeammate = S.currentPlayerIdx !== S.playerIdx &&
        (S.teamGamePlayers || []).some(p => p.idx === S.currentPlayerIdx && p.teamId === S.teamId);
      document.body.classList.toggle('team-teammate-turn', !!curIsTeammate);
    }
    if (typeof renderGameBoard === 'function') renderGameBoard();
    renderTeamProfiles();  // 1v1의 renderMyPieces/renderOppPieces 대체
    // 사용자 #14 수정: spotlight 진행 중에 재렌더되면 caster-spotlight 가 사라지므로 즉시 재적용.
    if (typeof reapplyCasterSpotlight === 'function') reapplyCasterSpotlight();
    if (typeof updateSPBar === 'function') updateSPBar();
    updateTurnBanner();  // 1v1과 통일된 턴 배너 + 팀전 턴 오더 도트
  } catch (e) {
    console.error('[team render] error:', e);
  }
}

// 팀전 프로필 렌더 — 누가 보든 위치 고정:
//   blue 팀 → 왼쪽 컨테이너 (my-pieces-info)
//   red  팀 → 오른쪽 컨테이너 (opp-pieces-info)
//   각 팀 내에서 slotPos 오름차순 = 위/아래 (slot 0/1) — idx 기준이 아닌 슬롯 위치 기준
function renderTeamProfiles() {
  const leftContainer = document.getElementById('my-pieces-info');   // 항상 blue 팀
  const rightContainer = document.getElementById('opp-pieces-info'); // 항상 red 팀
  if (!leftContainer || !rightContainer) return;

  const players = S.teamGamePlayers || [];
  const myTeam = S.teamId;

  // 팀 색상별 분류 — 각 팀은 slotPos 오름차순 (slot 0=상단, slot 1=하단)
  // slotPos 동률 시 idx 로 tiebreak (안정 정렬)
  const teamSort = (a, b) => {
    const pa = a.slotPos ?? 99;
    const pb = b.slotPos ?? 99;
    if (pa !== pb) return pa - pb;
    return a.idx - b.idx;
  };
  const blueTeam = players.filter(p => p.teamId === 0).sort(teamSort);
  const redTeam  = players.filter(p => p.teamId === 1).sort(teamSort);

  // isAlly = 해당 player의 teamId가 viewer의 teamId와 같으면 true
  // ★ 사용자 보고 (프로필 구버전 데이터): team_game_update 가 늦게 도착하면 renderTeamPlayerBlock 이
  //   S.teamGamePlayers 의 구버전 pieces 를 그리게 됨. S.myPieces / S.teammatePieces 는 개별 이벤트
  //   (move_ok, attack_result, being_attacked, skill_result) 가 즉시 갱신하므로 이를 우선 사용.
  const _augmentPl = (pl) => {
    if (S.isSpectator) return pl;  // 관전자는 teamGamePlayers 원본 그대로
    // ① 내 피스 — move_ok/attack_result/being_attacked/skill_result 가 즉시 갱신
    if (pl.idx === S.playerIdx && Array.isArray(S.myPieces) && S.myPieces.length > 0) {
      return { ...pl, pieces: S.myPieces };
    }
    // ② 팀원 피스 — team_ally_moved 가 S.teammatePieces 좌표 즉시 갱신
    const isTeammate = (pl.teamId === S.teamId && pl.idx !== S.playerIdx);
    if (isTeammate && Array.isArray(S.teammatePieces) && S.teammatePieces.length > 0) {
      return { ...pl, pieces: S.teammatePieces };
    }
    // ③ 적 플레이어 — attack_result/skill_result 후 S.oppPieces 가 최신이면 HP 공급.
    //   applyTeamGameState 가 ownerIdx 를 붙여 만드는 구조 활용 — ownerIdx 없으면 폴백.
    const isEnemy = pl.teamId !== S.teamId;
    if (isEnemy && Array.isArray(S.oppPieces) && S.oppPieces.length > 0) {
      const enemyPieces = S.oppPieces.filter(p => p.ownerIdx === pl.idx);
      if (enemyPieces.length > 0) return { ...pl, pieces: enemyPieces };
    }
    return pl;
  };
  leftContainer.innerHTML  = blueTeam.map(pl => renderTeamPlayerBlock(_augmentPl(pl), pl.teamId === myTeam)).join('');
  rightContainer.innerHTML = redTeam.map(pl => renderTeamPlayerBlock(_augmentPl(pl), pl.teamId === myTeam)).join('');
  // ★ 사용자 보고 (밀림 현상 수정): innerHTML 재구성으로 wipe 된 진행 중 hit/heal/protected
  //   애니메이션 클래스를 새 카드에 즉시 복원. 빠르게 연속 도착하는 이벤트 (attack_result →
  //   team_ally_hit → team_game_update 등) 가 매번 wipe 해도 애니가 끊기지 않음.
  if (typeof reapplyActiveProfileAnims === 'function') reapplyActiveProfileAnims();
  if (typeof fitLandscapePanels === 'function') fitLandscapePanels();

  // 내 pieces 카드에 클릭 리스너 연결 — 내 팀이 left든 right든 무관하게 my-piece-idx 가 박힌 카드만
  document.querySelectorAll('#my-pieces-info [data-my-piece-idx], #opp-pieces-info [data-my-piece-idx]').forEach(card => {
    card.addEventListener('click', () => {
      if (!S.isMyTurn) return;
      const idx = parseInt(card.dataset.myPieceIdx, 10);
      const pc = S.myPieces[idx];
      if (!pc || !pc.alive) return;
      S.selectedPiece = idx;
      renderGameBoard();
      renderTeamProfiles();
    });
  });

  // 호버 시 공격범위 팝업 — 좌측 컨테이너는 'left', 우측 컨테이너는 'right' 방향
  const attachTooltips = (container, side) => {
    container.querySelectorAll('.team-profile-block').forEach(block => {
      const idxAttr = block.getAttribute('data-player-idx');
      const playerIdx = idxAttr != null ? parseInt(idxAttr, 10) : null;
      if (playerIdx == null) return;
      const player = (S.teamGamePlayers || []).find(p => p.idx === playerIdx);
      if (!player) return;
      block.querySelectorAll('[data-team-piece]').forEach(card => {
        const pcIdx = parseInt(card.getAttribute('data-piece-idx'), 10);
        const pc = (!isNaN(pcIdx)) ? player.pieces?.[pcIdx] : null;
        if (pc && pc.alive) card.appendChild(buildPieceTooltip(pc, side));
      });
    });
  };
  attachTooltips(leftContainer, 'left');
  attachTooltips(rightContainer, 'right');

  // 추리 토큰 드래그 — 상대팀 카드에서만 (좌·우 컨테이너 어디든 적팀이면 가능)
  document.querySelectorAll('#my-pieces-info [data-deduction-key], #opp-pieces-info [data-deduction-key]').forEach(card => {
    card.addEventListener('dragstart', (e) => {
      const pieceKey = card.dataset.deductionKey;
      const icon = card.dataset.deductionIcon;
      const name = card.dataset.deductionName;
      e.dataTransfer.setData('text/plain', JSON.stringify({ pieceKey, icon, name, fromBoard: false }));
      e.dataTransfer.effectAllowed = 'move';
      const ghost = document.createElement('div');
      ghost.className = 'drag-ghost';
      ghost.textContent = icon;
      document.body.appendChild(ghost);
      e.dataTransfer.setDragImage(ghost, 14, 14);
      requestAnimationFrame(() => ghost.remove());
      card.classList.add('dragging');
    });
    card.addEventListener('dragend', () => card.classList.remove('dragging'));
  });
}

function renderTeamPlayerBlock(playerData, isAlly) {
  const isMe = playerData.idx === S.playerIdx;
  const currentPlayer = playerData.idx === S.currentPlayerIdx;
  const pieces = playerData.pieces || [];
  const aliveCount = pieces.filter(p => p.alive).length;

  // 팀 컬러 절대 기준: 블루팀은 항상 파랑, 레드팀은 항상 빨강 (관점 무관)
  const teamColorClass = playerData.teamId === 0 ? 'team-block-blue' : 'team-block-red';
  const meClass = isMe ? 'team-block-self-mark' : '';
  const blockClass = `${teamColorClass} ${meClass}`.trim();
  const blockLabel = isMe ? '내 캐릭터' : escapeHtmlGlobal(playerData.name);
  const teamLetter = playerData.teamId === 0 ? 'BLUE' : 'RED';

  // 지휘관 버프 — 내 팀(나+팀원) 지휘관에 인접한 같은 팀 말이면 +1
  const teamPlayers = (S.teamGamePlayers || []).filter(p => p.teamId === playerData.teamId);
  const teamCommanders = teamPlayers.flatMap(p => (p.pieces || []).filter(pp => pp.alive && pp.type === 'commander'));

  const piecesHtml = pieces.map((pc, i) => {
    // ★ 사용자 요청: 드래곤은 사망 시 프로필에서 삭제. 재소환 시 새 dragon piece 가 추가됨.
    if (pc.isDragon && !pc.alive) return '';
    // 카드 베이스 클래스 — 1v1 대전과 동일하게 통일: 아군=my-piece-card, 적=opp-piece-card
    const isCursedTm = pc.alive && (pc.statusEffects || []).some(e => e.type === 'curse');
    const baseCardClass = `${isAlly ? 'my-piece-card' : 'opp-piece-card'}${isCursedTm ? ' curse-active' : ''}`;
    if (!pc.alive) {
      // 사망 — 아이콘만 💀 로 변경. "격파" 텍스트는 제거 (피격 애니 + .turn-bright 가 사망 알림 역할).
      // 도장(damage stamp) 은 그 턴 동안 카드에 남아 마지막 일격 시각화.
      const _deadDmgOv = (typeof buildDamageOverlay === 'function')
        ? buildDamageOverlay(`${playerData.idx}:${i}`, 0, pc.maxHp || 1)
        : { stamp: '' };
      return `<div class="${baseCardClass} dead" data-team-piece="1" data-piece-idx="${i}">
        ${_deadDmgOv.stamp || ''}
        <div class="my-piece-header"><span class="p-icon">💀</span><strong>${escapeHtmlGlobal(pc.name || pc.type)}</strong></div>
      </div>`;
    }
    const hpPct = (pc.hp / pc.maxHp) * 100;
    const tagHtml = tagBadgeHtml(pc.tag);
    const miniHeaders = (typeof buildMiniHeaders === 'function') ? buildMiniHeaders(pc) : '';
    const myPieceAttr = (isAlly && isMe) ? `data-my-piece-idx="${i}"` : '';
    const selectedClass = (isAlly && isMe && S.selectedPiece === i) ? 'active-piece' : '';

    // 스킬·패시브 텍스트 라인은 제거됨 — 미니 헤더 (mini-header)가 이미 표시
    let skillHtml = '', passiveHtml = '', directionHtml = '', moraleHtml = '', statusHtml = '';
    if (isAlly) {
      if (pc.type === 'archer') {
        const dir = pc.toggleState === 'right' ? '우측 대각선' : '좌측 대각선';
        directionHtml = `<div style="font-size:0.68rem;color:#60a5fa;margin-top:1px">현재 공격 방향 : ${dir}</div>`;
      }
      if (pc.type === 'weaponSmith') {
        const dir = pc.toggleState === 'vertical' ? '세로' : '가로';
        directionHtml = `<div style="font-size:0.68rem;color:#60a5fa;margin-top:1px">현재 공격 방향 : ${dir}</div>`;
      }
      // 지휘관 사기증진 — 같은 팀 지휘관 인접 시
      const commanderBuff = pc.type !== 'commander' && teamCommanders.some(cm =>
        (Math.abs(cm.col - pc.col) === 1 && cm.row === pc.row) ||
        (Math.abs(cm.row - pc.row) === 1 && cm.col === pc.col)
      );
      if (commanderBuff) {
        moraleHtml = '<span class="status-badge" style="color:#22c55e;background:rgba(34,197,94,0.15)">📋 사기증진</span>';
      }
      statusHtml = renderStatusBadges(pc);
    } else {
      // 적 — 스킬·패시브 텍스트 라인 제거 (미니 헤더로 대체)
      // 궁수·무기상 공격 방향 — 1v1에서 보이는 것과 동일하게
      if (pc.type === 'archer') {
        const dir = pc.toggleState === 'right' ? '우측 대각선' : '좌측 대각선';
        directionHtml = `<div style="font-size:0.68rem;color:#60a5fa;margin-top:1px">현재 공격 방향 : ${dir}</div>`;
      }
      if (pc.type === 'weaponSmith') {
        const dir = pc.toggleState === 'vertical' ? '세로' : '가로';
        directionHtml = `<div style="font-size:0.68rem;color:#60a5fa;margin-top:1px">현재 공격 방향 : ${dir}</div>`;
      }
      // 적팀 사기증진 — 적팀 지휘관 인접한 같은 적팀 piece에 표시.
      //   ★ 사용자 요청: 적 사기증진 배지는 빨강 톤으로 표시해 아군 녹색과 구분.
      if (pc.type !== 'commander' && pc.col != null) {
        const oppTeamCommanders = teamPlayers.flatMap(pp => (pp.pieces || []).filter(p => p.alive && p.type === 'commander' && p.col != null));
        const enemyMorale = oppTeamCommanders.some(cm =>
          (Math.abs(cm.col - pc.col) === 1 && cm.row === pc.row) ||
          (Math.abs(cm.row - pc.row) === 1 && cm.col === pc.col));
        if (enemyMorale) {
          moraleHtml = '<span class="status-badge" style="color:#ef4444;background:rgba(239,68,68,0.15)">📋 사기증진</span>';
        }
      }
      // 표식 + 기타 상태이상도 표시 (그림자·저주는 적에게 보임)
      statusHtml = renderStatusBadges(pc);
    }

    // ★ 사용자 보고: 적팀 캐릭터가 자기 팀 지휘관과 인접해도 ATK +1 표시가 안 됨.
    //   기존 조건이 `isAlly && ...` 로 묶여 있어 적팀 표기 누락. teamCommanders 는 이미 playerData
    //   기준 동일팀(=렌더 대상의 자기팀) 지휘관 목록이므로 isAlly 제약 제거 + col 유효성 체크만 추가.
    //   ★ 사용자 요청: 색상 구분 — 아군은 초록(#22c55e), 적군은 빨강(#ef4444) 으로 합산 ATK 강조.
    const _commanderAdjacent = pc.type !== 'commander' && pc.col != null && teamCommanders.some(cm =>
      cm.col != null && (
        (Math.abs(cm.col - pc.col) === 1 && cm.row === pc.row) ||
        (Math.abs(cm.row - pc.row) === 1 && cm.col === pc.col)
      )
    );
    const _buffColor = isAlly ? '#22c55e' : '#ef4444';
    const atkDisplay = _commanderAdjacent
      ? `<span style="color:${_buffColor};font-weight:800">${(pc.atk || 0) + 1}</span>`
      : `${pc.atk}`;

    // 위치 표시 — 아군은 항상 / 적은 표식만
    let posText = '';
    if (isAlly) posText = `${coord(pc.col, pc.row)}`;
    else {
      const marked = (pc.statusEffects || []).find(e => e.type === 'mark');
      if (marked && pc.col != null) posText = `${coord(pc.col, pc.row)}`;
    }

    // 적 카드 — 추리 토큰 드래그 소스 + 배지 (ownerIdx 포함된 unique key)
    let placedBadge = '';
    let dragAttrs = '';
    if (!isAlly && pc.alive) {
      const pieceKey = `${pc.type}:${pc.subUnit || ''}@${playerData.idx}`;
      const placedToken = (S.deductionTokens || []).find(t => t.pieceKey === pieceKey);
      if (placedToken) {
        placedBadge = `<span class="deduction-badge" title="추리 토큰: ${coord(placedToken.col, placedToken.row)}">📌${coord(placedToken.col, placedToken.row)}</span>`;
      }
      dragAttrs = ` draggable="true" data-deduction-key="${pieceKey}" data-deduction-icon="${pc.icon || ''}" data-deduction-name="${escapeHtmlGlobal(pc.name || pc.type)}"`;
    }

    // 위치/생존 표시 — 1v1과 동일: 아군은 좌표, 적은 '생존' 또는 표식 시 좌표
    const posDisplayHtml = isAlly
      ? `<span class="my-piece-pos">${posText}</span>`
      : `<span style="color:${pc.alive ? 'var(--success)' : 'var(--danger)'};font-size:0.68rem">${posText ? `📍${posText}` : '생존'}</span>`;
    const nameLenCls = getNameLengthClass(pc.name || pc.type);
    // 이번 턴 데미지 도장 + HP 바 오버레이 (팀모드는 playerIdx 기반 키)
    const dmgOv = (typeof buildDamageOverlay === 'function')
      ? buildDamageOverlay(`${playerData.idx}:${i}`, pc.alive ? (pc.hp ?? 0) : 0, pc.maxHp || 1)
      : { stamp: '', barOverlay: '' };
    // HP 바 폭 — 회복 시 시작 HP 위치 유지, 피해 시 현재 HP 위치 (overlay 가 차이 표시)
    const _displayHpPct = (dmgOv.displayHpPct != null) ? dmgOv.displayHpPct : hpPct;
    return `<div class="${baseCardClass} ${selectedClass}" ${myPieceAttr} data-team-piece="1" data-piece-idx="${i}"${dragAttrs}>
      ${dmgOv.stamp /* 격파된 적·아군에도 데미지 도장 유지 — 사망 마지막 일격까지 보임 */}
      <div class="my-piece-header">
        <span class="p-icon">${pieceIconHtml(pc.icon, {size:'1.2em'})}</span>
        <strong class="${nameLenCls.trim()}">${escapeHtmlGlobal(pc.name || pc.type)}</strong>
        ${pc.tier ? `<span class="tier-badge">${pc.tier}T</span>` : ''}
        ${tagHtml}
        ${placedBadge}
      </div>
      ${miniHeaders ? `<div class="piece-mini-headers">${miniHeaders}</div>` : ''}
      <div class="hp-bar-bg hp-bar-with-text">
        <div class="hp-bar" style="width:${_displayHpPct}%"></div>
        ${pc.alive ? dmgOv.barOverlay : ''}
        <span class="hp-bar-text">${pc.hp}/${pc.maxHp}</span>
      </div>
      <div class="piece-stat-row">
        <span class="piece-stat-atk"><span class="stat-label">ATK</span> ${atkDisplay}</span>
        ${posDisplayHtml}
      </div>
      ${skillHtml}${passiveHtml}${directionHtml}${statusHtml}${moraleHtml}
    </div>`;
  }).join('');

  // #24: 보드 파괴로 *완전 탈락*한 플레이어 블록에 큰 '탈락' 도장 (사용자 요청: 캐릭터 카드가 아니라 플레이어 프로필 위)
  const isShrunkElim = S._shrunkEliminatedPlayers && S._shrunkEliminatedPlayers.has(playerData.idx);
  return `
    <div class="team-profile-block ${blockClass}${currentPlayer ? ' is-current-turn' : ''}${isShrunkElim ? ' player-eliminated' : ''}" data-player-idx="${playerData.idx}">
      ${isShrunkElim ? '<div class="player-elim-stamp">탈락</div>' : ''}
      <div class="team-profile-header">
        <div class="team-profile-header-left">
          <span class="team-letter team-${teamLetter.toLowerCase()}">${teamLetter}</span>
          <span class="team-block-label">${blockLabel}</span>
          ${currentPlayer ? '<span class="team-turn-mark">현재 차례</span>' : ''}
        </div>
      </div>
      ${piecesHtml}
    </div>
  `;
}

// 팀 대기실 렌더
function renderTeamWaitingRoom() {
  const statusMsg = document.getElementById('team-status-msg');
  const startBtn = document.getElementById('btn-team-start');
  const total = (S.teamPlayers || []).length;
  const teamAOk = (S.teamTeams[0] || []).length === 2;
  const teamBOk = (S.teamTeams[1] || []).length === 2;
  const ready = total === 4 && teamAOk && teamBOk;
  if (statusMsg) {
    if (total < 4) statusMsg.textContent = '4명이 모이면 게임을 시작하세요.';
    else if (!ready) statusMsg.textContent = '각 팀에 2명씩 배정해주세요.';
    else statusMsg.textContent = '모두 준비 완료!';
  }
  if (startBtn) {
    startBtn.disabled = !ready;
    startBtn.textContent = '게임 시작';
  }
  // 슬롯 렌더 — slotPos 기반 정확한 자리 표시
  document.querySelectorAll('#screen-team-waiting .team-slot').forEach(slotEl => {
    const teamId = parseInt(slotEl.dataset.team, 10);
    const pos = parseInt(slotEl.dataset.pos, 10);
    const player = (S.teamPlayers || []).find(p => p.teamId === teamId && (p.slotPos ?? -1) === pos);
    slotEl.classList.remove('filled', 'self', 'ai-bot');
    if (player) {
      const isMe = player.idx === S.playerIdx;
      const isBot = !!player.isAI || /^(블루봇|레드봇)/.test(player.name || '');
      slotEl.classList.add('filled');
      if (isMe) slotEl.classList.add('self');
      if (isBot) slotEl.classList.add('ai-bot');
      slotEl.innerHTML = `
        <span class="slot-nickname">${escapeHtmlGlobal(player.name)}</span>
        ${isMe ? '<span class="slot-you-badge">나</span>' : ''}
        ${isBot ? '<button class="slot-bot-remove" data-bot-remove="1" title="AI 봇 제거">×</button>' : ''}
      `;
    } else {
      slotEl.innerHTML = `
        <span class="team-slot-label">빈 슬롯</span>
        <button class="slot-add-bot" data-add-bot="1" title="이 자리에 AI 봇 추가">🤖 AI 봇 추가</button>
      `;
    }
  });
}

// 팀 슬롯 클릭 — 빈 슬롯이면 자리 이동, AI 봇 추가/제거 버튼이면 별도 처리
document.querySelectorAll('#screen-team-waiting .team-slot').forEach(slotEl => {
  slotEl.addEventListener('click', (e) => {
    if (!S.isTeamMode) return;
    const teamId = parseInt(slotEl.dataset.team, 10);
    const pos = parseInt(slotEl.dataset.pos, 10);
    // AI 봇 추가
    if (e.target.dataset?.addBot === '1') {
      e.stopPropagation();
      socket.emit('team_add_bot', { targetTeam: teamId, targetPos: pos });
      return;
    }
    // AI 봇 제거
    if (e.target.dataset?.botRemove === '1') {
      e.stopPropagation();
      socket.emit('team_remove_bot', { targetTeam: teamId, targetPos: pos });
      return;
    }
    // 차있는 슬롯 (사람) 클릭은 무시
    if (slotEl.classList.contains('filled')) return;
    socket.emit('team_change', { targetTeam: teamId, targetPos: pos });
  });
});

// 게임 시작 버튼
const btnTeamStart = document.getElementById('btn-team-start');
if (btnTeamStart) {
  btnTeamStart.addEventListener('click', () => {
    if (btnTeamStart.disabled) return;
    socket.emit('team_start_request');
  });
}
// 나가기 버튼
const btnTeamLeave = document.getElementById('btn-team-leave');
if (btnTeamLeave) {
  btnTeamLeave.addEventListener('click', () => {
    if (window._teamCountdownInterval) { clearInterval(window._teamCountdownInterval); window._teamCountdownInterval = null; }
    socket.emit('team_leave');
  });
}

// ── 관전자 모드 ──
socket.on('spectator_joined', ({ roomId, phase, gameState, draftState, hpState, placementState, characters, p0Name, p1Name }) => {
  S.isSpectator = true;
  S.playerIdx = -1;
  S.specP0Name = p0Name;
  S.specP1Name = p1Name;
  if (characters) S.specCharacters = characters;
  // 관전자 전용 채팅 표시
  const chatInput = document.getElementById('chat-input');
  if (chatInput) chatInput.placeholder = '관전자 채팅';

  if (phase === 'game' && gameState) {
    buildBoard('game-board', () => {});
    renderSpectatorGame(gameState);
    showScreen('screen-game');
  } else if (phase === 'draft' && draftState) {
    S.specDraft = { ...draftState, p0Browse: {}, p1Browse: {} };
    renderSpectatorDraft();
    showScreen('screen-draft');
  } else if (phase === 'hp_distribution' && hpState) {
    S.specDraft = draftState;
    S.specHp = { ...hpState, p0Hps: null, p1Hps: null, p0Draft: draftState?.p0 || null, p1Draft: draftState?.p1 || null };
    renderSpectatorHp();
    showScreen('screen-hp');
  } else if (phase === 'reveal' && hpState) {
    S.specReveal = { p0Pieces: hpState.p0Pieces, p1Pieces: hpState.p1Pieces, p0Name, p1Name };
    renderSpectatorReveal();
    showScreen('screen-reveal');
  } else if (phase === 'placement' && placementState) {
    S.specPlacement = placementState;
    S.boardBounds = placementState.boardBounds;
    renderSpectatorPlacement();
    showScreen('screen-placement');
  } else {
    document.getElementById('waiting-title').textContent = `👁 관전 모드 — ${p0Name} vs ${p1Name}`;
    document.getElementById('waiting-sub').textContent = phase === 'waiting' ? '게임이 아직 시작되지 않았습니다. 잠시 기다려주세요...' :
      '게임이 진행 중입니다. 잠시 기다려주세요...';
    document.getElementById('waiting-room-code').textContent = `방 코드: ${roomId}`;
    showScreen('screen-waiting');
  }
});

// ── 팀전 관전자 ──
socket.on('team_spectator_joined', ({ roomId, phase, gameState, characters, players, teams }) => {
  S.isSpectator = true;
  S.isTeamMode = true;
  S.playerIdx = -1;
  S.teamId = 0;
  if (characters) S.characters = characters;
  S.teamPlayers = players || [];
  S.teamTeams = teams || [[],[]];
  const chatInput = document.getElementById('chat-input');
  if (chatInput) chatInput.placeholder = '관전자 채팅';

  if (phase === 'game' && gameState) {
    buildBoard('game-board', () => {});
    applyTeamSpectatorState(gameState);
    if (typeof renderTeamGameSnapshot === 'function') renderTeamGameSnapshot();
    showScreen('screen-game');
    showActionBar(false);
  } else {
    document.getElementById('waiting-title').textContent = `👁 팀전 관전 모드`;
    document.getElementById('waiting-sub').textContent = phase === 'waiting'
      ? '팀전이 아직 시작되지 않았습니다. 잠시 기다려주세요...'
      : '팀전이 진행 중입니다. 잠시 기다려주세요...';
    document.getElementById('waiting-room-code').textContent = `방 코드: ${roomId}`;
    showScreen('screen-waiting');
  }
});

socket.on('team_spectator_update', (state) => {
  if (!S.isSpectator || !S.isTeamMode) return;
  const board = document.getElementById('game-board');
  if (board && !board.querySelector('.cell')) buildBoard('game-board', () => {});
  applyTeamSpectatorState(state);
  if (!document.getElementById('screen-game').classList.contains('active')) {
    showScreen('screen-game');
  }
  if (typeof renderTeamGameSnapshot === 'function') renderTeamGameSnapshot();
  showActionBar(false);
});

function applyTeamSpectatorState(state) {
  S.isSpectator = true;
  S.isTeamMode = true;
  S.isMyTurn = false;
  S.playerIdx = -1;
  S.teamId = 0;
  S.turnNumber = state.turnNumber;
  S.boardBounds = state.boardBounds;
  S.sp = state.sp;
  S.instantSp = state.instantSp;
  S.currentPlayerIdx = state.currentPlayerIdx;
  if (typeof state.turnSlotIdx === 'number') S.turnSlotIdx = state.turnSlotIdx;  // ★ 관전자도 슬롯 강조 통일
  S.teamGamePlayers = state.players || [];
  S.boardObjects = state.boardObjects || [];
  // ★ FIX (#1 유해 타이밍 / #5 사망·피격 모션과 유해 겹침): 1v1 의 _applyServerRemainsExcludingDeaths
  //   와 동일하게, 지금 사망 GIF 가 재생 중인 셀(_pendingDeathCells)의 유해는 제외하고 적용한다.
  //   그 셀의 유해는 사망 GIF 완료 후 _addClientSideRemains 가 추가·렌더한다. (이전엔 무조건 교체라
  //   사망/피격 모션 위에 유해가 겹쳐 보이거나, 게이트로 렌더가 밀려 그 턴에 유해가 안 보였음.)
  {
    const _rem = state.remains || [];
    const _pend = S._pendingDeathCells;
    let _next = (_pend && _pend.size > 0) ? _rem.filter(r => !_pend.has(`${r.col},${r.row}`)) : _rem;
    // ★ #5: 유해 피격 애니 진행 중인 셀은 현재 단계(hits)를 유지 — 서버의 새 단계로 조기 교체하면
    //   피격 GIF 위에 다음 단계 PNG 가 겹쳐 보임. 정착(finalize) 후 remains_update 가 최종 단계 반영.
    const _hitPend = S._pendingRemainsHitCells;
    if (_hitPend && _hitPend.size > 0) {
      const _cur = S.remains || [];
      _next = _next.map(r => {
        if (!_hitPend.has(`${r.col},${r.row}`)) return r;
        const _old = _cur.find(o => o.col === r.col && o.row === r.row);
        return _old || r;
      });
    }
    S.remains = _next;
  }
  S.teamTeams = state.teams || S.teamTeams;
  // 관전자 보드 표시 — A팀=내팀 슬롯, B팀=상대 슬롯 (적 좌표는 marked로 모두 노출)
  const teamA = (S.teamGamePlayers || []).filter(p => p.teamId === 0);
  const teamB = (S.teamGamePlayers || []).filter(p => p.teamId === 1);
  S.myPieces = teamA[0] ? teamA[0].pieces : [];
  S.teammatePieces = teamA[1] ? teamA[1].pieces : [];
  S.oppPieces = teamB.flatMap(p => (p.pieces || []).map(pc => ({
    ...pc, marked: true,
    ownerIdx: p.idx, ownerName: p.name, ownerTeamId: p.teamId,
  })));
}

socket.on('spectator_update', (gameState) => {
  if (!S.isSpectator) return;
  // 보드가 비어있으면 먼저 빌드
  const board = document.getElementById('game-board');
  if (board && !board.querySelector('.cell')) {
    buildBoard('game-board', () => {});
  }
  renderSpectatorGame(gameState);
  if (!document.getElementById('screen-game').classList.contains('active')) {
    showScreen('screen-game');
  }
});

// ── 관전자 저주 데미지 모션 — 플레이어와 동일하게 데미지 GIF 4번째 프레임에 피격 모션 ──
//   (curse_tick 은 플레이어 전용이라, 관전자는 별도 spectator_curse_tick 으로 col/row 를 받아 연출.)
socket.on('spectator_curse_tick', ({ playerIdx, targetName, col, row }) => {
  if (!S.isSpectator) return;
  if (col == null || row == null) return;
  // 순차 처리 — 해제가 데미지 임팩트 전에 터지지 않게 보류 기준 기록 (플레이어와 동일).
  if (typeof targetName === 'string') { if (!S._curseBusyUntil) S._curseBusyUntil = {}; S._curseBusyUntil[`${playerIdx}:${targetName}`] = Date.now() + 1300; }
  // 피격 흔들림 대상 — 팀 관전자는 owner 팀으로 결정(teamId 0 → piece-marker / 1 → opp-marked).
  //   1v1 관전자(.spec-piece)는 animateBoardIconHit 가 no-op 이라 값 무관(망령 데미지 GIF 만 재생).
  let isDef = true;
  if (S.isTeamMode) {
    const owner = (S.teamGamePlayers || []).find(p => p.idx === playerIdx);
    isDef = !(owner && owner.teamId === 1);
  }
  const _fire = () => { if (typeof animateBoardIconHit === 'function') { try { animateBoardIconHit([{ col, row }], isDef); } catch (e) {} } };
  setTimeout(() => {
    if (typeof playCurseBoardAnim === 'function') playCurseBoardAnim(col, row, 'damage');
    const _u = window.CURSE_GIFS && window.CURSE_GIFS.damage;
    const _fp = (_u && typeof _fetchGifFrameTimings === 'function') ? _fetchGifFrameTimings(_u) : Promise.resolve({ frameDelays: [] });
    Promise.resolve(_fp).then(t => {
      const fd = (t && t.frameDelays) || [];
      let d = (fd.length > 3) ? fd[3] : (fd.length ? fd[fd.length - 1] : (typeof ATTACK_IMPACT_DELAY !== 'undefined' ? ATTACK_IMPACT_DELAY : 500));
      d = Math.min(d, 3000);
      setTimeout(_fire, d);
    }).catch(() => setTimeout(_fire, 500));
  }, 250);
});

// ── 관전자 이동 슬라이드 애니 ──
//   ★ FIX (관전자 이동 모션): 서버가 상태 동기화(spectator_update / team_spectator_update) *직전* 에
//   이 이벤트를 보냄 → 보드가 아직 옛 위치를 표시하는 동안 animateMove 가 옛→새 칸으로 슬라이드.
//   animateMove 는 오버레이(플로팅 img)+_moveAnimDest 기반이라 1v1·팀 관전자 렌더 모델 모두 동작.
socket.on('spectator_move_anim', ({ prevCol, prevRow, col, row, pieceType, pieceSubUnit, owner }) => {
  if (!S.isSpectator) return;
  if (typeof animateMove !== 'function') return;
  if (prevCol == null || prevRow == null || col == null || row == null) return;
  if (prevCol === col && prevRow === row) return;
  try { playSfx('move'); } catch (e) {}
  const key = `spec:${owner}:${pieceType}:${pieceSubUnit || ''}`;
  try { animateMove('', prevCol, prevRow, col, row, pieceType, pieceSubUnit || null, key); } catch (e) {}
});

// ── 관전자 1v1 스킬 시전 애니 (마법구 비행 + dim) ──
// 1v1 모드에서만 사용 (팀모드는 team_skill_notice 가 동일 역할).
// 페이로드: casterIdx, casterName, casterPieceIdx, sp, instantSp, skillUsed
socket.on('spectator_skill_anim', ({ casterIdx, casterPieceIdx, sp, instantSp, skillUsed, twinJoin, msg, hits, healedPieces, borderCells, cursedPieceIdx, cursedOwnerIdx, ringTeleport, herbCenter, divineTarget, nightmareCells, destroyedRats }) => {
  if (!S.isSpectator) return;

  // ★ 분신 비행 — 관전자도 동일 애니메이션 + SFX
  if (twinJoin && typeof playTwinJoinFlight === 'function') {
    const moverSub = twinJoin.moverSub || 'elder';
    playTwinJoinFlight(moverSub, twinJoin.fromCol, twinJoin.fromRow, twinJoin.toCol, twinJoin.toRow);
    if (typeof playSfxTwinsJoin === 'function') playSfxTwinsJoin();
  }

  const oldSpSnap = Array.isArray(S.sp) ? [...S.sp] : [0, 0];
  const oldInstantSnap = Array.isArray(S.instantSp) ? [...S.instantSp] : [0, 0];

  // 1v1 관전자 화면: P0 카드는 #my-pieces-info, P1 카드는 #opp-pieces-info
  const containerSel = (casterIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
  const cardSel = (casterIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
  const casterCard = (typeof casterPieceIdx === 'number')
    ? document.querySelectorAll(`${containerSel} ${cardSel}`)[casterPieceIdx]
    : null;
  startSkillCastDim(casterCard);
  try { spendSPAttention(oldSpSnap, sp || S.sp, oldInstantSnap, instantSp || S.instantSp); } catch (e) {}

  // ★ 시전자 말풍선 (관전자 시점)
  if (casterCard && typeof casterPieceIdx === 'number') {
    // 관전자 — 양쪽 piece 데이터 모두 접근. 카드의 컨테이너로 누구 piece 인지 결정
    const sourcePieces = (casterIdx === 0) ? (S.myPieces || S.specP0Pieces) : (S.oppPieces || S.specP1Pieces);
    const casterPc = sourcePieces?.[casterPieceIdx];
    const skName = skillUsed?.skillName || (msg ? (msg.match(/[가-힣A-Za-z]+(?=:)/) || [])[0] : null);
    if (skName) {
      const stype = getSkillTypeFromPiece(casterPc, skName);
      showSkillCastBubble(casterCard, skName, stype);
    }
  }

  // ★ 통일 — SP 비행 종료 시점에 dim 해제 + sp 동기화
  const _spCost = spCostFromDelta(oldSpSnap, sp || S.sp, oldInstantSnap, instantSp || S.instantSp);
  const SP_END_MS = getSpFlightEndMs(_spCost);
  setTimeout(() => {
    endSkillCastDim(casterCard);
    if (sp) S.sp = sp;
    if (instantSp) S.instantSp = instantSp;
    if (sp || instantSp) try { updateSPBar(); } catch (e) {}

    // ★ 데미지 스킬 hits — 관전자 시점에서도 셀 hit 애니 + 카드 hit flash + turn-bright + 본체 도장.
    //   1v1 관전자: p0 → #my-pieces-info, p1 → #opp-pieces-info 매핑.
    if (Array.isArray(hits) && hits.length > 0) {
      const hitCells = hits.filter(h => h.col != null && h.row != null).map(h => ({ col: h.col, row: h.row }));
      // ★ 유황범람 라바 애니가 있을 때 hit 셀 표시를 지연 — 라바 ::before 가 빨간 배경을 덮으므로 라바 피크 후 표시
      if (hitCells.length > 0) {
        const _hasLava = Array.isArray(borderCells) && borderCells.length > 0;
        if (_hasLava) {
          setTimeout(() => { animateAttack([], hitCells); }, 1100);
        } else {
          animateAttack([], hitCells);
        }
      }
      // ★ attackLog 기록 — 보드 위 💥/· 셀 마크 (1v1 관전자 시점)
      //   관전자는 전체 정보 접근 가능 — borderCells 있으면 전체 범위, 없으면 hit 만.
      const _hitSetS = new Set(hitCells.map(c => `${c.col},${c.row}`));
      if (Array.isArray(borderCells) && borderCells.length > 0) {
        for (const bc of borderCells) {
          S.attackLog.push({ col: bc.col, row: bc.row, hit: _hitSetS.has(`${bc.col},${bc.row}`), turn: S.turnNumber });
        }
      } else {
        for (const c of hitCells) {
          S.attackLog.push({ col: c.col, row: c.row, hit: true, turn: S.turnNumber });
        }
      }
      if (S.specGameState) renderSpectatorGame(S.specGameState); // attackLog 마커 즉시 반영
      for (const h of hits) {
        if (h.defPieceIdx == null || h.defOwnerIdx == null) continue;
        const dmg = (typeof h.damage === 'number') ? h.damage : 0;
        if (dmg > 0) {
          const key = (h.defOwnerIdx === 0) ? `my:${h.defPieceIdx}` : `opp:${h.defPieceIdx}`;
          if (h.bodyguardRedirect) addLoyaltyDamage(key, dmg);
          else if (!h.redirectedToBodyguard) addBodyDamage(key, dmg);
        }
        if (h.redirectedToBodyguard && !h.bodyguardRedirect) continue;
        const containerSel = (h.defOwnerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
        const cardSel = (h.defOwnerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
        const cards = document.querySelectorAll(`${containerSel} ${cardSel}`);
        const card = cards[h.defPieceIdx];
        if (card) applyHitFlashWithBrighten(card);
      }
      if (S.specGameState) renderSpectatorGame(S.specGameState);
    }
    // ★ 회복 애니메이션 — 1v1 관전자 시점: { ownerIdx, pieceIdx } 페어로 카드 매핑.
    //   1v1 관전자: ownerIdx 0 → #my-pieces-info, 1 → #opp-pieces-info.
    if (Array.isArray(healedPieces) && healedPieces.length > 0) {
      setTimeout(() => {
        for (const h of healedPieces) {
          if (typeof h.ownerIdx !== 'number' || typeof h.pieceIdx !== 'number') continue;
          const containerSel = (h.ownerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
          const cardSel = (h.ownerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
          const card = document.querySelectorAll(`${containerSel} ${cardSel}`)[h.pieceIdx];
          if (!card) continue;
          card.classList.add('heal-flash');
          setTimeout(() => card.classList.remove('heal-flash'), 2000);
          spawnHealSparkles(card);
        }
      }, 50);
    }
    // ★ 유황범람으로 죽은 쥐 사망 모션 (관전자 시점)
    _animateSkillDestroyedRats(destroyedRats);
    // ★ 유황범람 라바 애니 — 1v1 관전자 시점에서도 표시 (사용자 보고 누락 수정).
    if (Array.isArray(borderCells) && borderCells.length > 0 && typeof animateLavaCells === 'function') {
      animateLavaCells(borderCells);
    }
    // ★ 악몽 시전 (1v1 관전자 시점) — 표식 적 셀 보라 펄스. (사망 GIF 는 아래 통합 블록에서 처리.)
    if (Array.isArray(nightmareCells) && nightmareCells.length > 0 &&
        typeof animateNightmareCast === 'function') {
      animateNightmareCast(nightmareCells, { spiralStyle: 'a', opacityLevel: 2 });
    }
    // ★ FIX (관전자 사망 GIF — 유황범람 등 비-악몽 데미지 스킬): 이전엔 악몽 사망만 재생 → 유황범람 등은
    //   사망 모션 없이 상태만 갱신됐음. 모든 데미지 스킬의 destroyed hit 에 사망 GIF + 유해 생성.
    //   라바면 피격 표시(+1100ms) 이후로 사망 지연(피격 모션이 사망 렌더에 덮이지 않도록).
    if (Array.isArray(hits) && hits.some(h => h.destroyed)) {
      const _deadSpec = hits.filter(h => h.destroyed);
      const _deathInfosSpec = _detectDeaths(_deadSpec, false);
      if (_deathInfosSpec.length > 0) {
        const _lavaDeathDelaySpec = (Array.isArray(borderCells) && borderCells.length > 0) ? 1600 : 500;
        setTimeout(() => {
          playDeathAnimations(_deathInfosSpec, () => {
            _addClientSideRemains(_deathInfosSpec);
            if (S.specGameState) renderSpectatorGame(S.specGameState);
          });
        }, _lavaDeathDelaySpec);
      }
    }
    // ★ 저주 부여 turn-bright — 1v1 관전자 시점 (누락 수정).
    //   1v1 관전자: ownerIdx 0 → #my-pieces-info, 1 → #opp-pieces-info.
    if (typeof cursedPieceIdx === 'number' && typeof cursedOwnerIdx === 'number') {
      requestAnimationFrame(() => {
        _persistTurnBright(cursedOwnerIdx, cursedPieceIdx);
        const containerSel = (cursedOwnerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
        const cardSel = (cursedOwnerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
        const card = document.querySelectorAll(`${containerSel} ${cardSel}`)[cursedPieceIdx];
        if (card) card.classList.add('turn-bright');
      });
    }
    // ★ 1v1 관전자 — 약초학/신성/절대복종반지 보드 애니 (관전자는 모든 정보 시각화).
    if (herbCenter && typeof animateHerbCast === 'function') {
      animateHerbCast(herbCenter.col, herbCenter.row);
    }
    if (divineTarget && typeof animateDivineCast === 'function') {
      animateDivineCast(divineTarget.col, divineTarget.row);
    }
    if (ringTeleport && typeof animateRingTeleport === 'function') {
      animateRingTeleport(ringTeleport, 'observer');
    }
  }, SP_END_MS);
});

// ── 관전자 일반 공격 애니메이션 ──
//   서버가 each being_attacked emit 옆에 같이 emit 함. defOwnerIdx 0/1 → my/opp 패널 매핑.
let _spectatorAttackSeq = 0;
socket.on('spectator_attack_anim', ({ atkCells, hits, friendlyFireHits, atkCol, atkRow, atkType, atkSubUnit }) => {
  if (!S.isSpectator) return;
  // ★ 공격 SFX 즉시 (휘두름). 셀 이펙트 + 피격 판정은 ATTACK_IMPACT_DELAY 후 동기화.
  try { playSfx('attack'); } catch (e) {}
  // ★ FIX (관전자 공격 모션): 공격자 칸에 공격 GIF 즉시 재생 — 플레이어 시점과 동일. 오버레이라
  //   관전자 렌더 모델(renderSpectatorGame/renderTeamGameSnapshot)과 무관하게 동작. 방향은 DOM 폴백.
  if (atkType != null && atkCol != null && atkRow != null && typeof animateAttackGif === 'function') {
    try { animateAttackGif(atkCol, atkRow, atkType, atkSubUnit || null, false, null); } catch (e) {}
  }
  // ★ 쥐 공격 모션은 서버의 rat_attack_anim 이벤트(쥐장수 공격 시에만)로 처리 — 여기서 자동 추정 X.
  const hitCellList = (hits || []).filter(h => h.col != null && h.row != null).map(h => ({ col: h.col, row: h.row }));
  const _capturedTurn = S.turnNumber;
  const _mySeq = ++_spectatorAttackSeq;
  // ★ 유해 피격 애니 동기화 기준 — 일반 유닛 피격과 같은 임팩트 순간.
  S._impactAtTs = Date.now() + ATTACK_IMPACT_DELAY;

  setTimeout(() => {
    if (S.turnNumber !== _capturedTurn) return; // C-1: turn changed, skip stale update
    if (_spectatorAttackSeq !== _mySeq) return; // C-3: newer event arrived, skip
    // ★ 공격 범위 셀 이펙트
    if (Array.isArray(atkCells) && atkCells.length > 0) {
      animateAttackCellEffect(atkCells);
    }
    // ── ★ 관전자 사망 감지 — 피격 애니 전 DOM 에서 방향 캡처 ──────────
    const _specDestroyedHits = (hits || []).filter(h => h.destroyed && h.col != null && h.row != null);
    // 관전자는 양 측 다 보이므로 isDefending 구분 불필요 — 아무 marker 에서 방향 추출
    const _specDeathInfos = _specDestroyedHits.length > 0 ? _detectDeaths(_specDestroyedHits, false) : [];

    // ── ★ 관전자 아군 피격/사망 (학살영웅 배반자) ──
    const _ffHitsSpec = (friendlyFireHits || []).filter(ff => ff.col != null && ff.row != null);
    const _ffHitCellsSpec = _ffHitsSpec.map(ff => ({ col: ff.col, row: ff.row }));
    const _ffDeadSpec = _ffHitsSpec.filter(ff => ff.destroyed);
    const _ffDeathInfosSpec = _ffDeadSpec.length > 0 ? _detectDeaths(_ffDeadSpec, false) : [];
    // 모든 사망 합산
    const _allSpecDeathInfos = _specDeathInfos.concat(_ffDeathInfosSpec);

    // 피격 셀 빨간 플래시
    if (hitCellList.length > 0) {
      animateAttack([], hitCellList);
    }
    // ── 아군 피격 보드 애니 (관전자 — 학살영웅 배반자) ──
    if (_ffHitCellsSpec.length > 0) {
      animateAttack([], _ffHitCellsSpec);
    }
    // 효과음 — kill / hit (임팩트 시점에)
    if ((hits || []).some(h => h.destroyed) || _ffDeadSpec.length > 0) {
      try { playSfx('kill'); } catch (e) {}
    } else if (hitCellList.length > 0 || _ffHitCellsSpec.length > 0) {
      try { playSfx('hit'); } catch (e) {}
    }

    // 1v1 관전자 — defOwnerIdx 0=p0(#my-pieces-info), 1=p1(#opp-pieces-info) 매핑.
    if (!S.isTeamMode) {
      for (const h of (hits || [])) {
        if (h.defPieceIdx == null || h.defOwnerIdx == null) continue;
        const dmg = (typeof h.damage === 'number') ? h.damage : 0;
        if (dmg > 0) {
          const key = (h.defOwnerIdx === 0) ? `my:${h.defPieceIdx}` : `opp:${h.defPieceIdx}`;
          if (h.bodyguardRedirect) addLoyaltyDamage(key, dmg);
          else if (!h.redirectedToBodyguard) addBodyDamage(key, dmg);
        }
        if (h.redirectedToBodyguard && !h.bodyguardRedirect) continue;
        const containerSel = (h.defOwnerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
        const cardSel = (h.defOwnerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
        const card = document.querySelectorAll(`${containerSel} ${cardSel}`)[h.defPieceIdx];
        if (card) applyHitFlashWithBrighten(card);
      }
      if (_allSpecDeathInfos.length > 0) {
        setTimeout(() => {
          playDeathAnimations(_allSpecDeathInfos, () => {
            // ★ 유해 즉시 반영
            _addClientSideRemains(_allSpecDeathInfos);
            if (S.specGameState) renderSpectatorGame(S.specGameState);
          });
        }, 400);
      } else {
        if (S.specGameState) renderSpectatorGame(S.specGameState);
      }
      return;
    }
    // 팀모드 관전자
    for (const h of (hits || [])) {
      if (h.defPieceIdx == null || h.defOwnerIdx == null) continue;
      const dmg = (typeof h.damage === 'number') ? h.damage : 0;
      if (dmg > 0) {
        const key = `${h.defOwnerIdx}:${h.defPieceIdx}`;
        if (h.bodyguardRedirect) addLoyaltyDamage(key, dmg);
        else if (!h.redirectedToBodyguard) addBodyDamage(key, dmg);
      }
      if (h.redirectedToBodyguard && !h.bodyguardRedirect) continue;
      const card = document.querySelector(`.team-profile-block[data-player-idx="${h.defOwnerIdx}"] [data-piece-idx="${h.defPieceIdx}"]`);
      if (card) applyHitFlashWithBrighten(card);
    }
    if (_allSpecDeathInfos.length > 0) {
      setTimeout(() => {
        playDeathAnimations(_allSpecDeathInfos, () => {
          // ★ 유해 즉시 반영
          _addClientSideRemains(_allSpecDeathInfos);
        });
      }, 400);
    }
  }, ATTACK_IMPACT_DELAY);
});

// ── 관전자 전투 로그 ──
socket.on('spectator_log', ({ msg, type, playerIdx, markCells }) => {
  if (!S.isSpectator) return;
  addLog(msg, type || 'system');
  if (type === 'event') {
    showSkillToast(msg, false, undefined, 'event');
  } else if (type === 'skill' || type === 'hit' || type === 'passive' || type === 'move' || type === 'miss' || type === 'attack') {
    showSkillToast(msg, false, playerIdx);
  }
  // ★ 표식 리워크 (관전자): 인두 낙하 애니메이션
  if (type === 'passive' && msg.startsWith('표식:') && Array.isArray(markCells) && markCells.length > 0 &&
      typeof animateMarkBrand === 'function') {
    try { animateMarkBrand(markCells); } catch (e) {}
  }
  // 관전자 전용 효과음: 메시지 내용으로 판단
  if (type === 'passive' && msg.startsWith('저주:') && msg.includes('0.5 피해')) {
    playSfxCurseDamage();
  } else if (type === 'passive' && msg.startsWith('표식:')) {
    // 표식 — 인두 시즐 (animateMarkBrand 의 사운드와 통일)
    playSfxTorturerMark();
  } else if (type === 'passive') {
    // 그 외 패시브는 전용 차임
    playSfxPassive();
  } else if (type === 'skill' && msg.startsWith('악몽')) {
    playSfxNightmare();
  } else if (type === 'hit' && msg.includes('덫')) {
    playSfxTrapSnap();
  } else if (type === 'hit' && msg.includes('폭탄')) {
    playSfxBombExplode();
  } else if (msg.includes('쥐') && (msg.includes('격파') || msg.includes('사라'))) {
    playSfxRatDeath();
  }
});

// ── 관전자: 페이즈 전환 알림 ──
socket.on('spectator_phase', ({ phase, p0Name, p1Name, characters, p0Draft, p1Draft }) => {
  if (!S.isSpectator) return;
  S.specP0Name = p0Name;
  S.specP1Name = p1Name;
  if (characters) S.specCharacters = characters;
  if (phase === 'draft') {
    S.specDraft = { p0: null, p1: null, draftDone: [false, false] };
    renderSpectatorDraft();
    showScreen('screen-draft');
  } else if (phase === 'hp') {
    S.specDraft = { p0: p0Draft, p1: p1Draft };
    S.specHp = {
      p0Pieces: [], p1Pieces: [], hpDone: [false, false],
      p0Hps: [4, 3, 3], p1Hps: [4, 3, 3],
      p0Draft: p0Draft, p1Draft: p1Draft,
    };
    renderSpectatorHp();
    showScreen('screen-hp');
  }
});

// ── 관전자: 드래프트 실시간 브라우징 ──
socket.on('spectator_draft_browse', ({ playerIdx, playerName, step, type, selected }) => {
  if (!S.isSpectator) return;
  if (!S.specDraft) S.specDraft = { p0: null, p1: null, draftDone: [false, false], p0Browse: {}, p1Browse: {} };
  const key = playerIdx === 0 ? 'p0Browse' : 'p1Browse';
  S.specDraft[key] = selected || {};
  renderSpectatorDraft();
});

// ── 관전자: 드래프트 최종 확정 ──
socket.on('spectator_draft_update', ({ playerIdx, playerName, draft, draftDone }) => {
  if (!S.isSpectator) return;
  if (!S.specDraft) S.specDraft = { p0: null, p1: null, draftDone: [false, false], p0Browse: {}, p1Browse: {} };
  if (playerIdx === 0) { S.specDraft.p0 = draft; S.specDraft.p0Browse = { 1: draft.t1, 2: draft.t2, 3: draft.t3 }; }
  else { S.specDraft.p1 = draft; S.specDraft.p1Browse = { 1: draft.t1, 2: draft.t2, 3: draft.t3 }; }
  S.specDraft.draftDone = draftDone;
  renderSpectatorDraft();
});

// ── 관전자: HP 실시간 조정 ──
socket.on('spectator_hp_browse', ({ playerIdx, playerName, draft, hps }) => {
  if (!S.isSpectator) return;
  if (!S.specHp) S.specHp = { p0Pieces: [], p1Pieces: [], hpDone: [false, false], p0Hps: null, p1Hps: null, p0Draft: null, p1Draft: null };
  const key = playerIdx === 0 ? 'p0' : 'p1';
  S.specHp[key + 'Hps'] = hps;
  S.specHp[key + 'Draft'] = draft;
  renderSpectatorHp();
});

// ── 관전자: HP 최종 확정 ──
socket.on('spectator_hp_update', ({ playerIdx, playerName, pieces, hpDone }) => {
  if (!S.isSpectator) return;
  if (!S.specHp) S.specHp = { p0Pieces: [], p1Pieces: [], hpDone: [false, false], p0Hps: null, p1Hps: null, p0Draft: null, p1Draft: null };
  if (playerIdx === 0) S.specHp.p0Pieces = pieces;
  else S.specHp.p1Pieces = pieces;
  S.specHp.hpDone = hpDone;
  renderSpectatorHp();
});

// ── 관전자: 공개 페이즈 ──
socket.on('spectator_reveal', ({ p0Pieces, p1Pieces, p0Name, p1Name }) => {
  if (!S.isSpectator) return;
  S.specReveal = { p0Pieces, p1Pieces, p0Name, p1Name };
  renderSpectatorReveal();
  showScreen('screen-reveal');
});

// ── 관전자: 배치 페이즈 시작 ──
socket.on('spectator_placement_start', ({ p0Pieces, p1Pieces, boardBounds }) => {
  if (!S.isSpectator) return;
  S.specPlacement = { p0Pieces, p1Pieces, boardBounds };
  S.boardBounds = boardBounds;
  renderSpectatorPlacement();
  showScreen('screen-placement');
});

// ── 관전자: 배치 업데이트 ──
socket.on('spectator_placement_update', ({ p0Pieces, p1Pieces, boardBounds }) => {
  if (!S.isSpectator) return;
  S.specPlacement = { p0Pieces, p1Pieces, boardBounds };
  S.boardBounds = boardBounds;
  renderSpectatorPlacement();
});

socket.on('opponent_joined', ({ opponentName }) => {
  S.opponentName = opponentName;
});

socket.on('phase_change', ({ phase }) => {
  if (phase === 'draft') {
    S.deckBuilderMode = false;
    document.getElementById('btn-deck-back').classList.add('hidden');
    const deckListEl = document.getElementById('deck-list');
    if (deckListEl) deckListEl.classList.add('hidden');
    S.draftStep = 1;
    S.draftPicked = [];
    // 저장된 덱에서 프리필
    const deck = loadDeck();
    if (deck && S.characters) {
      S.draftSelected = {};
      if (deck.t1 && S.characters[1]?.find(c => c.type === deck.t1)) S.draftSelected[1] = deck.t1;
      if (deck.t2 && S.characters[2]?.find(c => c.type === deck.t2)) S.draftSelected[2] = deck.t2;
      if (deck.t3 && S.characters[3]?.find(c => c.type === deck.t3)) S.draftSelected[3] = deck.t3;
    } else {
      S.draftSelected = {};
    }
    buildDraftStepUI();
    showScreen('screen-draft');
    // 프리필된 덱이 있으면 관전자에게도 알림
    if (deck && (deck.t1 || deck.t2 || deck.t3)) {
      socket.emit('draft_browse', { step: S.draftStep, type: S.draftSelected[S.draftStep], selected: { ...S.draftSelected } });
    }
  }
});

// ── 드래프트 확정 ──
socket.on('draft_ok', ({ t1, t2, t3, timeout, timeoutMsg }) => {
  S.myDraft = { t1, t2, t3 };
  if (timeout) {
    if (typeof playSfxTimeout === 'function') playSfxTimeout();
    // 서버 timeoutMsg: '자동 확정' (이미 다 채웠을 때) / '랜덤 선택' (빈 슬롯 채운 경우)
    const msg = `⏰ ${timeoutMsg || '랜덤 선택'}`;
    addLog(msg, 'system');
    showSkillToast(msg, false, undefined, 'event');
  }
});

// ── HP 분배 페이즈 ──
socket.on('hp_phase', ({ draft, hasTwins, hpDist }) => {
  S.myDraft = draft;
  // ★ 재접속 시 이미 분배한 HP 값 복원 (없으면 buildHpUI 가 기본 4/3/3 사용).
  S._restoredHpDist = (Array.isArray(hpDist) && hpDist.length === 3) ? hpDist.slice() : null;
  S.hasTwins = !!hasTwins;
  S.teamHpMode = false;
  // 1v1 모드 진입 시 팀전 패널 제거
  const tmPanel = document.getElementById('team-hp-teammate-panel');
  if (tmPanel) tmPanel.remove();
  buildHpUI();
  showScreen('screen-hp');
});

socket.on('hp_ok', ({ timeout }) => {
  if (timeout) {
    if (typeof playSfxTimeout === 'function') playSfxTimeout();
    addLog('⏰ 랜덤 분배', 'system');
    showSkillToast('⏰ 랜덤 분배', false, undefined, 'event');
  }
});

socket.on('twin_split_needed', ({ twinTierHp }) => {
  S.twinTierHp = twinTierHp;
  showTwinSplit(twinTierHp);
});

// ── 캐릭터 공개 (레거시 — 새 흐름에서는 사용 안 함) ──
socket.on('reveal_phase', ({ yourPieces, oppPieces }) => {
  S.myPieces = yourPieces;
  S.oppPieces = oppPieces;
  buildRevealUI(yourPieces, oppPieces);
  showScreen('screen-reveal');
});

// ── 초기 공개 (드래프트 직후) ──
socket.on('initial_reveal_phase', ({ myDraft, oppChars, myDeckName, oppDeckName, myName, oppName, alreadyDecided }) => {
  S.phase = 'initial_reveal';
  S.myDraft = myDraft;
  S.oppRevealChars = oppChars;
  S.myDeckName = myDeckName || '';
  S.oppDeckName = oppDeckName || '';
  buildInitialRevealUI(myDraft, oppChars);
  applyRevealDeckNames(myName, oppName, myDeckName, oppDeckName);
  showScreen('screen-initial-reveal');
  // ★ 재접속 — 이미 교체 여부를 결정했으면 선택 UI 숨기고 대기 상태 표시(다시 선택하는 혼란 방지).
  if (alreadyDecided) {
    ['btn-irev-no', 'btn-irev-yes', 'btn-irev-confirm'].forEach(id => { const b = document.getElementById(id); if (b) { b.classList.add('hidden'); b.disabled = true; } });
    const q = document.querySelector('#screen-initial-reveal .irev-decision-question, #screen-initial-reveal .irev-question');
    if (q) q.textContent = '결정 완료 — 상대를 기다리는 중...';
    try { showSkillToast('이미 교체 결정 완료. 상대 대기 중...', false, undefined, 'event'); } catch (e) {}
  }
});

// ── 교환 드래프트 ── 캐릭터 딕셔너리처럼 우측에서 슬라이드 인하는 오버레이로 표시.
//   뒤의 screen-initial-reveal 은 그대로 active 유지 → 백드롭 너머로 보임.
socket.on('exchange_draft_phase', ({ myDraft, available, oppDraft, alreadyExchanged }) => {
  S.phase = 'exchange_draft';
  S.exchangeAvailable = available;
  S.exchangeMyDraft = { ...myDraft };
  S.exchangeSelected = null;
  S.myDraft = myDraft;
  S._myExchangedThisRound = false;  // 새 교체 라운드 진입 — 플래그 초기화
  buildExchangeDraftUI(myDraft, available, oppDraft);
  openOverlayScreen('screen-exchange');
  // ★ 재접속 — 이미 교환 결정을 확정했으면 확정 버튼 비활성 + 대기 표시(재클릭 혼란 방지).
  if (alreadyExchanged) {
    const cb = document.getElementById('btn-exchange-confirm');
    if (cb) { cb.disabled = true; cb.textContent = '교환 완료 — 상대 대기 중'; }
    try { showSkillToast('이미 교환 결정 완료. 상대 대기 중...', false, undefined, 'event'); } catch (e) {}
  }
});

socket.on('exchange_done', ({ draft, exchanged, timeout }) => {
  S.exchangeMyDraft = draft;
  S.myDraft = draft;  // 교체 페이즈 카드 갱신용 — 페이즈 종료 후 다른 핸들러도 일관된 데이터 사용
  // ★ 내가 이번 라운드에 교체했음을 기록 — final_reveal_phase 가 "교체하지 않음" 라벨을 잘못 붙이지 않게.
  //   exchanged 가 truthy 면 실제 교체 발생. swap 애니가 이미 끝나서 swapTasks 에 안 잡히는 경우에도
  //   이 플래그로 detect → 라벨 스킵.
  S._myExchangedThisRound = !!exchanged;
  if (timeout) {
    if (typeof playSfxTimeout === 'function') playSfxTimeout();
    addLog('⏰ 자동 확정', 'system');
    showSkillToast('⏰ 자동 확정', false, undefined, 'event');
  } else if (exchanged) {
    // 토스트 제거 — 시각적으로 카드 자체가 바뀌므로 텍스트 안내 불필요
    // 내 슬롯에 즉시 swap-reveal: 기존 카드 페이드아웃 → 빈 슬롯 → 새 카드 등장
    animateMySwapInReveal(exchanged);
  }
});

// 내 측 교체 애니메이션 — exchange_done 도착 즉시 실행 (오버레이 슬라이드 아웃과 동시).
//   1) 기존 카드 fade-out (400ms)
//   2) 빈 슬롯 placeholder (200ms)
//   3) 새 캐릭터 카드 fade-in (900ms)  → 총 1.5초
//   대기 중에도 내 슬롯에는 이미 새 캐릭터가 자리잡고 있음.
function animateMySwapInReveal(exchanged) {
  if (!exchanged) return;
  const myContainer = document.getElementById('irev-my-chars');
  if (!myContainer) return;
  const cards = [...myContainer.querySelectorAll('.reveal-piece-card')];
  const targetIdx = exchanged.tier - 1;  // tier 1/2/3 → idx 0/1/2
  const oldEl = cards[targetIdx];
  if (!oldEl) return;
  // 진행 중 표시 — playExchangeRevealAnimation 가 동시에 끼어들어도 my 측 tier 를 건너뛰게.
  S._mySwapAnimatingTier = exchanged.tier;
  // SFX (기존 swap reveal 동일)
  try { playSfxSwapBlink(); } catch (e) {}
  setTimeout(() => { try { playSfxSwapReveal(); } catch (e) {} }, 400);
  // (1) fade-out
  oldEl.classList.add('swap-out');
  // (2) 400ms 후 빈 슬롯으로 교체
  setTimeout(() => {
    const emptySlot = document.createElement('div');
    emptySlot.className = 'reveal-slot-empty reveal-slot-swap-empty';
    // ★ 버그 수정: data-tier 부착 — 인덱스 기반 매핑이 placeholder 를 건너뛰고 어긋나는 문제 차단.
    emptySlot.dataset.tier = String(exchanged.tier);
    oldEl.replaceWith(emptySlot);
    // (3) 200ms 후 새 카드 fade-in
    setTimeout(() => {
      const newCard = createDraftRevealCard(exchanged.newChar, exchanged.tier, 'left');
      newCard.classList.add('swap-in', 'exchanged-highlight');
      emptySlot.replaceWith(newCard);
      // 애니메이션 완료 — 락 해제
      if (S._mySwapAnimatingTier === exchanged.tier) S._mySwapAnimatingTier = null;
    }, 200);
  }, 400);
}

// ── 교체 페이즈 (구 final_reveal) ── 통합된 교체 페이즈의 마지막 단계.
//   화면 전환 없이 screen-initial-reveal 위에서 변경된 티어의 카드만 swap-reveal 애니메이션 진행 (1.5초).
//   양측 모두 교체했으면 동시 진행, 변경 없으면 즉시 다음 단계로 진행.
//   "교체됨" 태그(exchanged-highlight) + SFX(playSfxSwapBlink/playSfxSwapReveal) 유지.
socket.on('final_reveal_phase', ({ myDraft, oppChars, myDeckName, oppDeckName, myName, oppName, reconnected }) => {
  S.phase = 'final_reveal';
  S.myDeckName = myDeckName || S.myDeckName || '';
  S.oppDeckName = oppDeckName || S.oppDeckName || '';
  // ★ 재접속 — 스왑 reveal 애니 재재생 생략, 최종 공개 화면을 정적으로 표시.
  if (reconnected) {
    clearAiWaitCountdown();
    const wOv = document.getElementById('exchange-waiting-overlay'); if (wOv) wOv.remove();
    try { buildFinalRevealUI(myDraft, oppChars); } catch (e) {}
    applyRevealDeckNames(myName, oppName, myDeckName, oppDeckName, /*final=*/true);
    showScreen('screen-final-reveal');
    return;
  }
  // 교환 드래프트 화면에서 돌아오는 경우 — 대기 오버레이 + 교환 드래프트 오버레이 + AI 카운트다운 모두 정리
  clearAiWaitCountdown();
  const waitOverlay = document.getElementById('exchange-waiting-overlay');
  if (waitOverlay) waitOverlay.remove();
  applyRevealDeckNames(myName, oppName, myDeckName, oppDeckName, /*final=*/false);
  // 교환 드래프트 오버레이가 떠 있으면 우측으로 슬라이드 아웃 (뒤의 교체 페이즈가 자연스럽게 노출)
  const exScreen = document.getElementById('screen-exchange');
  const isOverlayOpen = exScreen && exScreen.classList.contains('is-overlay');
  if (isOverlayOpen) {
    closeOverlayScreen('screen-exchange');
    S.phase = 'final_reveal';
    // 오버레이가 빠진 후 swap 애니메이션 시작 (화면이 자리 잡은 다음)
    //   ★ 진단 #7 — 440ms 사이에 disconnected/game_over 등이 도착해 화면이 다른 곳으로 넘어갔으면 중단.
    //     phase 가 final_reveal 이 아니거나 active screen 이 screen-initial-reveal 이 아니면 swap 애니 스킵.
    setTimeout(() => {
      const cur = document.querySelector('.screen.active');
      if (S.phase !== 'final_reveal' || !cur || cur.id !== 'screen-initial-reveal') return;
      playExchangeRevealAnimation(myDraft, oppChars);
    }, OVERLAY_ANIM_MS + 20);
  } else {
    // 인간이 ✗/미선택으로 그 자리(교체 페이즈) 에서 대기 중이거나 재접속 — 화면 전환 없이 곧장 swap 애니메이션
    const cur = document.querySelector('.screen.active');
    if (!cur || cur.id !== 'screen-initial-reveal') showScreen('screen-initial-reveal');
    else S.phase = 'final_reveal';
    playExchangeRevealAnimation(myDraft, oppChars);
  }
});

// 캐릭터 공개 화면에 닉네임 + 덱 이름 표시
function applyRevealDeckNames(myName, oppName, myDeckName, oppDeckName, isFinal) {
  const screenId = isFinal ? 'screen-final-reveal' : 'screen-initial-reveal';
  const screen = document.getElementById(screenId);
  if (!screen) return;
  // h3 .reveal-side-name (있으면 갱신, 없으면 buildXxxRevealUI가 만들어두므로 후행 갱신)
  const sides = screen.querySelectorAll('.reveal-side');
  if (sides.length >= 2) {
    const renderSide = (sideEl, name, deckName) => {
      let label = sideEl.querySelector('h3.reveal-side-name');
      if (!label) {
        label = sideEl.querySelector('h3');
      }
      if (label) {
        label.innerHTML = `${escapeHtmlGlobal(name || '')}${deckName ? `<div class="reveal-deck-name">${escapeHtmlGlobal(deckName)}</div>` : ''}`;
      }
    };
    renderSide(sides[0], myName || S.myName, myDeckName);
    renderSide(sides[1], oppName || S.opponentName, oppDeckName);
  }
}

// ── 배치 ──
socket.on('placement_phase', ({ pieces, oppPieces, alreadyConfirmed }) => {
  S.myPieces = pieces;
  if (oppPieces) S.oppPieces = oppPieces;
  S.teamPlacementMode = false;
  S.teamPlacementTeammates = [];
  const tmStatus = document.getElementById('team-placement-status-bar');
  if (tmStatus) tmStatus.remove();
  buildPlacementUI();
  showScreen('screen-placement');
  // ★ 재접속 — 이미 배치 확정했으면 확정 버튼 비활성 + 대기 표시(배치 좌표는 buildPlacementUI 가 이미 복원).
  if (alreadyConfirmed) {
    const cb = document.getElementById('btn-placement-confirm');
    if (cb) { cb.disabled = true; cb.textContent = '배치 완료 — 상대 대기 중'; }
    try { showSkillToast('배치 완료. 상대를 기다리는 중...', false, undefined, 'event'); } catch (e) {}
  }
});

socket.on('placed_ok', ({ pieceIdx, col, row }) => {
  S.myPieces[pieceIdx].col = col;
  S.myPieces[pieceIdx].row = row;
  updatePlacementUI();
});

// ── 재접속 지식 영속 (클라 전용 사적 정보: 추리토큰·공격마크·표식위치·유해방향) ──
//   서버 권위 상태는 페이로드로 오지만, 플레이어가 쌓은 사적 추리 정보는 서버에 없어 새로고침 시 유실.
//   sessionStorage(roomId 키)에 저장 → 재접속 game_start 에서 복원. (탭 닫으면 자동 정리)
function _knowledgeKey() {
  let rid = S.roomId;
  if (!rid) { try { rid = (JSON.parse(sessionStorage.getItem('caligo_session') || '{}') || {}).roomId; } catch (e) {} }
  return rid ? 'caligo_know_' + rid : null;
}
function _saveKnowledge() {
  const key = _knowledgeKey(); if (!key) return;
  try {
    sessionStorage.setItem(key, JSON.stringify({
      deductionTokens: S.deductionTokens || [],
      attackLog: S.attackLog || [],
      gameLog: S.gameLog || [],
      remainsFacing: S._remainsFacing || {},
      revealedMarkedOpps: (S._revealedMarkedOpps instanceof Map) ? [...S._revealedMarkedOpps.entries()] : [],
    }));
  } catch (e) {}
}
function _restoreKnowledge() {
  const key = _knowledgeKey(); if (!key) return;
  try {
    const raw = sessionStorage.getItem(key); if (!raw) return;
    const d = JSON.parse(raw);
    if (Array.isArray(d.deductionTokens)) S.deductionTokens = d.deductionTokens;
    if (Array.isArray(d.attackLog)) S.attackLog = d.attackLog;
    if (Array.isArray(d.gameLog)) S.gameLog = d.gameLog;
    if (d.remainsFacing && typeof d.remainsFacing === 'object') S._remainsFacing = d.remainsFacing;
    if (Array.isArray(d.revealedMarkedOpps) && S._revealedMarkedOpps instanceof Map) {
      for (const [k, v] of d.revealedMarkedOpps) S._revealedMarkedOpps.set(k, v);
    }
  } catch (e) {}
}

// ── 게임 시작 ──
socket.on('game_start', (data) => {
  S._gameEnded = false;  // 게임 종료 플래그 리셋 (재시작/다음 판 대비)
  S._gameOverShown = false;  // 결과화면 토스트 차단 플래그 리셋
  resetAnimGuards();     // 애니메이션 lock·guard 일괄 리셋 (재접속/다음 판 대비)
  closeAllModals(); // C-8: 모달 잔류 방지
  // ★ 표식 노출 정보 — 새 게임 시작 시 stale 엔트리 모두 정리
  if (S._revealedMarkedOpps instanceof Map) S._revealedMarkedOpps.clear();
  // ★ 재접속(새로고침) 복원 — 서버가 보낸 신원 정보로 잃어버린 S 필드 복구.
  //   buildGameUI/refreshGameView 전에 설정해야 보드 방향·facing 키가 올바름.
  if (typeof data.playerIdx === 'number') S.playerIdx = data.playerIdx;
  if (data.opponentName) S.opponentName = data.opponentName;
  S.myPieces = data.yourPieces || [];
  S.oppPieces = data.oppPieces || [];
  S.turnNumber = data.turnNumber;
  S.isMyTurn = data.isYourTurn;
  // ★ 이번 턴 행동 소진 상태 복원 (재접속) — 새 게임이면 모두 undefined → false 로 초기화.
  //   이 값을 buildGameUI/액션바 표시 *전*에 세팅해야 "이미 행동함" 상태가 UI 에 정확히 반영됨.
  S.actionDone = !!data.actionDone;
  S.actionUsedSkillReplace = !!data.actionUsedSkillReplace;
  S.skillsUsedThisTurn = Array.isArray(data.skillsUsed) ? data.skillsUsed : [];
  S.lastActionPieceType = data.lastActionPieceType || null;
  S.lastActionType = data.lastActionType || null;
  S.sp = data.sp || [1, 1];
  S.instantSp = data.instantSp || [0, 0];
  // ★ 후공 인스턴트 SP 지급 — 합류 연출 전까지 그 pip 을 숨김(시작 안내 직후 오브가 합류하며 등장).
  S._pendingSpGrant = null;
  {
    const _isRecon = !!data.reconnected || (data.turnNumber && data.turnNumber > 1);
    if (typeof data.secondPlayerIdx === 'number' && !_isRecon) {
      const gs = data.secondPlayerIdx;
      const real = (S.instantSp || []).slice();
      S.instantSp = real.slice();
      S.instantSp[gs] = Math.max(0, (S.instantSp[gs] || 0) - 1);   // 지급분 1 숨김
      S._pendingSpGrant = { real, side: data.youAreSecond ? 'mine' : 'opp' };
    }
  }
  S.boardBounds = data.boardBounds || { min: 0, max: 4 };
  S._cellFP = null; // ★ 새 게임 — 핑거프린트 캐시 무효화
  S.boardObjects = data.boardObjects || [];
  S.remains = data.remains || [];
  S._remainsFacing = {};  // 사망 GIF 방향 캐시 — 새 게임 초기화
  S.attackLog = [];
  S.action = null;
  S.selectedPiece = null;
  // ★ 재접속(새로고침) — 위 초기화 직후, 저장해둔 클라 사적 지식(추리토큰·공격마크·표식위치·유해방향) 복원.
  //   oppPieces 는 위(4259)에서 이미 세팅됨 → _revealedMarkedOpps 복원 후 재대입으로 setter reseed 재실행(표식 위치 반영).
  if (data.reconnected) { try { _restoreKnowledge(); S.oppPieces = S.oppPieces; } catch (e) {} }
  // 게임 시작 — 데미지 도장 초기 스냅샷
  if (typeof snapshotTurnStartHps === 'function') snapshotTurnStartHps();

  buildGameUI();
  showScreen('screen-game');
  // 패널 제목을 닉네임으로 갱신 — #screen-game 스코프로 한정 (튜토리얼 동명 패널 방지)
  const _gs = document.getElementById('screen-game');
  const leftH3 = _gs ? _gs.querySelector('.left-panel h3') : null;
  if (leftH3) leftH3.textContent = `${myN()}의 말`;
  const rightH3 = _gs ? _gs.querySelector('.right-panel h3') : null;
  if (rightH3) rightH3.textContent = `${oppN()}의 말`;
  refreshGameView();
  showActionBar(S.isMyTurn);
  updateSPBar();
  // ★ 재접속 — 복원된 S.gameLog 로 게임로그 DOM 재구성(정찰/공격/스킬 텍스트 히스토리 복원). buildGameUI 로 로그 DOM 생성된 뒤 호출.
  if (data.reconnected) { try { _rerenderGameLogFromState(); } catch (e) {} }
  // 재접속 (data.reconnected 또는 turnNumber > 1) — 다른 안내 메시지
  //   서버는 reconnected 키를 보냄(과거 reconnect 오타로 1턴 재접속 시 인트로가 재생되던 버그 수정).
  const isReconnect = !!data.reconnected || (data.turnNumber && data.turnNumber > 1);
  if (isReconnect) {
    const turnOwnerName = S.isMyTurn ? (myN() || '나') : (oppN() || '상대');
    addLog(`${turnOwnerName}의 턴`, 'system');
    playGameStartAnimation(S.isMyTurn, true, turnOwnerName);
  } else {
    addLog(`${S.isMyTurn ? '선공' : '후공'}`, 'system');
    playGameStartAnimation(S.isMyTurn);
    // ★ 후공 인스턴트 SP 지급 연출 — 인트로~SP 합류까지 "애니 페이즈"로 양측 행동 잠금.
    if (S._pendingSpGrant) {
      const g = S._pendingSpGrant; S._pendingSpGrant = null;
      setIntroPhaseLock(true);                       // 인트로 시작부터 입력 잠금
      const _safety = setTimeout(() => setIntroPhaseLock(false), 6500);  // 안전망(콜백 누락 대비)
      setTimeout(() => {
        try {
          showSecondPlayerSpAnnounce();
          playSecondPlayerSpGrant(g.side, () => {
            S.instantSp = g.real; try { updateSPBar(); } catch (e) {}
            clearTimeout(_safety); setIntroPhaseLock(false);   // 합류 완료 → 잠금 해제
          });
        } catch (e) { clearTimeout(_safety); setIntroPhaseLock(false); }
      }, 2000);
    }
  }
});

// 보드 파괴 첫 발동 풀스크린 연출 — 게임 시작과 비슷한 임팩트
function playBoardShrinkIntro() {
  let overlay = document.getElementById('board-shrink-overlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'board-shrink-overlay';
    overlay.className = 'game-start-overlay shrink-intro';
    document.body.appendChild(overlay);
  }
  overlay.innerHTML = `
    <div class="game-start-title shrink-intro-title">보드 파괴 시작</div>
    <div class="game-start-sub shrink-intro-sub">안쪽으로 대피하세요.</div>
  `;
  overlay.classList.remove('hidden');
  overlay.classList.add('active');
  // 사운드 — 보드 흔들림 SFX 보강 (오버레이용 톤 다운된 베이스)
  try {
    const ctx = getAudioCtx(); if (ctx) {
      const o = ctx.createOscillator(), g = ctx.createGain();
      o.connect(g); g.connect(ctx.destination);
      o.type = 'sawtooth';
      o.frequency.setValueAtTime(110, ctx.currentTime);
      o.frequency.linearRampToValueAtTime(55, ctx.currentTime + 0.7);
      g.gain.setValueAtTime(0, ctx.currentTime);
      g.gain.linearRampToValueAtTime(0.18, ctx.currentTime + 0.05);
      g.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.8);
      o.start(ctx.currentTime);
      o.stop(ctx.currentTime + 0.85);
    }
  } catch (e) {}
  setTimeout(() => {
    overlay.classList.remove('active');
    overlay.classList.add('hidden');
  }, 3000);
}

// 게임 시작 애니메이션 — 오버레이 "FIGHT!" + 1.2초 scale-up 페이드
function playGameStartAnimation(isMyTurn, isReconnect, turnOwnerName) {
  let overlay = document.getElementById('game-start-overlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'game-start-overlay';
    overlay.className = 'game-start-overlay';
    document.body.appendChild(overlay);
  }
  const title = isReconnect ? '재접속' : '전투 개시';
  const sub = isReconnect
    ? `${turnOwnerName || (isMyTurn ? '나' : '상대')}의 턴`
    : (isMyTurn ? '선공' : '후공');
  overlay.innerHTML = `
    <div class="game-start-title">${title}</div>
    <div class="game-start-sub">${sub}</div>
  `;
  overlay.classList.remove('hidden');
  overlay.classList.add('active');
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    const o = ctx.createOscillator(); const g = ctx.createGain();
    o.connect(g); g.connect(ctx.destination);
    o.type = 'triangle';
    o.frequency.setValueAtTime(440, ctx.currentTime);
    o.frequency.linearRampToValueAtTime(880, ctx.currentTime + 0.4);
    g.gain.setValueAtTime(0.0, ctx.currentTime);
    g.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 0.1);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.8);
    o.start(); o.stop(ctx.currentTime + 0.8);
  } catch (e) {}
  setTimeout(() => {
    overlay.classList.remove('active');
    overlay.classList.add('hidden');
  }, 1800);
}

// ── 내 턴 ──
socket.on('your_turn', (data) => {
  // 새 턴 진입 시 이전 턴 동안 유지된 turn-bright 카드 일괄 해제 (1v1)
  if (typeof clearAllTurnBright === 'function') clearAllTurnBright();
  // ★ 방어적 — 이전 턴에 flush 안 된 패시브 alert 버퍼는 폐기 (turn 경계 stale 누설 방지).
  if (Array.isArray(S._pendingDefensiveAlerts)) S._pendingDefensiveAlerts.length = 0;
  // 방어적 — 이전 턴의 쌍둥이 페이즈 잔재 정리 (정상 흐름이면 이미 종료됐어야 함)
  if (S.twinPhaseActive && typeof exitTwinMovePhase === 'function') {
    exitTwinMovePhase(/*emitToast=*/false);
  }
  // ★ 사용자 보고 (유닛 딤 안 풀림): 이전 턴의 행동 모드 잔재가 새 턴까지 유지되는 케이스 방어.
  //   action-locked / dim-morale-zone 강제 클리어 + setActionButtonMode(null) 로 버튼 상태도 통일.
  document.body.classList.remove('action-locked', 'dim-morale-zone');
  if (typeof setActionButtonMode === 'function') setActionButtonMode(null);
  S.isMyTurn = true;
  if (typeof applyTurnUiState === 'function') applyTurnUiState();
  S.turnNumber = data.turnNumber;
  S.attackLog = S.attackLog.filter(a => a.turn >= S.turnNumber - 1); // C-5: prune old entries
  S.myPieces = data.yourPieces || S.myPieces;
  S.oppPieces = data.oppPieces || S.oppPieces;
  S.sp = data.sp || S.sp;
  S.instantSp = data.instantSp || S.instantSp;
  S.boardBounds = data.boardBounds || S.boardBounds;
  S.boardObjects = data.boardObjects || S.boardObjects;
  S.remains = data.remains || S.remains;
  S.action = null;
  S.selectedPiece = null;
  S.targetSelectMode = false;
  S.actionDone = false;
  S.moveDone = false;
  S.skillsUsedThisTurn = [];
  S.actionUsedSkillReplace = false;
  S.twinMovePending = false;
  S.twinMovedSub = null;
  S.twinElderSkipped = false;
  S.twinYoungerSkipped = false;
  S.lastActionType = null;
  S.lastActionPieceType = null;
  // 새 턴 시작 — 데미지 도장/HP 빨간 마킹 초기화 (preCurseHps 로 저주 보라 도장 표시)
  if (typeof snapshotTurnStartHps === 'function') snapshotTurnStartHps(data.preCurseHps);

  refreshGameView();
  showActionBar(true);
  updateSPBar();
  addLog(`${data.turnNumber}턴 : ${myN()} 차례`, 'system');
  setTurnBackground(true);
  updateTurnBanner();
  playTurnBell();
});

// ── 상대 턴 ──
socket.on('opp_turn', (data) => {
  // 새 턴 진입 시 이전 턴 동안 유지된 turn-bright 카드 일괄 해제 (1v1)
  if (typeof clearAllTurnBright === 'function') clearAllTurnBright();
  // ★ 방어적 — 이전 턴에 flush 안 된 패시브 alert 버퍼 폐기 (stale 누설 방지).
  if (Array.isArray(S._pendingDefensiveAlerts)) S._pendingDefensiveAlerts.length = 0;
  // 내가 쌍둥이 이동 중이었는데 턴이 넘어가는 케이스 (타이머 만료/강제 종료) — UI 정리 필수
  if (S.twinPhaseActive && typeof exitTwinMovePhase === 'function') {
    exitTwinMovePhase(/*emitToast=*/false);
  }
  S.isMyTurn = false;
  if (typeof applyTurnUiState === 'function') applyTurnUiState();
  S.turnNumber = data.turnNumber;
  S.attackLog = S.attackLog.filter(a => a.turn >= S.turnNumber - 1); // C-5: prune old entries
  S.oppPieces = data.oppPieces || S.oppPieces;
  S.sp = data.sp || S.sp;
  S.instantSp = data.instantSp || S.instantSp;
  S.boardBounds = data.boardBounds || S.boardBounds;
  S.boardObjects = data.boardObjects || S.boardObjects;
  S.remains = data.remains || S.remains;
  S.action = null;
  S.selectedPiece = null;
  // 새 턴 시작 — 데미지 도장/HP 빨간 마킹 초기화 (preCurseHps 로 저주 보라 도장 표시)
  if (typeof snapshotTurnStartHps === 'function') snapshotTurnStartHps(data.preCurseHps);

  refreshGameView();
  showActionBar(false);
  updateSPBar();
  addLog(`${data.turnNumber}턴 : ${oppN()} 차례`, 'system');
  setTurnBackground(false);
  updateTurnBanner();
});

// ── 이동 결과 ──
socket.on('move_ok', ({ pieceIdx, prev, col, row, yourPieces, boardObjects, remains, twinMovePending, twinMovedSub }) => {
  const pc = yourPieces[pieceIdx];
  animateMove(pc.icon, prev.col, prev.row, col, row, pc.type, pc.subUnit, `${S.playerIdx}:${pieceIdx}`);
  playSfx('move');
  S.myPieces = yourPieces;
  if (boardObjects) S.boardObjects = boardObjects;
  if (remains) S.remains = remains;

  // 쌍둥이 이동 페이즈 — 토스트/로그는 페이즈 종료 시점에 단 한 번만 (개별 이동마다 X)
  if (S.twinPhaseActive) {
    if (twinMovePending) {
      // 첫 이동 끝남 — 두 번째 이동 대기
      S.twinFirstSubMoved = twinMovedSub;
      S.selectedPiece = null;
      S.moveDone = true;
      S.actionDone = true;
      S.lastActionType = 'move';
      S.lastActionPieceType = pc.type;
      renderGameBoard();
      renderMyPieces();
      // 두 번째 이동 안내 — 합류 상태면 picker, 아니면 floating 버튼
      refreshTwinPhaseButtons();
      setActionHint('두 번째 쌍둥이를 선택하거나 턴을 종료하세요.');
      showActionBar(true);
    } else {
      // 두 번째 이동 끝남 — 페이즈 종료 + 단일 토스트/로그
      S.moveDone = true;
      S.actionDone = true;
      S.lastActionType = 'move';
      S.lastActionPieceType = pc.type;
      exitTwinMovePhase(/*emitToast=*/true);
      showActionBar(true);
    }
    return;
  }

  // 일반 이동 — 기존 로직
  addLog(`${pc.name} 이동`, 'move');
  showSkillToast(`${pc.name} 이동`);
  S.action = null;
  S.selectedPiece = null;
  S.twinMovePending = false;
  S.twinMovedSub = null;
  S.moveDone = true;
  S.actionDone = true;
  S.lastActionType = 'move';
  S.lastActionPieceType = pc.type;
  setActionButtonMode(null);
  renderGameBoard();
  renderMyPieces();
  showActionBar(true);
});

// 팀모드: 팀원이 이동했을 때 실시간 애니메이션
socket.on('team_ally_moved', ({ moverName, pieceType, pieceIcon, pieceName, subUnit, prevCol, prevRow, col, row }) => {
  // 팀원 이동 SFX — 1v1의 자기 이동(playSfx('move'))과 동일하게 발화
  try { playSfx('move'); } catch (e) {}
  // 팀원 이동 플로팅 애니 (방향 반전 + 잔상 + 화이트 아웃라인)
  // 팀원 pieceKey: 'ally:type[:subUnit]' — 방향 상태 추적용
  const allyKey = 'ally:' + pieceType + (subUnit ? ':' + subUnit : '');
  animateMove(pieceIcon, prevCol, prevRow, col, row, pieceType, subUnit, allyKey);
  if (!Array.isArray(S.teammatePieces)) return;
  // S.teammatePieces 좌표 즉시 갱신 (broadcastTeamGameState 도착 직전 시각효과용)
  let target = null;
  if (subUnit) {
    target = S.teammatePieces.find(p => p.alive && p.type === pieceType && p.subUnit === subUnit && p.col === prevCol && p.row === prevRow);
  }
  if (!target) {
    target = S.teammatePieces.find(p => p.alive && p.type === pieceType && p.col === prevCol && p.row === prevRow);
  }
  if (target) { target.col = col; target.row = row; }
  if (typeof renderGameBoard === 'function') renderGameBoard();
  // ★ 팀원 프로필 카드 좌표도 즉시 갱신 — renderGameBoard 만으로는 프로필 카드 미갱신.
  //   _augmentPl 이 S.teammatePieces 를 쓰므로, renderTeamProfiles 호출만 하면 됨.
  //   ★ FIX: 1v1용 renderMyPieces 가 아니라 renderTeamProfiles 를 호출해야 팀원 프로필이 갱신됨(주석대로).
  if (typeof renderTeamProfiles === 'function') renderTeamProfiles();
  // 새 위치 셀 강조 + 이전 위치는 잔상
  const boardEl = document.getElementById('game-board');
  if (boardEl) {
    const newCell = boardEl.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
    const oldCell = boardEl.querySelector(`.cell[data-col="${prevCol}"][data-row="${prevRow}"]`);
    if (newCell) {
      newCell.classList.add('teammate-move-flash');
      setTimeout(() => newCell.classList.remove('teammate-move-flash'), 800);
    }
    if (oldCell) {
      oldCell.classList.add('teammate-move-trail');
      setTimeout(() => oldCell.classList.remove('teammate-move-trail'), 600);
    }
  }
  // 팀원 이동 — "[name] 이동" (인벤토리 B2 row)
  const moveMsg = `${moverName} 이동`;
  addLog(moveMsg, 'move');
  showSkillToast(moveMsg, false, undefined, 'move');
});

socket.on('opp_moved', ({ msg, prevCol, prevRow, col, row }) => {
  // 적 이동 SFX — 자기 이동과 동일 톤
  try { playSfx('move'); } catch (e) {}
  // 표식된 적이면 실시간 위치 업데이트 + 이동 애니메이션 (팝업/로그 없이 시각적 강조만)
  if (S.oppPieces && prevCol !== undefined && prevRow !== undefined && col !== undefined && row !== undefined) {
    const markedMover = S.oppPieces.find(p => p.marked && p.alive && p.col === prevCol && p.row === prevRow);
    if (markedMover) {
      // ★ 플로팅 애니메이션 — 위치 업데이트·renderGameBoard 보다 먼저 호출해야
      //   fromCell (구 위치) 에 .p-gif 가 아직 존재하는 상태에서 숨김 처리가 가능.
      const _oppMoveKey = `opp:${markedMover.type}${markedMover.subUnit ? ':' + markedMover.subUnit : ''}`;
      animateMove(markedMover.icon, prevCol, prevRow, col, row, markedMover.type, markedMover.subUnit, _oppMoveKey);

      markedMover.col = col;
      markedMover.row = row;
      // ★ 사용자 요청: 표식 적 이동 시 추리 토큰도 자동 위치 동기화.
      //   pieceKey: 1v1 = `${type}:${subUnit}`, 팀모드 = `${type}:${subUnit}@${ownerIdx}`.
      const pieceKey = S.isTeamMode && typeof markedMover.ownerIdx === 'number'
        ? `${markedMover.type}:${markedMover.subUnit || ''}@${markedMover.ownerIdx}`
        : `${markedMover.type}:${markedMover.subUnit || ''}`;
      let tokenUpdated = false;
      for (const t of (S.deductionTokens || [])) {
        if (t.pieceKey === pieceKey) {
          t.col = col;
          t.row = row;
          tokenUpdated = true;
        }
      }
      renderGameBoard();
      renderOppPieces();
      if (tokenUpdated && typeof refreshDeductionTokens === 'function') refreshDeductionTokens();
      const boardEl = document.getElementById('game-board');
      const cellEl = boardEl && boardEl.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
      if (cellEl) {
        cellEl.classList.add('marked-move-flash');
        setTimeout(() => cellEl.classList.remove('marked-move-flash'), 700);
      }
      // 팝업/로그 제거 — 시각 효과(셀 플래시)만 유지
      return;
    }
  }
  addLog(`상대가 이동했습니다.`, 'move');
  showSkillToast(`상대가 이동했습니다.`, true);
});

// ── 공격 결과 ──
socket.on('attack_result', ({ pieceIdx, cellResults, anyHit, attackerImpactedAnything, oppPieces, yourPieces, friendlyFireHits, bodyguardHits }) => {
  // ★ 공격 애니 시작 — sp_update 큐잉 활성화
  _attackAnimDeferred = true;
  _pendingSpUpdate = null;
  // ★ FIX (팀전 공격 타이밍 — 1v1 통일): 임팩트(피격 판정) 예정 시각 기록 → 곧 도착할
  //   team_game_update 가 이 시각까지 보드/HP 시각 갱신을 지연. 이전엔 T+0 에 HP가 임팩트보다
  //   먼저 떨어졌음. (실제 임팩트는 GIF 프레임 기준이나 동기 시점엔 미정 → ATTACK_IMPACT_DELAY 추정.)
  if (S.isTeamMode) S._teamRenderGateUntil = Date.now() + ATTACK_IMPACT_DELAY;
  // ★ FIX (마지막 유닛 사망 시 게임 즉시 종료): 사망 셋업(_pendingDeathCells)은 공격 GIF ~4프레임
  //   시점까지 지연되므로, 직후 도착하는 game_over 가 그 전에 결과화면을 노출했음. 스킬과 동일하게
  //   여기서 동기 사망 가드(_skillDeathGuardUntil)를 즉시 켜서 사망 GIF/유해 연출이 끝날 때까지 대기시킴.
  _markSkillDeathIncoming(cellResults);
  // 쥐 격파 감지: 공격 범위에 있던 상대 쥐 찾기 (서버가 자동 제거)
  const destroyedRats = [];
  if (S.boardObjects) {
    for (const c of cellResults) {
      const rat = S.boardObjects.find(o => o.type === 'rat' && o.owner !== S.playerIdx && o.col === c.col && o.row === c.row);
      if (rat) destroyedRats.push({ col: rat.col, row: rat.row });
    }
    for (const dr of destroyedRats) {
      S.boardObjects = S.boardObjects.filter(o => !(o.type === 'rat' && o.owner !== S.playerIdx && o.col === dr.col && o.row === dr.row));
    }
  }

  // 그림자 상태의 적은 공격자 입장에서도 빈 셀 — hit 정보 자체를 숨김 (피격 셀 흔들림 X)
  const isShadowAtOpp = (col, row) => {
    const p = (S.oppPieces || []).find(pc => pc.alive && pc.col === col && pc.row === row);
    return !!(p && (p.statusEffects || []).some(e => e.type === 'shadow'));
  };
  cellResults = (cellResults || []).map(c => {
    if (c.hit && isShadowAtOpp(c.col, c.row)) {
      // 빈 셀처럼 — hit=false 로 변경 (피격 표식·셀 흔들림·로그 전부 차단)
      return { ...c, hit: false, damage: 0, destroyed: false };
    }
    return c;
  });

  // 공격 범위 셀 + 피격 셀 추출
  const atkCells = cellResults.map(c => ({ col: c.col, row: c.row }));
  const hitCells = cellResults.filter(c => c.hit).map(c => ({ col: c.col, row: c.row }));
  // ★ 즉시 오렌지 번쩍임 제거 — animateAttackCellEffect 가 ~4번째 프레임 시점에 대체
  playSfx('attack');

  // 아군 HP 스냅샷 — 상태 업데이트 전 캡처 (학살 영웅 friendly fire 감지용)
  const oldMyHps = S.myPieces.map(p => p.hp);

  // 행동 소비 즉시 처리 — GIF 재생 중 중복 입력 방지
  const _preUpdatePc = S.myPieces[pieceIdx];
  S.action = null;
  S.selectedPiece = null;
  S.targetSelectMode = false;
  S.actionDone = true;
  S.lastActionType = 'attack';
  S.lastActionPieceType = _preUpdatePc ? _preUpdatePc.type : null;
  setActionButtonMode(null);
  showActionBar(true);

  // ★ 공격자 공격 GIF — 상태 업데이트 전 현재 위치/타입으로 오버레이 재생.
  //   각 Promise 는 GIF 1루프 재생 완료 시 resolve.
  const _gifPromises = [];
  (function () {
    const _pc = S.myPieces[pieceIdx];
    if (!_pc || !_pc.alive) return;
    const _otherTwin = (_pc.subUnit === 'elder' || _pc.subUnit === 'younger')
      ? S.myPieces.find(p => p !== _pc && (p.subUnit === 'elder' || p.subUnit === 'younger')
          && p.alive && p.col === _pc.col && p.row === _pc.row)
      : null;
    _gifPromises.push(animateAttackGif(_pc.col, _pc.row, _pc.type, _pc.subUnit, !!_otherTwin, pieceIdx));
    if ((_pc.subUnit === 'elder' || _pc.subUnit === 'younger') && !_otherTwin) {
      const _partnerIdx = S.myPieces.findIndex((p, i) =>
        i !== pieceIdx && (p.subUnit === 'elder' || p.subUnit === 'younger') && p.alive
      );
      const _partner = _partnerIdx >= 0 ? S.myPieces[_partnerIdx] : null;
      if (_partner && (_partner.col !== _pc.col || _partner.row !== _pc.row)) {
        _gifPromises.push(animateAttackGif(_partner.col, _partner.row, _partner.type, _partner.subUnit, false, _partnerIdx));
      }
    }
    // ★ 쥐장수 본인 쥐 공격 모션은 서버 rat_attack_anim 이벤트로 처리 (공격자 포함 모든 시점 동일 1회).
  })();

  // ══ 공격 GIF ~4번째 프레임 시점에 공격 범위 이펙트 + 피격 판정 시작 ══════════
  // GIF 프레임 타이밍 파싱 → 4번째 프레임 누적 시간에 attackCellEffect + 데미지 전체 실행.
  // GIF 없는 캐릭터 → 200ms 폴백. ★ 안전 장치: 최대 3초.
  // (공격 GIF 자체는 _gifPromises 를 통해 자체 cleanup — 여기선 타이밍만 참조)
  const _atkPc2 = S.myPieces[pieceIdx];
  const _atkTwin2 = (_atkPc2 && (_atkPc2.subUnit === 'elder' || _atkPc2.subUnit === 'younger'))
    ? S.myPieces.find(p => p !== _atkPc2 && (p.subUnit === 'elder' || p.subUnit === 'younger')
        && p.alive && p.col === _atkPc2.col && p.row === _atkPc2.row)
    : null;
  const _atkGifUrl = _atkPc2 ? _getAttackGifUrl(_atkPc2.type, _atkPc2.subUnit, !!_atkTwin2) : null;
  const _frameP = _atkGifUrl
    ? _fetchGifFrameTimings(_atkGifUrl)
    : Promise.resolve({ totalMs: 0, frameDelays: [] });
  _frameP.then(timings => {
    const _IMPACT_FRAME = 3; // 0-indexed → 4번째 프레임
    let _impactDelay;
    if (timings.frameDelays.length > _IMPACT_FRAME) {
      _impactDelay = timings.frameDelays[_IMPACT_FRAME];
    } else if (timings.frameDelays.length > 0) {
      _impactDelay = timings.frameDelays[timings.frameDelays.length - 1];
    } else {
      _impactDelay = ATTACK_IMPACT_DELAY; // GIF 없거나 파싱 실패 시 폴백 — 다른 시점과 동기화
    }
    _impactDelay = Math.min(_impactDelay, 3000);
    // ★ 유해 피격 애니를 일반 유닛 피격과 같은 임팩트 순간에 발동시키기 위한 기준 시각.
    S._impactAtTs = Date.now() + _impactDelay;
    setTimeout(() => {
      // ── ★ 사망 감지 — 상태 업데이트 전에 현재 DOM 에서 방향 캡처 ──────────
      const _destroyedCells = cellResults.filter(c => c.hit && c.destroyed);
      const _deathInfosRaw = _detectDeaths(_destroyedCells, false); // 공격자 시점 → 상대 말(opp-marked)
      // ★ 드래곤/유황솥 포함 — 모든 타입의 사망 애니를 공격자에게도 재생.
      //   유해 생성 여부는 _addClientSideRemains 내부에서 별도 처리 (dragon/sulfurCauldron/rat → skip).
      const _deathInfos = _deathInfosRaw;

      // ── ★ 아군 피격/사망 감지 (학살영웅 배반자) — 상태 업데이트 전 DOM 방향 캡처 ──
      const _ffHitCells = [];
      const _ffDeadCells = [];
      if (friendlyFireHits && friendlyFireHits.length > 0) {
        // 서버가 보내준 아군 피격 상세 데이터 사용
        for (const ff of friendlyFireHits) {
          _ffHitCells.push({ col: ff.col, row: ff.row });
          if (ff.destroyed) {
            _ffDeadCells.push({ col: ff.col, row: ff.row, type: ff.type });
          }
        }
      } else if (yourPieces) {
        // 폴백: HP 스냅샷 방식 (구버전 서버 호환)
        for (let i = 0; i < S.myPieces.length && i < yourPieces.length; i++) {
          const oldP = S.myPieces[i];
          const newP = yourPieces[i];
          if (!oldP || !oldP.alive || oldP.hp <= 0) continue;
          if (newP.hp < oldP.hp) {
            _ffHitCells.push({ col: oldP.col, row: oldP.row });
            if (newP.hp <= 0) {
              _ffDeadCells.push({ col: oldP.col, row: oldP.row, type: oldP.type });
            }
          }
        }
      }
      const _ffDeathInfosRaw = _detectDeaths(_ffDeadCells, true); // isDefending=true → 내 말
      const _ffDeathInfos = _ffDeathInfosRaw;

      // ── 게임 상태 업데이트 ─────────────────────────────────────────────
      if (oppPieces) { S.oppPieces = oppPieces; }
      if (yourPieces) { S.myPieces = yourPieces; }
      pruneDeductionTokens();

      // ── 공격 로그 (💥/· 셀 마크) ───────────────────────────────────────
      // ★ bodyguardRedirect 히트는 제외 — 충성으로 대신 맞은 호위무사 좌표를 공격자에게 노출하면 안 됨.
      for (const c of cellResults) {
        if (c.bodyguardRedirect) continue;
        S.attackLog.push({ col: c.col, row: c.row, hit: c.hit, turn: S.turnNumber });
      }

      // ── 데미지 도장 추적 ────────────────────────────────────────────────
      // ★ FIX (충성 도장 2배 표기): 충성(bodyguardRedirect) 도장은 아래 bodyguardHits 루프가 전담.
      //   여기서 또 찍으면 같은 흡수가 cellResults+bodyguardHits 양쪽에서 도장돼 충성 1→2 로 표기됐음.
      //   (bodyguardHits 는 모든 흡수 히트를 포함하므로 여기선 본체 데미지만 처리.)
      for (const c of cellResults) {
        if (!c.hit) continue;
        const dmg = (typeof c.damage === 'number') ? c.damage : 0;
        if (dmg <= 0 || c.defPieceIdx === undefined) continue;
        if (c.bodyguardRedirect || c.redirectedToBodyguard) continue;   // 충성 흡수/리다이렉트 원본은 본체도장 X
        const key = (S.isTeamMode && c.defOwnerIdx !== undefined)
          ? `${c.defOwnerIdx}:${c.defPieceIdx}`
          : `opp:${c.defPieceIdx}`;
        addBodyDamage(key, dmg);
      }
      // ★ 호위무사 충성 도장 — 모든 흡수(bodyguardRedirect) 히트는 여기서 전담 처리(유일 출처).
      //   (cellResults 루프는 충성을 안 찍음 → 중복 없음.)
      if (bodyguardHits && bodyguardHits.length > 0) {
        for (const bg of bodyguardHits) {
          const bgDmg = (typeof bg.damage === 'number') ? bg.damage : 0;
          if (bgDmg <= 0 || bg.defPieceIdx === undefined) continue;
          const bgKey = (S.isTeamMode && bg.defOwnerIdx !== undefined)
            ? `${bg.defOwnerIdx}:${bg.defPieceIdx}`
            : `opp:${bg.defPieceIdx}`;
          addLoyaltyDamage(bgKey, bgDmg);
        }
      }

      // ★ 아군 피격 (학살영웅 배반자) 데미지 도장 — friendlyFireHits 에 대해 addBodyDamage 호출
      if (friendlyFireHits && friendlyFireHits.length > 0) {
        for (const ff of friendlyFireHits) {
          const ffDmg = (typeof ff.damage === 'number') ? ff.damage : 0;
          if (ffDmg <= 0) continue;
          // defPieceIdx 우선 사용, 없으면 col/row 로 lookup
          let ffPieceIdx = (typeof ff.defPieceIdx === 'number') ? ff.defPieceIdx : -1;
          if (ffPieceIdx < 0) {
            ffPieceIdx = (S.myPieces || []).findIndex(p => p.col === ff.col && p.row === ff.row);
          }
          if (ffPieceIdx < 0) continue;
          const ffKey = S.isTeamMode ? `${S.playerIdx}:${ffPieceIdx}` : `my:${ffPieceIdx}`;
          addBodyDamage(ffKey, ffDmg);
        }
      }

      // ── 로그·토스트 + SFX (hit/kill 동시) ──────────────────────────────
      const _attackerHadAnyImpact = !!attackerImpactedAnything || destroyedRats.length > 0;
      if (!anyHit) {
        if (!_attackerHadAnyImpact) { addLog(`빗나감`, 'miss'); showSkillToast(`빗나감`); }
      } else {
        const meaningfulHits = cellResults.filter(c => c.hit && !c.redirectedToBodyguard && !(c.damage === 0 && !c.destroyed));
        const messageHits = meaningfulHits.filter(c => !c.bodyguardRedirect || c.destroyed);
        const killed = messageHits.filter(h => h.destroyed);
        const hitOnly = messageHits.filter(h => !h.destroyed);
        if (hitOnly.length > 0) { playSfx('hit'); addLog(`${hitOnly.map(h => coord(h.col, h.row)).join(', ')} 명중`, 'hit'); }
        if (killed.length > 0) {
          const labels = killed.map(h => `${pieceIconHtml(h.revealedIcon, {size:'1em'})}${h.revealedName||'유닛'}`).join(', ');
          playSfx('kill');
          showSkillToast(`${labels} 격파!`);
          addLog(`${killed.map(h => coord(h.col, h.row)).join(', ')} ${labels} 격파`, 'hit');
        }
      }

      // ── 방어 패시브 flush ───────────────────────────────────────────────
      const _attackKilled = (cellResults || []).some(c => c.hit && c.destroyed);
      if (typeof flushDefensiveAlerts === 'function') flushDefensiveAlerts({ skipReduction: _attackKilled });

      // ── 추리 토큰 자동 배치 ─────────────────────────────────────────────
      // ★ bodyguardRedirect 도 제외 — 충성으로 대신 맞은 호위무사에 추리 토큰 자동 배치 금지.
      // ★ FIX: 충성 흡수된 원 타깃(redirectedToBodyguard)도 1명으로 카운트 → 2명 이상 피격 시 토큰 금지.
      const _distinctHitKeys = new Set((cellResults || []).filter(c => c.hit && c.defPieceIdx != null && !c.bodyguardRedirect).map(c => `${c.defOwnerIdx ?? ''}:${c.defPieceIdx}`));
      const _meaningfulHits = (cellResults || []).filter(c => c.hit && !c.redirectedToBodyguard && !c.bodyguardRedirect && c.defPieceIdx !== undefined);
      if (_distinctHitKeys.size === 1 && _meaningfulHits.length === 1 && !_meaningfulHits[0].destroyed) {
        const c = _meaningfulHits[0];
        let piece = null, pieceKey = null;
        if (S.isTeamMode && c.defOwnerIdx !== undefined) {
          const ownerPlayer = (S.teamGamePlayers || []).find(p => p.idx === c.defOwnerIdx);
          if (ownerPlayer && ownerPlayer.pieces && ownerPlayer.pieces[c.defPieceIdx]) {
            piece = ownerPlayer.pieces[c.defPieceIdx];
            pieceKey = `${piece.type}:${piece.subUnit || ''}@${c.defOwnerIdx}`;
          }
        } else {
          piece = S.oppPieces?.[c.defPieceIdx];
          if (piece) pieceKey = `${piece.type}:${piece.subUnit || ''}`;
        }
        if (piece && pieceKey) {
          try {
            S.deductionTokens = (S.deductionTokens || []).filter(t => t.pieceKey !== pieceKey && !(t.col === c.col && t.row === c.row));
            S.deductionTokens.push({ pieceKey, icon: piece.icon, name: piece.name, col: c.col, row: c.row });
          } catch (e) {}
        }
      }

      // ── 피격 인덱스 수집 ────────────────────────────────────────────────
      const oppHitIndices = [];
      const oppProtectedIndices = [];
      for (const c of cellResults) {
        if (!c.hit) continue;
        // ★ 충성 리다이렉트 먼저 체크 — 보호받은 왕족(damage=0)을 protected 도장에서 제외
        if (c.redirectedToBodyguard) continue;
        const isProtected = (c.damage === 0 && !c.destroyed);
        if (isProtected) {
          if (c.defPieceIdx !== undefined) {
            const _p = S.oppPieces?.[c.defPieceIdx];
            const _shadow = _p && (_p.statusEffects || []).some(e => e.type === 'shadow');
            if (!_shadow && !oppProtectedIndices.includes(c.defPieceIdx)) oppProtectedIndices.push(c.defPieceIdx);
          }
          continue;
        }
        if (c.defPieceIdx !== undefined && !oppHitIndices.includes(c.defPieceIdx)) oppHitIndices.push(c.defPieceIdx);
      }
      // ★ 호위무사 프로필 피격 애니 — bodyguardHits 의 defPieceIdx 를 oppHitIndices 에 추가
      if (bodyguardHits && bodyguardHits.length > 0) {
        for (const bg of bodyguardHits) {
          if (bg.defPieceIdx !== undefined && !oppHitIndices.includes(bg.defPieceIdx)) {
            oppHitIndices.push(bg.defPieceIdx);
          }
        }
      }
      const myFriendlyFireIndices = [];
      for (let i = 0; i < S.myPieces.length; i++) {
        if (S.myPieces[i].hp < oldMyHps[i]) myFriendlyFireIndices.push(i);
      }

      // ── 렌더 + 피격 애니 + 사망 애니 분기 ─────────────────────────────────
      // 사망 유닛이 있으면: renderGameBoard 를 먼저 하되 사망 GIF 가 끝날 때까지 dead piece 를 DOM 에 유지.
      // 사망 유닛이 없으면: 기존대로 즉시 렌더.
      const _doPostRender = () => {
        // ★ 공격 범위 셀 이펙트 발동 — renderGameBoard() 이후에 호출해야 함.
        animateAttackCellEffect(atkCells);

        // ── 보드 피격 애니메이션 (셀 빨간 플래시·바라보는 방향 흔들림·아이콘 피격 GIF) ────
        if (hitCells.length > 0) animateAttack([], hitCells);
        // ── 아군 보드 피격 애니 (학살영웅 배반자) — isDefending=true → 내 말 마커 대상 ──
        if (_ffHitCells.length > 0) animateAttack([], _ffHitCells, true);

        // ── 프로필 카드 피격 애니메이션 ──────────────────────────────────────
        if (!S.isTeamMode) {
          applyProfileHitAnim('#opp-pieces-info .opp-piece-card', oppHitIndices);
          applyProfileHitAnim('#my-pieces-info .my-piece-card', myFriendlyFireIndices);
          applyProtectedAnimByIndex('#opp-pieces-info .opp-piece-card', oppProtectedIndices);
          for (const idx of oppProtectedIndices) addProtectedHit(`opp:${idx}`);
        } else {
          requestAnimationFrame(() => {
            for (const c of cellResults) {
              if (!c.hit || c.defPieceIdx == null || c.defOwnerIdx == null) continue;
              const isProtected = (c.damage === 0 && !c.destroyed);
              if (c.redirectedToBodyguard) continue;
              const card = document.querySelector(`.team-profile-block[data-player-idx="${c.defOwnerIdx}"] [data-piece-idx="${c.defPieceIdx}"]`);
              if (!card) continue;
              if (isProtected) {
                const ownerPlayer = (S.teamGamePlayers || []).find(p => p.idx === c.defOwnerIdx);
                const _tp = ownerPlayer?.pieces?.[c.defPieceIdx];
                const _ts = _tp && (_tp.statusEffects || []).some(e => e.type === 'shadow');
                if (!_ts) { applyProtectedAnim(card); addProtectedHit(`${c.defOwnerIdx}:${c.defPieceIdx}`); }
              } else {
                applyHitFlashWithBrighten(card);
              }
            }
            // ── 팀전 아군 피격 프로필 카드 애니 (학살영웅 배반자) ──
            for (const idx of myFriendlyFireIndices) {
              const card = document.querySelector(`.team-profile-block[data-player-idx="${S.playerIdx}"] [data-piece-idx="${idx}"]`);
              if (card) applyHitFlashWithBrighten(card);
            }
          });
        }
      };

      // ── 적 사망 + 아군 사망 통합 ──────────────────────────────────────────
      const _allDeathInfos = _deathInfos.concat(_ffDeathInfos);
      const _allDeathInfosRaw = _deathInfosRaw.concat(_ffDeathInfosRaw);

      if (_allDeathInfos.length > 0) {
        // ★ 사망 유닛 존재 — 먼저 렌더 (피격 GIF 대상 DOM 필요) 후 사망 GIF → 재렌더
        // ★ _pendingDeathCells: 사망 GIF 재생 전까지 dead piece 의 idle GIF 를 DOM 에 유지 (빈 프레임 방지)
        S._pendingDeathCells = new Set(_allDeathInfos.map(d => `${d.col},${d.row}`));
        renderGameBoard();
        renderMyPieces();
        renderOppPieces();
        _doPostRender();

        // 피격 GIF 정착 후 사망 GIF 재생 (400ms — 피격 흔들림 0.35s + 여유)
        // ★ 유해는 _allDeathInfosRaw (noRemains 타입 포함) 기준으로 선반영.
        scheduleDeathGif(_allDeathInfos, _allDeathInfosRaw, () => {
          renderGameBoard();
          renderMyPieces();
          renderOppPieces();
          _flushPendingSpUpdate(); // ★ 애니 완료 후 큐잉된 SP 적용
        });
      } else if (_allDeathInfosRaw.length > 0) {
        // ★ 사망은 있지만 모두 noRemains 타입 (드래곤/유황솥) — 사망 GIF 생략, 유해만 선반영 후 렌더
        _addClientSideRemains(_allDeathInfosRaw);
        renderGameBoard();
        renderMyPieces();
        renderOppPieces();
        _doPostRender();
        _flushPendingSpUpdate(); // ★ 애니 완료 후 큐잉된 SP 적용
      } else {
        // 사망 없음 — 기존 로직대로 즉시 렌더
        renderGameBoard();
        renderMyPieces();
        renderOppPieces();
        _doPostRender();
        _flushPendingSpUpdate(); // ★ 애니 완료 후 큐잉된 SP 적용
      }

      // ── 쥐 격파 피드백 ──────────────────────────────────────────────────
      if (destroyedRats.length > 0) {
        const msg = ratDestroyMsg(destroyedRats, false);
        showSkillToast(msg);
        addLog(msg, 'hit');
        animateRatDestruction(destroyedRats, false);
      }
    }, _impactDelay);
  });
});

// ── 피격 ──
let _beingAttackedSeq = 0;
socket.on('being_attacked', ({ atkCells, hitPieces, yourPieces, attackerImpactedAnything, friendlyFireHits }) => {
  // ★ 피격 애니 시작 — sp_update 큐잉 활성화
  _attackAnimDeferred = true;
  _pendingSpUpdate = null;
  // ★ FIX (마지막 유닛 사망 즉시 종료 방지): 사망 셋업 전 도착하는 game_over 가 결과화면을 조기 노출하지 않도록
  //   동기 사망 가드를 즉시 켬 (내 말이 마지막에 죽는 경우 — 사망 GIF/유해 연출 보장).
  _markSkillDeathIncoming(hitPieces);
  // 적 공격 휘두름 SFX — 1v1 attack_result 의 'attack' 과 동일 톤 (피격자 측에도 들림)
  try { playSfx('attack'); } catch (e) {}
  // ★ 쥐 공격 모션은 서버의 rat_attack_anim 이벤트(쥐장수 공격 시에만)로 처리 — 여기서 자동 추정 X.
  //   (이전엔 일반 유닛 공격 범위가 적 쥐 셀을 우연히 덮으면 그 쥐가 잘못 공격 모션을 재생했음.)
  if (S._bodyguardIntercepted) {
    S._bodyguardIntercepted = false;
  }

  // 그림자 상태 유닛은 빈 셀처럼 취급 — hitPieces 에서 완전 제거 (피격 셀 흔들림·도장·로그 모두 안 나옴)
  const isShadowAt = (col, row) => {
    const p = (S.myPieces || []).find(pc => pc.alive && pc.col === col && pc.row === row);
    return !!(p && (p.statusEffects || []).some(e => e.type === 'shadow'));
  };
  hitPieces = (hitPieces || []).filter(h => !isShadowAt(h.col, h.row));

  // 쥐 격파 감지: 상대 공격 범위에 있던 내 쥐
  const myDestroyedRats = [];
  if (S.boardObjects && atkCells) {
    for (const c of atkCells) {
      const rat = S.boardObjects.find(o => o.type === 'rat' && o.owner === S.playerIdx && o.col === c.col && o.row === c.row);
      if (rat) myDestroyedRats.push({ col: rat.col, row: rat.row });
    }
    for (const dr of myDestroyedRats) {
      S.boardObjects = S.boardObjects.filter(o => !(o.type === 'rat' && o.owner === S.playerIdx && o.col === dr.col && o.row === dr.row));
    }
  }

  // ★ 피격 판정 타이밍 동기화 — 공격자의 GIF 4번째 프레임(~520ms)과 일치시키기 위해
  //   피격자도 ATTACK_IMPACT_DELAY 후에 피격 표시·상태 업데이트·로그/토스트를 실행.
  //   'attack' SFX (공격 휘두름) 는 위에서 즉시 재생 → 임팩트는 딜레이 후.
  const hitCells = hitPieces.map(h => ({ col: h.col, row: h.row }));
  // ★ #5 충성(호위무사 가로채기)으로 보호받은 유닛은 피격 애니(흔들림/플래시/아이콘히트) 출력 안 함.
  //   서버가 redirectedToBodyguard=true 로 표시(데미지 0, 도장도 제외). attack_result/팀원 경로는
  //   이미 제외하나 1v1 being_attacked 만 누락이었음. (전용 '보호됨' 애니는 추후 추가 예정.)
  const _animCells = hitPieces.filter(h => !h.redirectedToBodyguard).map(h => ({ col: h.col, row: h.row }));
  const _capturedTurn = S.turnNumber;
  const _mySeq = ++_beingAttackedSeq;
  // ★ 유해 피격 애니 동기화 기준 — 일반 유닛 피격과 같은 임팩트 순간.
  S._impactAtTs = Date.now() + ATTACK_IMPACT_DELAY;
  // ★ FIX (팀전 공격 타이밍 — 1v1 통일): 피격자 측도 team_game_update 의 보드/HP 시각 갱신을
  //   임팩트 시점까지 지연 → HP가 피격 연출보다 먼저 떨어지지 않도록.
  if (S.isTeamMode) S._teamRenderGateUntil = Date.now() + ATTACK_IMPACT_DELAY;
  setTimeout(() => {
    if (S.turnNumber !== _capturedTurn) return; // turn changed, skip stale update
    if (_beingAttackedSeq !== _mySeq) return; // newer being_attacked arrived, skip

    // ── ★ 사망 감지 — 상태 업데이트 전에 현재 DOM 에서 방향 캡처 ──────────
    const _destroyedHits = hitPieces.filter(h => h.destroyed);
    const _deathInfos = _detectDeaths(_destroyedHits, true); // 피격자 시점 → 내 말(non-opp-marked)

    animateAttack([], _animCells, true); // isDefending=true — 내 말이 피격됨 (★ #5 보호된 유닛 제외)
    // attackLog 에는 명중 셀만 기록
    for (const hc of hitCells) {
      S.attackLog.push({ col: hc.col, row: hc.row, hit: true, turn: S.turnNumber });
    }

    S.myPieces = yourPieces;
    const _selfStampKey = (idx) => S.isTeamMode ? `${S.playerIdx}:${idx}` : `my:${idx}`;
    for (const h of hitPieces) {
      const dmg = (typeof h.damage === 'number') ? h.damage : 0;
      if (dmg < 0) continue;
      if (h.bodyguardRedirect) {
        let bgIdx = (typeof h.defPieceIdx === 'number') ? h.defPieceIdx : -1;
        if (bgIdx < 0) {
          bgIdx = (S.myPieces || []).findIndex(p => p.alive && p.col === h.col && p.row === h.row && p.type === 'bodyguard');
        }
        if (bgIdx < 0) continue;
        if (dmg > 0) addLoyaltyDamage(_selfStampKey(bgIdx), dmg);
      } else if (!h.redirectedToBodyguard) {
        let pieceIdx = (typeof h.defPieceIdx === 'number') ? h.defPieceIdx : -1;
        if (pieceIdx < 0) {
          pieceIdx = (S.myPieces || []).findIndex(p => p.alive && p.col === h.col && p.row === h.row);
        }
        if (pieceIdx < 0) continue;
        // ★ 0데미지(보호됨)도 피격 도장 — addProtectedHit (프로필 파랑 도장 + 보드 도장 자동)
        if (dmg > 0) addBodyDamage(_selfStampKey(pieceIdx), dmg);
        else if (!h.destroyed) addProtectedHit(_selfStampKey(pieceIdx));
      }
    }
    // ★ #6 적 학살영웅(배반자) 오사로 피해받은 '적 유닛'도 실시간 표시 (프로필 도장/HP/피격).
    //   defender 시점 → ff 대상은 공격자(상대)의 말 = opp. 보이는(표식) 말만 보드 도장, 카드는 항상.
    if (Array.isArray(friendlyFireHits)) {
      for (const ff of friendlyFireHits) {
        const _ffDmg = (typeof ff.damage === 'number') ? ff.damage : 0;
        const _ffKey = S.isTeamMode
          ? `${(ff.defOwnerIdx != null ? ff.defOwnerIdx : ff.ownerIdx)}:${ff.defPieceIdx}`
          : `opp:${ff.defPieceIdx}`;
        if (ff.defPieceIdx == null) continue;
        if (_ffDmg > 0) addBodyDamage(_ffKey, _ffDmg);
        else if (!ff.destroyed) addProtectedHit(_ffKey);
      }
    }
    const meaningfulHits = hitPieces.filter(h => !h.redirectedToBodyguard && !(h.damage === 0 && !h.destroyed));
    const directHits = meaningfulHits.filter(h => !h.bodyguardRedirect);
    const _myDestroyedRatsFlag = (myDestroyedRats && myDestroyedRats.length > 0);
    const _attackerHadAnyImpact = !!attackerImpactedAnything || _myDestroyedRatsFlag;
    if (hitPieces.length === 0) {
      if (!_attackerHadAnyImpact) {
        addLog(`${oppN()} 공격 빗나감`, 'miss');
        showSkillToast(`${oppN()} 공격 빗나감`, true);
      }
    } else if (directHits.length > 0) {
      const killedSelf = directHits.filter(h => h.destroyed);
      const hitOnlySelf = directHits.filter(h => !h.destroyed);
      if (killedSelf.length > 0) playSfx('kill');
      else if (hitOnlySelf.length > 0) playSfx('hit');
      if (killedSelf.length === 0) {
        showSkillToast(`공격받았습니다!`, true);
      }
      if (hitOnlySelf.length > 0) {
        const hitLabels = hitOnlySelf.map(h => h.icon && h.name ? `${pieceIconHtml(h.icon, {size:'1em'})}${h.name}` : '유닛').join(', ');
        addLog(`${hitLabels} 피격`, 'hit');
      }
      if (killedSelf.length > 0) {
        const killedLabels = killedSelf.map(h => h.icon && h.name ? `${pieceIconHtml(h.icon, {size:'1em'})}${h.name}` : '유닛').join(', ');
        showSkillToast(`${killedLabels} 격파!`, true);
        addLog(`${killedLabels} 격파`, 'hit');
      }
    }
    const _selfKilled = directHits.some(h => h.destroyed);
    if (typeof flushDefensiveAlerts === 'function') flushDefensiveAlerts({ skipReduction: _selfKilled });
    const hitIndices = findPieceIndices(S.myPieces, meaningfulHits);
    const isShadowMine = (h) => {
      const p = (S.myPieces || []).find(pc => pc.alive && pc.col === h.col && pc.row === h.row);
      return p && (p.statusEffects || []).some(e => e.type === 'shadow');
    };
    // ★ 충성 리다이렉트(redirectedToBodyguard)된 왕족은 protected에서 제외 — 파란 도장 중복 방지
    const protectedHits = hitPieces.filter(h => h.damage === 0 && !h.destroyed && !isShadowMine(h) && !h.redirectedToBodyguard);
    const protectedIndices = findPieceIndices(S.myPieces, protectedHits);

    // ── 렌더 + 사망 애니 분기 ─────────────────────────────────────────────
    const _doPostRenderDef = () => {
      if (!S.isTeamMode) {
        applyProfileHitAnim('#my-pieces-info .my-piece-card', hitIndices);
        applyProtectedAnimByIndex('#my-pieces-info .my-piece-card', protectedIndices);
        for (const i of protectedIndices) addProtectedHit(`my:${i}`);
      } else {
        for (const i of protectedIndices) {
          applyProtectedAnimTeam(S.playerIdx, i);
          addProtectedHit(`${S.playerIdx}:${i}`);
        }
        requestAnimationFrame(() => {
          for (const i of hitIndices) {
            const card = document.querySelector(`.team-profile-block[data-player-idx="${S.playerIdx}"] [data-piece-idx="${i}"]`);
            if (card) applyHitFlashWithBrighten(card);
          }
        });
      }
    };

    if (_deathInfos.length > 0) {
      // ★ 사망 유닛 존재 — 먼저 렌더 후 피격 애니, 400ms 후 사망 GIF → 재렌더
      // ★ _pendingDeathCells: 사망 GIF 재생 전까지 dead piece 의 idle GIF 를 DOM 에 유지 (빈 프레임 방지)
      S._pendingDeathCells = new Set(_deathInfos.map(d => `${d.col},${d.row}`));
      renderGameBoard();
      renderMyPieces();
      _doPostRenderDef();

      scheduleDeathGif(_deathInfos, _deathInfos, () => {
        renderGameBoard();
        renderMyPieces();
        _flushPendingSpUpdate(); // ★ 애니 완료 후 큐잉된 SP 적용
      });
    } else {
      renderGameBoard();
      renderMyPieces();
      _doPostRenderDef();
      _flushPendingSpUpdate(); // ★ 애니 완료 후 큐잉된 SP 적용
    }

    // 쥐 격파 피드백
    if (myDestroyedRats.length > 0) {
      const msg = ratDestroyMsg(myDestroyedRats, true);
      showSkillToast(msg, true);
      addLog(msg, 'hit');
      animateRatDestruction(myDestroyedRats, true);
    }
  }, ATTACK_IMPACT_DELAY);
});

// ── 표식 적 공격 모션 공유 ──
//   표식된 적이 공격하면 표식 부여자(고문기술자 소유자)에게 공격 셀 + hit 셀 전송.
//   being_attacked 는 피격 대상에게만 보내지만, 표식 부여자는 피격 대상이 아닐 수 있음(팀전).
//   1v1 에서도 atkCells 시각 효과(주황 오버레이) 를 표시하여 적 공격 범위 파악 가능.
socket.on('marked_enemy_attack', ({ atkCells, hitCells, attacker }) => {
  if (!atkCells || !Array.isArray(atkCells)) return;
  try { playSfx('attack'); } catch (e) {}
  // ★ 쥐 공격 모션은 서버 rat_attack_anim 이벤트(쥐장수 공격 시에만, 전 플레이어 수신)로 처리 — 자동 추정 X.
  // ★ 표식 적의 공격 캐릭터 모션 GIF — 공격 시작과 동시에 재생 (attack_result 와 동일 패턴).
  //   500ms(ATTACK_IMPACT_DELAY) 후 셀 효과/피격 판정이 GIF 4번째 프레임과 정렬됨.
  //   pieceIdx=null → animateAttackGif 가 내 piece 키 조회를 건너뛰고, 보드에 렌더된
  //   표식 적 idle GIF 의 transform(scaleX) 에서 바라보는 방향을 읽어 반영.
  if (attacker && typeof attacker.col === 'number' && typeof animateAttackGif === 'function') {
    animateAttackGif(attacker.col, attacker.row, attacker.type, attacker.subUnit, !!attacker.isJoined, null);
  }
  setTimeout(() => {
    // 주황 공격 범위 효과 + 빨간 피격 셀 효과
    if (typeof animateAttackCellEffect === 'function') animateAttackCellEffect(atkCells);
    const _hitOnly = (hitCells || []).filter(h => h.damage > 0 || h.destroyed);
    const _hitCoords = _hitOnly.map(h => ({ col: h.col, row: h.row }));
    if (_hitCoords.length > 0) {
      animateAttack(atkCells, _hitCoords);
    } else {
      animateAttack(atkCells, []);
    }
    // attackLog 에 기록 (보드 마크)
    for (const c of atkCells) {
      const wasHit = _hitOnly.some(h => h.col === c.col && h.row === c.row);
      S.attackLog.push({ col: c.col, row: c.row, hit: wasHit, turn: S.turnNumber });
    }
    renderGameBoard();
  }, ATTACK_IMPACT_DELAY);
});

// ── SP 업데이트 ──
// ★ 공격 애니메이션 진행 중에는 sp_update 큐잉 — 인스턴트 SP 스택킹 선노출 방지
let _attackAnimDeferred = false;
let _pendingSpUpdate = null;
// ★ 재접속/게임시작 시 애니메이션 lock·guard 일괄 초기화.
//   애니 도중 disconnect→reconnect 되면 완료 콜백이 영영 안 와서 SP바 정지,
//   _dragonIncoming/_pendingDeathCells 잔류 좌표가 말 GIF 를 영구 표시/은닉 → 프리징.
//   (함수 선언은 호이스팅되므로 위쪽 reconnect_ok/game_start 핸들러에서도 호출 가능.)
function resetAnimGuards() {
  if (typeof S === 'undefined' || !S) return;
  S._fullscreenBusy = false;
  S._fullscreenBusySince = null;
  S._fullscreenQueue = [];
  S._eventDuringFullscreen = [];
  if (S._fullscreenSafety) { clearTimeout(S._fullscreenSafety); S._fullscreenSafety = null; }
  S._spAnimGuard = false;
  S._spAnimGuardStart = null;
  if (S._spAnimGuardTimer) { clearTimeout(S._spAnimGuardTimer); S._spAnimGuardTimer = null; }
  S._dragonIncoming = null;
  S._pendingDeathCells = null;
  S._bombImpactAt = null;
  _attackAnimDeferred = false;
  _pendingSpUpdate = null;
  // ★ 재접속/새 판 시 쌍둥이 이동 페이즈 잔류 상태 해제 (UI 가 쌍둥이 모드로 잠기는 것 방지).
  S.twinPhaseActive = false;
  S.twinMovePending = false;
  S.twinFirstSubMoved = null;
}
function _flushPendingSpUpdate() {
  _attackAnimDeferred = false;
  if (_pendingSpUpdate) {
    const _psu = _pendingSpUpdate;
    _pendingSpUpdate = null;
    S.sp = _psu.sp;
    if (_psu.instantSp) S.instantSp = _psu.instantSp;
    playSfx('sp');
    updateSPBar();
  }
}
socket.on('sp_update', ({ sp, instantSp }) => {
  if (_attackAnimDeferred) {
    _pendingSpUpdate = { sp, instantSp };
    return;
  }
  S.sp = sp;
  if (instantSp) S.instantSp = instantSp;
  playSfx('sp');
  updateSPBar();
});

// ── 턴 이벤트 알림 ──
// 행동 없이 턴 종료한 플레이어 알림 — 모든 플레이어/관전자에게 동등하게 표시
socket.on('no_action_notice', ({ playerIdx, name, msg }) => {
  if (!msg) return;
  addLog(msg, 'event');
  showSkillToast(msg, false, playerIdx, 'event');
});

socket.on('turn_event', (payload) => {
  const { type, msg, sp: finalSp, instantSp: finalInstantSp } = payload || {};
  if (S.isSpectator) return; // 관전자는 spectator_log 경로로 수신
  // 1대1 대치는 풀스크린 알림 — 페이드 인 1s + 유지 1s + 페이드 아웃 1s
  if (type === 'stalemate_shrink') {
    addLog(msg, 'system');
    runFullscreenLocked(() => playStalemateShrinkAlert(msg), 3000);
    return;
  }
  // SP 지급 — 풀스크린 애니(4.4s) + 1.5s 버퍼 = 5.9s 동안 모든 토스트/로그 차단
  if (type === 'sp_grant') {
    addLog(msg, 'system');
    // 사용자 요청: SP 증정 애니는 강제 시청 — 디바이스 무관 스크롤 최상단으로 이동
    try { window.scrollTo({ top: 0, behavior: 'smooth' }); } catch (e) {
      try { window.scrollTo(0, 0); } catch (e2) {}
    }
    // 사용자 요청: SP 숫자는 애니 시작 시점이 아닌, 구슬이 숫자에 합쳐지는 순간에 변경되어야 함.
    // 서버가 페이로드에 final sp/instantSp 를 함께 보내므로 OLD 상태(=현재 S.sp)를 유지하다가
    // 애니 끝나는 흡수 시점에 NEW 로 갱신 (S.sp 동기화는 playSpGrantAnimation 내부에서 수행).
    //
    // ★ FIX: sp_grant 가 stalemate_shrink 뒤에 큐잉될 경우,
    //   playSpGrantAnimation 실행까지 ~3.5초 gap 동안 your_turn/opp_turn 이 도착하여
    //   S.sp 를 NEW 로 갱신 + updateSPBar 가 숫자를 미리 표시하는 버그.
    //   (1) 즉시 _spAnimGuard 를 켜서 updateSPBar 의 big number 갱신 차단.
    //   (2) OLD SP 값을 즉시 캡처 — playSpGrantAnimation 이 나중에 실행될 때 S.sp 가 이미 NEW 여도 OLD 유지.
    const _capturedOldSp = Array.isArray(S.sp) ? [...S.sp] : null;
    const _capturedOldInstantSp = Array.isArray(S.instantSp) ? [...S.instantSp] : null;
    S._spAnimGuard = true;
    if (S._spAnimGuardTimer) clearTimeout(S._spAnimGuardTimer);
    S._spAnimGuardTimer = setTimeout(() => { S._spAnimGuard = false; }, 10000); // 안전 cap: stalemate 3s + gap 0.5s + SP 애니 6s
    runFullscreenLocked(() => playSpGrantAnimation(finalSp, finalInstantSp, _capturedOldSp, _capturedOldInstantSp), 6000);
    return;
  }
  showSkillToast(`⚡ ${msg}`, false, undefined, 'event');
  addLog(`⚡ ${msg}`, 'system');
});

// 스킬 시전 시 SP 차감 집중 연출 — SP 바 위에서 마법 구슬이 시전자 → 상대 숫자로 이동
// 순서: 인스턴트 SP 먼저 소멸 → 0.5s 간격 → 일반 SP 마법구 비행
// 비행/소멸마다 카운터 숫자가 한 칸씩 변화 (시각적 tick + 효과음)
// ── SP 오브 비행 종료 시점 계산 ──
//   spendSPAttention 의 nextMs(80) + (cost-1)*130 + flight(700) 공식.
//   cost 0 (기폭) → 다른 스킬과 시각 호흡 통일 위해 cost 1 (780ms) 로 처리.
//   SP_END_OFFSET_MS — SP 오브 도착 후 추가로 더 기다리는 텀 (살짝 호흡).
const SP_END_OFFSET_MS = 200;
function getSpFlightEndMs(cost) {
  const c = Math.max(1, cost | 0);  // 0 → 1 로 처리
  return 780 + (c - 1) * 130 + SP_END_OFFSET_MS;
}
// 이벤트 payload 에 spCost 가 없을 때 fallback (SP delta 로 추정)
// ★ 버그 수정 (2인전 스킬 타이밍): 이전에는 viewer 본인 슬롯(mySlot)의 감소량만 봤다.
//   하지만 상대/적팀이 시전하면 viewer 슬롯 delta=0 → 항상 1 반환 → getSpFlightEndMs(1)=780ms 로
//   효과가 발동 → 고비용 스킬은 SP 마법구가 아직 비행 중인데 효과가 먼저 터졌다
//   (= "마법구 이동 타이밍과 동일하게 발동"). 시전자는 본인이 아닐 수 있으므로,
//   특정 슬롯이 아니라 '감소한' 슬롯(=실제 시전자)의 소비량을 cost 로 사용한다.
//   본인 시전 시에도 본인 슬롯이 감소 슬롯이므로 동일하게 동작 (회귀 없음).
function spCostFromDelta(oldSp, newSp, oldInstantSp, newInstantSp) {
  if (!oldSp || !newSp) return 1;
  const n = Math.max(oldSp.length || 0, newSp.length || 0);
  let maxConsumed = 0;
  for (let i = 0; i < n; i++) {
    const reg = (oldSp[i] || 0) - (newSp[i] || 0);
    const ins = ((oldInstantSp || [])[i] || 0) - ((newInstantSp || [])[i] || 0);
    const consumed = (reg > 0 ? reg : 0) + (ins > 0 ? ins : 0);
    if (consumed > maxConsumed) maxConsumed = consumed;
  }
  return Math.max(1, maxConsumed);
}

function spendSPAttention(oldSp, newSp, oldInstantSp, newInstantSp) {
  const sec = document.querySelector('.sp-section');
  if (sec) {
    sec.classList.remove('sp-spend-attn');
    void sec.offsetWidth;
    sec.classList.add('sp-spend-attn');
    setTimeout(() => sec.classList.remove('sp-spend-attn'), 2000);
  }
  if (!oldSp || !newSp) return;
  // 가드 ON — 애니 진행 중 외부 updateSPBar 가 큰 숫자/pip 트레이를 NEW 값으로 덮어쓰지 못하게.
  // C-11: 매 스킬 시전마다 가드 시작 시간 갱신 — 5초 cap 이 최초 시점 기준으로 고정되지 않도록.
  S._spAnimGuardStart = Date.now();
  S._spAnimGuard = true;
  if (S._spAnimGuardTimer) clearTimeout(S._spAnimGuardTimer);
  const _maxGuardRemain = Math.max(0, 5000 - (Date.now() - (S._spAnimGuardStart || 0)));
  const _guardMs = Math.min(2500, _maxGuardRemain);
  S._spAnimGuardTimer = setTimeout(() => { S._spAnimGuard = false; S._spAnimGuardStart = null; }, _guardMs || 100);

  const mySlot = S.isTeamMode ? (S.teamId ?? 0) : (S.playerIdx ?? 0);
  // ★ 사용자 요청: 절대 좌·우 슬롯 매핑 — 팀전: 블루=LEFT(0), 레드=RIGHT(1). 1v1: viewer 상대.
  //   인스턴트 트레이/숫자 위치가 좌·우에 절대 고정되므로 delta 도 leftSlot/rightSlot 으로 인덱싱해야
  //   레드팀 viewer 가 인스턴트 SP 소비할 때 RIGHT(레드) 트레이에서 팝되도록 보장.
  let leftSlot, rightSlot;
  if (S.isTeamMode) { leftSlot = 0; rightSlot = 1; }
  else { leftSlot = mySlot; rightSlot = 1 - mySlot; }

  const leftDelta  = (newSp[leftSlot]  || 0) - (oldSp[leftSlot]  || 0);
  const rightDelta = (newSp[rightSlot] || 0) - (oldSp[rightSlot] || 0);
  const leftInstantDelta  = ((newInstantSp || [])[leftSlot]  || 0) - ((oldInstantSp || [])[leftSlot]  || 0);
  const rightInstantDelta = ((newInstantSp || [])[rightSlot] || 0) - ((oldInstantSp || [])[rightSlot] || 0);
  const leftRegConsumed  = leftDelta  < 0 ? -leftDelta  : 0;
  const rightRegConsumed = rightDelta < 0 ? -rightDelta : 0;
  const leftRegGain      = leftDelta  > 0 ?  leftDelta  : 0;
  const rightRegGain     = rightDelta > 0 ?  rightDelta : 0;
  const leftInstantConsumed  = leftInstantDelta  < 0 ? -leftInstantDelta  : 0;
  const rightInstantConsumed = rightInstantDelta < 0 ? -rightInstantDelta : 0;
  // 일반 SP 비행 — left ↔ right 양방향 모두 처리
  const transferLR = (leftRegConsumed  > 0 && rightRegGain > 0) ? Math.min(leftRegConsumed,  rightRegGain) : 0;
  const transferRL = (rightRegConsumed > 0 && leftRegGain  > 0) ? Math.min(rightRegConsumed, leftRegGain)  : 0;

  const leftNumEl  = document.getElementById('sp-my-num');   // DOM 좌측 숫자
  const rightNumEl = document.getElementById('sp-opp-num');  // DOM 우측 숫자
  if (!leftNumEl || !rightNumEl) return;

  const rectCenter = (el) => {
    const r = el.getBoundingClientRect();
    return { x: r.left + r.width / 2, y: r.top + r.height / 2 };
  };
  const leftCenter  = rectCenter(leftNumEl);
  const rightCenter = rectCenter(rightNumEl);

  // 표시되는 숫자(displayed)를 OLD 값으로 보유 — 마법구 도착마다 1씩 변경
  let dispLeft  = oldSp[leftSlot]  || 0;
  let dispRight = oldSp[rightSlot] || 0;
  leftNumEl.textContent  = String(dispLeft);
  rightNumEl.textContent = String(dispRight);
  const tickDown = (el, val) => {
    el.textContent = String(val);
    el.classList.remove('sp-num-tick'); void el.offsetWidth; el.classList.add('sp-num-tick');
    // ★ 사용자 요청: 숫자 변경 시 fill bar 도 즉시 동기화 (그래프가 숫자 따라 움직임).
    if (typeof _syncSpFillBars === 'function') _syncSpFillBars();
  };
  const tickUp = (el, val) => {
    el.textContent = String(val);
    el.classList.remove('sp-num-tick-up'); void el.offsetWidth; el.classList.add('sp-num-tick-up');
    if (typeof _syncSpFillBars === 'function') _syncSpFillBars();
  };

  let nextMs = 80;
  // ① 인스턴트 SP 소비 — pop-in-place (제자리 팝 + 충격파 + 스파크 + dust + FLIP 슬라이드)
  //   - 양 트레이 모두 DOM-first pip 가 시각적으로 숫자에 가장 가까움 → 가까운 쪽부터 한 개씩
  //   - 좌·우 모두 동시에 소비될 수 있음 (일반적으론 한 쪽만)
  if (leftInstantConsumed > 0) {
    setTimeout(() => popInstantPipsOneByOne('sp-instant-tray-mine', leftNumEl, leftInstantConsumed), nextMs);
    nextMs += leftInstantConsumed * 220 + 200;
  }
  if (rightInstantConsumed > 0) {
    setTimeout(() => popInstantPipsOneByOne('sp-instant-tray-opp', rightNumEl, rightInstantConsumed), nextMs);
    nextMs += rightInstantConsumed * 220 + 200;
  }
  // 인스턴트 끝나고 0.3s 텀 (인스턴트 → 일반 SP 비행 전)
  if (leftInstantConsumed > 0 || rightInstantConsumed > 0) nextMs += 300;

  // ② 일반 SP 비행 — left → right (블루팀 시전 / 1v1 본인 시전)
  if (transferLR > 0) {
    for (let i = 0; i < transferLR; i++) {
      const t = nextMs;
      setTimeout(() => {
        dispLeft = Math.max(0, dispLeft - 1);
        tickDown(leftNumEl, dispLeft);
        try { playSfxSpOrbDepart(); } catch (e) {}
        spawnSpOrbFlight(leftCenter, rightCenter, 'mine', () => {
          dispRight = dispRight + 1;
          tickUp(rightNumEl, dispRight);
          try { playSfxSpOrbArrive(); } catch (e) {}
        });
      }, t);
      nextMs += 200;
    }
  }
  // ③ 일반 SP 비행 — right → left (레드팀 시전 / 1v1 상대 시전)
  if (transferRL > 0) {
    for (let i = 0; i < transferRL; i++) {
      const t = nextMs;
      setTimeout(() => {
        dispRight = Math.max(0, dispRight - 1);
        tickDown(rightNumEl, dispRight);
        try { playSfxSpOrbDepart(); } catch (e) {}
        spawnSpOrbFlight(rightCenter, leftCenter, 'opp', () => {
          dispLeft = dispLeft + 1;
          tickUp(leftNumEl, dispLeft);
          try { playSfxSpOrbArrive(); } catch (e) {}
        });
      }, t);
      nextMs += 200;
    }
  }
}

// ── 인스턴트 SP pip 순차 팝 (가까운 쪽부터, FLIP 슬라이드 포함) ──
//   사용자 요청: pip 이 제자리에서 팝되며 사라지고, 잔여 pip + 숫자가 자연스럽게 모임.
//   - 양 트레이 모두 DOM-first 가 숫자에 가장 가까움 (mine: row-reverse, opp: default row)
//   - 매 팝마다 중앙 플래시 + 링2개 + 스파크 12갈래 + dust 10개 + 인게임 SFX
function popInstantPipsOneByOne(trayId, numEl, count) {
  const tray = document.getElementById(trayId);
  if (!tray || count <= 0) return;
  let i = 0;
  const popNext = () => {
    if (i >= count) return;
    i++;
    const pips = tray.querySelectorAll('.sp-instant-pip:not(.sp-pip-pop):not(.sp-pip-consume)');
    const target = pips[0];  // DOM-first = 시각적으로 숫자에 가장 가까운 pip
    if (!target) return;
    const targetRect = target.getBoundingClientRect();
    const cx = targetRect.left + targetRect.width / 2;
    const cy = targetRect.top + targetRect.height / 2;
    spawnSpPopBurst(cx, cy);
    try { playSfxInstantConsume(); } catch (e) {}
    target.classList.add('sp-pip-pop');
    // FLIP — 잔여 pip + 숫자 BEFORE rect 캡처
    const others = Array.from(pips).slice(1);
    const beforeRects = new Map();
    for (const p of others) beforeRects.set(p, p.getBoundingClientRect());
    const numBefore = numEl ? numEl.getBoundingClientRect() : null;
    // 200ms 후 DOM 제거 → flex layout 재계산 → FLIP 적용
    setTimeout(() => {
      if (target.parentNode) target.remove();
      for (const p of others) {
        const before = beforeRects.get(p);
        const after = p.getBoundingClientRect();
        const dx = before.left - after.left;
        if (Math.abs(dx) > 0.5) {
          p.classList.remove('sp-flip-slide');
          p.style.transform = `translateX(${dx}px)`;
          void p.offsetWidth;
          p.classList.add('sp-flip-slide');
          p.style.transform = 'translateX(0)';
          setTimeout(() => {
            p.classList.remove('sp-flip-slide');
            p.style.transform = '';
          }, 320);
        }
      }
      if (numEl && numBefore) {
        const numAfter = numEl.getBoundingClientRect();
        const numDx = numBefore.left - numAfter.left;
        if (Math.abs(numDx) > 0.5) {
          numEl.classList.remove('sp-flip-slide');
          numEl.style.transform = `translateX(${numDx}px)`;
          void numEl.offsetWidth;
          numEl.classList.add('sp-flip-slide');
          numEl.style.transform = 'translateX(0)';
          setTimeout(() => {
            numEl.classList.remove('sp-flip-slide');
            numEl.style.transform = '';
          }, 320);
        }
      }
      setTimeout(popNext, 220);
    }, 200);
  };
  popNext();
}

// ── 인스턴트 SP 팝 버스트 이펙트 ──
//   중앙 플래시 + 링 2개 + 스파크 12갈래 + dust 10개 — 모두 (cx,cy) 중심 정렬
function spawnSpPopBurst(x, y) {
  const flash = document.createElement('div');
  flash.className = 'sp-pop-flash';
  flash.style.left = x + 'px';
  flash.style.top  = y + 'px';
  document.body.appendChild(flash);
  setTimeout(() => flash.remove(), 380);

  const r1 = document.createElement('div');
  r1.className = 'sp-pop-ring';
  r1.style.left = x + 'px';
  r1.style.top  = y + 'px';
  document.body.appendChild(r1);
  setTimeout(() => r1.remove(), 650);

  const r2 = document.createElement('div');
  r2.className = 'sp-pop-ring sp-pop-ring2';
  r2.style.left = x + 'px';
  r2.style.top  = y + 'px';
  document.body.appendChild(r2);
  setTimeout(() => r2.remove(), 830);

  for (let i = 0; i < 12; i++) {
    const sp = document.createElement('div');
    sp.className = 'sp-pop-spark';
    sp.style.left = x + 'px';
    sp.style.top  = y + 'px';
    sp.style.setProperty('--ang', (i * 30 + (Math.random() * 10 - 5)) + 'deg');
    if (i % 2 === 1) sp.style.height = '13px';
    document.body.appendChild(sp);
    setTimeout(() => sp.remove(), 600);
  }

  for (let i = 0; i < 10; i++) {
    const d = document.createElement('div');
    d.className = 'sp-pop-dust';
    d.style.left = x + 'px';
    d.style.top  = y + 'px';
    const angle = Math.random() * Math.PI * 2;
    const dist = 22 + Math.random() * 20;
    d.style.setProperty('--dx', Math.cos(angle) * dist + 'px');
    d.style.setProperty('--dy', Math.sin(angle) * dist - 8 + 'px');
    if (i % 3 === 0) { d.style.width = '3px'; d.style.height = '3px'; }
    document.body.appendChild(d);
    setTimeout(() => d.remove(), 850);
  }
}

// 인스턴트 SP 트레이 동기화 — count 만큼 .sp-instant-pip 유지
// 새로 추가되는 pip 은 .sp-pip-spawn 으로 등장 애니. 줄어들 때는 spendSPAttention 측에서 별도 비행 처리.
function syncInstantTray(trayId, count) {
  const tray = document.getElementById(trayId);
  if (!tray) return;
  // sp-pip-pop / sp-pip-consume 진행 중인 pip 은 카운트에서 제외 (애니 후 자동 제거됨)
  const cur = tray.querySelectorAll('.sp-instant-pip:not(.sp-pip-consume):not(.sp-pip-pop)').length;
  if (cur < count) {
    // 부족한 pip 추가 (등장 애니)
    for (let i = 0; i < count - cur; i++) {
      const pip = document.createElement('div');
      pip.className = 'sp-instant-pip sp-pip-spawn';
      tray.appendChild(pip);
    }
  } else if (cur > count) {
    // 많은 pip 제거 — 가장 안쪽(숫자 가까운) pip 부터
    const pips = tray.querySelectorAll('.sp-instant-pip:not(.sp-pip-consume):not(.sp-pip-pop)');
    const overflow = cur - count;
    for (let i = 0; i < overflow; i++) {
      // mine 트레이 (row-reverse): DOM-first = 시각적 우측 (숫자 가까움) → 첫 번째부터 제거
      // opp 트레이 (row): DOM-first = 시각적 좌측 (숫자 가까움) → 첫 번째부터 제거
      // 둘 다 DOM-first 가 숫자에 가장 가까움 (popInstantPipsOneByOne 과 동일한 규칙)
      const pip = pips[i];
      if (pip) pip.remove();
    }
  }
}

// 인스턴트 SP 획득 (마법사 인스턴트 매직 발동) — 황금 마법구가 마법사 프로필 카드에서 출발 → SP 숫자 옆 트레이 슬롯으로 합류
function spawnInstantGainOrb(targetSlot) {
  const isMine = (targetSlot === 'mine');
  // 출발지: 해당 플레이어의 마법사 프로필 카드
  const fromPos = getWizardCardCenter(isMine) || (() => {
    // 마법사 카드 못찾을 때 — SP 숫자 위쪽으로 폴백
    const numEl = isMine ? document.getElementById('sp-my-num') : document.getElementById('sp-opp-num');
    if (!numEl) return null;
    const r = numEl.getBoundingClientRect();
    return { x: r.left + r.width / 2, y: r.top + r.height / 2 - 80 };
  })();
  if (!fromPos) return;
  // 도착지: 트레이의 다음 슬롯 위치 (현재 pip 개수 기준)
  const trayId = isMine ? 'sp-instant-tray-mine' : 'sp-instant-tray-opp';
  const tray = document.getElementById(trayId);
  if (!tray) return;
  // sp_update가 이미 도착해 새 pip 이 트레이에 추가되어 있을 가능성 — 가장 최근 pip(=새로 추가된 것) 위치 사용
  const lastPip = isMine
    ? tray.lastElementChild
    : tray.firstElementChild;
  let toPos;
  if (lastPip) {
    // pip 위치를 비행 도착지로 사용 + 비행 동안 잠시 숨김
    const r = lastPip.getBoundingClientRect();
    toPos = { x: r.left + r.width / 2, y: r.top + r.height / 2 };
    lastPip.style.opacity = '0';
  } else {
    // 트레이가 비어있으면 트레이 자체 중심으로 (sp_update 가 아직 안 옴)
    const r = tray.getBoundingClientRect();
    toPos = { x: r.left + r.width / 2, y: r.top + r.height / 2 };
  }

  // 비행 — 페어리 트레일 포함
  const orb = document.createElement('div');
  orb.className = 'sp-orb sp-orb-instant';
  orb.style.left = fromPos.x + 'px';
  orb.style.top = fromPos.y + 'px';
  document.body.appendChild(orb);
  const dur = 800;
  const startT = performance.now();
  const mid = { x: (fromPos.x + toPos.x) / 2, y: (fromPos.y + toPos.y) / 2 - 50 };
  // 트레일 더스트
  const trailIv = setInterval(() => {
    const r = orb.getBoundingClientRect();
    const dust = document.createElement('div');
    dust.className = 'sp-dust sp-dust-instant';
    dust.style.left = (r.left + r.width / 2) + 'px';
    dust.style.top = (r.top + r.height / 2) + 'px';
    document.body.appendChild(dust);
    setTimeout(() => dust.remove(), 700);
  }, 35);
  function step(now) {
    const t = Math.min(1, (now - startT) / dur);
    const e = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
    const x = (1 - e) * (1 - e) * fromPos.x + 2 * (1 - e) * e * mid.x + e * e * toPos.x;
    const y = (1 - e) * (1 - e) * fromPos.y + 2 * (1 - e) * e * mid.y + e * e * toPos.y;
    const wobble = Math.sin(t * Math.PI * 6) * 4 * (1 - t);
    orb.style.left = (x + wobble) + 'px';
    orb.style.top = (y - wobble) + 'px';
    if (t < 1) requestAnimationFrame(step);
    else {
      clearInterval(trailIv);
      orb.classList.add('sp-orb-arrive');
      try { playSfxInstantGain(); } catch (e) {}
      // pip 노출 + 등장 애니 재시작
      if (lastPip) {
        lastPip.style.opacity = '1';
        lastPip.classList.remove('sp-pip-spawn');
        void lastPip.offsetWidth;
        lastPip.classList.add('sp-pip-spawn');
      }
      setTimeout(() => orb.remove(), 320);
    }
  }
  requestAnimationFrame(step);
}

// ── 후공 인스턴트 SP 지급 안내 메시지 ──
function showSecondPlayerSpAnnounce() {
  let el = document.getElementById('sp-grant-announce');
  if (!el) {
    el = document.createElement('div');
    el.id = 'sp-grant-announce';
    el.className = 'sp-grant-announce';
    el.innerHTML = `<div class="spga-k">GAME START</div><div class="spga-m">후공은 <b>인스턴트 SP</b>를 하나 지급받습니다</div>`;
    document.body.appendChild(el);
  }
  el.classList.remove('show'); void el.offsetWidth; el.classList.add('show');
  setTimeout(() => el.classList.remove('show'), 3000);
}
// ── 초반 연출 페이즈 입력 잠금 (인트로+후공 SP 지급 동안 양측 행동 불가) ──
function setIntroPhaseLock(on) {
  let el = document.getElementById('intro-phase-lock');
  if (on) {
    if (!el) {
      el = document.createElement('div');
      el.id = 'intro-phase-lock';
      el.style.cssText = 'position:fixed;inset:0;z-index:9200;background:transparent;cursor:wait';
      document.body.appendChild(el);
    }
  } else if (el) { el.remove(); }
}

// ── 후공 인스턴트 SP 오브 합류 연출 (화면 정중앙 5회전 → 해당 SP 숫자로 직선 합류) ──
//   pip 은 onArrive(합류 순간)에만 등장. CSS @keyframes 구동(탭 스로틀 무관). 코멧 트레일 + 도착 버스트.
//   내 쪽 합류면 역방향 회전, 상대 쪽이면 정방향. 막판 비틀기 없이 타겟 정면에서 직선 진입.
function playSecondPlayerSpGrant(targetSide, onArrive) {
  const isMine = (targetSide === 'mine');
  const numEl = document.getElementById(isMine ? 'sp-my-num' : 'sp-opp-num');
  if (!numEl) { if (typeof onArrive === 'function') onArrive(); return; }
  const nr = numEl.getBoundingClientRect();
  const target = { x: nr.left + nr.width / 2, y: nr.top + nr.height / 2 };
  const cx = window.innerWidth / 2, cy = window.innerHeight / 2;
  const _ease = (t) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
  const orbitR = 90, TURNS = 5, DUR = 1750, orbitFrac = 1150 / DUR;
  const startAng = -Math.PI / 2;
  const dir = isMine ? -1 : 1;
  const targetAng = Math.atan2(target.y - cy, target.x - cx);
  let rel = (dir > 0 ? targetAng - startAng : startAng - targetAng);
  rel = ((rel % (2 * Math.PI)) + 2 * Math.PI) % (2 * Math.PI);
  const sweep = dir * (TURNS * 2 * Math.PI + rel);
  const endAng = startAng + sweep;
  const orbit = (a) => ({ x: cx + Math.cos(a) * orbitR, y: cy + Math.sin(a) * orbitR });
  const HS = 9, N = 84; let frames = '';
  for (let i = 0; i <= N; i++) {
    const t = i / N; let pos;
    if (t <= orbitFrac) { const op = t / orbitFrac; const a = startAng + op * sweep; pos = orbit(a); }
    else { const fp = (t - orbitFrac) / (1 - orbitFrac); const e = _ease(fp); const o = orbit(endAng); pos = { x: o.x + (target.x - o.x) * e, y: o.y + (target.y - o.y) * e }; }
    frames += `${(t * 100).toFixed(3)}%{transform:translate(${(pos.x - HS).toFixed(1)}px,${(pos.y - HS).toFixed(1)}px)}`;
  }
  const name = 'spgrant' + Math.floor(performance.now());
  const styleEl = document.createElement('style'); styleEl.textContent = `@keyframes ${name}{${frames}}`; document.head.appendChild(styleEl);
  const made = [];
  function mkOrb(delay, op) { const o = document.createElement('div'); o.className = 'sp-orb sp-orb-instant'; o.style.left = '0'; o.style.top = '0'; o.style.opacity = String(op); o.style.animation = `${name} ${DUR}ms linear ${delay}ms both`; document.body.appendChild(o); made.push(o); return o; }
  mkOrb(150, 0.12); mkOrb(112, 0.2); mkOrb(74, 0.34); mkOrb(38, 0.55);
  const main = mkOrb(0, 1);
  const trailIv = setInterval(() => { const r = main.getBoundingClientRect(); if (!r.width) return; const d = document.createElement('div'); d.className = 'sp-dust sp-dust-instant'; d.style.left = (r.left + r.width / 2) + 'px'; d.style.top = (r.top + r.height / 2) + 'px'; document.body.appendChild(d); setTimeout(() => d.remove(), 700); }, 28);
  let done = false;
  function arrive() {
    if (done) return; done = true;
    clearInterval(trailIv);
    try { if (typeof playSfxInstantGain === 'function') playSfxInstantGain(); } catch (e) {}
    if (typeof onArrive === 'function') onArrive();   // 실제 instantSp 반영 → updateSPBar 가 pip 등장(sp-pip-spawn)
    numEl.classList.remove('sp-num-tick-up'); void numEl.offsetWidth; numEl.classList.add('sp-num-tick-up');
    for (let i = 0; i < 12; i++) { const d = document.createElement('div'); d.className = 'sp-dust sp-dust-instant'; d.style.left = (target.x + (Math.random() - 0.5) * 14) + 'px'; d.style.top = (target.y + (Math.random() - 0.5) * 14) + 'px'; document.body.appendChild(d); setTimeout(() => d.remove(), 700); }
    made.forEach(o => o.remove()); styleEl.remove();
  }
  main.addEventListener('animationend', arrive, { once: true });
  setTimeout(arrive, DUR + 180);
}

// ── 폭탄 폭발 파편 애니메이션 ──
//   detonation_intro 의 impact phase 에서 호출. 셀 좌표 기준 파편 비산.
//   폭발 GIF 오버레이와 함께 동작 (💥 burst 이모지 → 폭발 GIF 대체).
function playBombExplosion(cell) {
  if (!cell) return;
  const r = cell.getBoundingClientRect();
  if (!r.width) return;
  const cx = r.left + r.width / 2;
  const cy = r.top + r.height / 2;

  // 파편 — 사방으로 비산 (랜덤 거리 + 각도)
  const FRAG_CHARS = ['💢', '✦', '⚡', '🔥', '✨', '💥'];
  const N = 9;
  for (let i = 0; i < N; i++) {
    const p = document.createElement('div');
    p.className = 'bomb-fragment';
    p.textContent = FRAG_CHARS[Math.floor(Math.random() * FRAG_CHARS.length)];
    p.style.left = cx + 'px';
    p.style.top = cy + 'px';
    const angle = (i / N) * Math.PI * 2 + (Math.random() - 0.5) * 0.4;
    const dist = 55 + Math.random() * 40;
    p.style.setProperty('--dx', (Math.cos(angle) * dist).toFixed(1) + 'px');
    p.style.setProperty('--dy', (Math.sin(angle) * dist).toFixed(1) + 'px');
    p.style.animationDelay = (Math.random() * 0.06).toFixed(2) + 's';
    document.body.appendChild(p);
    setTimeout(() => { if (p.parentNode) p.remove(); }, 950);
  }
}

// ── 스킬 시전 말풍선 ──
//   시전자 프로필에서 보드 방향으로 꼬리 달린 oval 말풍선 — 스킬명 표시.
//   유형별 색상 (action 빨강 / once 노랑 / free 초록).
//   2초 유지 후 페이드아웃.
function getSkillTypeFromPiece(piece, skillName) {
  if (!piece || !skillName) return 'free';
  const skill = (piece.skills || []).find(s => s.name === skillName);
  if (skill) {
    if (skill.replacesAction) return 'action';
    if (skill.oncePerTurn) return 'once';
    return 'free';
  }
  // 폴백 — pc 자체 플래그 (구버전 데이터 호환)
  if (piece.skillReplacesAction) return 'action';
  if (piece.skillOncePerTurn) return 'once';
  return 'free';
}
function showSkillCastBubble(casterCard, skillName, skillType) {
  if (!casterCard || !skillName) return;
  const board = document.getElementById('game-board');
  if (!board) return;
  const cardRect = casterCard.getBoundingClientRect();
  const boardRect = board.getBoundingClientRect();
  if (!cardRect.width || !boardRect.width) return;
  // 보드가 카드의 어느 방향에 있는지 (꼬리는 카드 쪽으로 향함, 본체는 보드 쪽)
  const cardCx = cardRect.left + cardRect.width / 2;
  const boardCx = boardRect.left + boardRect.width / 2;
  const boardIsRight = boardCx > cardCx;
  const type = ['action', 'once', 'free', 'passive'].includes(skillType) ? skillType : 'free';

  // ★ 모바일 세로: 카드가 상단(좌/우), 보드는 아래라 '카드 옆 가로 배치'가 어긋남(상대 패널 겹침·화면밖).
  //   → 시전자 카드 정중앙에 오버레이로 덮어 표시(꼬리 없음, 화면밖/겹침 방지).
  const isMobilePortrait = !!(window.matchMedia && window.matchMedia('(max-width: 480px)').matches);
  const bubble = document.createElement('div');
  bubble.textContent = skillName;
  if (isMobilePortrait) {
    bubble.className = `skill-cast-bubble bubble-${type} bubble-overlay`;
    bubble.style.left = (cardRect.left + cardRect.width / 2) + 'px';
    bubble.style.top  = (cardRect.top + cardRect.height / 2) + 'px';
  } else {
    bubble.className = `skill-cast-bubble bubble-${type} bubble-tail-${boardIsRight ? 'left' : 'right'}`;
    // 카드 가장자리(보드 쪽) 에 붙이고, 살짝 보드 쪽으로 띄움
    if (boardIsRight) {
      bubble.style.left = (cardRect.right + 14) + 'px';
    } else {
      bubble.style.right = (window.innerWidth - cardRect.left + 14) + 'px';
    }
    bubble.style.top = (cardRect.top + cardRect.height / 2) + 'px';
  }
  document.body.appendChild(bubble);
  // 다음 프레임에 visible 클래스 → CSS 로 pop-in
  requestAnimationFrame(() => { bubble.classList.add('bubble-show'); });
  // 2초 유지 후 페이드아웃
  setTimeout(() => { bubble.classList.add('bubble-fade'); }, 2000);
  setTimeout(() => { if (bubble.parentNode) bubble.remove(); }, 2600);
}

// ── 스킬 시전 dim 오버레이 — 화면 어둡게, SP 바·시전자 프로필만 spotlight ──
function startSkillCastDim(casterCard, targetInfo) {
  const dim = document.getElementById('skill-cast-dim');
  if (dim) dim.classList.remove('hidden');
  const sec = document.querySelector('.sp-section');
  if (sec) sec.classList.add('caster-spotlight');
  if (casterCard) casterCard.classList.add('caster-spotlight');
  S._castSpotlightCard = casterCard || null;
  // 팀모드: team_game_update 가 곧이어 도착해 renderTeamProfiles 가 DOM 을 재생성하면
  //   .caster-spotlight 클래스가 날아감. {playerIdx, pieceIdx} 를 저장해 reapplyCasterSpotlight() 가
  //   재렌더 직후 다시 클래스 부여하도록.
  S._castSpotlightTarget = targetInfo || null;
  // ★ 사용자 요청: 스킬 시전 도입 SFX — Ethereal (페어리 더스트 + 3음 종소리). 마법구슬 비행과 별개.
  try { playSfxSkillCastWind(); } catch (e) {}
}
function endSkillCastDim(casterCard) {
  const dim = document.getElementById('skill-cast-dim');
  if (dim) dim.classList.add('hidden');
  const sec = document.querySelector('.sp-section');
  if (sec) sec.classList.remove('caster-spotlight');
  const card = casterCard || S._castSpotlightCard;
  if (card) card.classList.remove('caster-spotlight');
  // 또한 target 정보로 현재 DOM 의 매칭 카드도 클린업 (재렌더 사본까지 처리)
  if (S._castSpotlightTarget) {
    const t = S._castSpotlightTarget;
    document.querySelectorAll(`.team-profile-block[data-player-idx="${t.playerIdx}"] [data-piece-idx="${t.pieceIdx}"].caster-spotlight`)
      .forEach(el => el.classList.remove('caster-spotlight'));
  }
  S._castSpotlightCard = null;
  S._castSpotlightTarget = null;
}
// renderTeamProfiles 직후 호출 — spotlight 가 진행 중이면 매칭 카드에 다시 클래스 부여.
function reapplyCasterSpotlight() {
  const t = S._castSpotlightTarget;
  if (!t) return;
  const card = document.querySelector(`.team-profile-block[data-player-idx="${t.playerIdx}"] [data-piece-idx="${t.pieceIdx}"]`);
  if (card) {
    card.classList.add('caster-spotlight');
    S._castSpotlightCard = card;
  }
}

// #18 헬퍼: 피격 / 회복이 발생한 캐릭터 카드에 'turn-bright' 부여 — 그 턴 동안 계속 풀 밝기 유지.
//   사용자 요청: 한 번 피격되면 다음 턴 시작 전까지 계속 밝게. 블록 전체가 아니라 해당 카드만 밝게.
//   profile-hit / heal-flash 는 짧은 플래시 애니메이션 (자동 해제), turn-bright 는 turn change 시 일괄 해제.
// ★ 사용자 보고 (밀림 현상 원인): renderTeamProfiles 가 innerHTML 을 매 이벤트마다 통째로 교체 →
//   직전에 추가한 profile-hit / profile-protected / heal-flash / turn-bright 클래스가 wipe 됨.
//   여러 이벤트가 빠르게 도착하면 (attack_result → team_ally_hit → team_game_update → ...) 매번 wipe.
//   해결: 진행 중 애니메이션을 글로벌 레지스트리에 등록. 매 render 직후 자동 복원.
//   각 anim 은 expires 시각을 보유 — 만료된 것은 자동 제거.
if (!window._activeProfileAnims) window._activeProfileAnims = new Map();
function _registerProfileAnim(playerIdx, pieceIdx, kind, durationMs) {
  if (playerIdx == null || pieceIdx == null) return;
  const key = `${kind}:${playerIdx}:${pieceIdx}`;
  const expiresAt = Date.now() + durationMs;
  window._activeProfileAnims.set(key, { kind, playerIdx, pieceIdx, expiresAt, startAt: Date.now() });
  setTimeout(() => {
    const cur = window._activeProfileAnims.get(key);
    if (cur && cur.expiresAt <= Date.now() + 5) window._activeProfileAnims.delete(key);
    // 현재 카드에서 클래스 제거 (있으면)
    // ★ 팀모드는 반드시 data-player-idx 로 정확 매핑. 1v1 일 때만 인덱스 기반 폴백 허용.
    //   (팀모드 폴백은 #my-pieces-info 안에 자기+팀원 카드가 섞여 있어 [pieceIdx] 가 잘못된 카드를
    //    가리킬 수 있으므로 사용 금지 — 사용자 보고: 다른 플레이어 사망 시 내 카드 흔들림 방지.)
    let card = document.querySelector(`.team-profile-block[data-player-idx="${playerIdx}"] [data-piece-idx="${pieceIdx}"]`);
    if (!card && !S.isTeamMode) {
      card = document.querySelectorAll(`#my-pieces-info .my-piece-card, #opp-pieces-info .opp-piece-card`)[pieceIdx];
    }
    if (card) {
      if (kind === 'hit') card.classList.remove('profile-hit');
      else if (kind === 'heal') card.classList.remove('heal-flash');
      else if (kind === 'protected') card.classList.remove('profile-protected', 'v1', 'v2', 'v3', 'v4');
    }
  }, durationMs + 20);
}
// ★ turn-bright 전용 레지스트리 — 저주 데미지 등 turn 끝까지 유지가 필요한 케이스.
//   _activeProfileAnims 는 짧은 anim 클래스용 (1.1~2초) — turn-bright 는 턴 종료까지 (~30s).
//   clearAllTurnBright() 가 턴 변경 시점에 이 레지스트리도 함께 비움.
if (!window._activeTurnBrights) window._activeTurnBrights = new Map();
function _persistTurnBright(playerIdx, pieceIdx) {
  if (playerIdx == null || pieceIdx == null) return;
  const key = `${playerIdx}:${pieceIdx}`;
  // 만료 시점 — 60초 cap (turn timer 이내 해제 보장)
  window._activeTurnBrights.set(key, { playerIdx, pieceIdx, expiresAt: Date.now() + 60000 });
}
// ── render 후 호출 — 진행 중 애니 클래스를 새 카드에 복원
function reapplyActiveProfileAnims() {
  const now = Date.now();
  // (1) 짧은 anim 클래스 (hit / heal / protected) 복원
  if (window._activeProfileAnims && window._activeProfileAnims.size > 0) {
    window._activeProfileAnims.forEach((info, key) => {
      if (info.expiresAt < now) { window._activeProfileAnims.delete(key); return; }
      const card = _findPieceCard(info.playerIdx, info.pieceIdx);
      if (!card) return;
      if (info.kind === 'hit') {
        // ★ FIX (팀전 프로필 피격 애니 깜빡임): innerHTML 재생성된 카드에 클래스를 그냥 재적용하면
        //   1.8s 플래시가 처음부터 재생돼 매 렌더마다 깜빡이고 "마지막쯤 갑자기 플래시"가 보였다.
        //   경과시간만큼 음수 animation-delay 로 "이어서" 재생 → 재시작 없음(이미 끝났으면 종료 상태 유지).
        if (!card.classList.contains('profile-hit')) {
          card.style.animationDelay = '-' + Math.max(0, now - (info.startAt || now)) + 'ms';
          card.classList.add('profile-hit');
        }
        card.classList.add('turn-bright');
      } else if (info.kind === 'heal') {
        if (!card.classList.contains('heal-flash')) {
          card.style.animationDelay = '-' + Math.max(0, now - (info.startAt || now)) + 'ms';
          card.classList.add('heal-flash');
        }
        card.classList.add('turn-bright');
      } else if (info.kind === 'protected') {
        if (!card.classList.contains('profile-protected')) card.classList.add('profile-protected', 'v3');
      }
    });
  }
  // (2) turn-bright 전용 레지스트리 복원 (저주 데미지 등)
  if (window._activeTurnBrights && window._activeTurnBrights.size > 0) {
    window._activeTurnBrights.forEach((info, key) => {
      if (info.expiresAt < now) { window._activeTurnBrights.delete(key); return; }
      const card = _findPieceCard(info.playerIdx, info.pieceIdx);
      if (card) card.classList.add('turn-bright');
    });
  }
}
// 카드 찾기 — 1v1 / 팀모드 통합 매핑
function _findPieceCard(playerIdx, pieceIdx) {
  if (S.isTeamMode) {
    return document.querySelector(`.team-profile-block[data-player-idx="${playerIdx}"] [data-piece-idx="${pieceIdx}"]`);
  } else {
    const containerSel = (playerIdx === S.playerIdx) ? '#my-pieces-info' : '#opp-pieces-info';
    const cardSel = (playerIdx === S.playerIdx) ? '.my-piece-card' : '.opp-piece-card';
    return document.querySelectorAll(`${containerSel} ${cardSel}`)[pieceIdx];
  }
}
function applyHitFlashWithBrighten(card, durationMs) {
  if (!card) return;
  card.classList.remove('profile-hit');
  card.style.animationDelay = '';   // ★ 첫 플래시는 처음부터 (reapply 의 음수 delay 잔류 제거)
  void card.offsetWidth;
  card.classList.add('profile-hit');
  card.classList.add('turn-bright');  // 그 턴 동안 풀 밝기 유지
  // ★ 레지스트리 등록 — innerHTML wipe 후에도 복원되도록.
  const block = card.closest('.team-profile-block');
  const pIdx = block?.dataset?.playerIdx;
  const piIdx = card.dataset?.pieceIdx;
  if (S.isTeamMode && pIdx != null && piIdx != null) {
    _registerProfileAnim(pIdx, piIdx, 'hit', durationMs || 1800);
  } else if (!S.isTeamMode) {
    // 1v1 — 카드 부모 찾아 my/opp 구분
    const cont = card.closest('#my-pieces-info, #opp-pieces-info');
    if (cont && piIdx != null) {
      const ownerIdx = (cont.id === 'my-pieces-info') ? S.playerIdx : (1 - S.playerIdx);
      _registerProfileAnim(ownerIdx, piIdx, 'hit', durationMs || 1800);
    }
  }
}
function applyHealFlashWithBrighten(card, durationMs) {
  if (!card) return;
  card.classList.remove('heal-flash');
  card.style.animationDelay = '';   // ★ 첫 플래시는 처음부터 (reapply 의 음수 delay 잔류 제거)
  void card.offsetWidth;
  card.classList.add('heal-flash');
  card.classList.add('turn-bright');  // 그 턴 동안 풀 밝기 유지
  const block = card.closest('.team-profile-block');
  const pIdx = block?.dataset?.playerIdx;
  const piIdx = card.dataset?.pieceIdx;
  if (S.isTeamMode && pIdx != null && piIdx != null) {
    _registerProfileAnim(pIdx, piIdx, 'heal', durationMs || 2000);
  } else if (!S.isTeamMode) {
    const cont = card.closest('#my-pieces-info, #opp-pieces-info');
    if (cont && piIdx != null) {
      const ownerIdx = (cont.id === 'my-pieces-info') ? S.playerIdx : (1 - S.playerIdx);
      _registerProfileAnim(ownerIdx, piIdx, 'heal', durationMs || 2000);
    }
  }
}
// 턴 변경 시 모든 turn-bright 해제 — 다음 턴부터 다시 dim 상태로 돌아감.
function clearAllTurnBright() {
  document.querySelectorAll('.turn-bright').forEach(el => el.classList.remove('turn-bright'));
  // ★ turn-bright 레지스트리도 함께 비움 — 다음 턴에 stale 복원 차단.
  if (window._activeTurnBrights) window._activeTurnBrights.clear();
}

// 마법사 카드 위치 찾기 (instant gain 출발지)
function getWizardCardCenter(isMine) {
  const containerSel = isMine ? '#my-pieces-info' : '#opp-pieces-info';
  const cardSel = isMine ? '.my-piece-card' : '.opp-piece-card';
  const pieces = isMine ? S.myPieces : S.oppPieces;
  if (!pieces) return null;
  const wizIdx = pieces.findIndex(p => p && p.alive && p.type === 'wizard');
  if (wizIdx < 0) return null;
  const cards = document.querySelectorAll(`${containerSel} ${cardSel}`);
  const card = cards[wizIdx];
  if (!card) return null;
  const r = card.getBoundingClientRect();
  return { x: r.left + r.width / 2, y: r.top + r.height / 2 };
}

// 마법 구슬 — 두 점 사이를 부드러운 곡선으로 비행 (요정처럼)
// onArrive 콜백 — 도착 시 SP 숫자 tick 등을 호출
function spawnSpOrbFlight(from, to, kind, onArrive) {
  const orb = document.createElement('div');
  orb.className = 'sp-orb sp-orb-' + (kind || 'mine');
  document.body.appendChild(orb);
  const dur = 700;
  const startT = performance.now();
  const dx = to.x - from.x, dy = to.y - from.y;
  const mid = { x: (from.x + to.x) / 2, y: (from.y + to.y) / 2 - Math.abs(dx) * 0.2 - 30 };
  // 페어리 더스트 — 비행 경로를 따라 작은 입자 흩뿌림
  const trailIv = setInterval(() => {
    const r = orb.getBoundingClientRect();
    const dust = document.createElement('div');
    dust.className = 'sp-dust sp-dust-' + (kind || 'mine');
    dust.style.left = (r.left + r.width / 2) + 'px';
    dust.style.top = (r.top + r.height / 2) + 'px';
    document.body.appendChild(dust);
    setTimeout(() => dust.remove(), 700);
  }, 35);
  function step(now) {
    const t = Math.min(1, (now - startT) / dur);
    const e = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
    const x = (1 - e) * (1 - e) * from.x + 2 * (1 - e) * e * mid.x + e * e * to.x;
    const y = (1 - e) * (1 - e) * from.y + 2 * (1 - e) * e * mid.y + e * e * to.y;
    const wobble = Math.sin(t * Math.PI * 6) * 4 * (1 - t);
    orb.style.left = (x + wobble) + 'px';
    orb.style.top = (y - wobble) + 'px';
    if (t < 1) requestAnimationFrame(step);
    else {
      clearInterval(trailIv);
      orb.classList.add('sp-orb-arrive');
      setTimeout(() => orb.remove(), 320);
      if (typeof onArrive === 'function') onArrive();
    }
  }
  requestAnimationFrame(step);
}

// 인스턴트 SP 소멸 — 위로 떠오르며 페이드아웃
function spawnSpOrbVanish(from, kind) {
  const orb = document.createElement('div');
  orb.className = 'sp-orb sp-orb-' + (kind || 'instant');
  orb.style.left = from.x + 'px';
  orb.style.top = from.y + 'px';
  document.body.appendChild(orb);
  requestAnimationFrame(() => {
    orb.style.transition = 'top 0.7s ease-out, opacity 0.7s ease-out, transform 0.7s ease-out';
    orb.style.top = (from.y - 60) + 'px';
    orb.style.opacity = '0';
    orb.style.transform = 'scale(0.4)';
  });
  setTimeout(() => orb.remove(), 750);
}

// ── 쌍둥이 분신 비행 애니메이션 ──
//   mover (불려오는 쪽) 가 caller 위치로 빠르게 날아가며 잔상(작은 ghost copy) 을 남김.
//   SP 마법구 비행과 유사한 베지어 곡선 + 트레일 인터벌. 도착 시 작은 합체 펄스.
//   비행 동안 mover 의 보드 위 piece-marker 를 hidden 처리 (skill_result 의 yourPieces 적용 전까지).
//
// ★ 디버그 미리보기 — 실제 게임 흐름과 무관하게 비행 + SFX 만 미리 재생.
//   콘솔에서 `previewTwinJoin()` 호출. 게임 보드가 있으면 그 위에서, 없으면 화면 가운데에서 임의 좌표로 비행.
window.previewTwinJoin = function(moverSub = 'younger') {
  const board = document.getElementById('game-board');
  if (board && board.querySelectorAll('.cell').length >= 2) {
    // 보드 위에서 비행 — 임의의 두 셀 선택
    const cells = board.querySelectorAll('.cell');
    const fromCell = cells[0];
    const toCell = cells[Math.min(cells.length - 1, 7)];
    const fromCol = parseInt(fromCell.dataset.col), fromRow = parseInt(fromCell.dataset.row);
    const toCol = parseInt(toCell.dataset.col), toRow = parseInt(toCell.dataset.row);
    try { if (typeof playSfxTwinsJoin === 'function') playSfxTwinsJoin(); } catch(e) {}
    playTwinJoinFlight(moverSub, fromCol, fromRow, toCol, toRow);
    return `Flying twins(${moverSub}) from (${fromCol},${fromRow}) → (${toCol},${toRow})`;
  }
  // 보드 없을 때 — 화면 좌→우로 비행 (셀 없이 fixed 좌표 사용 위해 임시 가짜 호출)
  const W = window.innerWidth, H = window.innerHeight;
  const fromX = W * 0.25, fromY = H * 0.5;
  const toX = W * 0.75, toY = H * 0.5;
  // playTwinJoinFlight 는 셀 기반이라 fallback 으로 직접 비행 객체 생성
  const _moveUrl = (typeof getPieceMoveUrl === 'function') ? getPieceMoveUrl('twins', moverSub) : null;
  const _imgStyle = 'width:100%;height:100%;object-fit:contain;image-rendering:pixelated;' +
    'filter:drop-shadow(0 0 1px rgba(0,0,0,1)) drop-shadow(0 0 1px rgba(0,0,0,1));';
  const flyer = document.createElement('div');
  flyer.className = 'twin-join-flyer';
  flyer.innerHTML = _moveUrl ? `<img src="${_moveUrl}" alt="" style="${_imgStyle}" draggable="false">` : '';
  flyer.style.left = fromX + 'px';
  flyer.style.top = fromY + 'px';
  document.body.appendChild(flyer);
  try { if (typeof playSfxTwinsJoin === 'function') playSfxTwinsJoin(); } catch(e) {}
  const dur = 700, startT = performance.now();
  const mid = { x: (fromX + toX) / 2, y: fromY - Math.abs(toX - fromX) * 0.18 - 24 };
  const trailIv = setInterval(() => {
    const r = flyer.getBoundingClientRect();
    const ghost = document.createElement('div');
    ghost.className = 'twin-join-trail';
    ghost.innerHTML = flyer.innerHTML;
    ghost.style.left = (r.left + r.width / 2) + 'px';
    ghost.style.top = (r.top + r.height / 2) + 'px';
    document.body.appendChild(ghost);
    setTimeout(() => ghost.remove(), 480);
  }, 35);
  function step(now) {
    const t = Math.min(1, (now - startT) / dur);
    const e = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
    const x = (1 - e) * (1 - e) * fromX + 2 * (1 - e) * e * mid.x + e * e * toX;
    const y = (1 - e) * (1 - e) * fromY + 2 * (1 - e) * e * mid.y + e * e * toY;
    flyer.style.left = x + 'px';
    flyer.style.top = y + 'px';
    if (t < 1) requestAnimationFrame(step);
    else { clearInterval(trailIv); flyer.classList.add('twin-join-arrive'); setTimeout(() => flyer.remove(), 320); }
  }
  requestAnimationFrame(step);
  return `Preview flight twins(${moverSub}) (no board)`;
};

function playTwinJoinFlight(moverSub, fromCol, fromRow, toCol, toRow) {
  const board = document.getElementById('game-board');
  if (!board) return;
  const fromCell = board.querySelector(`.cell[data-col="${fromCol}"][data-row="${fromRow}"]`);
  const toCell   = board.querySelector(`.cell[data-col="${toCol}"][data-row="${toRow}"]`);
  if (!fromCell || !toCell) return;

  // ★ 합류 비행 방향 → _pieceFacingDir 갱신 (공격 GIF 방향 반영)
  if (typeof _pieceFacingDir !== 'undefined' && Array.isArray(S.myPieces)) {
    const _joinDir = (fromCol !== toCol) ? (toCol < fromCol ? 'left' : 'right') : null;
    if (_joinDir) {
      S.myPieces.forEach((p, i) => {
        if (p && p.alive && p.subUnit) _pieceFacingDir[`${S.playerIdx}:${i}`] = _joinDir;
      });
    }
  }

  // mover 의 piece-marker(단일) / cc-wrapper(캐러셀) 일시 숨김 — 비행 끝나고 보드 재렌더 시 자연 복귀
  const moverMarker = fromCell.querySelector('.piece-marker') || fromCell.querySelector('.cc-wrapper');
  if (moverMarker) moverMarker.classList.add('twin-flying');

  const fromR = fromCell.getBoundingClientRect();
  const toR   = toCell.getBoundingClientRect();
  const fromX = fromR.left + fromR.width  / 2;
  const fromY = fromR.top  + fromR.height / 2;
  const toX   = toR.left   + toR.width    / 2;
  const toY   = toR.top    + toR.height   / 2;

  // ★ 이동 PNG 로 비행 객체 생성 (이모지 대체)
  const _moverMoveUrl = (typeof getPieceMoveUrl === 'function') ? getPieceMoveUrl('twins', moverSub) : null;
  const _joinedIdleUrl = window.PIECE_GIFS && window.PIECE_GIFS.twins_joined;
  const _imgStyle = 'width:100%;height:100%;object-fit:contain;image-rendering:pixelated;' +
    'filter:drop-shadow(0 0 1px rgba(0,0,0,1)) drop-shadow(0 0 1px rgba(0,0,0,1));';
  const _flyerImgHtml = _moverMoveUrl
    ? `<img src="${_moverMoveUrl}" alt="" style="${_imgStyle}" draggable="false">`
    : (moverSub || '');

  const flyer = document.createElement('div');
  flyer.className = 'twin-join-flyer';
  flyer.innerHTML = _flyerImgHtml;
  flyer.style.left = fromX + 'px';
  flyer.style.top  = fromY + 'px';
  document.body.appendChild(flyer);

  // ── 사용자 요청: 곡선 → "준비 동작 + 일직선" 모션 ──
  //   ① 준비(wind-up): 0~180ms — target 반대 방향으로 살짝 후퇴 + scale 1.15 부풀어 오름
  //   ② 비행(launch):  180~700ms — wind-up 위치에서 target 까지 직선 이동 (ease-out)
  //   잔상 트레일은 비행 구간에서만 발사.
  const WINDUP_MS = 180;
  const FLIGHT_MS = 520;
  const TOTAL_MS = WINDUP_MS + FLIGHT_MS;
  const startT = performance.now();
  // wind-up 후퇴 거리 — target 반대 방향으로 진행 거리의 8% (작게)
  const dx = toX - fromX, dy = toY - fromY;
  const dist = Math.hypot(dx, dy) || 1;
  const ux = dx / dist, uy = dy / dist;        // target 방향 단위벡터
  const WINDUP_DIST = 14;                       // 14px 후퇴
  const windupX = fromX - ux * WINDUP_DIST;
  const windupY = fromY - uy * WINDUP_DIST;

  // 잔상 트레일 — 비행 구간(180ms 이후)에만 발사
  const trailIv = setInterval(() => {
    if (performance.now() - startT < WINDUP_MS) return;  // 준비 동작 중엔 잔상 X
    const r = flyer.getBoundingClientRect();
    const ghost = document.createElement('div');
    ghost.className = 'twin-join-trail';
    ghost.innerHTML = _flyerImgHtml;
    ghost.style.left = (r.left + r.width / 2) + 'px';
    ghost.style.top  = (r.top  + r.height / 2) + 'px';
    document.body.appendChild(ghost);
    setTimeout(() => ghost.remove(), 480);
  }, 30);

  function step(now) {
    const elapsed = now - startT;
    let x, y, scale;
    if (elapsed < WINDUP_MS) {
      // ① 준비 — easeOut 으로 후퇴 + 1.0 → 1.15 스케일
      const t = elapsed / WINDUP_MS;
      const e = 1 - Math.pow(1 - t, 3);
      x = fromX + (windupX - fromX) * e;
      y = fromY + (windupY - fromY) * e;
      scale = 1 + 0.15 * e;
    } else {
      // ② 일직선 비행 — wind-up 위치 → target. easeOutCubic 으로 빠르게 가속 후 살짝 감속.
      const t = Math.min(1, (elapsed - WINDUP_MS) / FLIGHT_MS);
      const e = 1 - Math.pow(1 - t, 3);
      x = windupX + (toX - windupX) * e;
      y = windupY + (toY - windupY) * e;
      scale = 1.15 - 0.15 * e;  // 1.15 → 1.0
    }
    flyer.style.left = x + 'px';
    flyer.style.top  = y + 'px';
    flyer.style.transform = `translate(-50%, -50%) scale(${scale.toFixed(3)})`;

    if (elapsed < TOTAL_MS) {
      requestAnimationFrame(step);
    } else {
      clearInterval(trailIv);
      // ★ 도착 펄스 — 합류 상태 이미지 (twins_joined idle GIF) 로 표시.
      if (_joinedIdleUrl) {
        flyer.innerHTML = `<img src="${_joinedIdleUrl}" alt="" style="${_imgStyle}" draggable="false">`;
      }
      flyer.classList.add('twin-join-arrive');
      setTimeout(() => flyer.remove(), 320);
    }
  }
  requestAnimationFrame(step);
}

// SP 지급 풀스크린 애니메이션 — 통합 스파이럴 모션 (수영하듯이 매끄럽게)
// 한 RAF 안에서 angle 과 radius 가 함께 변화 → 페이즈 사이 멈칫 없음, 빠른 템포, 2회 회전
//
// finalSp / finalInstantSp (선택): 서버가 turn_event sp_grant 로 보낸 NEW 값.
//   주어지면 애니메이션 동안에는 OLD(=현재 S.sp) 유지, 구슬 흡수 시점에 NEW 로 전환.
//   미제공(레거시 호출)일 경우 textContent 에서 NEW 를 추정해 fallback.
// capturedOldSp / capturedOldInstantSp (선택): sp_grant 수신 시점에 캡처한 OLD SP 값.
//   stalemate_shrink 뒤에 큐잉될 경우, 실행 시점까지 your_turn 이 S.sp 를 NEW 로 바꿀 수 있으므로
//   캡처 시점의 OLD 값을 사용해야 정확한 OLD → NEW 전환 연출이 가능.
function playSpGrantAnimation(finalSp, finalInstantSp, capturedOldSp, capturedOldInstantSp) {
  const overlay = document.getElementById('sp-grant-overlay');
  const orbL = document.getElementById('sp-grant-orb-left');
  const orbR = document.getElementById('sp-grant-orb-right');
  const textBox = overlay && overlay.querySelector('.sp-grant-text');
  if (!overlay || !orbL || !orbR || !textBox) return;
  document.body.classList.add('sp-granting');

  // ★ 사용자 요청: SP 숫자는 구슬이 합쳐지는 순간에 변경되어야 함.
  //   _spAnimGuard 를 켜서 your_turn / team_game_update 가 도착해 S.sp 가 NEW 로 바뀌어도
  //   updateSPBar 의 big number 갱신을 차단 (skipBigNumsAndTray). 흡수 시 명시적 갱신.
  //   (turn_event handler 에서 이미 guard 가 켜져있을 수 있지만 타이머 갱신 필요)
  S._spAnimGuard = true;
  if (S._spAnimGuardTimer) clearTimeout(S._spAnimGuardTimer);
  S._spAnimGuardTimer = setTimeout(() => { S._spAnimGuard = false; }, 4000);  // SP_GRANT 총 길이 안전 cap
  overlay.classList.remove('hidden', 'fading-out');
  textBox.classList.remove('show');
  textBox.style.opacity = '';

  const W = window.innerWidth, H = window.innerHeight;
  const cx = W / 2, cy = H / 2;
  const orbitR = 130;

  // 페이즈 비율 (전체 t in [0,1])
  const tEntryEnd = 0.20;     // 0~20%   진입 (반경 large → orbitR, 0.5바퀴)
  const tOrbitEnd = 0.78;     // 20~78%  궤도 (orbitR 유지, 2바퀴 회전)
  // 78~100% 분리 비행 (orbitR → SP 숫자)
  const TOTAL_MS = 2400;       // 더 빠르게 (이전 3500ms → 2400ms)

  // 좌 마법구 base angle = π, 우 = 0. 둘 다 시계방향 회전 (angle 양의 방향).
  const angleEntrySweep = Math.PI;     // 진입에서 절반 바퀴 (180°)
  const angleOrbits = Math.PI * 4;     // 2 회전 (720°)
  const angleDispatchSweep = Math.PI * 0.5;  // 분리에서 90° 추가
  const totalAngleSweep = angleEntrySweep + angleOrbits + angleDispatchSweep;

  const myNumEl = document.getElementById('sp-my-num');
  const oppNumEl = document.getElementById('sp-opp-num');

  // 숫자 증가는 구슬이 숫자에 합쳐지는 순간에 발생 — finalSp 가 주어지면 그 값을 NEW 로,
  //   주어지지 않은 경우엔 textContent 에서 추정 (레거시 호환).
  const mySlot = S.isTeamMode ? (S.teamId ?? 0) : (S.playerIdx ?? 0);
  const oppSlot = 1 - mySlot;
  // ★ FIX: capturedOldSp 가 주어지면 캡처 시점의 OLD 값 사용 (stalemate_shrink 큐잉 대응).
  //   주어지지 않으면 현재 S.sp 사용 (기존 동작 = sp_grant 단독 발생 시).
  const _oldSpSource = Array.isArray(capturedOldSp) ? capturedOldSp : S.sp;
  const oldMyNum = (_oldSpSource && _oldSpSource[mySlot] != null) ? _oldSpSource[mySlot] : (parseInt((myNumEl && myNumEl.textContent) || '0', 10) || 0);
  const oldOppNum = (_oldSpSource && _oldSpSource[oppSlot] != null) ? _oldSpSource[oppSlot] : (parseInt((oppNumEl && oppNumEl.textContent) || '0', 10) || 0);
  const finalMyNum = (Array.isArray(finalSp) && finalSp[mySlot] != null) ? finalSp[mySlot] : (oldMyNum + 1);
  const finalOppNum = (Array.isArray(finalSp) && finalSp[oppSlot] != null) ? finalSp[oppSlot] : (oldOppNum + 1);
  let _myAbsorbed = false, _oppAbsorbed = false;
  // 애니 동안 OLD 유지 (sp_update 가 더 이상 안 옴 → S.sp 도 OLD)
  if (myNumEl) myNumEl.textContent = String(oldMyNum);
  if (oppNumEl) oppNumEl.textContent = String(oldOppNum);
  // ★ 사용자 요청: 그래프도 OLD 로 sync — 외부 이벤트가 fill bar 를 미리 NEW 로 만들었을 가능성.
  if (typeof _syncSpFillBars === 'function') _syncSpFillBars();

  setOrbPos(orbL, cx - W * 0.6, cy);  // 멀리 좌측
  setOrbPos(orbR, cx + W * 0.6, cy);  // 멀리 우측
  orbL.style.opacity = '0';
  orbR.style.opacity = '0';

  // 트레일 더스트 — 비행 내내
  let trailIv = setInterval(() => {
    [[orbL, 'sp-dust-grant-l'], [orbR, 'sp-dust-grant-r']].forEach(([orb, cls]) => {
      if (orb.style.opacity === '0' || orb.style.opacity === '') return;
      const r = orb.getBoundingClientRect();
      // 메인 dust 1개 + 작은 sparkle 1~2개 (팅커벨 느낌)
      for (let k = 0; k < 2; k++) {
        const dust = document.createElement('div');
        dust.className = 'sp-dust ' + cls;
        if (k === 1) dust.style.transform = 'translate(-50%, -50%) scale(0.55)';
        dust.style.left = (r.left + r.width / 2 + (Math.random() - 0.5) * 8) + 'px';
        dust.style.top = (r.top + r.height / 2 + (Math.random() - 0.5) * 8) + 'px';
        document.body.appendChild(dust);
        setTimeout(() => dust.remove(), 700);
      }
    });
  }, 28);

  const t0 = performance.now();
  let dispatchTargetL = null, dispatchTargetR = null;
  let dispatchStartL = null, dispatchStartR = null;

  function animate() {
    const elapsed = performance.now() - t0;
    const t = Math.min(1, elapsed / TOTAL_MS);

    // 통합 angle progression — easeInOutCubic 으로 부드럽게 가속/감속
    // 진입 부분은 빠른 가속으로 시작 (수영의 발차기처럼)
    const eAngle = easeInOutCubic(t);
    const angle = eAngle * totalAngleSweep;

    // 페이즈 결정 (radius 와 dispatch 처리)
    let radius;
    let blendDispatch = 0;
    if (t < tEntryEnd) {
      const sub = t / tEntryEnd;
      radius = lerp(W * 0.6, orbitR, easeOutCubic(sub));
      // 텍스트는 진입 후반부터 페이드인
      if (sub > 0.6 && !textBox.classList.contains('show')) textBox.classList.add('show');
      // 페이드 인 (0~50% 구간)
      const fadeT = Math.min(1, sub / 0.5);
      orbL.style.opacity = String(fadeT);
      orbR.style.opacity = String(fadeT);
    } else if (t < tOrbitEnd) {
      radius = orbitR;
      orbL.style.opacity = '1';
      orbR.style.opacity = '1';
      if (!textBox.classList.contains('show')) textBox.classList.add('show');
    } else {
      // 분리 비행 — radius 그대로 유지하면서 target 으로 블렌드
      radius = orbitR;
      const sub = (t - tOrbitEnd) / (1 - tOrbitEnd);
      blendDispatch = easeInOutCubic(sub);
      if (sub > 0.6) textBox.style.opacity = String(1 - (sub - 0.6) / 0.4);
    }

    // 궤도 위치 (각도 + 반경)
    const baseLeft = Math.PI, baseRight = 0;
    let lx = cx + Math.cos(baseLeft + angle) * radius;
    let ly = cy + Math.sin(baseLeft + angle) * radius * 0.55;
    let rx = cx + Math.cos(baseRight + angle) * radius;
    let ry = cy + Math.sin(baseRight + angle) * radius * 0.55;

    // 분리 비행 시 — 궤도 위치와 SP 숫자 위치를 보간
    if (blendDispatch > 0) {
      if (!dispatchTargetL && myNumEl) dispatchTargetL = rectCenterEl(myNumEl);
      if (!dispatchTargetR && oppNumEl) dispatchTargetR = rectCenterEl(oppNumEl);
      if (!dispatchStartL) dispatchStartL = { x: lx, y: ly };
      if (!dispatchStartR) dispatchStartR = { x: rx, y: ry };
      if (dispatchTargetL) {
        // lift — 위로 살짝 솟았다가 내려옴
        const lift = -Math.sin(blendDispatch * Math.PI) * 50;
        lx = lerp(dispatchStartL.x, dispatchTargetL.x, blendDispatch);
        ly = lerp(dispatchStartL.y, dispatchTargetL.y, blendDispatch) + lift;
      }
      if (dispatchTargetR) {
        const lift = -Math.sin(blendDispatch * Math.PI) * 50;
        rx = lerp(dispatchStartR.x, dispatchTargetR.x, blendDispatch);
        ry = lerp(dispatchStartR.y, dispatchTargetR.y, blendDispatch) + lift;
      }
      // 흡수 직전 (95% 이상) — 숫자 증가 + 하얀 팝 (한 번만)
      if (blendDispatch >= 0.95) {
        if (!_myAbsorbed && myNumEl) {
          _myAbsorbed = true;
          myNumEl.textContent = String(finalMyNum);
          myNumEl.classList.remove('sp-num-tick-up');
          void myNumEl.offsetWidth;
          myNumEl.classList.add('sp-num-tick-up');
          // S.sp 도 흡수 시점에 NEW 로 동기화 (sp_update 가 안 오므로 여기서 갱신)
          if (Array.isArray(finalSp)) {
            if (!Array.isArray(S.sp)) S.sp = [0, 0];
            S.sp[mySlot] = finalMyNum;
          }
          // ★ 사용자 요청: 그래프 동기화 (숫자 변경과 동시).
          if (typeof _syncSpFillBars === 'function') _syncSpFillBars();
        }
        if (!_oppAbsorbed && oppNumEl) {
          _oppAbsorbed = true;
          oppNumEl.textContent = String(finalOppNum);
          oppNumEl.classList.remove('sp-num-tick-up');
          void oppNumEl.offsetWidth;
          oppNumEl.classList.add('sp-num-tick-up');
          if (Array.isArray(finalSp)) {
            if (!Array.isArray(S.sp)) S.sp = [0, 0];
            S.sp[oppSlot] = finalOppNum;
          }
          // instantSp 도 NEW 로 동기화
          if (Array.isArray(finalInstantSp)) {
            S.instantSp = [...finalInstantSp];
          }
          if (typeof _syncSpFillBars === 'function') _syncSpFillBars();
        }
      }
    }

    setOrbPos(orbL, lx, ly);
    setOrbPos(orbR, rx, ry);

    if (t < 1) {
      requestAnimationFrame(animate);
    } else {
      // 종료
      if (trailIv) { clearInterval(trailIv); trailIv = null; }
      orbL.style.opacity = '0';
      orbR.style.opacity = '0';
      // 흡수가 미처 안 일어났을 경우 안전장치 — 최종 숫자 동기화 + S.sp/S.instantSp 갱신
      if (myNumEl && !_myAbsorbed) {
        myNumEl.textContent = String(finalMyNum);
        myNumEl.classList.remove('sp-num-tick-up');
        void myNumEl.offsetWidth;
        myNumEl.classList.add('sp-num-tick-up');
      }
      if (oppNumEl && !_oppAbsorbed) {
        oppNumEl.textContent = String(finalOppNum);
        oppNumEl.classList.remove('sp-num-tick-up');
        void oppNumEl.offsetWidth;
        oppNumEl.classList.add('sp-num-tick-up');
      }
      if (Array.isArray(finalSp)) S.sp = [...finalSp];
      if (Array.isArray(finalInstantSp)) S.instantSp = [...finalInstantSp];
      try { if (typeof updateSPBar === 'function') updateSPBar(); } catch (e) {}
      // 1초 페이드 아웃
      overlay.classList.add('fading-out');
      setTimeout(() => {
        overlay.classList.add('hidden');
        overlay.classList.remove('fading-out');
        textBox.classList.remove('show');
        textBox.style.opacity = '';
        document.body.classList.remove('sp-granting');
      }, 1000);
    }
  }
  requestAnimationFrame(animate);

  try { playSpGrantChime(); } catch (e) {}
}

// 내부 헬퍼들
function setOrbPos(el, x, y) {
  el.style.left = x + 'px';
  el.style.top = y + 'px';
}
function rectCenterEl(el) {
  const r = el.getBoundingClientRect();
  return { x: r.left + r.width / 2, y: r.top + r.height / 2 };
}
function lerp(a, b, t) { return a + (b - a) * t; }
function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }
function easeInOutCubic(t) { return t < 0.5 ? 4*t*t*t : 1 - Math.pow(-2*t + 2, 3) / 2; }

// ── SP 마법구 효과음 (4가지 옵션) ──────────────────────────────────
// 사용자가 미리듣고 결정 후 선호하는 것으로 PROD 톤 고정.
// 기본은 옵션 1 (가장 매끄러운 페어리 톤). 옵션 변경: SP_ORB_SFX_VARIANT
const SP_ORB_SFX_VARIANT = 1;  // 1: 페어리 (기본 — 사용자 확정)

function playSfxSpOrbDepart() { _spOrbDepart(SP_ORB_SFX_VARIANT); }
function playSfxSpOrbArrive() { _spOrbArrive(SP_ORB_SFX_VARIANT); }
function _spOrbDepart(variant) {
  if (sfxMuted) return;
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    const now = ctx.currentTime;
    const out = ctx.destination;
    if (variant === 1) {
      // 페어리 출발 — 부드러운 상승 휘릭
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'triangle';
      o.frequency.setValueAtTime(700, now); o.frequency.exponentialRampToValueAtTime(1300, now + 0.18);
      g.gain.setValueAtTime(0.0001, now); g.gain.linearRampToValueAtTime(0.16, now + 0.02); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.22);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.25);
    } else if (variant === 2) {
      // 짧은 글래스 핑
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.setValueAtTime(1800, now);
      g.gain.setValueAtTime(0.16, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.18);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.2);
    } else if (variant === 3) {
      // 깃털 — 부드러운 화이트노이즈 슬라이드
      const buf = ctx.createBuffer(1, ctx.sampleRate * 0.18, ctx.sampleRate);
      const d = buf.getChannelData(0); for (let i = 0; i < d.length; i++) d[i] = (Math.random() * 2 - 1) * 0.15 * (1 - i / d.length);
      const src = ctx.createBufferSource(); src.buffer = buf; src.connect(out); src.start(now);
    } else {
      // 종 톡- (단톤)
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'triangle'; o.frequency.setValueAtTime(990, now);
      g.gain.setValueAtTime(0.0001, now); g.gain.linearRampToValueAtTime(0.18, now + 0.01); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.25);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.28);
    }
  } catch (e) {}
}
function _spOrbArrive(variant) {
  if (sfxMuted) return;
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    const now = ctx.currentTime;
    const out = ctx.destination;
    if (variant === 1) {
      // 도착 — 종소리 chime + 살짝 sparkle
      const o1 = ctx.createOscillator(); const g1 = ctx.createGain();
      o1.type = 'triangle'; o1.frequency.setValueAtTime(1568, now);
      g1.gain.setValueAtTime(0.0001, now); g1.gain.linearRampToValueAtTime(0.20, now + 0.02); g1.gain.exponentialRampToValueAtTime(0.0001, now + 0.45);
      o1.connect(g1); g1.connect(out); o1.start(now); o1.stop(now + 0.5);
      const o2 = ctx.createOscillator(); const g2 = ctx.createGain();
      o2.type = 'sine'; o2.frequency.setValueAtTime(2349, now + 0.04);
      g2.gain.setValueAtTime(0.0001, now + 0.04); g2.gain.linearRampToValueAtTime(0.10, now + 0.06); g2.gain.exponentialRampToValueAtTime(0.0001, now + 0.32);
      o2.connect(g2); g2.connect(out); o2.start(now + 0.04); o2.stop(now + 0.36);
    } else if (variant === 2) {
      // 단순 핑 — 1500Hz
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.setValueAtTime(1500, now);
      g.gain.setValueAtTime(0.22, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.32);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.35);
    } else if (variant === 3) {
      // 도착 통통 — 나무 상자 풍
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'square'; o.frequency.setValueAtTime(420, now); o.frequency.exponentialRampToValueAtTime(180, now + 0.1);
      g.gain.setValueAtTime(0.18, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.18);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.2);
    } else {
      // 푹- (저음 임팩트 + 고음 sparkle)
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.setValueAtTime(220, now);
      g.gain.setValueAtTime(0.20, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.18);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.2);
      const o2 = ctx.createOscillator(); const g2 = ctx.createGain();
      o2.type = 'triangle'; o2.frequency.setValueAtTime(2640, now);
      g2.gain.setValueAtTime(0.10, now); g2.gain.exponentialRampToValueAtTime(0.0001, now + 0.18);
      o2.connect(g2); g2.connect(out); o2.start(now); o2.stop(now + 0.2);
    }
  } catch (e) {}
}

// 인스턴트 SP 소비/획득 효과음 — 사용자 확정: 둘 다 SFX 3
const SP_INSTANT_CONSUME_VARIANT = 3;  // 3: 흩날림 (3음 빠른 캐스케이드)
const SP_INSTANT_GAIN_VARIANT = 3;     // 3: 황홀 sparkle (5음 1500→3300 상승)
function playSfxInstantConsume() { _spInstantConsume(SP_INSTANT_CONSUME_VARIANT); }
function playSfxInstantGain() { _spInstantGain(SP_INSTANT_GAIN_VARIANT); }
function _spInstantConsume(variant) {
  if (sfxMuted) return;
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    const now = ctx.currentTime;
    const out = ctx.destination;
    if (variant === 1) {
      // 황금 풉— 빠르게 사라지는 톤
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.setValueAtTime(2200, now); o.frequency.exponentialRampToValueAtTime(900, now + 0.25);
      g.gain.setValueAtTime(0.18, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.3);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.32);
    } else if (variant === 2) {
      // 빠른 허밍 — 인스턴트 소비 (단발)
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'triangle'; o.frequency.setValueAtTime(1320, now);
      g.gain.setValueAtTime(0.16, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.18);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.2);
    } else if (variant === 3) {
      // 흩날림 — 3음 빠른 캐스케이드 (1800/2400/3000 Hz)
      [1800, 2400, 3000].forEach((f, i) => {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        const t = now + i * 0.04;
        o.type = 'sine'; o.frequency.setValueAtTime(f, t);
        g.gain.setValueAtTime(0.12, t); g.gain.exponentialRampToValueAtTime(0.0001, t + 0.2);
        o.connect(g); g.connect(out); o.start(t); o.stop(t + 0.22);
      });
    } else {
      // 휘릭 (상승)
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sawtooth'; o.frequency.setValueAtTime(800, now); o.frequency.exponentialRampToValueAtTime(2200, now + 0.18);
      g.gain.setValueAtTime(0.10, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.22);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.25);
    }
  } catch (e) {}
}
function _spInstantGain(variant) {
  if (sfxMuted) return;
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    const now = ctx.currentTime;
    const out = ctx.destination;
    if (variant === 1) {
      // 풍성한 화음 — 마법사 인스턴트 매직 (메이저 트라이어드 + 종)
      [1047, 1319, 1568].forEach((f, i) => {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        const t = now + i * 0.05;
        o.type = 'triangle'; o.frequency.setValueAtTime(f, t);
        g.gain.setValueAtTime(0.0001, t); g.gain.linearRampToValueAtTime(0.16, t + 0.02); g.gain.exponentialRampToValueAtTime(0.0001, t + 0.45);
        o.connect(g); g.connect(out); o.start(t); o.stop(t + 0.5);
      });
    } else if (variant === 2) {
      // 단순 황금 핑
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.setValueAtTime(1760, now);
      g.gain.setValueAtTime(0.20, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.4);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.4);
    } else if (variant === 3) {
      // 황홀 sparkle (빠른 5음 상승)
      [1500, 1800, 2200, 2700, 3300].forEach((f, i) => {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        const t = now + i * 0.045;
        o.type = 'triangle'; o.frequency.setValueAtTime(f, t);
        g.gain.setValueAtTime(0.0001, t); g.gain.linearRampToValueAtTime(0.14, t + 0.02); g.gain.exponentialRampToValueAtTime(0.0001, t + 0.25);
        o.connect(g); g.connect(out); o.start(t); o.stop(t + 0.27);
      });
    } else {
      // 둥— + 차임
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'sine'; o.frequency.setValueAtTime(440, now);
      g.gain.setValueAtTime(0.18, now); g.gain.exponentialRampToValueAtTime(0.0001, now + 0.5);
      o.connect(g); g.connect(out); o.start(now); o.stop(now + 0.5);
      const o2 = ctx.createOscillator(); const g2 = ctx.createGain();
      o2.type = 'triangle'; o2.frequency.setValueAtTime(1760, now + 0.05);
      g2.gain.setValueAtTime(0.0001, now + 0.05); g2.gain.linearRampToValueAtTime(0.12, now + 0.07); g2.gain.exponentialRampToValueAtTime(0.0001, now + 0.32);
      o2.connect(g2); g2.connect(out); o2.start(now + 0.05); o2.stop(now + 0.35);
    }
  } catch (e) {}
}

// SP 지급 마법 차임 — 부드러운 종소리 (페어리 톤)
function playSpGrantChime() {
  if (sfxMuted) return;
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    const now = ctx.currentTime;
    const out = ctx.destination;
    // 종소리 5음 — C5, E5, G5, C6, E6 부드럽게 캐스케이드
    const notes = [523, 659, 784, 1047, 1319];
    notes.forEach((freq, i) => {
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = 'triangle';
      o.frequency.setValueAtTime(freq, now + i * 0.18);
      g.gain.setValueAtTime(0.0001, now + i * 0.18);
      g.gain.linearRampToValueAtTime(0.16, now + i * 0.18 + 0.04);
      g.gain.exponentialRampToValueAtTime(0.0001, now + i * 0.18 + 0.7);
      o.connect(g); g.connect(out);
      o.start(now + i * 0.18); o.stop(now + i * 0.18 + 0.8);
    });
    // 후반부 더스트 — 고음 sparkle
    setTimeout(() => {
      [2400, 3200, 4000].forEach((f, i) => {
        const o = ctx.createOscillator(); const g = ctx.createGain();
        const t = ctx.currentTime + i * 0.06;
        o.type = 'sine';
        o.frequency.setValueAtTime(f, t);
        g.gain.setValueAtTime(0.0001, t);
        g.gain.linearRampToValueAtTime(0.08, t + 0.02);
        g.gain.exponentialRampToValueAtTime(0.0001, t + 0.4);
        o.connect(g); g.connect(out);
        o.start(t); o.stop(t + 0.5);
      });
    }, 1200);
  } catch (e) {}
}

// 1대1 대치 풀스크린 알림 — 게임 시작 오버레이와 동일 스타일
function playStalemateShrinkAlert(msg) {
  let overlay = document.getElementById('stalemate-overlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'stalemate-overlay';
    overlay.className = 'game-start-overlay stalemate-overlay';
    document.body.appendChild(overlay);
  }
  overlay.innerHTML = `
    <div class="game-start-title" style="color:var(--danger)">1대1 대치</div>
    <div class="game-start-sub">5턴 후 보드가 축소됩니다.</div>
  `;
  overlay.classList.remove('hidden');
  overlay.classList.add('active');
  // 긴장감 있는 사운드 — 저음 임팩트 + 경고 톤
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    const now = ctx.currentTime;
    const out = ctx.destination;
    // 저음 임팩트
    const boom = ctx.createOscillator(); const bg = ctx.createGain();
    boom.type = 'sawtooth';
    boom.frequency.setValueAtTime(150, now);
    boom.frequency.exponentialRampToValueAtTime(60, now + 0.5);
    bg.gain.setValueAtTime(0.25, now);
    bg.gain.exponentialRampToValueAtTime(0.001, now + 0.6);
    boom.connect(bg); bg.connect(out);
    boom.start(now); boom.stop(now + 0.6);
    // 경고 트럼펫
    const trumpet = ctx.createOscillator(); const tg = ctx.createGain();
    trumpet.type = 'square';
    trumpet.frequency.setValueAtTime(440, now + 0.2);
    trumpet.frequency.setValueAtTime(660, now + 0.4);
    trumpet.frequency.setValueAtTime(880, now + 0.6);
    tg.gain.setValueAtTime(0.15, now + 0.2);
    tg.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
    trumpet.connect(tg); tg.connect(out);
    trumpet.start(now + 0.2); trumpet.stop(now + 1.0);
  } catch (e) {}
  setTimeout(() => {
    overlay.classList.remove('active');
    overlay.classList.add('hidden');
  }, 3000);
}

// ── 보드 축소 경고 ──
// 사용자 요청: 토스트·로그 출력 제거. 보드 최상단 텍스트와 카운트다운=10 오버레이만 유지.
// ★ 여러 축소 시퀀스가 동시 활성 가능 (예: 1대1 대치 트리거 + 1v1 40턴 정기 축소) — 각각을
//   별도 박스로 위/아래 스택. 서버가 'key' (예: '1v1-50', 'stalemate-25') 로 식별.
function _getShrinkWarnContainer() {
  let c = document.getElementById('shrink-warning-container');
  if (!c) {
    // 호환: 컨테이너가 없으면 legacy 단일 박스 옆에 생성
    c = document.createElement('div');
    c.id = 'shrink-warning-container';
    c.className = 'shrink-warning-container';
    const legacy = document.getElementById('shrink-warning');
    if (legacy && legacy.parentNode) legacy.parentNode.insertBefore(c, legacy);
  }
  return c;
}
function _renderShrinkWarnItem(key, text, opts) {
  const c = _getShrinkWarnContainer();
  if (!c) return;
  // key 가 없는 (구 emit) 경우 기존 단일 슬롯 사용
  const safeKey = key || '__default__';
  let item = c.querySelector(`[data-shrink-key="${CSS.escape(safeKey)}"]`);
  if (!item) {
    item = document.createElement('div');
    item.className = 'shrink-warning shrink-warning-item';
    item.dataset.shrinkKey = safeKey;
    c.appendChild(item);
  }
  if (opts && opts.stalemate) item.classList.add('shrink-warning-stalemate');
  else item.classList.remove('shrink-warning-stalemate');
  item.textContent = text;
  return item;
}
function _removeShrinkWarnItem(key) {
  const c = document.getElementById('shrink-warning-container');
  if (!c) return;
  const safeKey = key || '__default__';
  const item = c.querySelector(`[data-shrink-key="${CSS.escape(safeKey)}"]`);
  if (item && item.parentNode) item.parentNode.removeChild(item);
}
socket.on('board_shrink_warning', ({ turnsRemaining, key, stalemate, stage }) => {
  // 라벨 — stalemate 시퀀스는 별도로 명시
  const label = stalemate
    ? `1대1 대치 외곽 파괴까지 ${turnsRemaining}턴`
    : `외곽 파괴까지 ${turnsRemaining}턴`;
  _renderShrinkWarnItem(key, label, { stalemate });
  // 카운트다운이 10턴 남았을 때 — 풀스크린 인트로 강제 재생 (페이드 1s + 유지 1s + 페이드 1s)
  // 같은 stage/key 중복 호출 방지 — 매 턴 emit 이지만 인트로는 한 번만.
  if (turnsRemaining === 10) {
    if (!S._shrinkIntroFiredKeys) S._shrinkIntroFiredKeys = new Set();
    const introKey = key || `stage-${stage}`;
    if (!S._shrinkIntroFiredKeys.has(introKey)) {
      S._shrinkIntroFiredKeys.add(introKey);
      runFullscreenLocked(() => playBoardShrinkIntro(), 3000);
    }
  }
});

// ── 보드 축소 실행 ──
//   사용자 #24: 애니메이션 페이즈 소속. runFullscreenLocked 로 큐잉되어 다른 phase 애니와
//   0.5s 텀으로 순차 재생. SP 지급은 항상 이 다음.
socket.on('board_shrink', ({ bounds, eliminated, key }) => {
  // 매칭되는 경고 박스 즉시 제거 (해당 시퀀스 종료) — 다른 시퀀스 박스는 유지
  if (key) _removeShrinkWarnItem(key);
  // ★ 사용자 보고: 토스트/로그가 fullscreen 락 동안 buffered 되어 애니 끝난 후 늦게 출력 → 어색함.
  //   애니메이션과 동시에 보이도록 lock 진입 *전* 에 즉시 발사.
  if (!S.isSpectator) {
    showSkillToast('🔥 보드 외곽 파괴', false, undefined, 'event');
    addLog(`🔥 보드 외곽 파괴`, 'shrink');
  }
  runFullscreenLocked(() => _executeBoardShrinkAnim(bounds, eliminated), 3000);
});

function _executeBoardShrinkAnim(bounds, eliminated) {
  playSfx('shrink');
  try { playBoardQuake(); } catch (e) {}
  // ★ 보드 파괴 종료 시 결과 화면이 파괴 애니/프로필 갱신 도중 튀어나오지 않도록,
  //   이 연출이 끝나는 시점(보드 흔들림 1000ms 포함)을 기록해 둔다. scheduleGameOverReveal 가 참조.
  S._shrinkAnimUntil = Date.now() + 1200;
  S.boardBounds = bounds;
  S._cellFP = null; // ★ 보드 축소 — 핑거프린트 캐시 무효화
  S._shrinkOccurredCount = (S._shrinkOccurredCount || 0) + 1;
  // #24: 보드 파괴로 *완전 탈락*한 플레이어 추적 — 프로필 블록 위에 '탈락' 도장 표시용.
  //   사용자 요청: 도장은 캐릭터 카드가 아니라 *플레이어 프로필* 블록에 (두 캐릭터 위를 덮음).
  if (!S._shrunkEliminatedPlayers) S._shrunkEliminatedPlayers = new Set();
  // 이번 emit 에서 영향 받은 owner 들 수집
  const affectedOwners = new Set();
  for (const e of (eliminated || [])) affectedOwners.add(e.owner);
  // 각 owner 의 모든 piece 가 dead 면 (= 보드 파괴로 풀 탈락) 도장 부착
  for (const ownerIdx of affectedOwners) {
    if (S.isTeamMode) {
      const pl = (S.teamGamePlayers || []).find(p => p.idx === ownerIdx);
      if (pl && pl.pieces && pl.pieces.length > 0 && pl.pieces.every(p => !p.alive)) {
        S._shrunkEliminatedPlayers.add(ownerIdx);
      }
    } else {
      const arr = (ownerIdx === S.playerIdx) ? S.myPieces : S.oppPieces;
      if (arr && arr.length > 0 && arr.every(p => !p.alive)) {
        S._shrunkEliminatedPlayers.add(ownerIdx);
      }
    }
  }
  // ※ 토스트/로그는 board_shrink 핸들러에서 lock 진입 전 즉시 발사됨 (사용자 요청 — 동기화).
  if (eliminated && eliminated.length > 0) {
    // 같은 편(내 편/적 편)끼리 묶어서 한 번에 표시 (인벤토리 #F 외곽 말 파괴 row 빨간 피드백)
    // 1v1: e.owner === S.playerIdx 면 내 편, 아니면 적 편
    // 팀전: e.owner의 팀이 내 팀이면 내 편, 아니면 적 편
    // 관전자: 팀/플레이어 인덱스 0,1 별로 분리
    const formatGroup = (group) => group.map(e => `${pieceIconHtml(e.icon, {size:'1em'})}${e.name}`).join(', ');
    if (S.isSpectator) {
      // 관전자는 두 팀(또는 두 플레이어)로 분리. 사용자 #24: 토스트 X, 로그만.
      const groups = new Map();
      for (const e of eliminated) {
        const key = e.owner;
        if (!groups.has(key)) groups.set(key, []);
        groups.get(key).push(e);
      }
      for (const [ownerIdx, list] of groups.entries()) {
        addLog(`💀 ${formatGroup(list)} 탈락`, 'shrink');
      }
    } else {
      const isAllyOwner = (ownerIdx) => {
        if (S.isTeamMode) {
          const owner = (S.teamGamePlayers || []).find(p => p.idx === ownerIdx);
          return owner ? owner.teamId === S.teamId : false;
        }
        return ownerIdx === S.playerIdx;
      };
      const myGroup = [];
      const oppGroup = [];
      for (const e of eliminated) {
        (isAllyOwner(e.owner) ? myGroup : oppGroup).push(e);
      }
      const myLabel = S.isTeamMode ? '우리 편' : myN();
      const oppLabel = S.isTeamMode ? '적 편' : oppN();
      // 사용자 #24: 보드 파괴 사망은 토스트 X, 로그만 ([name 탈락]).
      if (myGroup.length > 0) addLog(`💀 ${myLabel}의 ${formatGroup(myGroup)} 탈락`, 'shrink');
      if (oppGroup.length > 0) addLog(`💀 ${oppLabel}의 ${formatGroup(oppGroup)} 탈락`, 'shrink');
    }
  }
  const sw = document.getElementById('shrink-warning');
  if (sw) sw.classList.add('hidden');
  renderGameBoard();
  if (S.isTeamMode) {
    if (typeof renderTeamProfiles === 'function') renderTeamProfiles();
  } else {
    renderMyPieces();
    renderOppPieces();
  }
  // 외곽이 destroyed 클래스로 보이는 상태에서 흔들림
  const boardEl = document.getElementById('game-board');
  if (boardEl) {
    boardEl.classList.add('board-shake');
    setTimeout(() => boardEl.classList.remove('board-shake'), 1000);
  }
}

// 힐 애니메이션: 지정된 인덱스의 piece 카드 2초간 초록 glow
// ★ 1v1 경로 — 회복된 카드에도 turn-bright 부여하여 그 턴 동안 풀 밝기 유지
//   (applyHealFlashWithBrighten 위임 — 레지스트리 등록 포함).
function flashHealPieces(indexes, opts) {
  const o = opts || {};
  const containerSelector = o.opp ? '#opp-pieces-info' : '#my-pieces-info';
  const cardSelector = o.opp ? '.opp-piece-card' : '.my-piece-card';
  const container = document.querySelector(containerSelector);
  if (!container) return;
  const cards = container.querySelectorAll(cardSelector);
  for (const idx of indexes) {
    const card = cards[idx];
    if (!card) continue;
    if (typeof applyHealFlashWithBrighten === 'function') {
      applyHealFlashWithBrighten(card);
    } else {
      card.classList.add('heal-flash');
      setTimeout(() => card.classList.remove('heal-flash'), 2000);
    }
    // 파티클 반짝이 추가
    spawnHealSparkles(card);
  }
}

// owner-aware 버전 — { ownerIdx, pieceIdx } 페어 배열을 받아 1v1/팀모드 양쪽에서 정확한 카드 매핑.
//   팀모드 약초학: 시전자뿐 아니라 팀원의 회복 대상도 카드 매핑 가능 (서버가 모든 healed 페어 전달).
// ★ 사용자 보고 (팀모드 회복 시 딤 미해제): 기존엔 heal-flash 만 추가해 dim 이 풀리지 않음.
//   applyHealFlashWithBrighten 로 위임해 turn-bright + 레지스트리 등록까지 일괄 처리 → 회복된
//   대상 (팀원 회복 포함) 카드가 그 턴 동안 풀 밝기 유지.
function flashHealPiecesByOwner(healedPieces) {
  if (!Array.isArray(healedPieces) || healedPieces.length === 0) return;
  for (const h of healedPieces) {
    if (h == null || typeof h.ownerIdx !== 'number' || typeof h.pieceIdx !== 'number') continue;
    const card = (typeof _findPieceCard === 'function') ? _findPieceCard(h.ownerIdx, h.pieceIdx) : null;
    if (!card) continue;
    if (typeof applyHealFlashWithBrighten === 'function') {
      applyHealFlashWithBrighten(card);
    } else {
      card.classList.add('heal-flash');
      setTimeout(() => card.classList.remove('heal-flash'), 2000);
    }
    spawnHealSparkles(card);
  }
}

// flashCursePieces 제거됨 — 사용자 요청으로 저주 점멸 효과 비활성화 (보라 도장 + 상시 배경으로 대체)

// 회복 시 카드 위에 반짝이는 파티클 6개를 짧게 띄움
function spawnHealSparkles(card) {
  const rect = card.getBoundingClientRect();
  const sparkleChars = ['✨', '✦', '★', '✧', '⭐', '✨'];
  const count = 6;
  for (let i = 0; i < count; i++) {
    const sp = document.createElement('div');
    sp.className = 'heal-sparkle';
    sp.textContent = sparkleChars[i % sparkleChars.length];
    const sx = rect.left + Math.random() * rect.width;
    const sy = rect.top + Math.random() * rect.height;
    sp.style.left = sx + 'px';
    sp.style.top = sy + 'px';
    sp.style.animationDelay = (Math.random() * 0.4) + 's';
    document.body.appendChild(sp);
    setTimeout(() => sp.remove(), 1500);
  }
}

// ── 저주 파티클 (불씨 도트) ──
// 저주 상태 카드의 바닥에서 작은 도트가 랜덤 시점에 생겨 위로 떠오름. 좌우로 살짝 흔들림.
const CURSE_PARTICLE_COLORS = ['#d8b4fe', '#c084fc', '#a855f7', '#e9d5ff', '#c4b5fd'];
const CURSE_RISE_KEYFRAMES = ['curse-rise-a', 'curse-rise-b', 'curse-rise-c'];
function spawnCurseParticle(card) {
  if (!card || !card.classList.contains('curse-active')) return;
  const p = document.createElement('div');
  p.className = 'curse-particle';
  // 위치·크기·색·키프레임·지속시간 모두 랜덤
  const size = 3 + Math.floor(Math.random() * 3);   // 3~5px 정사각형 도트
  p.style.width = size + 'px';
  p.style.height = size + 'px';
  p.style.left = (5 + Math.random() * 90) + '%';
  p.style.background = CURSE_PARTICLE_COLORS[Math.floor(Math.random() * CURSE_PARTICLE_COLORS.length)];
  // 박스섀도우로 약한 글로우
  p.style.boxShadow = `0 0 4px ${p.style.background}`;
  const kf = CURSE_RISE_KEYFRAMES[Math.floor(Math.random() * CURSE_RISE_KEYFRAMES.length)];
  const dur = 1.6 + Math.random() * 1.4;             // 1.6~3.0s
  p.style.animation = `${kf} ${dur}s linear forwards`;
  // 카드 높이를 --rise 변수로 부여 → 파티클이 카드 전체를 가로질러 상단까지 상승
  const cardH = card.getBoundingClientRect().height || 100;
  p.style.setProperty('--rise', cardH + 'px');
  card.appendChild(p);
  setTimeout(() => { if (p.parentNode) p.remove(); }, dur * 1000 + 100);
}
// 모든 .curse-active 카드를 주기적으로 순회하며 확률적으로 파티클 스폰 → 자연스러운 랜덤 등장
function _curseParticleTick() {
  const cards = document.querySelectorAll('.my-piece-card.curse-active, .opp-piece-card.curse-active');
  cards.forEach(card => {
    // 카드당 확률 60% — 매 tick 마다 결정
    if (Math.random() < 0.6) spawnCurseParticle(card);
  });
}
// 200ms 마다 tick (카드당 평균 0.6/0.2s = 초당 3개 정도 스폰)
setInterval(_curseParticleTick, 200);

// 쿠구궁 효과음 — Web Audio로 생성 (저주파 + 노이즈)
function playBoardQuake() {
  if (sfxMuted) return;
  try {
    const ctx = getAudioCtx(); if (!ctx) return;
    // 저주파 rumble
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain); gain.connect(ctx.destination);
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(60, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(30, ctx.currentTime + 0.9);
    gain.gain.setValueAtTime(0.0, ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.6, ctx.currentTime + 0.08);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.0);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 1.0);
  } catch (e) {}
}

// ── 스킬 결과 ──
// 시전 시퀀스 (사용자 요청):
//   ① 화면 dim 오버레이 등장 — SP 바·시전자 프로필만 spotlight (밝게 유지)
//   ② SP 차감 집중 + 마법구 비행 (~2s)
//   ③ 화면 dim 해제 (밝아짐)
//   ④ 0.5초 후 — 스킬 효과 시전 (HP/보드 업데이트, 셀 애니, 토스트, 로그)
socket.on('skill_result', ({ msg, success, yourPieces, oppPieces, sp, instantSp, boardObjects, remains, actionDone, actionUsedSkillReplace, skillsUsed, data, effects, pieceIdx, casterPieceIdx }) => {
  // ★ 스킬로 사망 발생 시 game_over 조기 노출 방지 가드 (동기 — _pendingDeathCells 세팅 전 브리지)
  _markSkillDeathIncoming(data && data.hits);
  const oldOppHps = S.oppPieces ? S.oppPieces.map(p => p.hp) : [];
  const oldMyHps = S.myPieces.map(p => p.hp);
  const oldSpSnap = Array.isArray(S.sp) ? [...S.sp] : [0, 0];
  const oldInstantSnap = Array.isArray(S.instantSp) ? [...S.instantSp] : [0, 0];

  // 1단계 — 즉시: 행동 플래그 + dim 오버레이 + SP 차감 집중 (마법구 비행)
  //   ★ SFX 는 SP 비행 종료 시점(SP_END) 으로 이동 — 보드 효과/토스트 와 동기화.
  if (actionDone !== undefined) S.actionDone = actionDone;
  if (actionUsedSkillReplace !== undefined) S.actionUsedSkillReplace = actionUsedSkillReplace;
  if (skillsUsed) S.skillsUsedThisTurn = skillsUsed;
  // dim 오버레이 + 시전자 프로필 spotlight (mine: 본인 카드)
  // 시전자 인덱스: 서버가 casterPieceIdx 로 보내며, 구 버전 호환을 위해 pieceIdx 도 fallback
  const _casterIdx = (typeof casterPieceIdx === 'number') ? casterPieceIdx
                    : (typeof pieceIdx === 'number') ? pieceIdx : null;
  const casterCard = (_casterIdx !== null)
    ? (S.isTeamMode
        ? document.querySelector(`#my-pieces-info .team-profile-block[data-player-idx="${S.playerIdx}"] [data-piece-idx="${_casterIdx}"]`)
        : document.querySelectorAll('#my-pieces-info .my-piece-card')[_casterIdx])
    : null;
  // targetInfo: 팀모드에서 재렌더 후 spotlight 재적용을 위해 caster 식별자 저장
  const _targetInfo = (S.isTeamMode && _casterIdx !== null && S.playerIdx != null)
    ? { playerIdx: S.playerIdx, pieceIdx: _casterIdx }
    : null;
  startSkillCastDim(casterCard, _targetInfo);
  // SP 마법구 이동
  try { spendSPAttention(oldSpSnap, sp || S.sp, oldInstantSnap, instantSp || S.instantSp); } catch (e) {}
  if (typeof setActionButtonMode === 'function') setActionButtonMode(null);

  // ★ 시전자 말풍선 — 시전자 카드에서 보드 쪽으로 꼬리 달린 스킬명 말풍선 (2초 유지)
  if (casterCard && _casterIdx != null) {
    const casterPc = (S.myPieces || [])[_casterIdx];
    const skName = (casterPc?.skills || []).find(s => (s.cost || 0) > 0)?.name
                 || casterPc?.skillName
                 || (msg ? (msg.match(/[가-힣A-Za-z]+(?=:)/) || [])[0] : null);
    // skillsUsed 의 마지막 사용 스킬을 우선 (정확)
    const lastUsed = skillsUsed && skillsUsed.length > 0 ? skillsUsed[skillsUsed.length - 1] : null;
    const lastSkillId = lastUsed ? lastUsed.split(':').pop() : null;
    const matchedSkill = casterPc && lastSkillId
      ? (casterPc.skills || []).find(s => s.id === lastSkillId)
      : null;
    const finalName = matchedSkill?.name || skName;
    if (finalName) {
      const stype = getSkillTypeFromPiece(casterPc, finalName);
      showSkillCastBubble(casterCard, finalName, stype);
    }
  }

  // ★ 분신 비행 애니메이션 — msg 가 "👫 분신" 으로 시작하면 mover 가 잔상 남기며 target 으로 빠르게 비행.
  //   비교: OLD S.myPieces 위치 vs NEW yourPieces 위치 → 좌표가 변한 쪽이 mover.
  //   비행 동안 mover 의 piece-marker 는 visibility:hidden, 도착 시 보드 재렌더로 합류 emoji 출현.
  if (msg && msg.indexOf('분신') >= 0 && yourPieces && typeof playTwinJoinFlight === 'function') {
    const oldElder   = (S.myPieces || []).find(p => p.subUnit === 'elder' && p.alive);
    const oldYounger = (S.myPieces || []).find(p => p.subUnit === 'younger' && p.alive);
    const newElder   = (yourPieces || []).find(p => p.subUnit === 'elder' && p.alive);
    const newYounger = (yourPieces || []).find(p => p.subUnit === 'younger' && p.alive);
    let moverSub = null, fromCol, fromRow, toCol, toRow;
    if (oldElder && newElder && (oldElder.col !== newElder.col || oldElder.row !== newElder.row)) {
      moverSub = 'elder'; fromCol = oldElder.col; fromRow = oldElder.row; toCol = newElder.col; toRow = newElder.row;
    } else if (oldYounger && newYounger && (oldYounger.col !== newYounger.col || oldYounger.row !== newYounger.row)) {
      moverSub = 'younger'; fromCol = oldYounger.col; fromRow = oldYounger.row; toCol = newYounger.col; toRow = newYounger.row;
    }
    if (moverSub) playTwinJoinFlight(moverSub, fromCol, fromRow, toCol, toRow);
  }

  // ★ 통일된 시퀀스 — SP 오브 비행 종료 시점에 SFX/보드 효과/토스트/로그 동시 발사.
  //   SP_END(cost) = 780 + (cost-1) * 130 ms.  cost 0 (기폭) → 1 로 처리해 780ms.
  //   T+0       : 마법구 비행 시작 + 시전자 spotlight (dim)
  //   T+SP_END  : SFX + 스킬 효과(HP/보드) + 토스트/로그 + dim 해제 — 모두 동시
  const _spCost = spCostFromDelta(oldSpSnap, sp || S.sp, oldInstantSnap, instantSp || S.instantSp);
  const TOAST_DELAY_MS = getSpFlightEndMs(_spCost);
  // ★ FIX (팀전 스킬 타이밍): 마법구 착지 예정 시각 기록 → 곧 도착할 team_game_update 가 이 시각까지
  //   보드/HP 시각 갱신을 지연(1v1 호흡 통일). 서버가 skill_result 를 broadcast 보다 먼저 보내므로
  //   team_game_update 도착 시점엔 이미 설정돼 있음.
  S._teamRenderGateUntil = Date.now() + TOAST_DELAY_MS;
  const isDetonate = data && Array.isArray(data.deferredBombEmits) && data.deferredBombEmits.length > 0;

  // 2단계 — T+SP_END: SFX + 스킬 효과 + 토스트·로그 + dim 해제 (모두 동시)
  setTimeout(() => {
    // SFX — 보드 효과와 정확히 같은 순간에 재생
    //   ★ 기폭(isDetonate) 은 detonation_intro 의 blast 단계(T+SP_END+550) 에서 폭발 SFX 재생 →
    //     여기서 또 호출하면 시전 시점에 폭발음이 미리 들림. 스킵.
    if (msg && !isDetonate) {
      const sfxRoute = pickSkillSfxByMsg(msg);
      if (sfxRoute) sfxRoute(); else playSfx('skill');
    }
    endSkillCastDim(casterCard);
    if (sp) { S.sp = sp; }
    if (instantSp) { S.instantSp = instantSp; }
    if (sp || instantSp) { updateSPBar(); }

    // 스킬 효과 적용 — 기폭은 별도 detonation_intro/bomb_detonated 흐름이라 HP 업데이트 스킵
    if (!isDetonate) {
      // ★ 스킬 사망 감지 — 상태 업데이트 전에 DOM 에서 방향 캡처 (renderGameBoard 전이라 marker 존재)
      //   악몽뿐 아니라 유황범람 등 data.hits 를 가진 모든 데미지 스킬의 사망을 처리.
      let _nightmareDeathInfos = [];
      if (data && Array.isArray(data.hits) && data.hits.some(h => h.destroyed)) {
        const _nmDead = data.hits.filter(h => h.destroyed);
        _nightmareDeathInfos = _detectDeaths(_nmDead, false); // 시전자 시점 → 적 말 사망 (isEnemy=true)
        // _pendingDeathCells 설정 → renderGameBoard 가 사망 유닛의 idle GIF 를 유지
        if (_nightmareDeathInfos.length > 0) {
          if (!S._pendingDeathCells) S._pendingDeathCells = new Set();
          for (const di of _nightmareDeathInfos) S._pendingDeathCells.add(`${di.col},${di.row}`);
        }
      }

      if (yourPieces) S.myPieces = yourPieces;
      if (oppPieces) S.oppPieces = oppPieces;
      pruneDeductionTokens();
      if (boardObjects) S.boardObjects = boardObjects;
      // ★ 스킬 사망 셀의 유해는 사망 GIF 완료 후 추가 (즉시 반영 시 사망 모션과 유해 동시 표시 버그).
      _applyServerRemainsExcludingDeaths(remains, _nightmareDeathInfos);

      const oppSkillDmgIdx = [];
      if (S.oppPieces) {
        for (let i = 0; i < S.oppPieces.length; i++) {
          if (i < oldOppHps.length && S.oppPieces[i].hp < oldOppHps[i]) oppSkillDmgIdx.push(i);
        }
      }
      const mySkillDmgIdx = [];
      for (let i = 0; i < S.myPieces.length; i++) {
        if (i < oldMyHps.length && S.myPieces[i].hp < oldMyHps[i]) mySkillDmgIdx.push(i);
      }
      // 회복 추적 — HP 가 늘어난 pieces 의 delta 를 healThisTurn 에 누적 (녹색 도장 + HP 바 녹색 오버레이)
      // ★ FIX (팀전 회복 도장 2 중복): 팀 모드는 team_game_update 가 HP 스냅샷 diff 로 회복 도장을
      //   단일 소스로 처리함. 여기서 또 같은 키(`${ownerIdx}:${i}`)로 addHeal 하면 1회복이 2로 찍힘
      //   (예: 약초학 호위무사 1회복 → 2회복 표시). 따라서 팀 모드에서는 skill_result 회복 도장을 스킵.
      const _myStampPrefix = S.isTeamMode ? null : 'my';
      const _oppStampPrefix = S.isTeamMode
        ? null  // 팀 모드는 owner 별 키이므로 별도 처리 필요 (skill_result 에서 opp 회복은 드뭄)
        : 'opp';
      if (_myStampPrefix) {
        for (let i = 0; i < S.myPieces.length; i++) {
          if (i < oldMyHps.length && S.myPieces[i].hp > oldMyHps[i]) {
            addHeal(`${_myStampPrefix}:${i}`, S.myPieces[i].hp - oldMyHps[i]);
          }
        }
      }
      if (S.oppPieces && _oppStampPrefix) {
        for (let i = 0; i < S.oppPieces.length; i++) {
          if (i < oldOppHps.length && S.oppPieces[i].hp > oldOppHps[i]) {
            addHeal(`${_oppStampPrefix}:${i}`, S.oppPieces[i].hp - oldOppHps[i]);
          }
        }
      }

      // ★ FIX: team_game_update 는 게이트(마법구 비행) 중 보드를 렌더하지 않으므로(이 핸들러가 임팩트
      //   시점 렌더 전담), 팀 모드에서도 여기서 반드시 렌더해야 보드/도장이 갱신됨. (이전 _skipTeamRender
      //   는 team_game_update 가 즉시 렌더한다는 가정이었으나, 1v1 통일 위해 렌더를 임팩트 시점으로 일원화.)
      renderGameBoard();
      renderMyPieces();
      renderOppPieces();
      if (S.isMyTurn) showActionBar(true);

      if (!S.isTeamMode) {
        applyProfileHitAnim('#opp-pieces-info .opp-piece-card', oppSkillDmgIdx);
        applyProfileHitAnim('#my-pieces-info .my-piece-card', mySkillDmgIdx);
      } else if (data && Array.isArray(data.hits)) {
        // ★ 사용자 보고 (유황범람 누락 — 시전자 시점): 팀모드에서 데미지 스킬 hit 시 피격 카드 밝아짐 누락.
        requestAnimationFrame(() => {
          for (const h of data.hits) {
            if (h.defPieceIdx == null || h.defOwnerIdx == null) continue;
            if (h.redirectedToBodyguard) continue;
            const isProtected = (h.damage === 0 && !h.destroyed);
            const card = document.querySelector(`.team-profile-block[data-player-idx="${h.defOwnerIdx}"] [data-piece-idx="${h.defPieceIdx}"]`);
            if (!card) continue;
            if (isProtected) {
              applyProtectedAnim(card);
              addProtectedHit(`${h.defOwnerIdx}:${h.defPieceIdx}`);
            } else {
              applyHitFlashWithBrighten(card);
            }
          }
        });
      }
      // ★ 유황범람 라바 애니 (시전자 시점)
      if (data && Array.isArray(data.borderCells) && data.borderCells.length > 0 && typeof animateLavaCells === 'function') {
        animateLavaCells(data.borderCells);
      }
      // ★ 유황범람으로 죽은 쥐 사망 모션 (시전자 시점)
      if (data) _animateSkillDestroyedRats(data.destroyedRats);
      // ★ 악몽 시전 (시전자 시점) — 표식 상태 적 셀에 보라 펄스 + scale.
      if (data && Array.isArray(data.nightmareCells) && data.nightmareCells.length > 0 &&
          typeof animateNightmareCast === 'function') {
        animateNightmareCast(data.nightmareCells, { spiralStyle: 'a', opacityLevel: 2 });
      }
      // ★ 스킬 사망 애니메이션 (시전자 시점) — 스킬 이펙트 후 사망 GIF + 유해 생성
      //   악몽: 보라 펄스 피크(~500ms) 후 사망 GIF. 기타 스킬: 피격 효과 후 사망 GIF.
      //   ★ FIX (유황범람 피격 모션 누락): 라바 스킬은 피격 표시가 +1100ms 지연되는데 사망을 500ms 에
      //     재생하면 사망 GIF 의 재렌더(~1200ms)가 1100ms 의 피격 셀 플래시를 덮어써 피격 모션이 안 보임.
      //     → 라바면 사망을 피격 모션 이후(1600ms)로 지연.
      if (_nightmareDeathInfos.length > 0) {
        const _lavaDeathDelay = (data && Array.isArray(data.borderCells) && data.borderCells.length > 0) ? 1600 : 500;
        setTimeout(() => {
          playDeathAnimations(_nightmareDeathInfos, () => {
            S._pendingDeathCells = null;
            _addClientSideRemains(_nightmareDeathInfos);
            renderGameBoard();
          });
        }, _lavaDeathDelay);
      }
      // ★ 약초학 시전 — 보드에 회복 영역 녹색 빛 + 잎 파티클 (시전자 본인은 항상 봄)
      if (data && data.herbCenter && typeof animateHerbCast === 'function') {
        animateHerbCast(data.herbCenter.col, data.herbCenter.row);
      }
      // ★ 신성 시전 — 대상 셀에 신성한 빛 기둥 + 십자
      if (data && data.divineTarget && typeof animateDivineCast === 'function') {
        animateDivineCast(data.divineTarget.col, data.divineTarget.row);
      }
      // ★ 절대복종 반지 — 오로라 펄스 + 순간이동 + 화이트 페이드. 시전자 본인은 자동 추리 토큰.
      if (data && data.ringTeleport && typeof animateRingTeleport === 'function') {
        // ★ 사용자 보고 (자동 추리 토큰 미동작): push 후 refresh 호출이 없어 DOM 에 토큰이 즉시 안 나타남.
        //   같은 pieceKey 의 기존 토큰은 filter 로 제거 후 새 위치로 push (= 갱신).
        //   refreshDeductionTokens 는 token DOM 만 재배치 → aurora 클래스 wipe 안 함.
        try {
          const rt = data.ringTeleport;
          const subUnit = '';                                // 일반 piece 라 subUnit 없음 (쌍둥이 제외)
          const ownerSuffix = S.isTeamMode ? `@${rt.victimOwnerIdx}` : '';
          const pieceKey = `${rt.victimType}:${subUnit}${ownerSuffix}`;
          S.deductionTokens = (S.deductionTokens || []).filter(t =>
            t.pieceKey !== pieceKey && !(t.col === rt.toCol && t.row === rt.toRow));
          S.deductionTokens.push({ pieceKey, icon: rt.victimIcon, name: rt.victimName, col: rt.toCol, row: rt.toRow });
          if (typeof refreshDeductionTokens === 'function') refreshDeductionTokens();
          if (typeof updateDeductionBadgesInPlace === 'function') updateDeductionBadgesInPlace();
        } catch (e) {}
        animateRingTeleport(data.ringTeleport, 'caster');
        if (window._crForceRingVictim) window._crForceRingVictim(data.ringTeleport);
      }

      const healedIdxs = (data && data.healedPieceIdxs) || (effects && effects.healedPieceIdxs);
      const healedPieces = (data && data.healedPieces) || (effects && effects.healedPieces);
      // 팀모드: healedPieces 가 있으면 owner-aware 매핑 (팀원 회복 카드도 포함)
      // 1v1: 시전자 본인 카드만 healedIdxs 로 매핑 (기존 동작)
      if (S.isTeamMode && Array.isArray(healedPieces) && healedPieces.length > 0) {
        setTimeout(() => flashHealPiecesByOwner(healedPieces), 50);
      } else if (Array.isArray(healedIdxs) && healedIdxs.length > 0) {
        setTimeout(() => flashHealPieces(healedIdxs), 50);
      }

      const hitsData = data && Array.isArray(data.hits) ? data.hits : null;
      if (hitsData && hitsData.length > 0) {
        const cells = hitsData.filter(h => h.col != null && h.row != null).map(h => ({ col: h.col, row: h.row }));
        // ★ 유황범람 라바 애니가 있을 때 hit 셀 표시를 지연 — 라바 ::before 가 빨간 배경을 덮으므로 라바 피크 후 표시
        if (cells.length > 0) {
          const _hasLava = data && Array.isArray(data.borderCells) && data.borderCells.length > 0;
          if (_hasLava) {
            setTimeout(() => { animateAttack([], cells); }, 1100);
          } else {
            animateAttack([], cells);
          }
        }

        // ★ attackLog 기록 — 보드 위 💥/· 셀 마크 (시전자 시점)
        //   borderCells 가 있으면 (유황범람 등) 전체 공격 범위 기록 (빗나감 · + 명중 💥).
        //   borderCells 가 없으면 (악몽 등) hit 셀만 기록.
        const _hitSet = new Set(cells.map(c => `${c.col},${c.row}`));
        if (data && Array.isArray(data.borderCells) && data.borderCells.length > 0) {
          for (const bc of data.borderCells) {
            S.attackLog.push({ col: bc.col, row: bc.row, hit: _hitSet.has(`${bc.col},${bc.row}`), turn: S.turnNumber });
          }
        } else {
          for (const c of cells) {
            S.attackLog.push({ col: c.col, row: c.row, hit: true, turn: S.turnNumber });
          }
        }
        renderGameBoard(); // attackLog 마커 즉시 반영

        // ★ 사용자 보고 (유황범람 누락): 데미지 스킬 hits 도 일반 공격처럼 hit/kill SFX 발생.
        const _meaningfulSkillHits = hitsData.filter(h => !h.redirectedToBodyguard && !(h.damage === 0 && !h.destroyed));
        const _hasKillSkill = _meaningfulSkillHits.some(h => h.destroyed);
        const _hasHitSkill = _meaningfulSkillHits.some(h => !h.destroyed);
        if (_hasKillSkill) { try { playSfx('kill'); } catch (e) {} }
        else if (_hasHitSkill) { try { playSfx('hit'); } catch (e) {} }

        // ★ 본체 빨간 도장 / 호위무사 파란 도장 — being_attacked 와 동일하게 처리.
        //   유황범람·악몽 등 데미지 스킬에서 빠져 있던 처리. defPieceIdx + defOwnerIdx 기반.
        for (const h of hitsData) {
          const dmg = (typeof h.damage === 'number') ? h.damage : 0;
          if (dmg <= 0 || h.defPieceIdx == null) continue;
          // 키 결정: 1v1 → opp:idx (시전자 시점에서 피해는 항상 상대), 팀모드 → ownerIdx:idx
          const key = (S.isTeamMode && h.defOwnerIdx !== undefined)
            ? `${h.defOwnerIdx}:${h.defPieceIdx}`
            : `opp:${h.defPieceIdx}`;
          if (h.bodyguardRedirect) {
            // 호위무사가 대신 받음 → 파란 충성 도장 (BG 카드)
            addLoyaltyDamage(key, dmg);
          } else if (!h.redirectedToBodyguard) {
            // 본체에 직접 들어간 피해 → 빨간 도장 (피격 카드)
            addBodyDamage(key, dmg);
          }
        }
        // ★ addBodyDamage 후 카드 재렌더 — buildDamageOverlay 가 빨간 도장 표시.
        //   재렌더 + 진행 중인 profile-hit/turn-bright 자동 복원 (reapplyActiveProfileAnims).
        if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles();
        else { if (typeof renderMyPieces === 'function') renderMyPieces(); if (typeof renderOppPieces === 'function') renderOppPieces(); }
        // ★ 데미지 스킬 hit 처리 직후 — 버퍼된 wizard / 충성 / 가호 등 패시브 alert flush.
        //   유황범람 같은 데미지 스킬에서 wizard 가 피격되면 server 가 즉시 passive_alert emit →
        //   클라가 _pendingDefensiveAlerts 에 buffer → 여기서 flush. 마법구 비행이 도장과 동기화됨.
        if (typeof flushDefensiveAlerts === 'function') {
          const _killed = (hitsData || []).some(h => h.destroyed);
          flushDefensiveAlerts({ skipReduction: _killed });
        }

        // ★ 사용자 요청: 2명 이상 피격 시 (사망 포함) 자동 추리 토큰 배치 절대 X.
        //   "여러 명 동시 피격" 정보 자체가 추리 단서 — 자동 노출 금지.
        //   이전 버그: aliveHits (사망 제외) 만 카운트 → 2 hit 중 1 사망 → length=1 → 토큰 자동 배치.
        // ★ bodyguardRedirect 도 제외 — 충성으로 대신 맞은 호위무사에 추리 토큰 자동 배치 금지.
        // ★ FIX: 실제 피격된 서로 다른 piece 수를 따로 카운트 — 충성으로 흡수된 원 타깃(redirectedToBodyguard,
        //   예: 척후병)도 1명으로 셈. (bodyguardRedirect 흡수 엔트리는 호위무사 중복 → 제외.)
        //   유황솥이 척후병+호위무사를 동시 타격하면 distinct=2 → 자동 토큰 금지(2명 이상 피격).
        const distinctHitKeys = new Set(hitsData.filter(h => h.defPieceIdx != null && !h.bodyguardRedirect).map(h => `${h.defOwnerIdx ?? ''}:${h.defPieceIdx}`));
        const meaningfulHits = hitsData.filter(h => !h.redirectedToBodyguard && !h.bodyguardRedirect && h.defPieceIdx !== undefined);
        if (distinctHitKeys.size === 1 && meaningfulHits.length === 1 && !meaningfulHits[0].destroyed) {
          const c = meaningfulHits[0];
          let piece = null;
          let pieceKey = null;
          if (S.isTeamMode && c.defOwnerIdx !== undefined) {
            const ownerPlayer = (S.teamGamePlayers || []).find(p => p.idx === c.defOwnerIdx);
            if (ownerPlayer && ownerPlayer.pieces && ownerPlayer.pieces[c.defPieceIdx]) {
              piece = ownerPlayer.pieces[c.defPieceIdx];
              pieceKey = `${piece.type}:${piece.subUnit || ''}@${c.defOwnerIdx}`;
            }
          } else {
            piece = S.oppPieces?.[c.defPieceIdx];
            if (piece) pieceKey = `${piece.type}:${piece.subUnit || ''}`;
          }
          if (piece && pieceKey) {
            try {
              S.deductionTokens = (S.deductionTokens || []).filter(t => t.pieceKey !== pieceKey && !(t.col === c.col && t.row === c.row));
              S.deductionTokens.push({ pieceKey, icon: piece.icon, name: piece.name, col: c.col, row: c.row });
              renderGameBoard();
            } catch (e) {}
          }
        }
      }
    }

    // ★ 저주 부여 시 — 부여된 카드는 그 턴 동안 dim 해제 (turn-bright).
    //   기존엔 저주 데미지(curse_tick) 시점에만 처리. 사용자 요청: 저주 부여 시점에도 동일 처리.
    if (data && typeof data.cursedPieceIdx === 'number') {
      const tIdx = data.cursedPieceIdx;
      const tOwner = (typeof data.cursedOwnerIdx === 'number') ? data.cursedOwnerIdx : null;
      requestAnimationFrame(() => {
        if (S.isTeamMode && tOwner != null) {
          _persistTurnBright(tOwner, tIdx);
          const card = _findPieceCard(tOwner, tIdx);
          if (card) card.classList.add('turn-bright');
        } else if (!S.isTeamMode) {
          _persistTurnBright(1 - S.playerIdx, tIdx);
          const card = document.querySelectorAll('#opp-pieces-info .opp-piece-card')[tIdx];
          if (card) card.classList.add('turn-bright');
        }
      });
    }
    // 토스트·로그 — 스킬 효과와 동시
    if (msg) {
      addLog(msg, 'skill');
      showSkillToast(msg);
    }
  }, TOAST_DELAY_MS);
});

// ── 상태 업데이트 (상대의 스킬 사용 시) ──
socket.on('status_update', ({ oppPieces, yourPieces, sp, instantSp, boardObjects, remains, msg, skillUsed, healedPieceIdxs, healedPieces, casterPieceIdx, twinJoin, hits, borderCells, cursedPieceIdx, cursedOwnerIdx, ringTeleport, nightmareCells, destroyedRats }) => {
  // ★ 분신 비행 애니메이션 — status_update 는 1v1 '적(상대)' 시점이므로 여기선 재생하지 않는다.
  //   (적에게는 분신 애니 비공개. 시전자=skill_result / 팀원=team_skill_notice / 관전자=spectator_skill_anim 에서 재생.)

  // 마법구 비행 + dim 오버레이 — skill_result(시전자) 와 동일한 시퀀스로 재현.
  // 시전자 카드는 1v1 상대 시점이므로 #opp-pieces-info 에 위치.
  // ★ 스킬로 사망 발생 시 game_over 조기 노출 방지 가드 (동기)
  _markSkillDeathIncoming(hits);
  const oldMyHpsCaptured = S.myPieces.map(p => p.hp);
  const oldOppHpsCaptured = S.oppPieces ? S.oppPieces.map(p => p.hp) : [];
  const oldSpSnap = Array.isArray(S.sp) ? [...S.sp] : [0, 0];
  const oldInstantSnap = Array.isArray(S.instantSp) ? [...S.instantSp] : [0, 0];

  const oppCasterCard = (typeof casterPieceIdx === 'number')
    ? document.querySelectorAll('#opp-pieces-info .opp-piece-card')[casterPieceIdx]
    : null;
  startSkillCastDim(oppCasterCard);
  // SP 마법구 비행 — opp 측이 SP 를 소비해 본인 측으로 transfer 되므로 transferToMe 경로(빨간 마법구)가 발동
  try { spendSPAttention(oldSpSnap, sp || S.sp, oldInstantSnap, instantSp || S.instantSp); } catch (e) {}

  // ★ 시전자 말풍선 (1v1 상대 시전 시점)
  if (oppCasterCard && typeof casterPieceIdx === 'number') {
    const oppPc = (S.oppPieces || [])[casterPieceIdx];
    const skName = skillUsed?.skillName || (msg ? (msg.match(/[가-힣A-Za-z]+(?=:)/) || [])[0] : null);
    if (skName) {
      const stype = getSkillTypeFromPiece(oppPc, skName);
      showSkillCastBubble(oppCasterCard, skName, stype);
    }
  }

  // ★ 통일된 시퀀스 — SP 비행 종료 시점에 SFX + 보드 효과 + 토스트/로그 동시 발사
  const _spCost = spCostFromDelta(oldSpSnap, sp || S.sp, oldInstantSnap, instantSp || S.instantSp);
  const TOAST_DELAY_MS = getSpFlightEndMs(_spCost);

  // T+SP_END: SFX + dim 해제 + sp 동기화 + HP/보드 + 토스트·로그 (모두 동시)
  //   ★ 기폭 msg 는 SFX 스킵 — detonation_intro blast 가 폭발 SFX 담당
  //   ★ 기폭 msg 는 HP/보드/도장/profile-hit 도 모두 스킵 — bomb_detonated 가 폭발 순간에 처리.
  //     (사용자 요청: 폭탄 피해는 폭발 순간 즉시 처리, 사전 토스트 시점에 미리 노출 X.)
  const _isDetonateMsg = msg && msg.indexOf('기폭') === 0;
  setTimeout(() => {
    if (msg && !_isDetonateMsg) {
      const sfxRoute = pickSkillSfxByMsg(msg);
      if (sfxRoute) sfxRoute(); else playSfx('opp_skill');
    }
    endSkillCastDim(oppCasterCard);
    if (sp) { S.sp = sp; }
    if (instantSp) { S.instantSp = instantSp; }
    if (sp || instantSp) { updateSPBar(); }

    // ★ 기폭은 HP/보드/도장/profile-hit 처리 스킵 — bomb_detonated 가 폭발 순간 처리.
    if (!_isDetonateMsg) {
      // ★ 스킬 사망 감지 — 상태 업데이트 전 DOM 방향 캡처 (피해자 시점 → 내 말 사망)
      //   악몽뿐 아니라 유황범람 등 모든 데미지 스킬의 사망을 처리.
      let _nightmareDeathInfosVictim = [];
      if (Array.isArray(hits) && hits.some(h => h.destroyed)) {
        const _nmDeadV = hits.filter(h => h.destroyed);
        _nightmareDeathInfosVictim = _detectDeaths(_nmDeadV, true); // 피해자 시점 → 내 말 (isEnemy=false)
        if (_nightmareDeathInfosVictim.length > 0) {
          if (!S._pendingDeathCells) S._pendingDeathCells = new Set();
          for (const di of _nightmareDeathInfosVictim) S._pendingDeathCells.add(`${di.col},${di.row}`);
        }
      }

      if (yourPieces) S.myPieces = yourPieces;
      if (oppPieces) S.oppPieces = oppPieces;
      pruneDeductionTokens();
      if (boardObjects) S.boardObjects = boardObjects;
      // ★ 스킬 사망 셀의 유해는 사망 GIF 완료 후 추가 (즉시 반영 시 사망 모션과 유해 동시 표시 버그).
      _applyServerRemainsExcludingDeaths(remains, _nightmareDeathInfosVictim);

      const mySkillDmgIdx = [];
      for (let i = 0; i < S.myPieces.length; i++) {
        if (i < oldMyHpsCaptured.length && S.myPieces[i].hp < oldMyHpsCaptured[i]) mySkillDmgIdx.push(i);
      }
      // 회복 추적 — 1v1 상대 시점에서 상대 pieces 회복 (heal 스킬)
      for (let i = 0; i < (S.oppPieces || []).length; i++) {
        if (i < oldOppHpsCaptured.length && S.oppPieces[i].hp > oldOppHpsCaptured[i]) {
          addHeal(`opp:${i}`, S.oppPieces[i].hp - oldOppHpsCaptured[i]);
        }
      }
      // (혹시 모를 본인 측 회복)
      for (let i = 0; i < S.myPieces.length; i++) {
        if (i < oldMyHpsCaptured.length && S.myPieces[i].hp > oldMyHpsCaptured[i]) {
          addHeal(`my:${i}`, S.myPieces[i].hp - oldMyHpsCaptured[i]);
        }
      }

      renderGameBoard();
      renderMyPieces();
      renderOppPieces();

      if (!S.isTeamMode) {
        applyProfileHitAnim('#my-pieces-info .my-piece-card', mySkillDmgIdx);
      }
      if (Array.isArray(healedPieceIdxs) && healedPieceIdxs.length > 0) {
        setTimeout(() => flashHealPieces(healedPieceIdxs, { opp: true }), 50);
      }
      // ★ 회복 (newer owner-aware) — 1v1 상대 시점에서도 적용 (누락 수정).
      if (Array.isArray(healedPieces) && healedPieces.length > 0) {
        setTimeout(() => flashHealPiecesByOwner(healedPieces), 50);
      }
      // ★ 유황범람 라바 애니 — 1v1 상대 시점에서도 표시 (사용자 보고 누락 수정).
      if (Array.isArray(borderCells) && borderCells.length > 0 && typeof animateLavaCells === 'function') {
        animateLavaCells(borderCells);
      }
      // ★ 유황범람으로 죽은 쥐 사망 모션 (1v1 피해자 시점)
      _animateSkillDestroyedRats(destroyedRats);
      // ★ 절대복종 반지 — 1v1 상대(피해자) 시점: 자기 piece 가 vanish 후 재등장.
      if (ringTeleport && typeof animateRingTeleport === 'function') {
        animateRingTeleport(ringTeleport, 'victim');
        if (window._crForceRingVictim) window._crForceRingVictim(ringTeleport);
      }
      // ★ 저주 부여 turn-bright — 1v1 상대 시점 (누락 수정).
      if (typeof cursedPieceIdx === 'number') {
        // 1v1: cursedOwnerIdx 가 명시되지 않으면 받는 쪽이 곧 피해자 — my:idx 로 매핑
        requestAnimationFrame(() => {
          if (typeof cursedOwnerIdx === 'number') {
            _persistTurnBright(cursedOwnerIdx, cursedPieceIdx);
            const card = (typeof _findPieceCard === 'function') ? _findPieceCard(cursedOwnerIdx, cursedPieceIdx) : null;
            if (card) card.classList.add('turn-bright');
          } else {
            // 1v1 받는 쪽 = 피해자 → my-pieces-info 매핑
            _persistTurnBright(S.playerIdx, cursedPieceIdx);
            const card = document.querySelectorAll('#my-pieces-info .my-piece-card')[cursedPieceIdx];
            if (card) card.classList.add('turn-bright');
          }
        });
      }
      // ★ 악몽 시전 (1v1 상대 시점) — 표식 적 셀 보라 펄스.
      if (Array.isArray(nightmareCells) && nightmareCells.length > 0 &&
          typeof animateNightmareCast === 'function') {
        animateNightmareCast(nightmareCells, { spiralStyle: 'a', opacityLevel: 2 });
      }
      // ★ 스킬 사망 애니메이션 (1v1 피해자 시점) — 스킬 이펙트 후 사망 GIF + 유해 생성
      //   ★ FIX (유황범람 피격 모션 누락): 라바면 사망을 피격 모션(+1100ms) 이후(1600ms)로 지연.
      if (_nightmareDeathInfosVictim.length > 0) {
        const _lavaDeathDelayV = (Array.isArray(borderCells) && borderCells.length > 0) ? 1600 : 500;
        setTimeout(() => {
          playDeathAnimations(_nightmareDeathInfosVictim, () => {
            S._pendingDeathCells = null;
            _addClientSideRemains(_nightmareDeathInfosVictim);
            renderGameBoard();
            renderMyPieces();
          });
        }, _lavaDeathDelayV);
      }

      // ★ 데미지 스킬 hits 처리 — 셀 hit 애니 + 본체 빨간 도장 / 충성 파란 도장.
      //   server status_update 가 hits 를 보내며, defPieceIdx 는 받는 쪽의 yourPieces (= S.myPieces) 인덱스.
      if (Array.isArray(hits) && hits.length > 0) {
        const hitCells = hits.filter(h => h.col != null && h.row != null).map(h => ({ col: h.col, row: h.row }));
        // ★ 유황범람 라바 애니가 있을 때 hit 셀 표시를 지연 — 라바 ::before 가 빨간 배경을 덮으므로 라바 피크 후 표시
        if (hitCells.length > 0) {
          const _hasLava = Array.isArray(borderCells) && borderCells.length > 0;
          if (_hasLava) {
            setTimeout(() => { animateAttack([], hitCells); }, 1100);
          } else {
            animateAttack([], hitCells);
          }
        }
        // ★ attackLog 기록 — 보드 위 💥/· 셀 마크 (1v1 상대 시점 — 피격자)
        //   being_attacked 와 동일: hit 셀만 💥 기록. 빗나감 atkCells 는 피격자에게 비공개.
        for (const c of hitCells) {
          S.attackLog.push({ col: c.col, row: c.row, hit: true, turn: S.turnNumber });
        }
        renderGameBoard(); // attackLog 마커 즉시 반영
        let _stampsAdded = false;
        for (const h of hits) {
          const dmg = (typeof h.damage === 'number') ? h.damage : 0;
          if (dmg <= 0 || h.defPieceIdx == null) continue;
          // 1v1 status_update 받는 쪽 = 피해 받는 쪽 → 본인 카드 (my:idx)
          const key = `my:${h.defPieceIdx}`;
          if (h.bodyguardRedirect) {
            addLoyaltyDamage(key, dmg);
            _stampsAdded = true;
          } else if (!h.redirectedToBodyguard) {
            addBodyDamage(key, dmg);
            _stampsAdded = true;
          }
        }
        // ★ 사용자 보고 (도장 미출력): stamps 가 addBodyDamage/addLoyaltyDamage 로 누적된 후
        //   renderMyPieces 가 호출되어야 buildDamageOverlay 가 실행되어 도장이 시각화됨.
        //   line 6264 의 renderMyPieces 는 stamps 추가 전에 실행되어 도장이 누락됨 → 추가 재렌더.
        if (_stampsAdded) {
          if (typeof renderMyPieces === 'function') renderMyPieces();
        }
        // 피격 카드 brighten/protected 애니 — server status_update 가 보낸 hits 대상에 적용.
        //   defPieceIdx 는 받는 쪽 (= S.playerIdx) 의 my-pieces 인덱스.
        requestAnimationFrame(() => {
          for (const h of hits) {
            if (h.defPieceIdx == null) continue;
            if (h.redirectedToBodyguard) continue;
            const isProtected = (h.damage === 0 && !h.destroyed);
            const card = document.querySelectorAll('#my-pieces-info .my-piece-card')[h.defPieceIdx];
            if (!card) continue;
            if (isProtected) {
              applyProtectedAnim(card);
              addProtectedHit(`my:${h.defPieceIdx}`);
            } else {
              applyHitFlashWithBrighten(card);
            }
          }
        });
        // ★ 버퍼된 wizard 등 패시브 alert flush — 1v1 상대 스킬에 의해 본인 wizard 가 피격된 시점.
        if (typeof flushDefensiveAlerts === 'function') {
          const _killed = hits.some(h => h.destroyed);
          flushDefensiveAlerts({ skipReduction: _killed });
        }
      }
    }

    if (msg) {
      showSkillToast(msg, true);
      addLog(msg, 'skill-enemy');
    }
  }, TOAST_DELAY_MS);
});

// ── 정찰 결과 ──
socket.on('scout_result', ({ axis, value, targetName }) => {
  const label = axis === 'row' ? `${ROW_LABELS[value] || value}열` : `${value+1}행`;
  if (typeof playSfxScout === 'function') playSfxScout(); else playSfx('skill');
  // 인벤토리 E1 본인 셀: "정찰: 상대 [target]의 위치는 [label]"
  addLog(`정찰: 상대 ${targetName}의 위치는 ${label}`, 'skill');
  showSkillToast(`정찰: 상대 ${targetName}의 위치는 ${label}`);
});

// ── 쥐 소환 ──
socket.on('rats_spawned', ({ rats, owner, spCost, casterCol, casterRow }) => {
  // ★ FIX (관전자 쥐 소환 모션): 팀 관전자는 renderGameBoard 기반이라 플레이어와 동일 처리.
  //   단, 1v1 관전자는 별도 렌더 경로(renderSpectatorGame)라 이 핸들러의 renderGameBoard 가 보드를
  //   덮어쓸 수 있어 건너뜀(쥐는 다음 spectator_update 상태 동기화로 표시 — 무애니, 회귀 없음).
  if (S.isSpectator && !S.isTeamMode) return;
  const SP_END_MS = getSpFlightEndMs(spCost || 2);
  const isMine = owner === S.playerIdx;
  const isAlly = S.isTeamMode && (S.teamGamePlayers || []).some(p => p.idx === owner && p.teamId === S.teamId && p.idx !== S.playerIdx);
  // ★ 사용자 요청: 애니메이션 완료 전엔 쥐가 보드에 표시되지 않게.
  //   _ratIncoming Set 에 등록 → renderGameBoard 가 이 key 일치하는 rat span 을 skip.
  //   animateRatSpawn 의 swapToMarker 가 키 제거 후 renderGameBoard 호출 → 마커 등장.
  if (!S._ratIncoming) S._ratIncoming = new Set();
  for (const rat of (rats || [])) {
    S._ratIncoming.add(`${rat.col},${rat.row},${owner}`);
  }
  // 즉시 재렌더 — 이미 boardObjects 에 들어와 있던 쥐 span 즉시 숨김
  if (typeof renderGameBoard === 'function') renderGameBoard();
  setTimeout(() => {
    if (typeof playSfxRatSummon === 'function') playSfxRatSummon(); else playSfx('skill');
    if (isMine) {
      addLog(`역병의 자손들: 쥐 ${rats.length}마리 소환`, 'skill');
      showSkillToast(`역병의 자손들: 쥐 ${rats.length}마리 소환`);
    } else if (isAlly) {
      addLog(`역병의 자손들: 쥐 ${rats.length}마리 소환`, 'skill');
      showSkillToast(`역병의 자손들: 쥐 ${rats.length}마리 소환`);
    } else {
      addLog(`역병의 자손들: 상대가 쥐 소환. 쥐는 공격으로 제거 가능`, 'skill');
      showSkillToast(`역병의 자손들: 상대가 쥐 소환. 쥐는 공격으로 제거 가능`, true);
    }
    // ★ 쥐 비행 애니메이션 + 셀 보라 마크 — rat-anim.js 의 generic animateRatSpawn 호출.
    //   game 전용 state (viewerIdx, marksArr, turnNumber, onLanded) 를 opts 로 주입.
    if (typeof animateRatSpawn === 'function') {
      if (!S._ratSpawnMarks) S._ratSpawnMarks = [];
      animateRatSpawn(rats, owner, {
        boardId: 'game-board',
        viewerIdx: S.playerIdx,
        marksArr: S._ratSpawnMarks,
        turnNumber: S.turnNumber,
        onLanded: (rat, _opts) => {
          if (S._ratIncoming) S._ratIncoming.delete(`${rat.col},${rat.row},${owner}`);
          // ★ skipRender: rat-anim.js가 idle GIF를 직접 배치 → renderGameBoard 불필요
          if (!(_opts && _opts.skipRender) && typeof renderGameBoard === 'function') renderGameBoard();
        },
      });
    }
    renderGameBoard();
  }, SP_END_MS);
});

// ── 드래곤 소환 ──
socket.on('dragon_spawned', ({ dragon, owner, spCost }) => {
  // ★ FIX (관전자 드래곤 소환 모션): 팀 관전자는 플레이어와 동일 처리. 1v1 관전자는 별도 렌더
  //   경로라 건너뜀(드래곤은 다음 spectator_update 상태 동기화로 표시 — 무애니, 회귀 없음).
  if (S.isSpectator && !S.isTeamMode) return;
  // ★ 통일 — SP 비행 종료 시점에 SFX + 토스트/로그 + 강림 애니 (드래곤 5 SP → 1300ms)
  //   다른 스킬 (역병의 자손들/덫 발동 등) 과 같은 페이즈 정렬: SP 마법구 비행 후 일제히 발동.
  const SP_END_MS = getSpFlightEndMs(spCost || 5);
  const isMine = owner === S.playerIdx;
  const isAlly = S.isTeamMode && (S.teamGamePlayers || []).some(p => p.idx === owner && p.teamId === S.teamId && p.idx !== S.playerIdx);
  const isOpponent = !isMine && !isAlly && !S.isSpectator;

  // ★ 애니메이션 완료 전엔 드래곤이 보드에 표시되지 않게 — _dragonIncoming Set 에 등록.
  //   renderGameBoard 가 이 key 와 일치하는 드래곤 piece 를 skip 하고, 강림 완료 시점에 제거.
  if (!S._dragonIncoming) S._dragonIncoming = new Set();
  const _dragonKey = `${dragon.col},${dragon.row},${owner}`;
  S._dragonIncoming.add(_dragonKey);
  // ★ 워치독 — 키 제거가 단일 setTimeout 체인(강림 애니)에만 의존하므로, 그 콜백이
  //   도달 전 예외/재접속으로 끊기면 드래곤이 보드에 영영 안 그려짐. 독립 안전 해제로 보장.
  setTimeout(() => {
    if (S._dragonIncoming && S._dragonIncoming.has(_dragonKey)) {
      S._dragonIncoming.delete(_dragonKey);
      if (typeof renderGameBoard === 'function') renderGameBoard();
    }
  }, SP_END_MS + 3000);
  if (typeof renderGameBoard === 'function') renderGameBoard();

  setTimeout(() => {
    if (isMine || isAlly) {
      addLog(`드래곤 소환: ${coord(dragon.col,dragon.row)}에 드래곤 소환`, 'skill');
      showSkillToast(`드래곤 소환: ${coord(dragon.col,dragon.row)}에 드래곤 소환`);
    } else {
      addLog(`드래곤 소환: 상대가 ${coord(dragon.col,dragon.row)}에 드래곤 소환`, 'skill');
      showSkillToast(`드래곤 소환: 상대가 ${coord(dragon.col,dragon.row)}에 드래곤 소환`, true);
    }
    // ★ 강림 애니메이션 — 거대 광주 + 천둥 + 드래곤 즉시 등장. SFX 는 animateDragonSummon 내부에서 재생.
    if (typeof animateDragonSummon === 'function') {
      animateDragonSummon(dragon.col, dragon.row, owner);
    } else {
      try { if (typeof playSfxDragonSummon === 'function') playSfxDragonSummon(); else playSfx('skill'); } catch (e) {}
      S._dragonIncoming.delete(`${dragon.col},${dragon.row},${owner}`);
      if (typeof renderGameBoard === 'function') renderGameBoard();
    }
    // ★ 사용자 요청: 상대편(적팀)은 강림한 칸에 자동 추리 토큰 부여.
    //   ★ 사용자 보고 (토큰 사라짐): pieceKey 형식이 pruneDeductionTokens 의 aliveKey 와 다르면
    //     매 렌더마다 즉시 제거됨. aliveKey 형식: `${type}:${subUnit}${ownerSuffix}` — 드래곤은 subUnit 없음.
    //     1v1: `dragon:` / 팀모드: `dragon:@${owner}` (ownerIdx 가 oppPieces 에 있을 때만).
    if (isOpponent) {
      try {
        // 팀모드는 oppPieces 의 piece 가 ownerIdx 를 갖고, 1v1 은 안 가짐.
        const pieceKey = S.isTeamMode ? `dragon:@${owner}` : `dragon:`;
        S.deductionTokens = (S.deductionTokens || []).filter(t => t.pieceKey !== pieceKey && !(t.col === dragon.col && t.row === dragon.row));
        S.deductionTokens.push({ pieceKey, icon: '/assets/icons/dragon.png', name: '드래곤', col: dragon.col, row: dragon.row });
      } catch (e) {}
    }
  }, SP_END_MS);
});

// ── 드래곤 강림 애니메이션 (재설계) ──
//   사용자 요청: "임팩트 강하게, 광주는 굵고 한번에, 드래곤은 빛처럼 즉시 등장, 전설 유닛처럼 위압감"
//   T+0    : 거대 광주 (빛 기둥) 하늘에서 내리쬠 + 풀스크린 플래시 + 보드 흔들림 + 천둥 SFX (한 방)
//   T+0    : 셀 강렬한 화이트 폭발 + 충격파 링 3겹 + 드래곤 즉시 등장 (3.5x → 1x 수축)
//   T+900  : 애니 종료 → _dragonIncoming 키 제거 → 실제 드래곤 piece 표시
function animateDragonSummon(col, row, owner) {
  const board = document.getElementById('game-board');
  if (!board) return;
  const cell = board.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
  if (!cell) {
    if (S._dragonIncoming) S._dragonIncoming.delete(`${col},${row},${owner}`);
    if (typeof renderGameBoard === 'function') renderGameBoard();
    return;
  }
  const rect = cell.getBoundingClientRect();
  // ★ 착지 위치 = idle GIF 중심(셀중심 −6px, HP 텍스트 때문) 의 셀비례 % — 1v1/2v2/모바일 모든 셀 크기에서 정착과 일치.
  const _dragonTopPct = (rect.height > 0 ? ((rect.height / 2 - 6) / rect.height * 100).toFixed(2) : 40) + '%';
  const stage = document.createElement('div');
  stage.className = 'dragon-summon-stage';
  stage.style.left = rect.left + 'px';
  stage.style.top = rect.top + 'px';
  stage.style.width = rect.width + 'px';
  stage.style.height = rect.height + 'px';
  document.body.appendChild(stage);

  // 1. 거대 광주 (빛 기둥) — 굵게 한 번에 내리쬠
  const pillar = document.createElement('div');
  pillar.className = 'dragon-light-pillar';
  stage.appendChild(pillar);
  const core = document.createElement('div');
  core.className = 'dragon-light-pillar-core';
  stage.appendChild(core);

  // 2. 풀스크린 플래시 — 화면 전체가 번쩍 (관전자도 놀라게)
  const fullFlash = document.createElement('div');
  fullFlash.className = 'dragon-fullscreen-flash';
  document.body.appendChild(fullFlash);
  setTimeout(() => fullFlash.remove(), 600);

  // 3. 셀 강렬한 화이트 폭발
  cell.classList.remove('dragon-strike-cell');
  void cell.offsetWidth;
  cell.classList.add('dragon-strike-cell');

  // 4. 충격파 3겹 — 시간차로 펑펑펑
  for (const cls of ['r1', 'r2', 'r3']) {
    const ring = document.createElement('div');
    ring.className = `dragon-shockwave-ring ${cls}`;
    stage.appendChild(ring);
  }

  // 5. 보드 흔들림 — 천둥 진동
  if (board) {
    board.classList.remove('dragon-board-quake');
    void board.offsetWidth;
    board.classList.add('dragon-board-quake');
    setTimeout(() => board.classList.remove('dragon-board-quake'), 550);
  }

  // 6. 드래곤 착지 GIF 강림 — 착지 GIF 1회 재생 후 idle 전환
  //    착지 GIF (96×96) 셀 대비 220%, top 40% (idle GIF 중심 = 셀 39% 지점에 맞춤). NETSCAPE 블록 제거로 정확히 1회 재생.
  //    착지 GIF 없으면 이동 PNG 수축 폴백.
  const _landingUrl = window.DRAGON_LANDING_GIF;
  const _dragonMoveUrl = (typeof getPieceMoveUrl === 'function') ? getPieceMoveUrl('dragon') : null;
  const _LANDING_DURATION = 950; // 착지 GIF 910ms + 40ms 여유

  if (_landingUrl) {
    // ★ 착지 GIF Blob fetch → NETSCAPE 블록 제거 → 1회 재생 Blob URL
    //   프리로드 캐시 히트 시 즉시 처리. 미스 시 300ms 타임아웃 후 PNG 폴백.
    const cached = window._gifBlobCache && window._gifBlobCache[_landingUrl];
    const blobP = cached ? Promise.resolve(cached) : fetch(_landingUrl).then(r => r.blob());
    let _landingHandled = false;
    // ★ 타임아웃 가드 — fetch 가 300ms 내 완료 안 되면 PNG 폴백
    const _loadTimeout = setTimeout(() => {
      if (_landingHandled) return;
      _landingHandled = true;
      _dragonSummonFallback(stage, _dragonMoveUrl, col, row, owner, _dragonTopPct);
    }, 300);
    blobP.then(blob => blob.arrayBuffer()).then(ab => {
      if (_landingHandled) return; // 이미 폴백 발동됨
      _landingHandled = true;
      clearTimeout(_loadTimeout);
      const src = new Uint8Array(ab);
      let nsStart = -1;
      for (let i = 0; i < src.length - 18; i++) {
        if (src[i] === 0x21 && src[i+1] === 0xFF && src[i+2] === 0x0B) {
          const sig = String.fromCharCode(src[i+3],src[i+4],src[i+5],src[i+6],src[i+7],
            src[i+8],src[i+9],src[i+10],src[i+11],src[i+12],src[i+13]);
          if (sig === 'NETSCAPE2.0') { nsStart = i; break; }
        }
      }
      let patched = src;
      if (nsStart >= 0) {
        patched = new Uint8Array(src.length - 19);
        patched.set(src.subarray(0, nsStart), 0);
        patched.set(src.subarray(nsStart + 19), nsStart);
      }
      const blobUrl = URL.createObjectURL(new Blob([patched], { type: 'image/gif' }));
      const landImg = document.createElement('img');
      landImg.src = blobUrl;
      landImg.draggable = false;
      landImg.className = 'dragon-landing-gif';
      landImg.style.width = '220%';
      landImg.style.height = '220%';
      landImg.style.top = _dragonTopPct; // idle GIF 중심(셀비례) — 셀 크기 무관 정착과 일치
      stage.appendChild(landImg);

      setTimeout(() => {
        landImg.remove();
        URL.revokeObjectURL(blobUrl);
        if (S._dragonIncoming) S._dragonIncoming.delete(`${col},${row},${owner}`);
        if (typeof renderGameBoard === 'function') renderGameBoard();
        if (stage.parentNode) stage.remove();
      }, _LANDING_DURATION);
    }).catch(() => {
      if (_landingHandled) return;
      _landingHandled = true;
      clearTimeout(_loadTimeout);
      // fetch 실패 시 이동 PNG 폴백
      _dragonSummonFallback(stage, _dragonMoveUrl, col, row, owner);
    });
  } else {
    // 착지 GIF 미등록 — 이동 PNG 폴백
    _dragonSummonFallback(stage, _dragonMoveUrl, col, row, owner, _dragonTopPct);
  }

  // 7. SFX — 거대 천둥 한 방 (드래곤 강림 SFX 가 천둥 + 으르렁을 모두 포함)
  try { if (typeof playSfxDragonSummon === 'function') playSfxDragonSummon(); } catch (e) {}
}

// 드래곤 소환 폴백 — 이동 PNG 수축 등장 (착지 GIF 미사용 시)
function _dragonSummonFallback(stage, moveUrl, col, row, owner, topPct) {
  const dragon = document.createElement('div');
  dragon.className = 'dragon-revealed';
  dragon.style.width = '150%';
  dragon.style.height = '150%';
  if (topPct) dragon.style.top = topPct;   // idle 중심(셀비례) — 셀 크기 무관 정착과 일치
  if (moveUrl) {
    dragon.innerHTML = `<img src="${moveUrl}" alt="" style="width:100%;height:100%;object-fit:contain;image-rendering:pixelated;filter:drop-shadow(0 0 1px rgba(0,0,0,1)) drop-shadow(0 0 1px rgba(0,0,0,1));" draggable="false">`;
  }
  stage.appendChild(dragon);
  setTimeout(() => {
    if (S._dragonIncoming) S._dragonIncoming.delete(`${col},${row},${owner}`);
    if (typeof renderGameBoard === 'function') renderGameBoard();
    if (stage.parentNode) stage.remove();
  }, 900);
}

// ── 사냥꾼 카드 찾기 헬퍼 (덫 시전 강조용) ──
//   ★ 사용자 보고: 사냥꾼이 이미 사망한 경우 (덫 설치 후 죽음) cast intro 스킵 → 본 적 없음.
//   alive 필터 제거 — 사망한 사냥꾼 카드도 찾아서 강조 애니 적용 (덫은 사후에도 발동).
function _findHunterCard(trapOwnerIdx) {
  if (trapOwnerIdx == null) return null;
  if (S.isTeamMode) {
    const player = (S.teamGamePlayers || []).find(p => p.idx === trapOwnerIdx);
    if (!player) return null;
    const hunterIdx = (player.pieces || []).findIndex(p => p.type === 'manhunter');
    if (hunterIdx < 0) return null;
    return document.querySelector(`.team-profile-block[data-player-idx="${trapOwnerIdx}"] [data-piece-idx="${hunterIdx}"]`);
  }
  // 1v1
  if (trapOwnerIdx === S.playerIdx) {
    const hunterIdx = (S.myPieces || []).findIndex(p => p.type === 'manhunter');
    if (hunterIdx < 0) return null;
    return document.querySelectorAll('#my-pieces-info .my-piece-card')[hunterIdx];
  } else {
    const hunterIdx = (S.oppPieces || []).findIndex(p => p.type === 'manhunter');
    if (hunterIdx < 0) return null;
    return document.querySelectorAll('#opp-pieces-info .opp-piece-card')[hunterIdx];
  }
}
function _findHunterPieceIdx(trapOwnerIdx) {
  if (trapOwnerIdx == null) return -1;
  if (S.isTeamMode) {
    const player = (S.teamGamePlayers || []).find(p => p.idx === trapOwnerIdx);
    return player ? (player.pieces || []).findIndex(p => p.type === 'manhunter') : -1;
  }
  if (trapOwnerIdx === S.playerIdx) {
    return (S.myPieces || []).findIndex(p => p.type === 'manhunter');
  }
  return (S.oppPieces || []).findIndex(p => p.type === 'manhunter');
}

// ── 함정 발동 ──
//   ★ 사용자 요청: 덫 발동을 화약상 기폭처럼 시전 강조 형태로 표현.
//   1) 사냥꾼 카드에 [덫 발동] 빨간 말풍선 + spotlight (마법구 비행 X — SP 소모 없음)
//   2) ~700ms 후 — spotlight 해제 + 이빨 스냅 애니 + 데미지/사망/SFX/도장/토스트/로그 동시 발동
socket.on('trap_triggered', ({ col, row, pieceInfo, damage, owner, destroyed, newHp, victimOwnerIdx, trapOwnerIdx }) => {
  // 시전 도입부 — 사냥꾼 카드 spotlight + 빨간 말풍선 (사냥꾼 사망/생존 무관 — alive 필터 제거됨)
  const hunterCard = _findHunterCard(trapOwnerIdx);
  const _hunterPieceIdx = _findHunterPieceIdx(trapOwnerIdx);
  const _targetInfo = (S.isTeamMode && trapOwnerIdx != null && _hunterPieceIdx >= 0)
    ? { playerIdx: trapOwnerIdx, pieceIdx: _hunterPieceIdx }
    : null;
  if (hunterCard) {
    startSkillCastDim(hunterCard, _targetInfo);
    showSkillCastBubble(hunterCard, '덫 발동', 'action');  // 'action' = 빨간 (덫 설치 와 동일)
  }
  // ★ 트랩 셀 자체에도 시각 강조 — 사냥꾼이 죽었거나 카드를 못 찾는 경우의 fallback,
  //   그리고 사냥꾼 카드 강조와 함께 시전이 어디서 일어나는지 명확히 알리는 효과.
  const board = document.getElementById('game-board');
  if (board) {
    const trapCell = board.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
    if (trapCell) {
      trapCell.classList.remove('trap-cast-cell');
      void trapCell.offsetWidth;
      trapCell.classList.add('trap-cast-cell');
      setTimeout(() => trapCell.classList.remove('trap-cast-cell'), 750);
    }
  }
  // 시전 도입부 SFX — 다른 스킬과 통일 (skill cast wind)
  try { if (typeof playSfxSkillCastWind === 'function') playSfxSkillCastWind(); } catch (e) {}

  // 시전 도입부 후 (~700ms) 모든 효과 발동
  setTimeout(() => {
    if (hunterCard) endSkillCastDim(hunterCard);
    _runTrapEffects(col, row, pieceInfo, damage, owner, destroyed, newHp, victimOwnerIdx);
  }, 700);
});
function _runTrapEffects(col, row, pieceInfo, damage, owner, destroyed, newHp, victimOwnerIdx) {
  // 트랩 전용 사운드 + 일반 피격/격파 사운드 레이어링
  playSfxTrapSnap();
  if (destroyed) playSfx('kill'); else playSfx('hit');
  // ★ 사용자 요청: 맹수 이빨이 콱 무는 애니 — 셀 위·아래에서 이빨이 들어와 중앙에서 스냅.
  if (typeof animateTrapSnap === 'function') animateTrapSnap(col, row);

  // ★ 1v1 관전자 — 별도 처리: spectator 의 S.myPieces/oppPieces 가 비어있어 일반 경로가 무동작.
  //   victimOwnerIdx 0=p0(#my-pieces-info), 1=p1(#opp-pieces-info) 매핑.
  if (S.isSpectator && !S.isTeamMode) {
    addLog(`덫 발동!`, 'hit');
    showSkillToast(`덫 발동!`);
    S.attackLog.push({ col, row, hit: true, turn: S.turnNumber });
    animateAttack([], [{ col, row }]);
    if (victimOwnerIdx != null) {
      const arr = (victimOwnerIdx === 0) ? (S.specGameState?.p0Pieces || []) : (S.specGameState?.p1Pieces || []);
      let idx = arr.findIndex(p => p.alive && p.name === pieceInfo?.name && p.col === col && p.row === row);
      if (idx < 0) idx = arr.findIndex(p => p.alive && p.name === pieceInfo?.name);
      if (idx >= 0) {
        if (typeof damage === 'number' && damage > 0) {
          const key = (victimOwnerIdx === 0) ? `my:${idx}` : `opp:${idx}`;
          addBodyDamage(key, damage);
        }
        const containerSel = (victimOwnerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
        const cardSel = (victimOwnerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
        const card = document.querySelectorAll(`${containerSel} ${cardSel}`)[idx];
        if (card) applyHitFlashWithBrighten(card);
      }
    }
    if (S.specGameState) renderSpectatorGame(S.specGameState);
    return;
  }

  // 인벤토리 E7 트랩 발동
  const msg = `덫 발동!`;
  addLog(msg, 'hit');
  showSkillToast(msg);
  S.attackLog.push({ col, row, hit: true, turn: S.turnNumber });

  // HP 즉시 갱신 — 일반 피격과 동일하게 클라이언트에서 바로 반영
  // ★ 사용자 보고 (트랩 같은 티어 피격 애니 버그) — victimOwnerIdx 로 정확 분기.
  //   양 측이 같은 캐릭터(이름)를 보유했을 때 cross-side 이름 매칭으로 잘못된 piece 가 업데이트되던 문제.
  //   bomb_detonated 핸들러와 동일한 owner 필터링 패턴 적용.
  const updatePiece = (arr, expectedOwnerIdx) => {
    if (!Array.isArray(arr)) return -1;
    // owner 가 일치하지 않으면 스킵 (서버가 victimOwnerIdx 를 보냈을 때만 필터링).
    if (typeof victimOwnerIdx === 'number' && typeof expectedOwnerIdx === 'number' && victimOwnerIdx !== expectedOwnerIdx) {
      return -1;
    }
    let idx = arr.findIndex(p => p.alive && p.name === pieceInfo.name && p.col === col && p.row === row);
    if (idx < 0) idx = arr.findIndex(p => p.alive && p.name === pieceInfo.name);
    if (idx >= 0) {
      if (newHp != null) arr[idx].hp = newHp;
      if (destroyed) arr[idx].alive = false;
    }
    return idx;
  };
  // 1v1: S.myPieces = my(0 or 1). S.oppPieces = other(1 or 0).
  // 팀모드: S.myPieces = local player only. S.teammatePieces = teammate. S.oppPieces = flattened enemies.
  const teammateOwnerIdx = (S.isTeamMode && Array.isArray(S.teamGamePlayers))
    ? (S.teamGamePlayers.find(p => p.teamId === S.teamId && p.idx !== S.playerIdx)?.idx)
    : null;
  const oneVoneOppIdx = (typeof S.playerIdx === 'number') ? (1 - S.playerIdx) : null;
  const myIdx = updatePiece(S.myPieces, S.playerIdx);
  const tmIdx = (S.isTeamMode && teammateOwnerIdx != null)
    ? updatePiece(S.teammatePieces, teammateOwnerIdx)
    : -1;
  // 팀모드 oppPieces 는 flat enemy 배열 — 자체 ownerIdx 속성으로 필터.
  let oppIdx = -1;
  if (S.isTeamMode) {
    if (Array.isArray(S.oppPieces) && typeof victimOwnerIdx === 'number') {
      oppIdx = S.oppPieces.findIndex(p => p.alive && p.ownerIdx === victimOwnerIdx
        && p.name === pieceInfo.name && p.col === col && p.row === row);
      if (oppIdx < 0) oppIdx = S.oppPieces.findIndex(p => p.alive && p.ownerIdx === victimOwnerIdx && p.name === pieceInfo.name);
      if (oppIdx >= 0) {
        if (newHp != null) S.oppPieces[oppIdx].hp = newHp;
        if (destroyed) S.oppPieces[oppIdx].alive = false;
      }
    }
  } else {
    oppIdx = updatePiece(S.oppPieces, oneVoneOppIdx);
  }

  // 본체 직접 피해 추적 (덫은 본체에 직접 들어가는 피해)
  if (damage > 0) {
    if (myIdx >= 0) addBodyDamage(`my:${myIdx}`, damage);
    else if (oppIdx >= 0) addBodyDamage(`opp:${oppIdx}`, damage);
    else if (tmIdx >= 0 && victimOwnerIdx != null) addBodyDamage(`${victimOwnerIdx}:${tmIdx}`, damage);
  }

  // ★ 자동 추리토큰 — 덫이 적의 piece 위치를 노출. 사망 아닌 경우에만 토큰 배치.
  //   1v1: victim 이 상대 (1 - playerIdx) 일 때.
  //   팀모드: victim 이 적팀 piece (= 내 팀이 아님) 일 때.
  if (!destroyed && pieceInfo && pieceInfo.name && victimOwnerIdx != null) {
    let isEnemyVictim = false;
    let pieceKey = null;
    if (S.isTeamMode) {
      const victimPlayer = (S.teamGamePlayers || []).find(p => p.idx === victimOwnerIdx);
      isEnemyVictim = !!(victimPlayer && victimPlayer.teamId !== S.teamId);
      if (isEnemyVictim) {
        const piece = victimPlayer.pieces?.find(p => p.name === pieceInfo.name && p.col === col && p.row === row);
        if (piece) pieceKey = `${piece.type}:${piece.subUnit || ''}@${victimOwnerIdx}`;
      }
    } else {
      isEnemyVictim = (typeof S.playerIdx === 'number') && (victimOwnerIdx !== S.playerIdx);
      if (isEnemyVictim && oppIdx >= 0 && S.oppPieces?.[oppIdx]) {
        const piece = S.oppPieces[oppIdx];
        pieceKey = `${piece.type}:${piece.subUnit || ''}`;
      }
    }
    if (isEnemyVictim && pieceKey) {
      try {
        S.deductionTokens = (S.deductionTokens || []).filter(t => t.pieceKey !== pieceKey && !(t.col === col && t.row === row));
        S.deductionTokens.push({ pieceKey, icon: pieceInfo.icon, name: pieceInfo.name, col, row });
      } catch (e) {}
    }
  }
  // 사망 시 추리 토큰 즉시 제거
  if (destroyed && typeof pruneDeductionTokens === 'function') pruneDeductionTokens();

  // 셀 + 보드 아이콘 피격 애니메이션 (일반 공격과 동일)
  animateAttack([], [{ col, row }]);

  // ★ 쌍둥이 이동 페이즈 중 첫 번째 쌍둥이가 덫으로 사망 → twin phase 강제 탈출
  //   (서버는 actionDone=true이므로 턴 종료 가능, 클라가 twin phase에 갇히는 프리즈 방지)
  if (destroyed && S.twinPhaseActive) {
    const isMyPiece = (typeof victimOwnerIdx === 'number')
      ? (victimOwnerIdx === S.playerIdx)
      : (myIdx >= 0);
    if (isMyPiece && typeof exitTwinMovePhase === 'function') {
      exitTwinMovePhase(false);
    }
  }

  // ★ 트랩 사망 애니메이션 정보 수집 — alive 업데이트 완료, DOM 아직 미갱신 상태에서 방향 캡처.
  const _trapDeathInfos = [];
  if (destroyed) {
    const _isMyUnit = (typeof victimOwnerIdx === 'number')
      ? (victimOwnerIdx === S.playerIdx || (S.isTeamMode && victimOwnerIdx === teammateOwnerIdx))
      : (myIdx >= 0 || tmIdx >= 0);
    let facingLeft = false;
    const _tboard = document.getElementById('game-board');
    if (_tboard) {
      const _tcell = _tboard.querySelector(`.cell[data-col="${col}"][data-row="${row}"]`);
      if (_tcell) {
        const _msel = _isMyUnit ? '.piece-marker:not(.opp-marked)' : '.piece-marker.opp-marked';
        const _mk = _tcell.querySelector(_msel) || _tcell.querySelector('.piece-marker');
        if (_mk) {
          const _gif = _mk.querySelector('.p-icon img.p-gif');
          if (_gif && (_gif.style.transform || '').includes('scaleX(-1)')) facingLeft = true;
        }
      }
    }
    // type 결정 — 서버가 pieceInfo.type 으로 직접 전달
    const _ttype = pieceInfo?.type || null;
    _trapDeathInfos.push({
      col, row,
      type: _ttype,
      facingLeft,
      isEnemy: !_isMyUnit,
    });
  }

  // ★ 렌더 후 피격/프로필 애니메이션 공통 로직
  const _doPostTrapRender = () => {
    // 셀 + 보드 아이콘 피격 애니메이션 — renderGameBoard 이후에 호출 (셀 DOM 필요)
    animateAttack([], [{ col, row }]);
    // 프로필 카드 흔들림 + 금색 플래시 — 1v1 만 (팀모드는 별도 처리)
    if (!S.isTeamMode) {
      if (myIdx >= 0) applyProfileHitAnim('#my-pieces-info .my-piece-card', [myIdx]);
      if (oppIdx >= 0) applyProfileHitAnim('#opp-pieces-info .opp-piece-card', [oppIdx]);
    }
    // 팀모드: 팀원이 트랩에 걸렸으면 팀원 카드 hit 애니
    if (tmIdx >= 0 && S.isTeamMode) {
      const teammate = (S.teamGamePlayers || []).find(p => p.teamId === S.teamId && p.idx !== S.playerIdx);
      if (teammate) {
        requestAnimationFrame(() => {
          const card = document.querySelector(`#my-pieces-info .team-profile-block[data-player-idx="${teammate.idx}"] [data-piece-idx="${tmIdx}"]`);
          if (card) {
            card.classList.remove('profile-hit');
            void card.offsetWidth;
            card.classList.add('profile-hit');
            setTimeout(() => card.classList.remove('profile-hit'), 1800);
          }
        });
      }
    }
  };

  // ★ 트랩 사망 애니메이션 — bomb_detonated, attack_result 와 동일한 패턴.
  if (_trapDeathInfos.length > 0) {
    S._pendingDeathCells = new Set(_trapDeathInfos.map(d => `${d.col},${d.row}`));
    renderGameBoard();
    if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles();
    else { renderMyPieces(); renderOppPieces(); }
    _doPostTrapRender();

    // 피격 GIF 정착 후 사망 GIF 재생 (400ms)
    scheduleDeathGif(_trapDeathInfos, _trapDeathInfos, () => {
      renderGameBoard();
      if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles();
      else { renderMyPieces(); renderOppPieces(); }
    });
  } else {
    renderGameBoard();
    if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles();
    else { renderMyPieces(); renderOppPieces(); }
    _doPostTrapRender();
  }
}

// ── 사망 기폭 시전 애니메이션 ──
//   화약상이 죽으면서 자동으로 발동되는 기폭. 서버는 600ms 사망 인지 텀 후 이 이벤트 emit.
//   여러 화약상이 동시 사망 (학살영웅 attack / 보드 축소 등) 한 wave 면 casters 배열에 다수 포함.
//   클라는 각 caster 카드에 "사망 기폭" 노란 말풍선 + spotlight 동시 출력.
//   SP 마법구 비행 없음 (cost 0 자동 발동).
// ── 표식 발동 시전 인트로 (사망 기폭과 유사 패턴) ──
//   서버가 모든 패시브/스킬 연쇄 처리 후 최후반에 emit. 시전자 토르처러 카드 spotlight + "표식" 말풍선.
//   780ms 후 spotlight 해제 + 별도 passive_alert (type='torturer', markCells) 이 도착 → animateMarkBrand 발동.
socket.on('mark_cast', ({ casters, markedTargets }) => {
  if (!Array.isArray(casters) || casters.length === 0) return;
  // ★ 사용자 보고 (시전 시 적 위치 안 보임 / 턴 종료해야 갱신):
  //   mark_cast 직후 attack_result 등이 S.oppPieces 를 새 배열로 통째 교체하며 mutation 손실.
  //   해결: _revealedMarkedOpps Map 에 보존 + oppPieces setter 가 매 할당 시 자동 reseed.
  if (Array.isArray(markedTargets) && markedTargets.length > 0) {
    S._revealedMarkedOpps = S._revealedMarkedOpps || new Map();
    for (const mt of markedTargets) {
      if (mt.col == null || mt.row == null) continue;
      const isMyCast = (typeof mt.sourceOwnerIdx === 'number' && mt.sourceOwnerIdx === S.playerIdx);
      let isTeammateCast = false;
      if (S.isTeamMode && typeof mt.sourceOwnerIdx === 'number') {
        const sameTeam = (S.teamGamePlayers || []).filter(p => p.teamId === S.teamId).map(p => p.idx);
        isTeammateCast = sameTeam.includes(mt.sourceOwnerIdx);
      }
      if ((isMyCast || isTeammateCast) && Array.isArray(S.oppPieces)) {
        // Map 에 보존
        const key = `${mt.targetOwnerIdx}:${mt.targetPieceIdx}`;
        S._revealedMarkedOpps.set(key, {
          col: mt.col, row: mt.row,
          name: mt.name, icon: mt.icon,
          hasMarkStatus: false,  // 인두 낙하 후 true (passive_alert 에서 갱신)
        });
        // 즉시 mutation — Map 도 set 됐으니 oppPieces 새 할당 시에도 setter 가 reseed
        let opp = null;
        if (typeof mt.targetPieceIdx === 'number') {
          if (S.isTeamMode) {
            opp = S.oppPieces.find(p => p && p.alive && p.index === mt.targetPieceIdx
              && (typeof mt.targetOwnerIdx !== 'number' || p.ownerIdx === mt.targetOwnerIdx));
          } else {
            opp = S.oppPieces[mt.targetPieceIdx];
          }
        }
        if (!opp) {
          opp = S.oppPieces.find(p => p && p.alive && p.name === mt.name && p.icon === mt.icon);
        }
        if (opp && opp.alive) {
          opp.col = mt.col;
          opp.row = mt.row;
          opp.marked = true;
        }
      }
    }
    if (typeof renderGameBoard === 'function') renderGameBoard();
    // ★ 안전망: 브랜드(passive_alert) 가 끝내 안 오면 적이 영영 숨겨지지 않도록 2s 후 강제 노출.
    setTimeout(() => {
      if (!(S._revealedMarkedOpps instanceof Map)) return;
      let _ch = false;
      for (const info of S._revealedMarkedOpps.values()) { if (info && info.hasMarkStatus === false) { info.hasMarkStatus = true; _ch = true; } }
      if (_ch && typeof renderGameBoard === 'function') renderGameBoard();
    }, 2000);
  }

  const resolveCard = (c) => {
    if (S.isTeamMode) {
      return document.querySelector(`.team-profile-block[data-player-idx="${c.ownerIdx}"] [data-piece-idx="${c.pieceIdx}"]`);
    } else if (S.isSpectator) {
      const containerSel = (c.ownerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
      const cardSel = (c.ownerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
      return document.querySelectorAll(`${containerSel} ${cardSel}`)[c.pieceIdx];
    } else {
      if (c.ownerIdx === S.playerIdx) {
        return document.querySelectorAll('#my-pieces-info .my-piece-card')[c.pieceIdx];
      } else {
        return document.querySelectorAll('#opp-pieces-info .opp-piece-card')[c.pieceIdx];
      }
    }
  };
  for (const c of casters) {
    if (c.ownerIdx == null || c.pieceIdx == null) continue;
    const card = resolveCard(c);
    if (!card) continue;
    if (typeof startSkillCastDim === 'function') {
      const _targetInfo = (S.isTeamMode && c.ownerIdx != null && c.pieceIdx != null)
        ? { playerIdx: c.ownerIdx, pieceIdx: c.pieceIdx }
        : null;
      startSkillCastDim(card, _targetInfo);
    }
    // 표식 — 패시브 톤 (자유시전형 'free' 와 비슷한 톤 또는 'once') — 일관성 위해 'once' 사용
    if (typeof showSkillCastBubble === 'function') {
      showSkillCastBubble(card, '표식', 'once');
    }
  }
  setTimeout(() => {
    for (const c of casters) {
      if (c.ownerIdx == null || c.pieceIdx == null) continue;
      const card = resolveCard(c);
      if (card && typeof endSkillCastDim === 'function') endSkillCastDim(card);
    }
  }, 780);
});

socket.on('death_detonate_cast', ({ casters, bombs }) => {
  if (!Array.isArray(casters) || casters.length === 0) return;
  // 각 caster 카드 찾아서 spotlight + 말풍선
  for (const c of casters) {
    if (c.ownerIdx == null || c.pieceIdx == null) continue;
    let card = null;
    if (S.isTeamMode) {
      // 팀 모드 — team-profile-block[data-player-idx][data-piece-idx]
      card = document.querySelector(`.team-profile-block[data-player-idx="${c.ownerIdx}"] [data-piece-idx="${c.pieceIdx}"]`);
    } else if (S.isSpectator) {
      // 1v1 관전자 — p0 → my-pieces-info, p1 → opp-pieces-info
      const containerSel = (c.ownerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
      const cardSel = (c.ownerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
      card = document.querySelectorAll(`${containerSel} ${cardSel}`)[c.pieceIdx];
    } else {
      // 1v1 인게임 — 본인이면 my-pieces, 상대면 opp-pieces
      if (c.ownerIdx === S.playerIdx) {
        card = document.querySelectorAll('#my-pieces-info .my-piece-card')[c.pieceIdx];
      } else {
        card = document.querySelectorAll('#opp-pieces-info .opp-piece-card')[c.pieceIdx];
      }
    }
    if (!card) continue;
    // spotlight (skill cast dim 와 동일 메커니즘) — caster card 강조 + 다른 dim
    if (typeof startSkillCastDim === 'function') {
      const _targetInfo = (S.isTeamMode && c.ownerIdx != null && c.pieceIdx != null)
        ? { playerIdx: c.ownerIdx, pieceIdx: c.pieceIdx }
        : null;
      startSkillCastDim(card, _targetInfo);
    }
    // "사망 기폭" 노란 말풍선 (자유·턴1회 색상 = once) — 이모지 없음
    if (typeof showSkillCastBubble === 'function') {
      showSkillCastBubble(card, '사망 기폭', 'once');
    }
  }
  // 780ms (CAST_DURATION 과 일치) 후 spotlight 해제 — detonation_intro 가 곧 도착
  setTimeout(() => {
    for (const c of casters) {
      if (c.ownerIdx == null || c.pieceIdx == null) continue;
      let card = null;
      if (S.isTeamMode) {
        card = document.querySelector(`.team-profile-block[data-player-idx="${c.ownerIdx}"] [data-piece-idx="${c.pieceIdx}"]`);
      } else if (S.isSpectator) {
        const containerSel = (c.ownerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
        const cardSel = (c.ownerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
        card = document.querySelectorAll(`${containerSel} ${cardSel}`)[c.pieceIdx];
      } else {
        if (c.ownerIdx === S.playerIdx) {
          card = document.querySelectorAll('#my-pieces-info .my-piece-card')[c.pieceIdx];
        } else {
          card = document.querySelectorAll('#opp-pieces-info .opp-piece-card')[c.pieceIdx];
        }
      }
      if (card && typeof endSkillCastDim === 'function') endSkillCastDim(card);
    }
  }, 780);
});

// ── 기폭 인트로 (폭발 GIF → impact 타이밍에 셀 쉐이크/플래시) ──
// 인트로 마커(💣 idle) 없이 바로 폭발 GIF 오버레이 시작.
// BOMB_IMPACT_DELAY(1300ms, frame #10) 에서 셀 쉐이크 + 컬러 플래시 + 파편 + SFX 발동.
socket.on('detonation_intro', ({ bombs }) => {
  if (!Array.isArray(bombs) || bombs.length === 0) return;
  const board = document.getElementById('game-board');
  if (!board) return;
  const SKILL_START_MS = getSpFlightEndMs(1);  // 780ms
  S._suppressNextBombSfx = (S._suppressNextBombSfx || 0) + bombs.length;

  const BOMB_IMPACT_DELAY = 1300;   // frame #10 — 폭발 최대 크기 도달
  const BOMB_GIF_DURATION  = 2600;  // 20 frames × 130ms
  const BOMB_STAGGER_MS    = 350;

  // ★ 팀 컬러 결정
  const isOwnerMine = (ownerIdx) => {
    if (ownerIdx == null) return false;
    if (S.isTeamMode && Array.isArray(S.teamGamePlayers)) {
      const ownerPl = S.teamGamePlayers.find(p => p.idx === ownerIdx);
      return !!(ownerPl && ownerPl.teamId === S.teamId);
    }
    return ownerIdx === S.playerIdx;
  };

  // 셔플 — 폭발 순서 무작위
  const blastOrder = bombs.map((_, i) => i);
  for (let i = blastOrder.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [blastOrder[i], blastOrder[j]] = [blastOrder[j], blastOrder[i]];
  }

  // ★ 폭발 GIF — 프리뷰(bomb-preview.html)의 createExplodeImg 와 완전 동일한 방식.
  //   매 폭탄마다 fresh fetch → NETSCAPE 제거 → Blob URL → body에 fixed 배치.
  //   Comment Extension 미삽입 (프리뷰와 동일).
  const explodeUrl = window.BOMB_EXPLODE_GIF || '/assets/bomb_explode.gif';

  // 프리뷰와 동일한 GIF 클린 함수 + Chrome 동일 바이너리 타이머 공유 차단
  if (!window._bombGifUid) window._bombGifUid = 0;
  function _createBombExplodeBlob() {
    return fetch(explodeUrl)
      .then(r => r.arrayBuffer())
      .then(buf => {
        const bytes = new Uint8Array(buf);
        let cleaned = bytes;
        for (let i = 0; i < bytes.length - 18; i++) {
          if (bytes[i] === 0x21 && bytes[i+1] === 0xFF && bytes[i+2] === 0x0B) {
            const sig = String.fromCharCode(...bytes.slice(i+3, i+14));
            if (sig === 'NETSCAPE2.0' || sig === 'ANIMEXTS1.0') {
              cleaned = new Uint8Array(buf.byteLength - 19);
              cleaned.set(bytes.slice(0, i));
              cleaned.set(bytes.slice(i + 19), i);
              break;
            }
          }
        }
        // ★ 고유 GIF Comment Extension 삽입 — Chrome 동일 바이너리 GIF 타이머 공유 차단.
        //   같은 bomb_explode.gif 를 동시에 여러 셀에서 재생 시,
        //   Chrome 이 바이트 동일 GIF 의 애니메이션 타이머를 공유 → 한쪽 종료 시 다른 쪽도 멈춤.
        //   고유 4-byte ID 를 Comment Extension 으로 삽입하여 바이너리를 차별화.
        const _uid = ++window._bombGifUid;
        const _comment = new Uint8Array([0x21, 0xFE, 4,
          (_uid >>> 24) & 0xFF, (_uid >>> 16) & 0xFF, (_uid >>> 8) & 0xFF, _uid & 0xFF, 0x00]);
        // Global Color Table 끝 직후에 삽입
        const _packed = cleaned[10];
        const _hasGCT = (_packed >> 7) & 1;
        const _gctBytes = _hasGCT ? 3 * (1 << ((_packed & 7) + 1)) : 0;
        const _insertAt = 13 + _gctBytes;
        const _final = new Uint8Array(cleaned.length + _comment.length);
        _final.set(cleaned.subarray(0, _insertAt), 0);
        _final.set(_comment, _insertAt);
        _final.set(cleaned.subarray(_insertAt), _insertAt + _comment.length);

        const blob = new Blob([_final], { type: 'image/gif' });
        return URL.createObjectURL(blob);
      });
  }

  blastOrder.forEach((bombIdx, slot) => {
    const b = bombs[bombIdx];
    const startT = SKILL_START_MS + slot * BOMB_STAGGER_MS;

    setTimeout(() => {
      const cell = board.querySelector(`.cell[data-col="${b.col}"][data-row="${b.row}"]`);
      if (!cell) return;

      // 팀 컬러 클래스
      cell.classList.add(isOwnerMine(b.owner) ? 'bomb-team-mine' : 'bomb-team-enemy');

      // 기존 bomb idle GIF 제거
      const existingIdle = cell.querySelector('.bomb-marker-gif');
      if (existingIdle) existingIdle.remove();

      // ★ 매 폭탄마다 fresh Blob 생성 (프리뷰와 동일)
      _createBombExplodeBlob().then(blobUrl => {
        // document.body에 position:fixed 배치 — renderGameBoard 영향 밖
        const cellRect = cell.getBoundingClientRect();
        const gif = document.createElement('img');
        gif.className = 'bomb-explode-overlay';
        gif.src = blobUrl;
        gif.style.position = 'fixed';
        gif.style.left = (cellRect.left + cellRect.width / 2) + 'px';
        gif.style.top = (cellRect.top + cellRect.height / 2) + 'px';
        gif.style.width = Math.round(cellRect.width * 1.4) + 'px';
        gif.style.height = Math.round(cellRect.height * 1.4) + 'px';
        gif.style.zIndex = '9600';
        // ★ 기폭 앞 10프레임(=BOMB_IMPACT_DELAY)은 폭탄 idle 과 동일한 아웃라인 유지,
        //   임팩트(frame10) 이후 본격 폭발에서는 아웃라인 제거.
        gif.style.filter =
          'drop-shadow(0.9px 0 0 rgba(98,101,147,0.65)) drop-shadow(-0.9px 0 0 rgba(98,101,147,0.65))' +
          ' drop-shadow(0 0.9px 0 rgba(98,101,147,0.65)) drop-shadow(0 -0.9px 0 rgba(98,101,147,0.65))' +
          ' drop-shadow(0 0 1.5px rgba(98,101,147,0.9))';
        setTimeout(() => { gif.style.filter = ''; }, BOMB_IMPACT_DELAY);
        document.body.appendChild(gif);

        // ★ 임팩트 타임스탬프 기록 — bomb_detonated 핸들러가 이 시점까지 대기
        if (!S._bombImpactAt) S._bombImpactAt = {};
        S._bombImpactAt[`${b.col},${b.row}`] = Date.now() + BOMB_IMPACT_DELAY;

        // ★ BOMB_IMPACT_DELAY 후 — 셀 쉐이크 + 컬러 플래시 + SFX
        setTimeout(() => {
          const c2 = board.querySelector(`.cell[data-col="${b.col}"][data-row="${b.row}"]`);
          if (c2) {
            c2.classList.add(isOwnerMine(b.owner) ? 'bomb-team-mine' : 'bomb-team-enemy');
            c2.classList.add('bomb-blast');
            c2.classList.add('bomb-cell-shake');
            setTimeout(() => c2.classList.remove('bomb-cell-shake'), 450);
          }
          try { playSfxBombExplode(); } catch (e) {}
        }, BOMB_IMPACT_DELAY);

        // ★ GIF 종료 후 정리 (2600ms + 200ms 버퍼 = 2800ms — 프리뷰와 동일)
        setTimeout(() => {
          if (gif.parentNode) gif.remove();
          URL.revokeObjectURL(blobUrl);
          const c3 = board.querySelector(`.cell[data-col="${b.col}"][data-row="${b.row}"]`);
          if (c3) c3.classList.remove('bomb-blast', 'bomb-team-mine', 'bomb-team-enemy');
        }, BOMB_GIF_DURATION + 200);
      });
    }, startT);
  });

  // 보드 정리 — 마지막 폭탄 GIF 종료 후
  const totalMs = SKILL_START_MS + (bombs.length - 1) * BOMB_STAGGER_MS + BOMB_GIF_DURATION + 250;
  setTimeout(() => {
    if (Array.isArray(S.boardObjects)) {
      const coordSet = new Set(bombs.map(b => `${b.col},${b.row}`));
      S.boardObjects = S.boardObjects.filter(o => !(o.type === 'bomb' && coordSet.has(`${o.col},${o.row}`)));
      try { renderGameBoard(); } catch (e) {}
    }
  }, totalMs);
});

// ── 폭탄 폭발 ──
socket.on('bomb_detonated', function _onBombDetonated({ col, row, hits, remainsHits, destroyedRats }) {
  // ★ 폭탄 피격 타이밍 동기화 — detonation_intro 의 셀 흔들림 시점까지 HP 갱신/데미지 표시 대기.
  //   서버가 bomb_detonated 를 먼저 보내도, 클라이언트에서 셀이 흔들리는 그 순간에 피격이 보이도록.
  const _ik = col + ',' + row;
  if (S._bombImpactAt && S._bombImpactAt[_ik]) {
    const _delay = S._bombImpactAt[_ik] - Date.now();
    delete S._bombImpactAt[_ik];
    if (_delay > 50) {
      setTimeout(() => _onBombDetonated({ col, row, hits, remainsHits, destroyedRats }), _delay);
      return;
    }
  }

  // ★ FIX (폭탄으로 쥐 격파): 폭발 임팩트 순간에 쥐 사망 애니 + boardObjects 제거.
  //   _animateSkillDestroyedRats 가 관전/플레이어 시점 모두 처리(viewerIdx 분기).
  if (Array.isArray(destroyedRats) && destroyedRats.length > 0) {
    _animateSkillDestroyedRats(destroyedRats);
  }

  // ★ 유해 폭발 피격 — 폭발 임팩트(blast)와 동일 순간에 단계별 연출 재생.
  //   (이 시점은 위 delay 재스케줄로 인해 정확히 셀 흔들림/폭발 프레임과 일치)
  if (Array.isArray(remainsHits) && remainsHits.length > 0 && typeof animateRemainsHit === 'function') {
    const _rb = document.getElementById('game-board');
    if (_rb) {
      for (const rh of remainsHits) {
        const facingLeft = !!(S._remainsFacing && S._remainsFacing[`${rh.col},${rh.row}`]);
        animateRemainsHit(_rb, rh.col, rh.row, { hitNumber: (rh.stage || 2) - 1, facingLeft, onSettle: () => {
          if (!S.remains) return;
          if (rh.destroyed) S.remains = S.remains.filter(r => !(r.col === rh.col && r.row === rh.row));
          else { const e = S.remains.find(r => r.col === rh.col && r.row === rh.row); if (e) e.hits = (rh.stage || 2) - 1; }
          S._cellFP = null;
        }});
      }
    }
  }

  // ★ 기폭 스킬로 발동된 경우 — detonation_intro 가 이미 SFX 재생했으므로 중복 차단.
  //   화약상 사망 자동 폭발 등 다른 경로는 정상 SFX 재생.
  if (S._suppressNextBombSfx && S._suppressNextBombSfx > 0) {
    S._suppressNextBombSfx--;
  } else {
    playSfxBombExplode();
  }
  // ★ 피격/격파 SFX — 트랩 핸들러와 동일 패턴 (사용자 요청: 폭탄 피격 효과음 누락 수정).
  if (Array.isArray(hits) && hits.length > 0) {
    if (hits.some(h => h.destroyed)) { try { playSfx('kill'); } catch (e) {} }
    else { try { playSfx('hit'); } catch (e) {} }
  }
  // ★ 1v1 관전자 — 별도 처리: spectator 의 S.myPieces/oppPieces 가 비어있어 일반 경로가 무동작.
  //   defOwnerIdx 0=p0(#my-pieces-info), 1=p1(#opp-pieces-info) 매핑으로 카드 hit flash 적용.
  if (S.isSpectator && !S.isTeamMode) {
    if (Array.isArray(S.boardObjects)) {
      S.boardObjects = S.boardObjects.filter(o => !(o.type === 'bomb' && o.col === col && o.row === row));
    }
    animateAttack([], hits.map(h => ({ col: h.col, row: h.row })));
    // ★ 사용자 요청: 동시간대 사망자/피해자는 단일 토스트·로그로 통합.
    const _killedLabelsSpec = [];
    const _hurtLabelsSpec = [];
    for (const h of hits) {
      if (h.defPieceIdx == null || h.defOwnerIdx == null) continue;
      const dmg = (typeof h.damage === 'number') ? h.damage : 0;
      if (dmg > 0) {
        const key = (h.defOwnerIdx === 0) ? `my:${h.defPieceIdx}` : `opp:${h.defPieceIdx}`;
        addBodyDamage(key, dmg);
      }
      if (h.name) {
        const label = h.icon ? `${pieceIconHtml(h.icon, {size:'1em'})}${h.name}` : h.name;
        if (h.destroyed) _killedLabelsSpec.push(label);
        else if (dmg > 0) _hurtLabelsSpec.push(label);
      }
      const containerSel = (h.defOwnerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
      const cardSel = (h.defOwnerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
      const card = document.querySelectorAll(`${containerSel} ${cardSel}`)[h.defPieceIdx];
      if (card) applyHitFlashWithBrighten(card);
    }
    if (_killedLabelsSpec.length > 0) {
      const lbl = _killedLabelsSpec.join(', ');
      showSkillToast(`${lbl} 격파!`);
      addLog(`${lbl} 격파`, 'hit');
    }
    if (_hurtLabelsSpec.length > 0) {
      addLog(`${_hurtLabelsSpec.join(', ')} 폭탄 피해`, 'hit');
    }
    if (S.specGameState) renderSpectatorGame(S.specGameState);
    return;
  }
  // 보드에서 해당 폭탄 제거 (자동 폭발 케이스 등)
  if (Array.isArray(S.boardObjects)) {
    S.boardObjects = S.boardObjects.filter(o => !(o.type === 'bomb' && o.col === col && o.row === row));
  }
  // ★ 사용자 요청: 동시간대 사망/피해는 단일 토스트·로그로 통합 (한 hit 마다 X).
  //   격파 토스트는 일반 공격과 동일한 [labels 격파!] 양식 (사용자 요청: 통일).
  //   폭탄 피해 로그만 폭탄 식별을 위해 [labels 폭탄 피해] 표기 유지.
  const _killedLabels = [];
  const _hurtLabels = [];
  for (const h of hits) {
    S.attackLog.push({ col: h.col, row: h.row, hit: true, turn: S.turnNumber });
    if (h.name) {
      const label = h.icon ? `${pieceIconHtml(h.icon, {size:'1em'})}${h.name}` : h.name;
      if (h.destroyed) _killedLabels.push(label);
      else if (typeof h.damage === 'number' && h.damage > 0) _hurtLabels.push(label);
    }
  }
  if (_killedLabels.length > 0) {
    const lbl = _killedLabels.join(', ');
    showSkillToast(`${lbl} 격파!`);
    addLog(`${lbl} 격파`, 'hit');
  }
  if (_hurtLabels.length > 0) {
    addLog(`${_hurtLabels.join(', ')} 폭탄 피해`, 'hit');
  }
  if (hits.length === 0) {
    S.attackLog.push({ col, row, hit: false, turn: S.turnNumber });
  }

  // ★ HP 갱신 + 본체 데미지 도장 — 트랩(`trap_triggered`)과 동일하게 처리.
  //   원래는 후속 game_state/team_game_update 가 HP 를 가져왔지만, 그 사이 시각적으로
  //   HP 바·도장·사망 아이콘이 누락되는 문제가 있어 즉시 반영.
  let bombAnyDestroyed = false;
  // ★ 사용자 보고 (치명적 버그): 양 측이 같은 이름 캐릭터(예: 양쪽 화약상) 보유 시
  //   name fallback 이 cross-side 매칭 → 잘못된 piece 의 HP 가 갱신되던 문제.
  //   trap_triggered 의 victimOwnerIdx 패턴과 동일하게 hits[].defOwnerIdx 로 owner 강제 일치.
  const _myOwnerIdx = S.playerIdx;
  const _oneVoneOppIdx = (typeof S.playerIdx === 'number') ? (1 - S.playerIdx) : null;
  const _teammateOwnerIdx = (S.isTeamMode && Array.isArray(S.teamGamePlayers))
    ? (S.teamGamePlayers.find(p => p.teamId === S.teamId && p.idx !== S.playerIdx)?.idx)
    : null;

  // ★ 폭발 임팩트 피격 GIF — 이 핸들러는 이미 폭발 임팩트 시각으로 재스케줄되어 실행됨(위 _bombImpactAt).
  //   따라서 지금 호출하면 셀 흔들림/폭발 프레임과 같은 순간에 피격 GIF 가 재생됨 (사용자 요청).
  //   내 말/팀원 = isDefending true(non-opp-marked), 상대 말 = false(opp-marked).
  //   숨겨진(미공개) 적은 보드에 마커가 없어 animateBoardIconHit 가 자동 스킵.
  //   (재렌더 생존은 _activeHitGifs/_reapplyActiveHitGifs 가 보장 → 후속 HP 렌더에도 안 사라짐)
  {
    const _myHitCells = [], _oppHitCells = [];
    for (const h of hits) {
      if (h.col == null || h.row == null) continue;
      const _mine = (h.defOwnerIdx === _myOwnerIdx) ||
        (S.isTeamMode && _teammateOwnerIdx != null && h.defOwnerIdx === _teammateOwnerIdx);
      (_mine ? _myHitCells : _oppHitCells).push({ col: h.col, row: h.row });
    }
    // 셀 배경 플래시/흔들림은 폭발(bomb-blast/bomb-cell-shake)이 이미 담당 →
    // 여기선 유닛 아이콘 피격 GIF + 마커 흔들림만(animateBoardIconHit) 재생.
    if (_oppHitCells.length > 0) animateBoardIconHit(_oppHitCells, false);
    if (_myHitCells.length > 0)  animateBoardIconHit(_myHitCells, true);
  }

  for (const h of hits) {
    const updateInArr = (arr, expectedOwnerIdx) => {
      if (!Array.isArray(arr)) return -1;
      // owner 일치 강제 — 다른 owner 면 스킵 (1v1 양 측 같은 이름 cross-match 방지).
      if (typeof h.defOwnerIdx === 'number' && typeof expectedOwnerIdx === 'number'
          && h.defOwnerIdx !== expectedOwnerIdx) {
        return -1;
      }
      let idx = arr.findIndex(p => p.alive && p.name === h.name && p.col === h.col && p.row === h.row);
      if (idx < 0) idx = arr.findIndex(p => p.alive && p.name === h.name);
      if (idx >= 0) {
        if (typeof h.newHp === 'number') arr[idx].hp = h.newHp;
        if (h.destroyed) arr[idx].alive = false;
      }
      return idx;
    };
    const myI  = updateInArr(S.myPieces, _myOwnerIdx);
    const oppI = updateInArr(S.oppPieces, _oneVoneOppIdx);
    const tmI  = (S.isTeamMode && S.teammatePieces && _teammateOwnerIdx != null)
      ? updateInArr(S.teammatePieces, _teammateOwnerIdx)
      : -1;
    if (h.destroyed) bombAnyDestroyed = true;
    if (typeof h.damage === 'number' && h.damage > 0) {
      if (myI >= 0) addBodyDamage(`my:${myI}`, h.damage);
      else if (oppI >= 0) addBodyDamage(`opp:${oppI}`, h.damage);
      else if (tmI >= 0 && S.isTeamMode && _teammateOwnerIdx != null) {
        addBodyDamage(`${_teammateOwnerIdx}:${tmI}`, h.damage);
      }
    }
  }
  // ★ 폭탄 사망 애니메이션 정보 수집 — alive 업데이트 완료, DOM 아직 미갱신 상태에서 방향 캡처.
  //   attack_result 의 _detectDeaths 와 동일한 패턴이지만 hits 배열에서 직접 구축.
  const _bombDeathInfos = [];
  if (bombAnyDestroyed) {
    const _bboard = document.getElementById('game-board');
    for (const h of hits) {
      if (!h.destroyed) continue;
      const _isMyUnit = (h.defOwnerIdx === _myOwnerIdx) ||
        (S.isTeamMode && h.defOwnerIdx === _teammateOwnerIdx);
      let facingLeft = false;
      if (_bboard) {
        const _bcell = _bboard.querySelector(`.cell[data-col="${h.col}"][data-row="${h.row}"]`);
        if (_bcell) {
          const _msel = _isMyUnit
            ? '.piece-marker:not(.opp-marked)'
            : '.piece-marker.opp-marked';
          const _mk = _bcell.querySelector(_msel) || _bcell.querySelector('.piece-marker');
          if (_mk) {
            const _gif = _mk.querySelector('.p-icon img.p-gif');
            if (_gif && (_gif.style.transform || '').includes('scaleX(-1)')) facingLeft = true;
          }
        }
      }
      // type 결정 — piece 배열에서 조회 (alive=false 이지만 type 필드는 유지)
      let _dtype = h.type || null;
      if (!_dtype) {
        const _findT = (arr) => {
          if (!Array.isArray(arr)) return null;
          const p = arr.find(pp => pp.col === h.col && pp.row === h.row && pp.name === h.name);
          return p ? (p.type || p.pieceType || null) : null;
        };
        _dtype = _findT(S.myPieces) || _findT(S.oppPieces)
          || (S.isTeamMode ? _findT(S.teammatePieces) : null) || null;
      }
      _bombDeathInfos.push({
        col: h.col, row: h.row,
        type: _dtype,
        facingLeft,
        isEnemy: !_isMyUnit,
      });
    }
  }
  // ★ 자동 추리토큰 — 폭탄도 적의 piece 위치를 노출. 팀원 폭탄 / 본인 폭탄 양쪽 모두 적용.
  //   조건: meaningful hit (사망 제외) 정확히 1명 + 적팀 piece (1v1: 상대) — 일반 공격과 동일 규칙.
  {
    const _meaningful = (hits || []).filter(h => !h.destroyed && typeof h.damage === 'number' && h.damage > 0
      && h.defPieceIdx != null);
    if (_meaningful.length === 1) {
      const h = _meaningful[0];
      let isEnemyVictim = false;
      let pieceKey = null;
      let pieceObj = null;
      if (S.isTeamMode && h.defOwnerIdx != null) {
        const victimPlayer = (S.teamGamePlayers || []).find(p => p.idx === h.defOwnerIdx);
        isEnemyVictim = !!(victimPlayer && victimPlayer.teamId !== S.teamId);
        if (isEnemyVictim) {
          pieceObj = victimPlayer.pieces?.[h.defPieceIdx];
          if (pieceObj) pieceKey = `${pieceObj.type}:${pieceObj.subUnit || ''}@${h.defOwnerIdx}`;
        }
      } else if (!S.isTeamMode) {
        // 1v1 — defOwnerIdx 가 1 - playerIdx 이면 상대
        const myIdx = S.playerIdx;
        if (typeof myIdx === 'number' && (h.defOwnerIdx == null || h.defOwnerIdx !== myIdx)) {
          isEnemyVictim = true;
          pieceObj = S.oppPieces?.[h.defPieceIdx];
          if (pieceObj) pieceKey = `${pieceObj.type}:${pieceObj.subUnit || ''}`;
        }
      }
      if (isEnemyVictim && pieceKey && pieceObj) {
        try {
          S.deductionTokens = (S.deductionTokens || []).filter(t => t.pieceKey !== pieceKey && !(t.col === h.col && t.row === h.row));
          S.deductionTokens.push({ pieceKey, icon: pieceObj.icon || h.icon, name: pieceObj.name || h.name, col: h.col, row: h.row });
        } catch (e) {}
      }
    }
  }
  // 사망 시 추리 토큰 즉시 제거 (트랩과 동일)
  if (bombAnyDestroyed && typeof pruneDeductionTokens === 'function') pruneDeductionTokens();

  // 폭탄 피격 애니메이션: 내 유닛 & 상대 유닛 모두 (팀모드는 팀원도 포함)
  // ★ 사용자 보고 (잘못된 링크): 양 측이 같은 캐릭터 보유 시 name 매칭이 cross-side 매칭하던 문제 →
  //   ownerIdx 인자 전달로 hits 의 defOwnerIdx 와 일치하는 것만 매칭 (1v1 자기/상대 정확 분리).
  const myOwnerIdx = S.playerIdx;
  const oppOwnerIdx = (S.playerIdx != null) ? (1 - S.playerIdx) : undefined;
  const myBombIdx = findPieceIndices(S.myPieces, hits, true, myOwnerIdx);
  const oppBombIdx = findPieceIndices(S.oppPieces, hits, true, oppOwnerIdx);
  // 팀모드: 팀원 → 팀원의 ownerIdx 와 일치하는 hits 만
  let tmBombIdx = [];
  if (S.isTeamMode && S.teammatePieces) {
    const teammate = (S.teamGamePlayers || []).find(p => p.teamId === S.teamId && p.idx !== S.playerIdx);
    if (teammate) tmBombIdx = findPieceIndices(S.teammatePieces, hits, true, teammate.idx);
  }

  // ★ 렌더 후 피격·프로필 애니메이션 공통 로직
  const _doPostBombRender = () => {
    // 셀 + 보드 아이콘 피격 애니메이션 — renderGameBoard 이후에 호출 (셀 DOM 필요)
    animateAttack([], hits.map(h => ({ col: h.col, row: h.row })));
    if (!S.isTeamMode) {
      applyProfileHitAnim('#my-pieces-info .my-piece-card', myBombIdx);
      applyProfileHitAnim('#opp-pieces-info .opp-piece-card', oppBombIdx);
    }
    // ★ 사용자 보고 (갑주무사 패시브 누설): flushDefensiveAlerts 즉시 flush.
    if (typeof flushDefensiveAlerts === 'function') {
      const _bombKilled = (hits || []).some(h => h.destroyed);
      flushDefensiveAlerts({ skipReduction: _bombKilled });
    }
    // 팀모드: 팀원 카드 — data-piece-idx 기반 정확 매칭
    if (tmBombIdx.length > 0 && S.isTeamMode) {
      const teammate = (S.teamGamePlayers || []).find(p => p.teamId === S.teamId && p.idx !== S.playerIdx);
      if (teammate) {
        requestAnimationFrame(() => {
          for (const i of tmBombIdx) {
            const card = document.querySelector(`#my-pieces-info .team-profile-block[data-player-idx="${teammate.idx}"] [data-piece-idx="${i}"]`);
            if (card) {
              card.classList.remove('profile-hit');
              void card.offsetWidth;
              card.classList.add('profile-hit');
              setTimeout(() => card.classList.remove('profile-hit'), 1800);
            }
          }
        });
      }
    }
  };

  // ★ 폭탄 사망 애니메이션 — attack_result 와 동일한 _pendingDeathCells → playDeathAnimations 패턴.
  //   사망 유닛이 있으면: renderGameBoard 먼저 하되 사망 GIF 끝날 때까지 dead piece 를 DOM 에 유지.
  if (_bombDeathInfos.length > 0) {
    S._pendingDeathCells = new Set(_bombDeathInfos.map(d => `${d.col},${d.row}`));
    renderGameBoard();
    if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles();
    else { renderMyPieces(); renderOppPieces(); }
    _doPostBombRender();

    // 피격 GIF 정착 후 사망 GIF 재생 (400ms — 피격 흔들림 0.35s + 여유)
    scheduleDeathGif(_bombDeathInfos, _bombDeathInfos, () => {
      renderGameBoard();
      if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles();
      else { renderMyPieces(); renderOppPieces(); }
    });
  } else {
    // 사망 없음 또는 모든 사망이 유해 제외 타입 — 기존대로 즉시 렌더
    if (bombAnyDestroyed) _addClientSideRemains(_bombDeathInfos);
    renderGameBoard();
    if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles();
    else { renderMyPieces(); renderOppPieces(); }
    _doPostBombRender();
  }
});

// ── 저주 지속 데미지 — 토스트·로그 없음. 프로필 애니메이션 + 보라 데미지 도장 (3초)만 ──
// 사용자 요청: 절대 토스트 출력 X. 일반 피격 애니메이션과도 구별되어야 함.
// 그래서 다음 team_game_update 의 빨간 profile-hit 트리거를 스킵하기 위해 _recentCurseDamageKeys 마킹.
socket.on('curse_tick', ({ playerIdx, targetName, damage, newHp }) => {
  if (!targetName) return;
  // 일반 피격 애니가 후속 team_game_update 에서 중복 발동되지 않게 마킹 (임팩트까지 커버하도록 길게)
  if (!S._recentCurseDamageKeys) S._recentCurseDamageKeys = new Set();
  const key = `${playerIdx}:${targetName}`;
  S._recentCurseDamageKeys.add(key);
  setTimeout(() => { if (S._recentCurseDamageKeys) S._recentCurseDamageKeys.delete(key); }, 2500);
  // ★ 순차 처리: 이 저주 데미지가 곧바로 해제(HP≤1)로 이어질 때, 해제 모션·토스트·로그가 데미지
  //   임팩트(피격 모션) 전에 먼저 터지는 것을 막는다. 임팩트+피격 완료 시각까지 해제를 보류시킬
  //   기준 시각을 기록(_curseBusyUntil). 데미지 모션 시작(250) + 임팩트(~520) + 피격(~450) 여유.
  if (!S._curseBusyUntil) S._curseBusyUntil = {};
  S._curseBusyUntil[key] = Date.now() + 1300;
  // ★ 저주 데미지를 "공격 모션"처럼 — 아래에서 대상만 해석하고, 실제 효과(피격모션·토스트·로그·HP)는
  //   저주 데미지 GIF 4번째 프레임(임팩트) 시점에 동기. (일반 공격과 동일 타이밍.)
  let _ctPc = null, _ctCol = null, _ctRow = null, _ctStamp = null, _ctDef = true, _ctBO = playerIdx, _ctBI = -1, _ctOn = false;

  // 1v1: playerIdx 로 피해 대상 플레이어를 특정 — 양쪽에 이름이 같은 말이 있어도 혼동 없음
  // ★ 이름(targetName)만으로 myPieces/oppPieces 를 동시 탐색하면 마녀 vs 마녀처럼
  //   같은 캐릭터명이 양쪽에 있을 때 상대 말에도 HP 변경 + 도장이 잘못 적용되는 버그 발생.
  if (!S.isTeamMode) {
    if (playerIdx === S.playerIdx) {
      const myIdx = S.myPieces?.findIndex(p => p.alive && p.name === targetName) ?? -1;
      if (myIdx >= 0) { _ctPc=S.myPieces[myIdx]; _ctCol=_ctPc.col; _ctRow=_ctPc.row; _ctStamp=`my:${myIdx}`; _ctDef=true; _ctBO=S.playerIdx; _ctBI=myIdx; _ctOn=true; }
    } else {
      const oppIdx = S.oppPieces?.findIndex(p => p.alive && p.name === targetName) ?? -1;
      if (oppIdx >= 0) { _ctPc=S.oppPieces[oppIdx]; _ctCol=_ctPc.col; _ctRow=_ctPc.row; _ctStamp=`opp:${oppIdx}`; _ctDef=false; _ctBO=1-S.playerIdx; _ctBI=oppIdx; _ctOn=!!_ctPc.marked; }
    }
  }
  // 팀모드: playerIdx 가 일치하는 플레이어만 업데이트
  if (S.isTeamMode) {
    for (const pl of (S.teamGamePlayers || [])) {
      if (pl.idx !== playerIdx) continue;
      const idxInPl = (pl.pieces || []).findIndex(p => p.alive && p.name === targetName);
      if (idxInPl < 0) continue;
      const _cp = pl.pieces[idxInPl]; const _ours = (pl.idx === S.playerIdx) || (pl.teamId === S.teamId);
      _ctPc=_cp; _ctCol=_cp.col; _ctRow=_cp.row; _ctStamp=`${pl.idx}:${idxInPl}`; _ctDef=_ours; _ctBO=pl.idx; _ctBI=idxInPl; _ctOn = _ours || !!_cp.marked;
      break;
    }
  }
  if (!_ctPc) return;
  const _ctDmgStr = Number.isInteger(damage) ? `${damage}` : `${damage.toFixed(1)}`;
  // ── 임팩트 — 저주 데미지 GIF 4번째 프레임 시점: 피격모션 + 토스트 + 로그 + 실제 데미지(도장/HP) 동기 ──
  const _ctImpact = () => {
    try { playSfxCurseDamage(); } catch (e) {}
    if (_ctStamp) addCurseDamageStampValue(_ctStamp, damage);
    if (typeof newHp === 'number' && _ctPc) _ctPc.hp = newHp;
    if (_ctOn && typeof animateBoardIconHit === 'function') animateBoardIconHit([{ col: _ctCol, row: _ctRow }], _ctDef);
    try { addLog(`☠ 저주: ${targetName} ${_ctDmgStr} 피해`, 'skill'); } catch (e) {}
    try { showSkillToast(`☠ 저주: ${targetName} ${_ctDmgStr} 피해`, !_ctDef, undefined, 'curse'); } catch (e) {}
    try { if (S.isTeamMode && typeof renderTeamProfiles === 'function') renderTeamProfiles(); else { renderMyPieces(); renderOppPieces(); } } catch (e) {}
    // dim 해제(turn-bright) persist — 후속 render 에서 wipe 방지
    if (_ctBI >= 0) { try { _persistTurnBright(_ctBO, _ctBI); const _c = _findPieceCard(_ctBO, _ctBI); if (_c) _c.classList.add('turn-bright'); } catch (e) {} }
  };
  // ── 모션 시작(턴 시작 렌더 settle 후) → 저주 데미지 GIF 재생 → 4번째 프레임(frame4)에 임팩트 ──
  //   타이밍은 일반 공격과 동일: _fetchGifFrameTimings 의 frameDelays[3] (없으면 ATTACK_IMPACT_DELAY).
  setTimeout(() => {
    if (_ctOn) playCurseBoardAnim(_ctCol, _ctRow, 'damage');
    const _u = window.CURSE_GIFS && window.CURSE_GIFS.damage;
    const _fp = (_u && typeof _fetchGifFrameTimings === 'function') ? _fetchGifFrameTimings(_u) : Promise.resolve({ frameDelays: [] });
    _fp.then(t => {
      const fd = (t && t.frameDelays) || [];
      let d = (fd.length > 3) ? fd[3] : (fd.length ? fd[fd.length - 1] : ATTACK_IMPACT_DELAY);
      d = Math.min(d, 3000);
      setTimeout(_ctImpact, d);
    }).catch(() => setTimeout(_ctImpact, ATTACK_IMPACT_DELAY));
  }, 250);
});
// (구) DOM 기반 저주 도장 함수 — 더 이상 호출되지 않음.
// 새 시스템: S.curseDamageThisTurn 누적 → buildDamageOverlay 가 카드 마크업에 도장 포함.
function attachCurseDamageStamp(card, damage) {
  // no-op (호환용 빈 스텁)
  return;
  // 이전 코드 (참고용 보존):
  if (!card) return;
  const existing = card.querySelector('.dmg-stamp.curse');
  if (existing) existing.remove();
  const stamp = document.createElement('div');
  stamp.className = 'dmg-stamp curse';
  const dmgText = Number.isInteger(damage) ? `${damage} 데미지` : `${damage.toFixed(1)} 데미지`;
  stamp.textContent = dmgText;
  if (getComputedStyle(card).position === 'static') card.style.position = 'relative';
  card.appendChild(stamp);
  setTimeout(() => { if (stamp.parentNode) stamp.remove(); }, 3000);
}

// ── 패시브 알림 ──
// '공격받았습니다!' 가 항상 먼저 나오도록 — 공격 반응형 패시브(bodyguard/monk/count/armoredWarrior 등)는
// being_attacked 처리 후로 출력 순서를 미룬다.
// 공격 반응형 패시브 — 'wizard' 도 포함 (토스트·로그 출력 + 마법구 애니메이션 동시)
// ★ 'wizard' 를 다시 DEFENSIVE 버퍼에 포함 — 타이밍 문제 해결용 (사용자 보고: 유황범람 시전 중 wizard
//   passive 가 sulfur 애니 재생 전에 fire 되어 마법구 비행 도착 시점에 트레이가 비어있음).
//   ★ 원래 문제 (팀원/관전자 flush 누락) 도 해결 — flush 호출을 적절한 핸들러들에 추가:
//   attack_result (기존), being_attacked (기존), skill_result (NEW — 시전자), team_skill_notice (NEW — 같은팀/적팀),
//   team_ally_attacked (NEW), team_ally_hit (NEW), status_update (NEW — 1v1 상대 시전 시점).
const DEFENSIVE_PASSIVE_TYPES = new Set(['bodyguard', 'monk', 'count', 'armoredWarrior', 'wizard']);
S._pendingDefensiveAlerts = S._pendingDefensiveAlerts || [];

// 패시브 type → { pieceType, displayName } — 말풍선 표시 대상
const PASSIVE_BUBBLE_INFO = {
  wizard:         { pieceType: 'wizard',         name: '인스턴트매직' },
  monk:           { pieceType: 'monk',           name: '가호' },
  monk_attack:    { pieceType: 'monk',           name: '가호' },
  armoredWarrior: { pieceType: 'armoredWarrior', name: '아이언스킨' },
  count:          { pieceType: 'count',          name: '폭정' },
  bodyguard:      { pieceType: 'bodyguard',      name: '충성' },
  torturer:       { pieceType: 'torturer',       name: '표식' },
};

// 패시브 발동 시 — 해당 piece 카드에서 보드 쪽으로 주황 말풍선 (스킬 시전 말풍선과 동일 디자인)
function showPassiveBubble(type, playerIdx) {
  const info = PASSIVE_BUBBLE_INFO[type];
  if (!info) return;
  // 카드 찾기 — 1v1 / 팀 모드 분기
  let card = null;
  if (S.isTeamMode) {
    const player = (S.teamGamePlayers || []).find(p => p.idx === playerIdx);
    const idx = (player?.pieces || []).findIndex(pc => pc.type === info.pieceType);
    if (idx >= 0) {
      card = document.querySelector(`.team-profile-block[data-player-idx="${playerIdx}"] [data-piece-idx="${idx}"]`);
    }
  } else if (S.isSpectator) {
    // 관전자 — playerIdx 별 컨테이너 + my-piece-card / opp-piece-card 구분
    const containerSel = (playerIdx === 0) ? '#my-pieces-info' : '#opp-pieces-info';
    const cardSel = (playerIdx === 0) ? '.my-piece-card' : '.opp-piece-card';
    const sourcePieces = (playerIdx === 0) ? (S.specP0Pieces || S.myPieces) : (S.specP1Pieces || S.oppPieces);
    const idx = (sourcePieces || []).findIndex(pc => pc.type === info.pieceType);
    if (idx >= 0) {
      card = document.querySelectorAll(`${containerSel} ${cardSel}`)[idx];
    }
  } else {
    // 1v1 — playerIdx 가 본인이면 my, 아니면 opp
    const isMine = (playerIdx === S.playerIdx);
    const sourcePieces = isMine ? S.myPieces : S.oppPieces;
    const idx = (sourcePieces || []).findIndex(pc => pc.type === info.pieceType);
    if (idx >= 0) {
      const containerSel = isMine ? '#my-pieces-info' : '#opp-pieces-info';
      const cardSel = isMine ? '.my-piece-card' : '.opp-piece-card';
      card = document.querySelectorAll(`${containerSel} ${cardSel}`)[idx];
    }
  }
  if (card && typeof showSkillCastBubble === 'function') {
    showSkillCastBubble(card, info.name, 'passive');
  }
}

function _renderPassiveAlert(payload) {
  const { type, msg, playerIdx, targetName } = payload || {};
  // ★ 순차 처리: 저주 데미지가 곧 해제로 이어지는 경우(HP≤1), 해제 토스트/로그/SFX 가 데미지
  //   임팩트(피격 모션) 전에 먼저 터지지 않도록, 임팩트 완료 시각까지 이 알림 전체를 보류한다.
  if (type === 'curse_removed' && typeof playerIdx === 'number' && targetName) {
    const _wait = (typeof _curseRemovalWaitMs === 'function') ? _curseRemovalWaitMs(`${playerIdx}:${targetName}`) : 0;
    if (_wait > 0) { setTimeout(() => { try { _renderPassiveAlert(payload); } catch (e) {} }, _wait + 50); return; }
  }
  addLog(msg, 'skill');
  if (type !== 'curse_tick') {
    const passiveSfx = pickPassiveSfxByType(type);
    if (passiveSfx) passiveSfx(); else playSfxPassive();
  }
  // ★ 사용자 보고 (유황범람 + 마법사 타이밍): wizard 의 SP gain 오브 애니는 toast/log 와 같이
  //   flush 시점에 발사돼야 함. 이전엔 passive_alert 수신 즉시 spawn → 보드 애니 시작 전 출현.
  if (type === 'wizard') {
    let targetSlot = 'mine';
    if (S.isTeamMode) {
      const owner = (S.teamGamePlayers || []).find(p => p.idx === playerIdx);
      if (owner) targetSlot = (owner.teamId === S.teamId) ? 'mine' : 'opp';
    } else {
      targetSlot = (playerIdx === S.playerIdx) ? 'mine' : 'opp';
    }
    try { spawnInstantGainOrb(targetSlot); } catch (e) {}
  }
  // ★ 패시브 말풍선 — 해당 piece 카드에서 주황 말풍선 (저주 관련 type 은 스킬·패시브 와 무관해 제외)
  if (typeof playerIdx === 'number' && PASSIVE_BUBBLE_INFO[type]) {
    showPassiveBubble(type, playerIdx);
  }
  const isCurseToast = (type === 'curse_tick' || type === 'curse_removed');
  if (S.isSpectator) {
    showSkillToast(msg, false, playerIdx, isCurseToast ? 'curse' : undefined);
    return;
  }
  const isEnemy = (playerIdx !== undefined) ? (playerIdx !== S.playerIdx) : false;
  showSkillToast(msg, isEnemy, undefined, isCurseToast ? 'curse' : undefined);
}

// 데미지 감소형 패시브(가호/폭정/아이언스킨) — 격파 발생 시 토스트 생략, 로그는 유지
const REDUCTION_PASSIVE_TYPES = new Set(['monk', 'count', 'armoredWarrior']);
function flushDefensiveAlerts(opts) {
  if (!S._pendingDefensiveAlerts || S._pendingDefensiveAlerts.length === 0) return;
  const skipReduction = !!(opts && opts.skipReduction);
  const list = S._pendingDefensiveAlerts;
  S._pendingDefensiveAlerts = [];
  for (const item of list) {
    if (skipReduction && REDUCTION_PASSIVE_TYPES.has(item.type)) {
      // 로그만 작성 (토스트 생략)
      addLog(item.msg, 'skill');
      continue;
    }
    _renderPassiveAlert(item);
  }
}

socket.on('passive_alert', (payload) => {
  const { type, playerIdx, markCells } = payload || {};
  // 호위무사 가로채기 플래그는 being_attacked 측 보호 애니메이션 분기에 사용
  if (type === 'bodyguard') S._bodyguardIntercepted = true;
  // ★ 사용자 보고: wizard 의 SP gain 오브는 더 이상 즉시 spawn 안 함 — flush 시점(_renderPassiveAlert)에 발사.
  // 공격 반응형 패시브는 버퍼에 쌓아두고 being_attacked 직후 flush
  if (DEFENSIVE_PASSIVE_TYPES.has(type)) {
    S._pendingDefensiveAlerts.push(payload);
    return;
  }
  // ★ 표식 리워크: 인두 낙하 보드 애니메이션 — 셀 좌표가 있을 때만 발사.
  //   sound 는 animateMarkBrand 의 onSizzle 콜백에서 playSfxTorturerMark 호출 → _renderPassiveAlert
  //   의 기본 패시브 사운드와 중복 방지를 위해 type='torturer' 일 때 pickPassiveSfxByType 가 이미
  //   playSfxTorturerMark 를 반환하므로, anim 의 onSizzle 은 생략하고 기본 SFX 만 사용.
  if (type === 'torturer' && Array.isArray(markCells) && markCells.length > 0) {
    // ★ 사용자 요청 (분리): 🎯 아이콘 / statusEffects 는 인두 낙하 시점 (이 핸들러) 에서 적용.
    //   적 위치 노출(marked) 은 이미 mark_cast 시점에 처리됨 — 여기선 statusEffects 갱신만.
    const isMyOrTeammate = (() => {
      if (typeof playerIdx !== 'number') return false;
      if (playerIdx === S.playerIdx) return true;
      if (S.isTeamMode) {
        const mates = (S.teamGamePlayers || []).filter(p => p.teamId === S.teamId).map(p => p.idx);
        return mates.includes(playerIdx);
      }
      return false;
    })();
    for (const cell of markCells) {
      let _markedPc = null;   // ★ 캐러셀이면 이 새로 표식된 유닛 슬롯으로 자동 이동
      // 시전자 시점에서 적 piece 의 statusEffects 갱신 (🎯 아이콘 렌더링 트리거)
      if (isMyOrTeammate && Array.isArray(S.oppPieces)) {
        const opp = S.oppPieces.find(p => p && p.alive && p.col === cell.col && p.row === cell.row);
        if (opp) {
          _markedPc = opp;
          opp.marked = true;
          opp.statusEffects = opp.statusEffects || [];
          if (!opp.statusEffects.some(e => e.type === 'mark')) {
            opp.statusEffects.push({ type: 'mark', source: playerIdx });
          }
          // ★ 사용자 보고 (턴 종료해야 갱신): Map 의 hasMarkStatus 갱신 — 다음 reseed 에서도 🎯 보장
          if (S._revealedMarkedOpps instanceof Map) {
            const targetOwnerIdx = (typeof opp.ownerIdx === 'number') ? opp.ownerIdx : (1 - S.playerIdx);
            const pieceIdx = (typeof opp.index === 'number') ? opp.index : S.oppPieces.indexOf(opp);
            const key = `${targetOwnerIdx}:${pieceIdx}`;
            if (S._revealedMarkedOpps.has(key)) {
              const info = S._revealedMarkedOpps.get(key);
              info.hasMarkStatus = true;
              S._revealedMarkedOpps.set(key, info);
            }
          }
        }
      }
      // 피격자 시점 — 자기 piece 가 그 셀에 있으면 자기 statusEffects 갱신 (카드 🎯 표시용)
      if (Array.isArray(S.myPieces)) {
        const my = S.myPieces.find(p => p && p.alive && p.col === cell.col && p.row === cell.row);
        if (my) {
          if (!_markedPc) _markedPc = my;
          my.statusEffects = my.statusEffects || [];
          if (!my.statusEffects.some(e => e.type === 'mark')) {
            my.statusEffects.push({ type: 'mark', source: playerIdx });
          }
        }
      }
      // 팀모드 — 팀원 piece 도 statusEffects 갱신 (카드 🎯 표시)
      if (S.isTeamMode && Array.isArray(S.teammatePieces)) {
        const tp = S.teammatePieces.find(p => p && p.alive && p.col === cell.col && p.row === cell.row);
        if (tp) {
          if (!_markedPc) _markedPc = tp;
          tp.statusEffects = tp.statusEffects || [];
          if (!tp.statusEffects.some(e => e.type === 'mark')) {
            tp.statusEffects.push({ type: 'mark', source: playerIdx });
          }
        }
      }
      // ★ 캐러셀이면 새로 표식된 유닛 슬롯으로 자동 이동(표식 부여 연출이 그 유닛에 보이도록)
      if (window._crForceCell && _markedPc) window._crForceCell(cell.col, cell.row, _markedPc);
    }
    // ★ animateMarkBrand 를 renderGameBoard 보다 먼저 — 소환 플래그(동기)로 idle 표식 레이어를 억제해
    //   인두/생성 GIF 가 idle 과 따로 놀지 않고 한 시퀀스로 재생되게 함.
    if (typeof animateMarkBrand === 'function') {
      try { animateMarkBrand(markCells); } catch (e) {}
    }
    if (typeof renderGameBoard === 'function') renderGameBoard();
    if (typeof renderMyPieces === 'function') renderMyPieces();
    if (typeof renderOppPieces === 'function') renderOppPieces();
  }
  _renderPassiveAlert(payload);
});

// ── 유해 피격/파괴 동기화 ──
// 서버가 공격으로 유해 stage 가 바뀌거나(1→2→3) 파괴(3타)될 때 보낸다.
//   hits: [{col,row,stage,destroyed}] — stage 기반 그래픽 처리는 추후 확장.
socket.on('remains_update', ({ remains, hits }) => {
  const board = document.getElementById('game-board');
  // ★ 새로 생긴 유해(사망 → 유해 생성) 감지 — 캐러셀이면 그 유해 슬롯으로 자동 이동.
  //   _crApplyForced 는 renderGameBoard 끝에서 돌므로, 각 renderGameBoard 직전에 플래그를 세팅.
  const _oldRemKeys = new Set((S.remains || []).map(r => `${r.col},${r.row}`));
  const _newRemains = (remains || []).filter(r => r && !_oldRemKeys.has(`${r.col},${r.row}`));
  const _forceNewRemains = () => {};   // 사망→유해는 인덱스 해골 모핑으로 표현 — 셀 페이지 전환 안 함
  // 폴백 — 애니 모듈/보드 없거나 hits 정보 없으면 상태만 즉시 반영.
  if (!board || !Array.isArray(hits) || hits.length === 0 || typeof animateRemainsHit !== 'function') {
    S.remains = remains || [];
    S._cellFP = null;
    _forceNewRemains();
    if (typeof renderGameBoard === 'function') renderGameBoard();
    return;
  }
  // ★ 단계별 피격 연출 — 현재 DOM(이전 단계)에서 GIF 재생 후 다음 단계 정착/제거.
  //   S.remains(상태)는 애니 정착 후에 갱신 → 그 전 동시 렌더가 셀을 새 단계로 덮어쓰지 않음
  //   (핑거프린트가 변하지 않아 해당 셀은 재구축되지 않고 진행 중 GIF 가 보존됨).
  // ★ 타이밍 동기화 — 일반 유닛 피격과 동일한 임팩트 순간(S._impactAtTs)에 발동.
  //   서버가 remains_update 를 공격 이벤트 뒤(process.nextTick)에 보내므로, 이 핸들러가 돌 때
  //   직전 공격 핸들러가 S._impactAtTs 를 이미 세팅해 둠. 그 시각까지 대기 후 재생.
  const _now = Date.now();
  const _aimAt = S._impactAtTs || 0;
  const _delay = (_aimAt > _now && (_aimAt - _now) < 4000) ? (_aimAt - _now) : 0;
  S._impactAtTs = 0;  // 1회성 — 다음 이벤트로 재사용 방지
  // ★ FIX (#5 팀전 유해 피격 다음단계 겹침): 피격 애니 진행 중인 셀을 보호 집합에 등록.
  //   팀전의 team_game_update(applyTeamGameState)가 이 셀의 유해를 서버의 새 단계로 조기 교체하면
  //   피격 GIF 위에 다음 단계 PNG 가 겹쳐 보인다 → 보호 집합의 셀은 현재 단계를 유지(아래 applyTeamGameState).
  if (!S._pendingRemainsHitCells) S._pendingRemainsHitCells = new Set();
  for (const h of hits) S._pendingRemainsHitCells.add(`${h.col},${h.row}`);
  let pending = hits.length;
  const finalize = () => {
    if (--pending > 0) return;
    for (const h of hits) S._pendingRemainsHitCells.delete(`${h.col},${h.row}`);
    S.remains = remains || [];
    S._cellFP = null;  // 다음 렌더가 최종 단계를 정확히 반영
    _forceNewRemains();   // ★ 새 유해 생성 셀이 캐러셀이면 그 유해로 이동
    // ★ FIX (유해 피격 단계 미반영): 애니 정착 직후 즉시 재렌더 — 새 단계가 화면에 바로 반영되게.
    //   (이전엔 다음 렌더(턴 종료)까지 옛 단계가 남는 레이스가 있었음)
    if (typeof renderGameBoard === 'function') renderGameBoard();
  };
  // ★ 멀티유닛 셀: 유해 슬롯이 숨어있으면 임팩트 전에 미리 그 슬롯으로 슬라이드 → 임팩트 시 셀에서 단계 GIF(파괴 애니) 재생
  //   = 단계 진행이 보이게. (유해는 단계 메커닉이 핵심이라 인덱스 해골만으론 단계를 못 보여줌 → 셀 GIF 유지.) 인덱스 해골도 함께 피격.
  let _slideNeeded = false;
  for (const h of hits) {
    try {
      const _ck = `${h.col},${h.row}`;
      const _st = window._cellCarouselState && window._cellCarouselState[_ck];
      if (_st && _st.pieces && _st.pieces.length > 1) {
        const _ri = _st.pieces.findIndex(p => p.owner === 'remains');
        if (_ri >= 0 && _ri !== _st.idx && !_st.busy && typeof window._crSlideTo === 'function') {
          window._crSlideTo(_ck, _ri); _slideNeeded = true;
        }
      }
    } catch (e) {}
  }
  const _run = () => {
    for (const h of hits) {
      const _ck = `${h.col},${h.row}`;
      const _st = window._cellCarouselState && window._cellCarouselState[_ck];
      if (_st && _st.pieces && _st.pieces.length > 1) {
        try { const _remP = _st.pieces.find(p => p.owner === 'remains'); if (_remP) window._crHitIndex(_ck, _remP.pcRef); } catch (e) {}   // 인덱스 해골도 흔들림+번쩍
      }
      const facingLeft = !!(S._remainsFacing && S._remainsFacing[_ck]);
      animateRemainsHit(board, h.col, h.row, { hitNumber: (h.stage || 2) - 1, facingLeft, onSettle: finalize });   // 셀에서 단계 GIF + 단계 진행
    }
  };
  const _runDelay = Math.max(_delay, _slideNeeded ? 230 : 0);
  if (_runDelay > 0) setTimeout(_run, _runDelay); else _run();
});
socket.on('spectator_remains_update', ({ remains, hits }) => {
  S.remains = remains || [];
  S._cellFP = null;
  if (S.specGameState) {
    S.specGameState.remains = remains || [];
    if (typeof renderSpectatorGame === 'function') renderSpectatorGame(S.specGameState);
  } else if (typeof renderGameBoard === 'function') {
    renderGameBoard();
  }
});

// ── 게임 오버 ──
socket.on('game_over', ({ win, draw, opponentName, winnerName, loserName, spectator, reason, replayWinnerPieces, replayBoardObjects, replayBounds }) => {
  // 게임 간 stale 데이터 차단 — 다음 게임의 교환 배지 오탐 방지
  S.oppRevealChars = null;
  // 무승부 시에도 타이머 절대 재가동 안 되게 차단
  S._gameEnded = true;
  stopClientTimer();
  // 세팅 단계 기권: 즉시 + 페이드 없음 / 게임 중: 마지막 연출(사망 GIF·유해 / 보드 파괴)이
  // 완료된 뒤 1초 텀을 두고 결과 화면 표시. (scheduleGameOverReveal 가 연출 종료를 감지)
  const inGame = _isInGameScreen();
  scheduleGameOverReveal(inGame, () => {
    _showGameOverScreen(!inGame);
    runGameOverRender();
  });
  function runGameOverRender() {
  if (!spectator) bgmPlay(win ? 'victory' : (draw ? 'victory' : 'defeat'));
  const r = reason || {};
  const victims = (r.victims || []).join(', ');
  const killer = r.killer || '';

  // Helper: build victim string (e.g. "궁수, 장군, 기사")
  function victimStr(vs) {
    const arr = vs || [];
    if (arr.length === 0) return '';
    if (arr.length === 1) return arr[0];
    if (arr.length === 2) return `${arr[0]}${조사(arr[0], '과', '와')} ${arr[1]}`;
    return arr.join(', ');
  }

  // ── 무승부 (보드 축소 양측 전멸 또는 unreachable) ──
  if (draw) {
    document.getElementById('gameover-icon').textContent = '🤝';
    document.getElementById('gameover-title').textContent = '무승부';
    document.getElementById('gameover-title').style.color = 'var(--muted)';
    const drawMsg = (reason && reason.type === 'unreachable_draw')
      ? '게임을 끝낼 수 없어 무승부입니다.'
      : (reason && reason.type === 'simultaneous_draw')
      ? '폭탄 폭발로 양 측 모든 유닛이 동시에 전멸했습니다.'
      : '보드 축소로 양 팀 모든 말이 전멸해 무승부입니다.';
    document.getElementById('gameover-sub').textContent = drawMsg;
    return;
  }

  const isSpec = spectator || S.isSpectator;
  const W = winnerName || opponentName || '?';
  const L = loserName || opponentName || '?';
  const vs = victimStr(r.victims);

  if (isSpec) {
    // ── 관전자 메시지 ──
    document.getElementById('gameover-icon').textContent = '👁';
    document.getElementById('gameover-title').textContent = '게임 종료';
    document.getElementById('gameover-title').style.color = 'var(--accent)';
    let sub = '';
    switch (r.type) {
      case 'surrender': sub = `${L}의 기권으로, ${W}의 승리입니다.`; break;
      case 'shrink': sub = `보드 축소로 ${L}의 말이 전멸해 ${W}의 승리`; break;
      case 'trap': sub = `덫으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
      case 'bomb': sub = `폭탄으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
      case 'sulfur': sub = `유황범람으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
      case 'nightmare': sub = `악몽으로 상대의 모든 말을 제거해 ${W}의 승리`; break;
      case 'attack': sub = `${W}의 승리`; break;
      default: sub = `${W}의 승리`;
    }
    document.getElementById('gameover-sub').textContent = sub;
  } else if (win) {
    // ── 승리 메시지 ──
    document.getElementById('gameover-icon').textContent = '🏆';
    document.getElementById('gameover-title').textContent = '승리';
    document.getElementById('gameover-title').style.color = 'var(--accent)';
    let sub = '';
    switch (r.type) {
      case 'surrender': sub = `${opponentName}의 기권입니다.`; break;
      case 'shrink': sub = `상대가 보드 축소를 피하지 못해 승리했습니다.`; break;
      case 'trap': sub = `덫으로 상대의 모든 말을 제거해 승리했습니다.`; break;
      case 'bomb': sub = `폭탄으로 상대의 모든 말을 제거해 승리했습니다.`; break;
      case 'sulfur': sub = `유황범람으로 상대의 모든 말을 제거해 승리했습니다.`; break;
      case 'nightmare': sub = `악몽으로 상대의 모든 말을 제거해 승리했습니다.`; break;
      case 'attack': sub = `${opponentName}의 모든 유닛을 제거해 승리했습니다.`; break;
      default: sub = `${opponentName}의 모든 유닛을 제거해 승리했습니다.`;
    }
    document.getElementById('gameover-sub').textContent = sub;
  } else {
    // ── 패배 메시지 ──
    // #15: 일반 패배는 해골 이모지 제거 + 상대 마지막 배치 그리드 노출.
    //      단, 기권·세팅 단계 이탈로 인한 패배는 그리드가 무의미하므로 기존대로 💀 유지.
    document.getElementById('gameover-icon').textContent = r.type === 'surrender' ? '💀' : '';
    document.getElementById('gameover-title').textContent = r.type === 'surrender' ? '기권' : '패배';
    document.getElementById('gameover-title').style.color = 'var(--danger)';
    let sub = '';
    switch (r.type) {
      case 'surrender': sub = `기권하여 패배했습니다.`; break;
      case 'shrink': sub = `보드 축소를 피하지 못해 패배하였습니다.`; break;
      case 'trap': sub = `덫으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
      case 'bomb': sub = `폭탄으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
      case 'sulfur': sub = `유황범람으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
      case 'nightmare': sub = `악몽으로 모든 유닛이 쓰러져 패배하였습니다.`; break;
      case 'attack': sub = `${opponentName}에게 패배했습니다.`; break;
      default: sub = `${opponentName}에게 패배했습니다.`;
    }
    document.getElementById('gameover-sub').textContent = sub;
    // 상대 마지막 배치 그리드 렌더 (기권은 의미 없음 → 표시 안함)
    if (r.type !== 'surrender' && Array.isArray(replayWinnerPieces) && replayBounds) {
      try { renderDefeatReplayBoard(replayWinnerPieces, replayBoardObjects || [], replayBounds); } catch (e) {}
    }
  }
  }  // end runGameOverRender
});

// #15: 패배 화면 — 상대 마지막 배치 그리드 렌더 (인게임 보드와 동일한 셀 스타일·마크업)
function renderDefeatReplayBoard(winnerPieces, objects, bounds) {
  const wrap = document.getElementById('gameover-replay');
  const board = document.getElementById('gameover-replay-board');
  if (!wrap || !board) return;
  wrap.classList.remove('hidden');
  const total = (bounds.max - bounds.min + 1);
  // ★ #10 — 셀 크기를 뷰포트에 맞게 산정(모바일 7x7 이 넘쳐 포메이션 깨지던 문제). 데스크탑은 56px 유지.
  const _gap = 4, _pad = 12;
  const _avail = Math.min((window.innerWidth || 360) - 36, 380);
  const cellPx = Math.max(26, Math.min(56, Math.floor((_avail - _pad - _gap * (total - 1)) / total)));
  board.innerHTML = '';
  board.style.gridTemplateColumns = `repeat(${total}, ${cellPx}px)`;
  board.style.gridTemplateRows = `repeat(${total}, ${cellPx}px)`;
  for (let r = 0; r < total; r++) {
    for (let c = 0; c < total; c++) {
      const cell = document.createElement('div');
      cell.className = 'cell';
      const realCol = bounds.min + c;
      const realRow = bounds.min + r;
      cell.dataset.col = realCol;
      cell.dataset.row = realRow;
      const pcs = (winnerPieces || []).filter(p => p.alive && p.col === realCol && p.row === realRow);
      if (pcs.length > 0) {
        const pc = pcs[0];
        cell.classList.add('has-piece');
        // 인게임 piece-marker 와 동일 마크업
        cell.innerHTML = `<div class="piece-marker"><span class="p-icon">${pieceIconHtml(pc.icon, {size:'1.2em'})}</span><span class="p-hp">${pc.hp}</span></div>`;
      }
      const objHere = (objects || []).find(o => o.col === realCol && o.row === realRow);
      if (objHere) {
        if (objHere.type === 'trap') cell.classList.add('has-trap');
        else if (objHere.type === 'bomb') cell.classList.add('has-bomb');
        else if (objHere.type === 'rat') cell.classList.add('has-rat');
      }
      board.appendChild(cell);
    }
  }
}

// ── 게임 종료 화면을 "연출 완료 후 텀을 두고" 띄우는 스케줄러 ──
// 서버는 킬/보드파괴 연산이 끝나는 즉시 game_over 를 보내지만, 인간이 결과를 인지하려면
// 마지막 연출이 끝난 뒤 약간의 텀이 필요하다. (사용자 요청)
//   - 사망으로 인한 종료: 마지막 사망 GIF + 유해 생성 완료까지 대기 → 1초 후 결과 화면.
//   - 보드 파괴(축소)로 인한 종료: 보드 파괴 애니 + 프로필 사망 갱신 완료까지 대기 → 1초 후.
//   - 세팅 단계 종료(기권 등): 연출이 없으므로 즉시.
// 진행 중인 연출은 S._pendingDeathCells(사망 GIF) / S._shrinkAnimUntil(보드 파괴) 로 감지.
// 스킬 hits 에 destroyed 가 있으면(스킬로 누군가 사망) 동기 가드를 켠다.
//   _pendingDeathCells 는 SP 비행 종료 후에야 세팅되므로, 그 전에 game_over 가 도착해도
//   scheduleGameOverReveal 이 결과 화면을 조기 노출하지 않도록 ~2.3초간 가드.
function _markSkillDeathIncoming(hits) {
  if (Array.isArray(hits) && hits.some(h => h && h.destroyed)) {
    S._skillDeathGuardUntil = Date.now() + 2300;
  }
}

function scheduleGameOverReveal(inGame, revealFn, opts) {
  opts = opts || {};
  if (!inGame) { revealFn(); return; }               // 세팅 단계 — 즉시
  const start = Date.now();
  // ★ 사용자 요청(강조): 승리/패배 대기 카운트는 *게임 중 모든 애니메이션 + 모든 토스트가
  //   완료된 시점*부터 시작. 결과 화면에 토스트가 뜨면 안 됨. → 토스트 큐/처리/표시 + 풀스크린
  //   연출 큐까지 모두 비워질 때까지 대기. 무한 대기 방지용 넉넉한 안전 캡만 둔다.
  const MAX_WAIT = 20000;
  const BUFFER = (opts.buffer != null) ? opts.buffer : 1000;  // 연출 완료 후 인지 텀
  (function waitAnims() {
    const deathPending  = !!S._pendingDeathCells;             // 사망 GIF/유해 진행 중
    const shrinkPending = (S._shrinkAnimUntil || 0) > Date.now();  // 보드 파괴 애니 진행 중
    const skillDeathGuard = (S._skillDeathGuardUntil || 0) > Date.now();  // 스킬 사망 연출 가드
    // ★ 풀스크린 연출(보드파괴/SP증정 등) 큐 진행 중
    const fullscreenPending = !!S._fullscreenBusy ||
      (Array.isArray(S._fullscreenQueue) && S._fullscreenQueue.length > 0) ||
      (Array.isArray(S._eventDuringFullscreen) && S._eventDuringFullscreen.length > 0);
    // ★ 토스트 — 큐 대기 / 처리 중 / 화면에 보이는 것까지 모두 사라질 때까지 대기.
    const toastPending = (_toastQueue && _toastQueue.length > 0) || _toastProcessing ||
      (_toastVisible && _toastVisible.length > 0);
    if ((deathPending || shrinkPending || skillDeathGuard || fullscreenPending || toastPending)
        && (Date.now() - start) < MAX_WAIT) {
      setTimeout(waitAnims, 80);
      return;
    }
    setTimeout(revealFn, BUFFER);
  })();
}

// 게임오버 화면 전환 — instant=true면 즉시, 아니면 느린 페이드인 (1.5초)
function _showGameOverScreen(instant) {
  // ★ 결과 화면 표시 후로는 토스트 절대 금지 (사용자 요청). scheduleGameOverReveal 이 이미 큐를
  //   비우고 호출하지만, 늦게 도착한 이벤트의 토스트까지 차단하는 안전장치.
  S._gameOverShown = true;
  const scr = document.getElementById('screen-gameover');
  if (scr) {
    scr.classList.remove('fade-in', 'fade-in-slow');
    if (!instant) scr.classList.add('fade-in-slow');
    document.querySelectorAll('.screen').forEach(s => { if (s !== scr) s.classList.remove('active'); });
    scr.classList.add('active');
    if (!instant) setTimeout(() => scr.classList.remove('fade-in-slow'), 1550);
  }
  // 게임 종료 시 세션 토큰 정리
  try { sessionStorage.removeItem('caligo_session'); } catch (e) {}
}

// 현재 화면이 게임 중인지 (세팅 단계면 false)
function _isInGameScreen() {
  const active = document.querySelector('.screen.active')?.id;
  return active === 'screen-game';
}

socket.on('disconnected', ({ msg }) => {
  stopClientTimer();
  addLog(msg, 'system');
  // #8: 0.2초 대기 + 페이드인
  setTimeout(() => {
    _showGameOverScreen();
    document.getElementById('gameover-icon').textContent = '🔌';
    document.getElementById('gameover-title').textContent = '연결 끊김';
    document.getElementById('gameover-title').style.color = 'var(--muted)';
    document.getElementById('gameover-sub').textContent = msg;
  }, 200);
});

socket.on('err', ({ msg }) => {
  showError('placement-error', msg);
  showError('hp-error', msg);
  showError('draft-error', msg);
  addLog(`⚠ ${msg}`, 'system');
  // 사용자에게 즉시 피드백 — 어떤 화면에서든 토스트로 알림 (버튼이 응답 없이 멈춰있다는 오해 방지)
  try { showSkillToast(`⚠ ${msg}`, false, undefined, 'event'); } catch (e) {}
  // ── 응답 없이 버튼이 잠긴 채로 머무는 문제 방지 ──
  // 세팅/게임 단계의 '대기 중...' 버튼들을 자동 복구하여 재시도 가능하게 함
  const RECOVER_BTN_IDS = [
    'btn-draft-confirm', 'btn-draft-select', 'btn-draft-random', 'btn-draft-recommend',
    'btn-team-draft-confirm', 'btn-team-reveal-continue',
    'btn-hp-confirm',
    'btn-reveal-confirm', 'btn-irev-confirm', 'btn-frev-confirm',
    'btn-exchange-confirm',
    'btn-placement-confirm',
  ];
  for (const id of RECOVER_BTN_IDS) {
    const el = document.getElementById(id);
    if (!el) continue;
    if (el.disabled && /대기 중/.test(el.textContent || '')) {
      el.disabled = false;
      // 원래 텍스트는 다음 렌더에서 복구되므로 임시 라벨만 정리
      el.textContent = '재시도';
    }
  }
});

socket.on('wait_msg', () => {
  // 의미: 세팅 단계에서 본인 확정 후 다른 플레이어 대기 (재접속/턴과 무관)
  // 사이드바의 n/4 진행도로 이미 충분히 표시됨 → UI는 변경하지 않음 (no-op)
});

