function getSkillIconHtml(skillId, opts) {
  const file = SKILL_ICON_PNG[skillId];
  if (!file) return '';
  const cls = (opts && opts.cls) ? opts.cls : 'skill-png-icon';
  return `<img class="${cls}" src="${encodeURI(file)}" alt="" loading="lazy">`;
}

