    const _markPc  = (_pc && _isMarked(_pc)) ? _pc : ((_tw && _isMarked(_tw)) ? _tw : null);
    const _cursePc = (_pc && _isCursed(_pc)) ? _pc : ((_tw && _isCursed(_tw)) ? _tw : null);
