    _sfxNoise(ctx, now, 0.04, 0.18, 200, 1200);
    _sfxTone(ctx, now, 180, 0.05, 'square', 0.1);
    _sfxNoise(ctx, now + 0.12, 0.04, 0.14, 200, 1200);
    _sfxTone(ctx, now + 0.12, 220, 0.05, 'square', 0.08);
    // 끝 클릭
