function openTutorial() {
  tutStep = 0;
  showScreen('screen-tutorial');
  renderTutorial();
}

function renderTutorial() {
  const content = document.getElementById('tutorial-content');
  content.innerHTML = TUTORIAL_STEPS[tutStep]();
  // re-trigger animation
  content.style.animation = 'none';
  content.offsetHeight;
  content.style.animation = '';

  // progress dots
  const prog = document.getElementById('tutorial-progress');
  prog.innerHTML = TUTORIAL_STEPS.map((_, i) =>
    `<div class="tut-dot ${i < tutStep ? 'done' : ''} ${i === tutStep ? 'active' : ''}"></div>`
  ).join('');

  // step label
  document.getElementById('tutorial-step-label').textContent = `${tutStep + 1} / ${TUTORIAL_STEPS.length}`;

  // nav buttons
  document.getElementById('btn-tut-prev').style.visibility = tutStep === 0 ? 'hidden' : 'visible';
  const nextBtn = document.getElementById('btn-tut-next');
  if (tutStep === TUTORIAL_STEPS.length - 1) {
    nextBtn.textContent = '🎮 게임 시작!';
    nextBtn.className = 'btn btn-secondary';
  } else {
    nextBtn.textContent = '다음 →';
    nextBtn.className = 'btn btn-primary';
  }
}

document.getElementById('btn-tutorial')?.addEventListener('click', openTutorial);
document.getElementById('btn-tutorial-back')?.addEventListener('click', () => showScreen('screen-lobby'));
document.getElementById('btn-tut-prev')?.addEventListener('click', () => {
  if (tutStep > 0) { tutStep--; renderTutorial(); }
});
document.getElementById('btn-tut-next')?.addEventListener('click', () => {
  if (tutStep < TUTORIAL_STEPS.length - 1) {
    tutStep++;
    renderTutorial();
  } else {
    // 마지막 페이지 → 로비로 돌아가기
    showScreen('screen-lobby');
  }
});

// ═══════════════════════════════════════════════════════════════
// ── 캐릭터 사전 (게임 중 열람) — '내 덱' 메뉴 슬라이드 동일 구성
// ═══════════════════════════════════════════════════════════════
(function setupCharacterDictionary() {
  const overlay = document.getElementById('char-dict-overlay');
  const btnOpen = document.getElementById('btn-char-dict');
  const btnClose = document.getElementById('char-dict-close');
  if (!overlay || !btnOpen) return;

  let dictTier = 1;
  let dictIdx = 0;
  let dictPreviewMode = 'attack';

  function getChars(tier) {
    return (S.characters || S.specCharacters || {})[tier] || [];
  }

  // dict-preview-board 5x5 그리드 빌드 (한 번만) — 드래프트 미리보기와 동일 사이즈
  function ensureDictBoard() {
    const board = document.getElementById('dict-preview-board');
    if (!board || board.dataset.built === '1') return;
    const totalSize = 5;
    const cellPx = 56;
    board.innerHTML = '';
    board.style.gridTemplateColumns = `repeat(${totalSize}, ${cellPx}px)`;
    board.style.gridTemplateRows = `repeat(${totalSize}, ${cellPx}px)`;
    for (let r = 0; r < totalSize; r++) {
      for (let cc = 0; cc < totalSize; cc++) {
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.dataset.col = cc;
        cell.dataset.row = r;
        board.appendChild(cell);
      }
    }
    board.dataset.built = '1';
  }

  // 미리보기 보드 갱신 — 단일 구현(updateDraftPreview)에 위임.
  //   이전에는 별도 복제 함수로 인해 쌍둥이 강도 분리 배치/색 분기/joinedTwins 색 분리가
  //   드래프트(=내 덱) 슬라이드와 일치하지 않았음. 이제 한 함수로 통합되어 모든 변경이 자동 동기화됨.
  function updateDictPreview(charData) {
    updateDraftPreview(charData, {
      boardEl: document.getElementById('dict-preview-board'),
      infoEl: document.getElementById('dict-preview-info'),
      tabsRoot: overlay,
      tabAttr: 'dict-mode',
      mode: dictPreviewMode,
    });
  }

  function renderDictSlide() {
    const chars = getChars(dictTier);
    if (chars.length === 0) return;
    if (dictIdx < 0) dictIdx = chars.length - 1;
    if (dictIdx >= chars.length) dictIdx = 0;
    const c = chars[dictIdx];
    dictPreviewMode = 'attack';

    // 공유 헬퍼 — 드래프트(=내 덱) 슬라이드와 동일 콘텐츠 렌더
    populateSlideContent(c, 'dict-slide');

    ensureDictBoard();
    updateDictPreview(c);

    // 아이콘 인덱스 활성 상태
    overlay.querySelectorAll('#dict-icon-index .icon-index-btn').forEach((btn, i) => {
      btn.classList.toggle('active', i === dictIdx);
    });
    // 스텝 인디케이터 활성/완료 상태
    overlay.querySelectorAll('#dict-step-indicator .dict-bookmark').forEach(el => {
      const tier = Number(el.dataset.tier);
      el.classList.toggle('active', tier === dictTier);
    });
  }

  function buildIconIndex() {
    const chars = getChars(dictTier);
    const wrap = document.getElementById('dict-icon-index');
    if (!wrap) return;
    wrap.innerHTML = '';
    chars.forEach((c, i) => {
      const btn = document.createElement('button');
      btn.className = 'icon-index-btn';
      btn.title = c.name;
      btn.innerHTML = `<span class="icon-index-emoji">${pieceIconHtml(c.icon, {size:'1.1em'})}</span>`;
      btn.addEventListener('click', () => { dictIdx = i; renderDictSlide(); });
      wrap.appendChild(btn);
    });
  }

  function setTier(tier) {
    if (!getChars(tier).length) return;
    dictTier = tier;
    dictIdx = 0;
    buildIconIndex();
    renderDictSlide();
  }

  function openDict() {
    if (!getChars(dictTier).length) {
      // 캐릭터 데이터가 아직 없으면 1티어부터 다시 시도 — 게임 시작 후 항상 채워짐
      dictTier = 1;
    }
    overlay.classList.remove('hidden');
    overlay.setAttribute('aria-hidden', 'false');
    buildIconIndex();
    renderDictSlide();
  }
  function closeDict() {
    overlay.classList.add('hidden');
    overlay.setAttribute('aria-hidden', 'true');
  }

  btnOpen.addEventListener('click', openDict);
  if (btnClose) btnClose.addEventListener('click', closeDict);
  overlay.addEventListener('click', (e) => { if (e.target === overlay) closeDict(); });

  // ★ 사용자 요청: 프로필 더블클릭 → 딕셔너리 해당 캐릭터 페이지로 직행.
  //   드래곤 → 드래곤 조련사 / 쌍둥이 누나·동생 → 쌍둥이 강도 매핑.
  //   특정 type 으로 딕셔너리를 열어 해당 캐릭터를 활성 슬라이드로 표시.
  window.openCharDictAt = function (charType) {
    if (!charType) return;
    let target = charType;
    if (target === 'dragon') target = 'dragonTamer';
    if (target === 'twins_elder' || target === 'twins_younger') target = 'twins';
    const characters = S.characters || S.specCharacters || {};
    let foundTier = null, foundIdx = -1;
    for (const tier of [1, 2, 3]) {
      const arr = characters[tier] || [];
      const idx = arr.findIndex(c => c && c.type === target);
      if (idx >= 0) { foundTier = tier; foundIdx = idx; break; }
    }
    if (foundTier == null) return;
    dictTier = foundTier;
    dictIdx = foundIdx;
    openDict();
  };

  // 튜토리얼 전용: 게임 외부에서 specCharacters 를 주입할 수 있도록 노출
  window.setSpecCharactersForTutorial = function(chars) {
    if (!S.characters) S.specCharacters = chars;
  };

  // 화살표
  const prevBtn = document.getElementById('dict-slide-prev');
  const nextBtn = document.getElementById('dict-slide-next');
  if (prevBtn) prevBtn.addEventListener('click', () => {
    const chars = getChars(dictTier);
    if (chars.length === 0) return;
    dictIdx = ((dictIdx - 1) % chars.length + chars.length) % chars.length;
    renderDictSlide();
  });
  if (nextBtn) nextBtn.addEventListener('click', () => {
    const chars = getChars(dictTier);
    if (chars.length === 0) return;
    dictIdx = (dictIdx + 1) % chars.length;
    renderDictSlide();
  });

  // 티어 탭
  overlay.querySelectorAll('#dict-step-indicator .dict-bookmark').forEach(el => {
    el.addEventListener('click', () => {
      const tier = Number(el.dataset.tier);
      if (tier) setTier(tier);
    });
  });

  // 공격범위 / 스킬 미리보기 탭
  overlay.querySelectorAll('.slide-preview-tab[data-dict-mode]').forEach(t => {
    t.addEventListener('click', () => {
      if (t.disabled) return;
      dictPreviewMode = t.dataset.dictMode;
      const chars = getChars(dictTier);
      if (chars[dictIdx]) updateDictPreview(chars[dictIdx]);
    });
  });

  // ESC 로 닫기
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && !overlay.classList.contains('hidden')) closeDict();
  });
})();

// ══════════════════════════════════════════════════════════════════
// ★ 보드 아래 4-버튼 액션바 통합 (행동 / 스킬 / 턴종료 / 기권)
// ══════════════════════════════════════════════════════════════════
(function setupBottomActionBar() {

  // ── 어떤 캐릭터가 행동 가능한가? ─────────────────────────────────
  function getActablePieces() {
    if (!S.myPieces || !S.isMyTurn) return [];
    const out = [];
    for (let i = 0; i < S.myPieces.length; i++) {
      const pc = S.myPieces[i];
      if (!pc || !pc.alive) continue;
      if (typeof pieceCanTakeBasicAction === 'function' && pieceCanTakeBasicAction(pc)) out.push(i);
      else if (typeof canPieceUseAnySkill === 'function' && canPieceUseAnySkill(i)) out.push(i);
    }
    return out;
  }

  // 시전 가능한 스킬이 한 개라도 있는가? — 스킬 버튼 dim 판정용
  function anyCastableSkill() {
    if (!S.myPieces || !S.isMyTurn) return false;
    for (let i = 0; i < S.myPieces.length; i++) {
      if (typeof canPieceUseAnySkill === 'function' && canPieceUseAnySkill(i)) return true;
    }
    return false;
  }

  // 기본 행동권 사용 가능한가? — 행동 버튼 dim 판정용
  function anyActableForBasic() {
    if (!S.myPieces || !S.isMyTurn) return false;
    for (const pc of S.myPieces) {
      if (pc && pc.alive && typeof pieceCanTakeBasicAction === 'function' && pieceCanTakeBasicAction(pc)) return true;
    }
    return false;
  }

  // ── 보드 위 [행동가능] / [행동불가] 플로팅 버튼 ────────────────────
  function _clearActionFloatingBtns() {
    document.querySelectorAll('.action-floating-btn').forEach(b => b.remove());
    document.querySelectorAll('#game-board .cell.actable-highlight').forEach(c => c.classList.remove('actable-highlight'));
  }
  function _placeActionFloatingBtn(pc, mode) {
    const board = document.getElementById('game-board');
    if (!board) return;
    const cellEl = board.querySelector(`.cell[data-col="${pc.col}"][data-row="${pc.row}"]`);
    if (!cellEl) return;
    if (mode === 'actable') cellEl.classList.add('actable-highlight');
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'action-floating-btn ' + (mode === 'actable' ? 'actable' : 'unable');
    btn.textContent = mode === 'actable' ? '행동가능' : '행동불가';
    btn.style.left = (cellEl.offsetLeft + cellEl.offsetWidth / 2) + 'px';
    btn.style.top = cellEl.offsetTop + 'px';
    btn.dataset.pieceIdx = String(S.myPieces.indexOf(pc));
    if (mode === 'actable') {
      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        _clearActionFloatingBtns();
        const idx = Number(btn.dataset.pieceIdx);
        if (Number.isInteger(idx) && typeof _showRadialActionMenu === 'function') {
          _showRadialActionMenu(pc.col, pc.row, idx);
        }
      });
    } else {
      btn.addEventListener('click', (e) => e.stopPropagation());
    }
    board.appendChild(btn);
  }

  function showActableHighlights() {
    _clearActionFloatingBtns();
    if (!S.myPieces) return;
    const idxs = getActablePieces();
    const actableSet = new Set(idxs);
    // ★ 사용자 요청: 질주/쌍검무 등 일부 piece 만 actable 인 케이스에서 나머지에는 [행동불가]
    //   플로팅 버튼 부착 — 시전자만 [행동가능], 그 외 모두 [행동불가]. (이전엔 무표시였음.)
    for (let i = 0; i < S.myPieces.length; i++) {
      const pc = S.myPieces[i];
      if (!pc || !pc.alive) continue;
      _placeActionFloatingBtn(pc, actableSet.has(i) ? 'actable' : 'unable');
    }
  }
  function showUnableHighlights() {
    _clearActionFloatingBtns();
    if (!S.myPieces) return;
    for (const pc of S.myPieces) {
      if (pc && pc.alive) _placeActionFloatingBtn(pc, 'unable');
    }
  }
  // ── 행동 버튼 상태 (let → 호이스팅 안 됨 → click 핸들러보다 먼저 선언 필수) ──
  // ★ 사용자 보고 (행동 버튼이 행동가능/행동불가 분류를 더이상 출력하지 않음):
  //   document click 핸들러는 floating 버튼을 지웠지만 _actionBtnState 는 그대로 두어
  //   다음 클릭 때 "이미 표시 중" 분기로 진입 → close-only → 표시되지 않음 (사용자 보고).
  //   해결: 클릭 시 floating 을 지울 때 state 도 idle 로 동기 리셋.
  let _actionBtnState = 'idle';   // 'idle' | 'actable-shown' | 'unable-shown'

  // 다른 곳 클릭 시 자동 닫힘
  document.addEventListener('click', (e) => {
    if (e.target.closest('.action-floating-btn')) return;
    if (e.target.closest('#btn-action')) return;
    _clearActionFloatingBtns();
    _actionBtnState = 'idle';   // ★ 상태도 동기화 — stale 'actable-shown' 잔존 차단
  });

  // ── 행동 버튼 핸들러 ──────────────────────────────────────────
  function onActionButtonClick() {
    if (!S.isMyTurn) return;
    const btn = document.getElementById('btn-action');
    const dimmed = btn && btn.classList.contains('dimmed');
    // 토글: 이미 표시 중이면 닫기
    if (_actionBtnState !== 'idle') {
      _clearActionFloatingBtns();
      _actionBtnState = 'idle';
      return;
    }
    // ★ floating 잔존물이 있다면 우선 클린 (방어적)
    _clearActionFloatingBtns();
    if (dimmed) {
      showUnableHighlights();
      _actionBtnState = 'unable-shown';
    } else {
      showActableHighlights();
      _actionBtnState = 'actable-shown';
    }
  }
  // 외부 트리거: 보드 셀 클릭 / 라디얼 등장 / 행동 완료 시 — state idle 로 리셋
  function _resetActionBtnState() { _actionBtnState = 'idle'; }
  // export to window for cleanup
  window._caligoResetActionBtnState = _resetActionBtnState;
  window._caligoClearActionFloatingBtns = _clearActionFloatingBtns;

  // ★ game.js 는 </body> 직전에 로드 → IIFE 실행 시점에 DOM 이미 완성.
  //   DOMContentLoaded 를 기다릴 필요 없이 즉시 핸들러 등록.
  //   (DOMContentLoaded 리스너는 이미 fired 후 추가되면 영원히 실행 안 됨 — 타이밍 버그 원천 차단)
  (function _registerBottomBarHandlers() {
    const btnAct = document.getElementById('btn-action');
    if (btnAct) btnAct.addEventListener('click', onActionButtonClick);
    const btnSkillEl = document.getElementById('btn-skill');
    if (btnSkillEl) {
      // 기본 동작 가로채기 — 글로벌 스킬 탭 열기
      btnSkillEl.addEventListener('click', (e) => {
        e.stopImmediatePropagation();
        if (!S.isMyTurn) return;
        openGlobalSkillTab();
      }, true);
    }
    // 글로벌 탭 닫기
    const closeBtn = document.getElementById('global-skill-close');
    if (closeBtn) closeBtn.addEventListener('click', closeGlobalSkillTab);
    const modal = document.getElementById('global-skill-modal');
    if (modal) modal.addEventListener('click', (e) => { if (e.target === modal) closeGlobalSkillTab(); });
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') {
        closeGlobalSkillTab();
        closeCharSkillPopup();
      }
    });
  })();

  // ── 글로벌 스킬 탭 모달 (읽기 전용) ─────────────────────────────
  function openGlobalSkillTab() {
    const modal = document.getElementById('global-skill-modal');
    if (!modal) return;
    renderGlobalSkillGrid();
    modal.classList.remove('hidden');
  }
  function closeGlobalSkillTab() {
    const modal = document.getElementById('global-skill-modal');
    if (!modal) return;
    modal.classList.add('hidden');
  }
  window.openGlobalSkillTab = openGlobalSkillTab;

  function renderGlobalSkillGrid() {
    const grid = document.getElementById('global-skill-grid');
    if (!grid || !S.myPieces) return;
    grid.innerHTML = '';
    // 액티브 스킬 보유 + 살아있는 캐릭터만
    const visible = [];
    const seenTwin = { elder: false, younger: false };
    for (let i = 0; i < S.myPieces.length; i++) {
      const pc = S.myPieces[i];
      if (!pc || !pc.alive) continue;
      const skills = (pc.skills && pc.skills.length > 0) ? pc.skills : [];
      if (skills.length === 0) continue;
      // 쌍둥이 중복 방지 — elder 만 표시
      if (pc.subUnit === 'elder' || pc.subUnit === 'younger') {
        if (seenTwin.elder || seenTwin.younger) continue;
        seenTwin.elder = true;
      }
      visible.push({ pc, idx: i, skills });
    }
    for (const { pc, idx, skills } of visible) {
      const card = document.createElement('div');
      card.className = 'gskill-card';
      // 캐릭터 행
      const charRow = document.createElement('div');
      charRow.className = 'gskill-char-row';
      charRow.innerHTML = `<span class="ic">${pieceIconHtml(pc.icon, {size:'1.2em'}) || '◯'}</span><span class="nm">${pc.name || pc.type}</span>`;
      card.appendChild(charRow);
      let anyOk = false;
      for (const sk of skills) {
        const ev = evalSkillCastable(idx, pc, sk);
        const box = document.createElement('div');
        box.className = 'gskill-box' + (ev.ok ? '' : ' locked');
        const tagInfo = getSkillTagInfo(sk);
        const spLabel = (sk.cost === 0 || sk.cost == null) ? '0 SP' : `${sk.cost} SP`;
        const spClass = (sk.cost === 0 || sk.cost == null) ? 'gskill-sp zero' : 'gskill-sp';
        box.innerHTML = `
          <span class="gskill-status-tag ${ev.ok ? 'ok' : 'no'}">${ev.ok ? '✓ 가능' : '✗ 불가'}</span>
          <div class="gskill-row-inline">
            ${getSkillIconHtml(sk.id, { cls: 'skill-png-icon gskill-icon' })}
            <span class="gskill-name">${sk.name || sk.id}</span>
            <span class="gskill-type-text ${tagInfo.cls}">${tagInfo.label}</span>
            <span class="${spClass}">${spLabel}</span>
          </div>
          ${ev.ok ? '' : `<div class="gskill-block-reason">${ev.why}</div>`}`;
        card.appendChild(box);
        if (ev.ok) anyOk = true;
      }
      if (anyOk) card.classList.add('has-castable');
      grid.appendChild(card);
    }
  }

  // ── 캐릭터 전용 스킬 탭 팝업 (부채꼴 → [스킬] 진입) ────────────────
  function openCharSkillPopup(pieceIdx, anchorRect) {
    closeCharSkillPopup();
    const pc = S.myPieces && S.myPieces[pieceIdx];
    if (!pc) return;
    const skills = (pc.skills && pc.skills.length > 0) ? pc.skills : [];
    if (skills.length === 0) return;
    const popup = document.createElement('div');
    popup.id = 'char-skill-popup';
    popup.className = 'char-skill-popup';
    popup.innerHTML = `
      <span class="corner-ornament tl"></span>
      <span class="corner-ornament tr"></span>
      <span class="corner-ornament bl"></span>
      <span class="corner-ornament br"></span>
      <div class="cskill-entries"></div>`;
    document.body.appendChild(popup);
    const wrap = popup.querySelector('.cskill-entries');
    for (const sk of skills) {
      const ev = evalSkillCastable(pieceIdx, pc, sk);
      const tagInfo = getSkillTagInfo(sk);
      const miniHeaderCls = tagInfo.cls.replace('tag-', 'mini-header-');
      const entry = document.createElement('div');
      entry.className = 'cskill-entry' + (ev.ok ? ' castable' : ' locked');
      const spLabel = (sk.cost === 0 || sk.cost == null) ? 'SP 소모 없음' : `SP ${sk.cost} 소모`;
      const spClass = (sk.cost === 0 || sk.cost == null) ? 'cskill-sp-cost zero' : 'cskill-sp-cost';
      const desc = getSkillBodyDesc(pc.type, sk.id, sk.desc || '');
      entry.innerHTML = `
        <div class="cskill-head">
          ${getSkillIconHtml(sk.id, { cls: 'skill-png-icon cskill-icon' })}
          <span class="cskill-name ${miniHeaderCls}">${sk.name || sk.id}</span>
          <span class="cskill-type-text ${tagInfo.cls}">${tagInfo.label}</span>
          <span class="${spClass}">${spLabel}</span>
        </div>
        <div class="cskill-desc-box">
          <p class="cskill-desc-text">${desc}</p>
          <div class="cskill-actions${ev.ok ? '' : ' has-reason'}">
            ${ev.ok ? '' : `<span class="cskill-block-reason">${ev.why}</span>`}
            <button class="cskill-cast-btn ${ev.ok ? '' : 'disabled'}" ${ev.ok ? '' : 'disabled'}>
              ${ev.ok ? '시전' : '시전 불가'}
            </button>
          </div>
        </div>`;
      if (ev.ok) {
        const skId = sk.id;
        entry.querySelector('.cskill-cast-btn').addEventListener('click', (e) => {
          e.stopPropagation();
          closeCharSkillPopup();
          // 시전 직행 — 모달 재진입 없이 바로 스킬 핸들러 호출
          if (typeof handleSkillUse === 'function') {
            handleSkillUse(pieceIdx, pc, skId);
          } else if (typeof openSkillModal === 'function') {
            openSkillModal(pieceIdx);
          }
        });
      }
      wrap.appendChild(entry);
    }
    // 위치 — anchorRect 옆 (오른쪽이 화면 밖이면 왼쪽으로 fallback)
    const margin = 14;
    const popupW = 360;
    const popupH = popup.offsetHeight || 240;
    let left = (anchorRect ? anchorRect.right + margin : window.innerWidth / 2 - popupW / 2);
    let top  = (anchorRect ? anchorRect.top + (anchorRect.height / 2) - (popupH / 2) : window.innerHeight / 2 - popupH / 2);
    if (left + popupW > window.innerWidth - 12) {
      left = (anchorRect ? anchorRect.left - popupW - margin : 12);
    }
    if (left < 12) left = 12;
    if (top < 12) top = 12;
    if (top + popupH > window.innerHeight - 12) top = window.innerHeight - popupH - 12;
    popup.style.left = left + 'px';
    popup.style.top  = top + 'px';
  }
  function closeCharSkillPopup() {
    const popup = document.getElementById('char-skill-popup');
    if (popup) popup.remove();
  }
  document.addEventListener('click', (e) => {
    const popup = document.getElementById('char-skill-popup');
    if (popup && !popup.contains(e.target) && !e.target.closest('.radial-btn')) closeCharSkillPopup();
  });
  window.openCharSkillPopup = openCharSkillPopup;
  window.closeCharSkillPopup = closeCharSkillPopup;

  // 튜토리얼 전용: myPieces / sp / actionDone 임시 주입용 setter
  window.setMyPiecesForTutorial = function(pieces, sp, actionDone) {
    S.myPieces   = pieces;
    S.sp         = sp;
    S.actionDone = actionDone;
  };
  window.restoreMyPiecesAfterTutorial = function(origMyPieces, origSp, origActionDone) {
    S.myPieces   = origMyPieces;
    S.sp         = origSp;
    S.actionDone = origActionDone;
  };

  // ── 스킬 castability 평가 (글로벌·캐릭터 탭 공통) ───────────────
  function evalSkillCastable(pieceIdx, pc, sk) {
    if (!pc || !pc.alive) return { ok: false, why: '사망 — 시전 불가' };
    const isCursed = pc.statusEffects && pc.statusEffects.some(e => e.type === 'curse');
    if (isCursed) return { ok: false, why: '저주에 걸려 스킬 봉인' };
    const spSlot = S.isTeamMode ? (S.teamId ?? 0) : (S.playerIdx ?? 0);
    const totalSP = ((S.sp && S.sp[spSlot]) || 0) + ((S.instantSp && S.instantSp[spSlot]) || 0);
    if ((sk.cost || 0) > totalSP) return { ok: false, why: `SP 부족 (필요 ${sk.cost} · 보유 ${totalSP})` };
    if (sk.replacesAction && S.actionDone) return { ok: false, why: '이미 행동을 사용함' };
    if (sk.oncePerTurn && S.skillsUsedThisTurn && S.skillsUsedThisTurn.includes(`${pieceIdx}:${sk.id}`)) {
      return { ok: false, why: '이 스킬은 턴당 1회 — 이미 사용' };
    }
    if (sk.id === 'sprint' && pc.messengerSprintActive) return { ok: false, why: '이미 질주 활성' };
    if (sk.id === 'dualStrike' && pc.dualBladeAttacksLeft > 0) return { ok: false, why: '이미 쌍검무 활성' };
    // ★ 사용자 보고: 전령 질주 — 공격 후 / 다른 유닛 이동 후 사용 불가 (server 가드 동일 — server.js:4657-4663).
    if (sk.id === 'sprint') {
      if (S.lastActionType === 'attack') return { ok: false, why: '공격 후에는 질주를 사용할 수 없음' };
      if (S.lastActionType === 'move' && S.lastActionPieceType && S.lastActionPieceType !== 'messenger') {
        return { ok: false, why: '다른 유닛이 이동했으므로 질주를 사용할 수 없음' };
      }
    }
    // ★ 사용자 보고: 쌍검무 — 이동 후 / 다른 유닛 공격 후 사용 불가 (server 가드 동일 — server.js:4827-4833).
    if (sk.id === 'dualStrike') {
      if (S.lastActionType === 'move') return { ok: false, why: '이미 이동했으므로 쌍검무를 사용할 수 없음' };
      if (S.lastActionType === 'attack' && S.lastActionPieceType && S.lastActionPieceType !== 'dualBlade') {
        return { ok: false, why: '다른 유닛이 행동했으므로 쌍검무를 사용할 수 없음' };
      }
    }
    if (sk.id === 'detonate') {
      const bombs = (S.boardObjects || []).filter(o => o.type === 'bomb');
      if (bombs.length === 0) return { ok: false, why: '설치된 폭탄 없음' };
    }
    // ★ 사용자 요청: 쌍둥이 한쪽이 사망하면 나머지 한쪽 분신 스킬 무조건 잠금.
    //   분신 스킬은 elder ↔ younger 합류 — 짝이 없으면 사용 불가.
    if (sk.id === 'brothers' && (pc.subUnit === 'elder' || pc.subUnit === 'younger')) {
      const partnerSub = pc.subUnit === 'elder' ? 'younger' : 'elder';
      const partner = (S.myPieces || []).find(p => p.subUnit === partnerSub);
      if (!partner || !partner.alive) return { ok: false, why: '쌍둥이 짝이 사망 — 분신 불가' };
      // ★ 사용자 보고: 이미 같은 칸에 합류돼 있으면 분신 불필요 (이동이 무의미).
      if (partner.col === pc.col && partner.row === pc.row) {
        return { ok: false, why: '이미 합류 상태 — 분신 불필요' };
      }
    }
    // ★ 사용자 요청: 인간 사냥꾼 — 자기 칸에 이미 덫/폭탄이 있으면 잠금 (서버 가드와 매칭).
    if (sk.id === 'trap' && pc.type === 'manhunter') {
      const hasObjAtCell = (S.boardObjects || []).some(o =>
        (o.type === 'trap' || o.type === 'bomb') && o.col === pc.col && o.row === pc.row);
      if (hasObjAtCell) return { ok: false, why: '이미 덫/폭탄이 설치된 위치' };
    }
    // ★ 사용자 요청: 화약상 폭탄 설치 — 자기 칸 제외, 주변 8칸만 후보.
    //   8칸 모두 덫/폭탄 또는 보드 밖이면 잠금. 한 칸이라도 비어있으면 통과.
    if (sk.id === 'bomb' && pc.type === 'gunpowder') {
      const bounds = S.boardBounds || { min: 0, max: 4 };
      const objs = (S.boardObjects || []).filter(o => o && (o.type === 'trap' || o.type === 'bomb'));
      let anyOpen = false;
      for (let dc = -1; dc <= 1 && !anyOpen; dc++) {
        for (let dr = -1; dr <= 1 && !anyOpen; dr++) {
          if (dc === 0 && dr === 0) continue;       // 자기 칸 제외 — 8칸만 후보
          const c = pc.col + dc, r = pc.row + dr;
          if (c < bounds.min || c > bounds.max || r < bounds.min || r > bounds.max) continue;
          if (objs.some(o => o.col === c && o.row === r)) continue;
          anyOpen = true;
        }
      }
      if (!anyOpen) return { ok: false, why: '주변 설치 가능한 칸 없음' };
    }
    if (typeof skillHasValidTarget === 'function' && !skillHasValidTarget(pc, sk)) {
      return { ok: false, why: '유효한 대상이 없음' };
    }
    return { ok: true, why: null };
  }
  // ★ 사용자 요청: 글로벌 스킬 버튼 판정 (showActionBar) 도 동일 함수로 통일 — 전역 노출.
  window.evalSkillCastable = evalSkillCastable;

  // 스킬 유형 클래스/라벨 — 게임 통일 표기
  function getSkillTagInfo(sk) {
    if (sk.replacesAction) return { cls: 'tag-action', label: '행동소비형' };
    if (sk.oncePerTurn)    return { cls: 'tag-once',   label: '자유시전·1회' };
    return                       { cls: 'tag-free',   label: '자유시전형' };
  }

  // 정규 본문 설명 — CHAR_DETAILS 참조 (없으면 fallback)
  function getSkillBodyDesc(pieceType, skillId, fallback) {
    try {
      if (typeof CHAR_DETAILS === 'undefined') return fallback || '';
      const baseType = pieceType === 'twins_elder' || pieceType === 'twins_younger' ? 'twins' : pieceType;
      const detail = CHAR_DETAILS[baseType];
      if (!detail) return fallback || '';
      // 다중 스킬 (gunpowder 등) — blocks 의 desc
      if (Array.isArray(detail.blocks)) {
        for (const blk of detail.blocks) {
          if (blk.desc && (blk.head === skillId || _matchesSkillName(blk.head, skillId, baseType))) {
            return blk.desc;
          }
        }
      }
      // 단일 스킬 — body
      return detail.body || fallback || '';
    } catch (e) { return fallback || ''; }
  }
  function _matchesSkillName(head, skillId, pieceType) {
    // skillId 매핑 (서버의 id ↔ blocks 의 head 한글명)
    const map = {
      reform: '정비', sprint: '질주', recon: '정찰', trap: '덫 설치',
      bomb: '폭탄 설치', detonate: '기폭', herb: '약초학', shadow: '그림자 숨기',
      curse: '저주', dualStrike: '쌍검무', rats: '역병의 자손들',
      ring: '절대복종 반지', dragon: '드래곤 소환', divine: '신성',
      sulfurRiver: '유황범람', nightmare: '악몽', brothers: '분신',
    };
    return head === map[skillId];
  }

  // ── 라디얼 메뉴 [스킬] 클릭 시 — openSkillModal 대신 캐릭터 전용 팝업 ──
  // monkey-patch: openSkillModal 호출 인자가 piece-specific 일 때만 가로채기
  if (typeof window.openSkillModal === 'function' || true) {
    const _origOpen = window.openSkillModal;
    // openSkillModal 자체는 시전 처리에 활용되므로 별도 wrap 함수 export
    window.openCharSkillFromRadial = function(pieceIdx, anchorRect) {
      openCharSkillPopup(pieceIdx, anchorRect);
    };
  }

  // ── 행동 / 스킬 / 턴종료 버튼 dim 상태 갱신 (showActionBar 후 호출) ──
  function refreshBottomBarStates() {
    const btnAct  = document.getElementById('btn-action');
    const btnSkill = document.getElementById('btn-skill');
    const btnEnd  = document.getElementById('btn-end-turn');
    if (!btnAct || !btnSkill || !btnEnd) return;
    if (!S.isMyTurn) {
      // ★ 사용자 요청: 내 차례가 아니면 모든 액션 버튼을 dim 처리 (이전엔 dim 을 제거해 빛나는 버그).
      btnAct.classList.add('dimmed');
      btnSkill.classList.add('dimmed');
      btnEnd.classList.remove('attention');
      return;
    }
    btnAct.classList.toggle('dimmed', !anyActableForBasic());
    btnSkill.classList.toggle('dimmed', !anyCastableSkill());
    // 턴 종료 — 행동 안 했으면 attention pulse
    const noActionDone = !S.actionDone && !S.actionUsedSkillReplace
      && !(S.skillsUsedThisTurn && S.skillsUsedThisTurn.length > 0);
    btnEnd.classList.toggle('attention', noActionDone);
  }
  window._caligoRefreshBottomBar = refreshBottomBarStates;

  // showActionBar 호출 후 자동으로 refreshBottomBarStates 도 실행되도록 patch
  if (typeof window.showActionBar === 'function' || typeof showActionBar === 'function') {
    const origShow = (typeof window.showActionBar === 'function') ? window.showActionBar : null;
    // showActionBar 는 module-scoped 라 직접 patch 어려움 → 주기적 갱신 + 수동 호출 콤보로 처리
    // 보드 클릭 / 행동 / 스킬 / 턴 진입 등 모든 트리거에서 refresh 가 필요한데,
    // 가장 확실한 방법은 짧은 인터벌 (200ms) 로 주기적 갱신.
    setInterval(refreshBottomBarStates, 250);
  }

  // 라디얼 메뉴가 열릴 때 행동 플로팅 버튼 닫기
  const observer = new MutationObserver(() => {
    if (document.getElementById('radial-action-menu')) {
      _clearActionFloatingBtns();
      _actionBtnState = 'idle';
    }
  });
  // ★ game.js 는 </body> 직전에 로드 → DOM 이미 완성. 즉시 observe.
  observer.observe(document.body, { childList: true, subtree: false });

})();

// ══════════════════════════════════════════════════════════════════
// ★ 라디얼 메뉴 [스킬] 클릭 → 캐릭터 전용 팝업으로 라우팅 (override)
// ══════════════════════════════════════════════════════════════════
(function patchRadialSkillFlow() {
  // 부채꼴 메뉴 [스킬] 버튼이 클릭되면 cell-anchor 기준으로 캐릭터 전용 팝업 열기.
  // 캡처 단계에서 클릭 가로채기 → openSkillModal 우회.
  document.addEventListener('click', (e) => {
    const btn = e.target.closest('.radial-btn');
    if (!btn) return;
    if (btn.dataset.key !== 'skill') return;
    if (btn.disabled) return;
    if (!S.isMyTurn) return;
    if (typeof window.openCharSkillPopup !== 'function') return;
    // 라디얼이 닫히기 직전 piece idx 캡처
    const pieceIdx = S._radialMenuPiece;
    if (pieceIdx == null) return;
    // 셀 위치를 anchor 로
    const pc = S.myPieces && S.myPieces[pieceIdx];
    if (!pc) return;
    const cellEl = document.querySelector(`#game-board .cell[data-col="${pc.col}"][data-row="${pc.row}"]`);
    const anchorRect = cellEl ? cellEl.getBoundingClientRect() : null;
    // 기본 핸들러 (openSkillModal 호출) 차단
    e.stopImmediatePropagation();
    e.preventDefault();
    // 라디얼 닫기 + 캐릭터 팝업 열기
    if (typeof _closeRadialActionMenu === 'function') _closeRadialActionMenu();
    setTimeout(() => window.openCharSkillPopup(pieceIdx, anchorRect), 50);
  }, true);
})();

// ═══════════════════════════════════════════════════════════════
// ── 프로필 더블클릭/더블탭 → 캐릭터 딕셔너리 해당 페이지로 ──
//   대상: 본인 프로필 (.my-piece-card), 상대 프로필 (.opp-piece-card),
//         팀모드 4인 프로필 (.team-profile-block 안의 [data-team-piece]).
//   특수: 드래곤 → 드래곤 조련사, 쌍둥이 누나/동생 → 쌍둥이 강도 (window.openCharDictAt 가 처리).
//   delegation 으로 처리 — 카드가 자주 재렌더되어도 유지됨.
// ═══════════════════════════════════════════════════════════════
(function setupProfileDoubleClickToDictionary() {
  // 프로필 카드 → 해당 piece type 추출
  function _resolveTypeFromCard(card) {
    if (!card) return null;
    // 팀모드 카드 (data-team-piece) — 부모 .team-profile-block 의 player-idx + 카드의 piece-idx
    if (card.matches('[data-team-piece="1"]')) {
      const block = card.closest('.team-profile-block');
      if (!block) return null;
      const playerIdx = parseInt(block.getAttribute('data-player-idx'), 10);
      const pieceIdx = parseInt(card.getAttribute('data-piece-idx'), 10);
      if (isNaN(playerIdx) || isNaN(pieceIdx)) return null;
      // 1) 게임 중 — S.teamGamePlayers 우선
      const player = (S.teamGamePlayers || []).find(p => p.idx === playerIdx);
      const pc = player?.pieces?.[pieceIdx];
      if (pc?.type) return pc.type;
      // 2) 관전자 — specGameState 의 teamGamePlayers
      const specPlayer = (S.specGameState?.teamGamePlayers || []).find(p => p.idx === playerIdx);
      return specPlayer?.pieces?.[pieceIdx]?.type || null;
    }
    // 1v1 본인 카드 — #my-pieces-info .my-piece-card 인덱스 → S.myPieces
    if (card.matches('.my-piece-card') && card.closest('#my-pieces-info')) {
      const cards = document.querySelectorAll('#my-pieces-info .my-piece-card');
      const idx = Array.prototype.indexOf.call(cards, card);
      if (idx < 0) return null;
      // 관전자 시점 — specGameState.p0Pieces 사용
      if (S.isSpectator && S.specGameState) {
        return (S.specGameState.p0Pieces || [])[idx]?.type || null;
      }
      return (S.myPieces || [])[idx]?.type || null;
    }
    // 1v1 상대 카드 — #opp-pieces-info .opp-piece-card 인덱스 → S.oppPieces
    if (card.matches('.opp-piece-card') && card.closest('#opp-pieces-info')) {
      const cards = document.querySelectorAll('#opp-pieces-info .opp-piece-card');
      const idx = Array.prototype.indexOf.call(cards, card);
      if (idx < 0) return null;
      if (S.isSpectator && S.specGameState) {
        return (S.specGameState.p1Pieces || [])[idx]?.type || null;
      }
      return (S.oppPieces || [])[idx]?.type || null;
    }
    return null;
  }

  // ★ 카드의 "논리적 식별자" — DOM element 가 재렌더로 바뀌어도 같은 piece 면 같은 키.
  //   본인 카드 click 시 renderMyPieces 가 container.innerHTML='' 으로 카드 element 를 새로 만들기 때문에
  //   기본 dblclick 이벤트가 발사되지 않음. mousedown 두번을 직접 카운트해서 우회.
  function _logicalKey(card) {
    if (!card) return null;
    if (card.matches('[data-team-piece="1"]')) {
      const block = card.closest('.team-profile-block');
      const playerIdx = block ? block.getAttribute('data-player-idx') : null;
      const pieceIdx = card.getAttribute('data-piece-idx');
      return `team:${playerIdx}:${pieceIdx}`;
    }
    if (card.matches('.my-piece-card') && card.closest('#my-pieces-info')) {
      const cards = document.querySelectorAll('#my-pieces-info .my-piece-card');
      const idx = Array.prototype.indexOf.call(cards, card);
      return `my:${idx}`;
    }
    if (card.matches('.opp-piece-card') && card.closest('#opp-pieces-info')) {
      const cards = document.querySelectorAll('#opp-pieces-info .opp-piece-card');
      const idx = Array.prototype.indexOf.call(cards, card);
      return `opp:${idx}`;
    }
    return null;
  }

  // 더블클릭/더블탭 — mousedown 으로 직접 카운트. 첫 클릭 후 카드 DOM 이 재생성돼도 logical key 가 같으면 OK.
  let _lastClickKey = null;
  let _lastClickTime = 0;
  let _lastClickType = null;
  function _handleProfileTap(card) {
    if (!card) {
      _lastClickKey = null; _lastClickTime = 0; _lastClickType = null;
      return;
    }
    const key = _logicalKey(card);
    if (!key) return;
    const charType = _resolveTypeFromCard(card);
    if (!charType) return;
    const now = Date.now();
    // 두 번째 탭/클릭 — 같은 logical key + 320ms 안
    if (_lastClickKey === key && (now - _lastClickTime) < 320) {
      _lastClickKey = null; _lastClickTime = 0; _lastClickType = null;
      if (typeof window.openCharDictAt === 'function') {
        window.openCharDictAt(charType);
      }
      return;
    }
    _lastClickKey = key; _lastClickTime = now; _lastClickType = charType;
  }
  // 마우스: mousedown 두 번 — single-click 핸들러가 DOM 을 갈아엎기 전에 카운트.
  document.addEventListener('mousedown', (e) => {
    if (e.button !== 0) return;
    const card = e.target.closest('[data-team-piece="1"], .my-piece-card, .opp-piece-card');
    _handleProfileTap(card);
  }, true);
  // 터치: touchend — 모바일 더블탭. 동일 로직.
  document.addEventListener('touchend', (e) => {
    const card = e.target.closest('[data-team-piece="1"], .my-piece-card, .opp-piece-card');
    if (!card) {
      _lastClickKey = null; _lastClickTime = 0; _lastClickType = null;
      return;
    }
    const key = _logicalKey(card);
    const charType = _resolveTypeFromCard(card);
    if (!key || !charType) return;
    const now = Date.now();
    if (_lastClickKey === key && (now - _lastClickTime) < 320) {
      e.preventDefault();   // 줌 방지
      _lastClickKey = null; _lastClickTime = 0; _lastClickType = null;
      if (typeof window.openCharDictAt === 'function') window.openCharDictAt(charType);
      return;
    }
    _lastClickKey = key; _lastClickTime = now; _lastClickType = charType;
  }, { passive: false });
})();
